-- Poems batch 2
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('f87f89bd-21a1-4861-9590-eb27a2888aa2','郊廟歌辭 梁太廟樂舞辭 大合舞','不詳','唐','唐诗','tang','','[]','於穆皇祖，濬哲雍熙。',40,'全唐诗/poet.tang.0.json','["於穆皇祖，濬哲雍熙。", "美溢中夏，化被南陲。", "后稷累德，公劉創基。", "肇興九廟，樂合來儀。"]'),
('d5f1c26b-b71b-41d9-a261-95b0f036fe9c','郊廟歌辭 梁太廟樂舞辭 象功舞','不詳','唐','唐诗','tang','','[]','天地合德，睿聖昭彰。',40,'全唐诗/poet.tang.0.json','["天地合德，睿聖昭彰。", "累贈太傅，俄登魏王。", "雄名不朽，奕葉而光。", "建國之兆，君臨萬方。"]'),
('32a6054f-b534-4e84-b350-3ac909640f93','郊廟歌辭 梁太廟樂舞辭 來儀舞','不詳','唐','唐诗','tang','','[]','於赫帝命，應天順人。',40,'全唐诗/poet.tang.0.json','["於赫帝命，應天順人。", "亭育品彙，賓禮百神。", "洪基永固，景命惟新。", "肅恭孝享，祚我生民。"]'),
('826ce190-8078-4566-abe8-cd6b0f008072','郊廟歌辭 梁太廟樂舞辭 昭德舞','不詳','唐','唐诗','tang','','[]','肅肅文考，源濬派長。',40,'全唐诗/poet.tang.0.json','["肅肅文考，源濬派長。", "漢稱誕季，周實生昌。", "奄有四海，超彼百王。", "笙鏞迭奏，禮物熒煌。"]'),
('6ef3f8b3-47d4-46fc-a4e6-1e5f5409ca4b','郊廟歌辭 梁太廟樂舞辭 飲福','不詳','唐','唐诗','tang','','[]','戛玉摐金永頌聲，檿絲孤竹和且清。',32,'全唐诗/poet.tang.0.json','["戛玉摐金永頌聲，檿絲孤竹和且清。", "靈歆醉止犧象盈，自天降福千萬齡。"]'),
('bee147ae-b09f-4b5b-a916-8297f1584642','郊廟歌辭 梁太廟樂舞辭 撤豆','不詳','唐','唐诗','tang','','[]','笙鏞洋洋，庭燎煌煌。',42,'全唐诗/poet.tang.0.json','["笙鏞洋洋，庭燎煌煌。", "明星有爛，祝史下堂。", "[籩]豆斯撤，禮容有章。", "克勤克儉，無怠無荒。"]'),
('54a1868d-5896-4ede-81ee-9793077ce6a2','郊廟歌辭 梁太廟樂舞辭 送神','不詳','唐','唐诗','tang','','[]','其降無從，其往無蹤。',40,'全唐诗/poet.tang.0.json','["其降無從，其往無蹤。", "黍稷非馨，有感必通。", "赫奕令德，髣髴睟容。", "再拜慌忽，遐想昊穹。"]'),
('3efeffba-63c5-4de4-90d4-203e176ea4b6','郊廟歌辭 後唐宗廟樂舞辭 昭德舞','崔居儉、盧文紀','唐','唐诗','tang','','[]','懿彼明德，赫赫煌煌。',40,'全唐诗/poet.tang.0.json','["懿彼明德，赫赫煌煌。", "名高閫域，功著旂常。", "道符休泰，運叶祺祥。", "慶傳萬祀，以播耿光。"]'),
('c459ade7-f1ec-449d-9280-f885c9680769','郊廟歌辭 後唐宗廟樂舞辭 文明舞','崔居儉、盧文紀','唐','唐诗','tang','','[]','帝業光揚，皇圖翕赫。',40,'全唐诗/poet.tang.0.json','["帝業光揚，皇圖翕赫。", "聖德孔彰，神功不測。", "信及豚魚，恩霑動植。", "懿範鴻名，傳之萬億。"]'),
('c4562669-eb6d-49db-9be9-7e0188a5607e','郊廟歌辭 後唐宗廟樂舞辭 應天舞','崔居儉、盧文紀','唐','唐诗','tang','','[]','晉國肇興，雄圖再固。',40,'全唐诗/poet.tang.0.json','["晉國肇興，雄圖再固。", "黼黻帝道，金玉王度。", "皇天無親，惟德是輔。", "載誕英明，永光聖祚。"]'),
('41ee0b46-12c6-47ea-a6c5-e4aac44c2fc4','郊廟歌辭 後唐宗廟樂舞辭 永平舞','崔居儉、盧文紀','唐','唐诗','tang','','[]','慶傳瓚祚，位正瑤圖。',40,'全唐诗/poet.tang.0.json','["慶傳瓚祚，位正瑤圖。", "功宣四海，化被八區。", "靜彰帝道，動合乾符。", "千秋萬祀，永荷昭蘇。"]'),
('6efdeafd-8fbd-40a2-83f3-7a570f43a2e8','郊廟歌辭 後唐宗廟樂舞辭 武成舞','崔居儉、盧文紀','唐','唐诗','tang','','[]','艱難王業，返正皇唐。',40,'全唐诗/poet.tang.0.json','["艱難王業，返正皇唐。", "先天再造，却日重光。", "漢紹世祖，夏資少康。", "功成德茂，率祀無疆。"]'),
('bc43dea3-2c32-4f99-a810-7ed8854a3b9d','郊廟歌辭 後唐宗廟樂舞辭 雍煕舞','崔居儉、盧文紀','唐','唐诗','tang','','[]','仁君御宇，寰海謐清。',40,'全唐诗/poet.tang.0.json','["仁君御宇，寰海謐清。", "運符武德，道協文明。", "九成式敍，百度惟貞。", "金門積慶，玉葉傳榮。"]'),
('3ab117a7-0b6d-43fc-8ff4-412ef61802de','郊廟歌辭 漢宗廟樂舞辭 武德舞','張昭','唐','唐诗','tang','','[]','明明我祖，天集休明。',40,'全唐诗/poet.tang.0.json','["明明我祖，天集休明。", "神母夜哭，彤雲晝興。", "籩豆有踐，管籥斯登。", "孝孫致告，神其降靈。"]'),
('07232e95-0109-4302-ad90-957ca3c2cd2f','郊廟歌辭 漢宗廟樂舞辭 靈長舞','張昭','唐','唐诗','tang','','[]','天降祥，漢祚昌。',64,'全唐诗/poet.tang.0.json','["天降祥，漢祚昌。", "火炎上，水靈長。", "建廟社，潔蒸嘗。", "羅鐘石，儼珩璜。", "陳玉豆，酌金觴。", "氣昭感，德馨香。", "祗洛汭，瞻晉陽。", "降吾祖，福穰穰。"]'),
('2bf39a54-a034-4425-8044-d7d70738f029','郊廟歌辭 漢宗廟樂舞辭 積善舞','張昭','唐','唐诗','tang','','[]','黍稷斯馨，祖德惟明。',80,'全唐诗/poet.tang.0.json','["黍稷斯馨，祖德惟明。", "蛇告赤帝，龜謀大橫。", "雲行雨施，天成地平。", "造我家邦，斡我璿衡。", "陶匏在御，醍盎惟精。", "或戛或擊，載炮載烹。", "飲福受胙，舞降歌迎。", "滔滔不竭，洪惟水行。"]'),
('4866e70c-51c9-48bb-a2b4-d4d975e338fe','郊廟歌辭 漢宗廟樂舞辭 顯仁舞','張昭','唐','唐诗','tang','','[]','運極金行謝，天資水德隆。',96,'全唐诗/poet.tang.0.json','["運極金行謝，天資水德隆。", "禮神鄜畤館，布政未央宮。", "詰旦備明祀，登歌荅茂功。", "雲軒臨降久，星俎薦陳豐。", "靄靄沈檀霧，鏗鏘環佩風。", "熒煌升藻藉，肸蠁轉珠櫳。", "尊祖咸韶備，貽孫書軌同。", "京坻長有積，宗社享無窮。"]'),
('792ab2c6-7baf-427b-bccf-e9e58537de8e','郊廟歌辭 漢宗廟樂舞辭 章慶舞','張昭','唐','唐诗','tang','','[]','罘罳曉唱雞人，三牲八簋斯陳。',112,'全唐诗/poet.tang.0.json','["罘罳曉唱雞人，三牲八簋斯陳。", "霧集瑤階瑣闥，香生綺席華茵。", "珠佩貂璫熠爚，羽旄干戚紛綸。", "酌鬯既終三獻，凝旒何止千春。", "阿閣長棲綵鳳，郊宮疊奏祥麟。", "赤伏英靈未泯，玄圭運祚重新。", "玉斝犧樽瀲灩，龍旂鳳轄逡巡。", "瞻望月遊冠冕，猶疑蒼野回輪。"]'),
('6f12b2f5-d237-4507-aa77-3eaab9fa5a8c','郊廟歌辭 漢宗廟樂舞辭 觀德舞','張昭','唐','唐诗','tang','','[]','高廟明靈再啓圖，金根玉輅幸神都。',130,'全唐诗/poet.tang.0.json','["高廟明靈再啓圖，金根玉輅幸神都。", "巢阿丹凰銜書命，入昴飛星獻寶符。", "正換熏弦娛赤子，忽登仙駕泣蒼梧。", "薦櫻鶴館笳簫咽，酌鬯金楹劒佩趨。", "星俎雲罍兼魯禮，朱干象箾雜巴渝。", "氤氳龍麝交青瑣，髣髴[錫]鑾下蘂珠。", "薦豆奉觴親玉几，配天合祖耀璿樞。", "受釐飲酒皇歡洽，仰俟餘靈泰九區。"]'),
('b8833a3c-5382-478d-aa30-1fb1f4a93a3c','郊廟歌辭 周宗廟樂舞辭 肅順','不詳','唐','唐诗','tang','','[]','我后至孝，祗謁祖先。',40,'全唐诗/poet.tang.0.json','["我后至孝，祗謁祖先。", "仰瞻廟貌，夙設宮懸。", "朱弦疏越，羽舞迴旋。", "神其來格，明祀惟虔。"]'),
('a20f5b10-ab9d-4422-b68e-e0fbfa4f3992','郊廟歌辭 周宗廟樂舞辭 治順','不詳','唐','唐诗','tang','','[]','清廟將入，衮服是依。',40,'全唐诗/poet.tang.0.json','["清廟將入，衮服是依。", "載行載止，令行令儀。", "永終就養，空極孝思。", "瞻望如在，顧復長違。"]'),
('40427e69-1d6a-4d07-8428-f3cbda689880','郊廟歌辭 周宗廟樂舞辭 肅雍舞','不詳','唐','唐诗','tang','','[]','周道載興，象日之明。',80,'全唐诗/poet.tang.0.json','["周道載興，象日之明。", "萬邦咸慶，百穀用成。", "於穆聖祖，祗薦鴻名。", "祀於廟社，陳其犧牲。", "進旅退旅，皇武之形。", "一倡三歎，朱弦之聲。", "以妥以侑，既和且平。", "至誠潛達，介福攸寧。"]'),
('1db83204-895b-41ca-9ad5-502106899bf4','郊廟歌辭 周宗廟樂舞辭 章德舞','不詳','唐','唐诗','tang','','[]','清廟新，展嚴禋。',64,'全唐诗/poet.tang.0.json','["清廟新，展嚴禋。", "恭祖德，厚人倫。", "雅樂薦，禮器陳。", "儼皇尸，列虞賓。", "神如在，聲不聞。", "享必信，貌惟夤。", "想龍服，奠犧樽。", "禮既備，慶來臻。"]'),
('f8e557fd-6b68-47b3-b14f-b26de587fe6b','郊廟歌辭 周宗廟樂舞辭 善慶舞','不詳','唐','唐诗','tang','','[]','卜世長，帝祚昌。',64,'全唐诗/poet.tang.0.json','["卜世長，帝祚昌。", "定中國，服四方。", "修明祀，從舊章。", "奏激楚，轉清商。", "羅俎豆，列簪裳。", "歌纍纍，容皇皇。", "望來格，降休祥。", "祝敢告，壽無疆。"]'),
('640ab086-c340-4b15-8669-15ba50c0689d','郊廟歌辭 周宗廟樂舞辭 觀成舞','不詳','唐','唐诗','tang','','[]','穆穆王國，奕奕神功。',80,'全唐诗/poet.tang.0.json','["穆穆王國，奕奕神功。", "毖祀載展，明德有融。", "彝樽斯滿，簠簋斯豐。", "紛絺旄羽，鏘洋磬鐘。", "或升或降，克和克同。", "孔惠之禮，必肅之容。", "錫以純嘏，祚其允恭。", "神保是饗，萬世無窮。"]'),
('ef905ab2-4dae-4b94-9295-1d10156acfaf','郊廟歌辭 周宗廟樂舞辭 明德舞','不詳','唐','唐诗','tang','','[]','惟彼岐陽，德大流光。',80,'全唐诗/poet.tang.0.json','["惟彼岐陽，德大流光。", "載造周室，澤及遐荒。", "於鑠聖祖，上帝是皇。", "迺聖迺神，知微知彰。", "新廟奕奕，豐年穰穰。", "取彼血膋，以往蒸嘗。", "黍稷惟馨，籩豆大房。", "工祝致告，受福無疆。"]'),
('ed40a913-e197-4ac1-85bd-d82dd147bede','郊廟歌辭 周宗廟樂舞辭 咸順','不詳','唐','唐诗','tang','','[]','萬舞咸列，三階克清。',40,'全唐诗/poet.tang.0.json','["萬舞咸列，三階克清。", "貫珠一倡，擊石九成。", "盈觴雖酌，靈坐無形。", "永懷我祖，達其孝誠。"]'),
('d0b0a9b7-a1ef-4cf7-b1c8-c9f205db19e2','郊廟歌辭 周宗廟樂舞辭 禋順','不詳','唐','唐诗','tang','','[]','旨酒既獻，嘉殽乃迎。',40,'全唐诗/poet.tang.0.json','["旨酒既獻，嘉殽乃迎。", "振其鼗鼓，潔以鉶羹。", "肇禋肇祀，或炮或烹。", "皇尸儼若，保饗是明。"]'),
('2144751c-5633-4d58-b0bd-5dc2f044b83d','郊廟歌辭 周宗廟樂舞辭 福順','不詳','唐','唐诗','tang','','[]','新廟奕奕，金奏洋洋。',40,'全唐诗/poet.tang.0.json','["新廟奕奕，金奏洋洋。", "享于祖考，循彼典章。", "清酤特滿，嘉玉騰光。", "神醉既告，帝祉無疆。"]'),
('6229fb2d-8df5-4435-9aae-b41a928a4d74','郊廟歌辭 周宗廟樂舞辭 忠順','不詳','唐','唐诗','tang','','[]','稱文既表溫柔德，示武須成蹈厲容。',32,'全唐诗/poet.tang.0.json','["稱文既表溫柔德，示武須成蹈厲容。", "綴兆疾舒皆應節，明明我祖樂無窮。"]'),
('42500782-6469-41ae-aeae-ecaba64511e1','郊廟歌辭  善勝舞','不詳','唐','唐诗','tang','','[]','聖祖累功，福鍾來裔。',20,'全唐诗/poet.tang.0.json','["聖祖累功，福鍾來裔。", "持羽執干，舞文不廢。"]'),
('00f241fc-a107-454f-81fa-f0ac4893d155','郊廟歌辭  禋順','不詳','唐','唐诗','tang','','[]','禮畢祀先，香散几筵。',20,'全唐诗/poet.tang.0.json','["禮畢祀先，香散几筵。", "罷舞干戚，收撤豆籩。"]'),
('e46c92f3-c08f-41a9-9e61-2d2a4e23ebce','郊廟歌辭  肅順','不詳','唐','唐诗','tang','','[]','樂奏四順，福受萬年。',20,'全唐诗/poet.tang.0.json','["樂奏四順，福受萬年。", "神歸碧天，庭餘瑞煙。"]'),
('ed452c0c-f893-4743-80ff-cd9170831490','郊廟歌辭 晉朝饗樂章 初舉酒文同樂','不詳','唐','唐诗','tang','','[]','赫矣昌運，明哉聖王。',40,'全唐诗/poet.tang.0.json','["赫矣昌運，明哉聖王。", "文興墜典，禮復舊章。", "鴛鸞濟濟，鳥獸蹌蹌。", "一人有慶，萬福無疆。"]'),
('48105ca4-28d4-4477-a6c3-73ae21a928fb','郊廟歌辭 晉朝饗樂章 舉酒','不詳','唐','唐诗','tang','','[]','大明御宇，至德動天。',40,'全唐诗/poet.tang.0.json','["大明御宇，至德動天。", "君臣慶會，禮樂昭宣。", "劒佩成列，金石在縣。", "椒觴再獻，寶曆萬年。"]'),
('20bc12d7-5879-4e6d-a3ec-45b0034abe7b','郊廟歌辭 晉朝饗樂章 再舉酒','不詳','唐','唐诗','tang','','[]','朝野無事，寰瀛大康。',40,'全唐诗/poet.tang.0.json','["朝野無事，寰瀛大康。", "聖人有作，盛禮重光。", "萬國執玉，千官奉觴。", "南山永固，地久天長。"]'),
('f84ae8f0-fb73-470d-abe6-0e7415d9a96e','郊廟歌辭 晉朝饗樂章 四舉酒','不詳','唐','唐诗','tang','','[]','八表歡無事，三秋賀有成。',48,'全唐诗/poet.tang.0.json','["八表歡無事，三秋賀有成。", "照臨同日遠，渥澤並雲行。", "河變千年色，山呼萬歲聲。", "願修封岱禮，方以稱文明。"]'),
('9f407039-aaf9-41fe-a393-af670d5ff23c','郊廟歌辭 晉朝饗樂章 羣臣酒行歌 一','不詳','唐','唐诗','tang','','[]','劒佩儼如林，齊傾拱北心。',48,'全唐诗/poet.tang.0.json','["劒佩儼如林，齊傾拱北心。", "渥恩頒美祿，咸濩聽和音。", "一德君臣合，重瞳日月臨。", "歌時兼樂聖，唯待贊泥金。"]'),
('7f4d2f20-a7ac-4310-b2d5-3fb079011272','郊廟歌辭 晉朝饗樂章 羣臣酒行歌 二','不詳','唐','唐诗','tang','','[]','萬國咸歸禹，千官共祝堯。',48,'全唐诗/poet.tang.0.json','["萬國咸歸禹，千官共祝堯。", "拜恩瞻鳳扆，傾耳聽雲韶。", "運啓金行遠，時和玉燭調。", "酒酣齊抃舞，同賀聖明朝。"]'),
('8a756cea-8b47-419c-99d0-06c17359dc05','郊廟歌辭 晉朝饗樂章 羣臣酒行歌 三','不詳','唐','唐诗','tang','','[]','令節陳高會，羣臣侍御筵。',48,'全唐诗/poet.tang.0.json','["令節陳高會，羣臣侍御筵。", "玉墀留愛景，金殿靄祥煙。", "振鷺涵天澤，靈禽下樂懸。", "聖明無一事，何處讓堯年。"]'),
('48f870b0-fa59-43e1-8ef2-6c58dd86f6a3','郊廟歌辭 周朝饗樂章 忠順','不詳','唐','唐诗','tang','','[]','歲迎更始，節及朝元。',40,'全唐诗/poet.tang.0.json','["歲迎更始，節及朝元。", "冕旒仰止，冠劒相連。", "八音合奏，萬物齊宣。", "常陳盛禮，願永千年。"]'),
('805b734f-4a62-45df-b725-0b775bb116d9','郊廟歌辭 周朝饗樂章 忠順','不詳','唐','唐诗','tang','','[]','明君當宁，列辟奉觴。',40,'全唐诗/poet.tang.0.json','["明君當宁，列辟奉觴。", "雲容表瑞，日影初長。", "衣冠濟濟，鐘磬洋洋。", "令儀克盛，嘉會有章。"]'),
('f5ec0478-b462-441b-bfa3-59c93c82f376','郊廟歌辭 周朝饗樂章 治順','不詳','唐','唐诗','tang','','[]','庭陳大樂，作當太微。',40,'全唐诗/poet.tang.0.json','["庭陳大樂，作當太微。", "凝旒負扆，端拱垂衣。", "鴛鸞成列，簪組相輝。", "御爐香散，郁郁霏霏。"]'),
('64afb35e-d5b9-4f5b-af6b-1b47a72d1e9e','郊廟歌辭 周朝饗樂章 福順','不詳','唐','唐诗','tang','','[]','聖皇端拱，多士輸忠。',40,'全唐诗/poet.tang.0.json','["聖皇端拱，多士輸忠。", "蠻觴共獻，臣心畢同。", "聲齊嵩嶽，祝比華封。", "千齡萬祀，常保時雍。"]'),
('2df45b12-b0e8-46d3-b366-8a0f26cbfbec','郊廟歌辭 周朝饗樂章 康順','不詳','唐','唐诗','tang','','[]','鴻鈞廣運，嘉節良辰。',40,'全唐诗/poet.tang.0.json','["鴻鈞廣運，嘉節良辰。", "列辟在位，萬國來賓。", "干旌屢舞，金石咸陳。", "禮容既備，帝履長春。"]'),
('f73247fb-5b23-431e-8e31-e388cd6b44ba','郊廟歌辭 周朝饗樂章 忠順','不詳','唐','唐诗','tang','','[]','禮成三爵，樂畢九成。',20,'全唐诗/poet.tang.0.json','["禮成三爵，樂畢九成。", "共離金戺，復列彤庭。"]'),
('23abe3f3-6a5a-404a-8875-5844c102efc4','郊廟歌辭 周朝饗樂章 忠順','不詳','唐','唐诗','tang','','[]','明庭展禮，爲龍爲光。',20,'全唐诗/poet.tang.0.json','["明庭展禮，爲龍爲光。", "咸韶息韻，鵷鷺歸行。"]'),
('ff874166-6794-41a3-945b-4f9c949adbdb','郊廟歌辭 晉昭德成功舞歌 昭德舞歌二首 一','不詳','唐','唐诗','tang','','[]','聖代修文德，明庭舉舊章。',48,'全唐诗/poet.tang.0.json','["聖代修文德，明庭舉舊章。", "兩階陳羽籥，萬舞合宮商。", "劒佩森鴛鷺，簫韶下鳳凰。", "我朝青史上，千古有輝光。"]'),
('3806494e-a073-476c-b9e0-bac7f834a4dc','郊廟歌辭 晉昭德成功舞歌 昭德舞歌二首 二','不詳','唐','唐诗','tang','','[]','淮海干戈戢，朝廷禮樂施。',48,'全唐诗/poet.tang.0.json','["淮海干戈戢，朝廷禮樂施。", "白駒皆就縶，丹鳳復來儀。", "德備三苗格，風行萬國隨。", "小臣同百獸，率舞賀昌期。"]'),
('f72402fd-ddb2-4782-a5d7-1402c8cf495c','郊廟歌辭 晉昭德成功舞歌 武功舞歌二首 一','不詳','唐','唐诗','tang','','[]','撥亂資英主，開基自晉陽。',48,'全唐诗/poet.tang.0.json','["撥亂資英主，開基自晉陽。", "一戎成大業，七德煥前王。", "炎漢提封遠，姬周世祚長。", "朱干將玉戚，全象武功揚。"]'),
('a6014337-3716-40f7-80fd-ce7b8b8a7c76','郊廟歌辭 晉昭德成功舞歌 武功舞歌二首 二','不詳','唐','唐诗','tang','','[]','睿算超前古，神功格上圓。',48,'全唐诗/poet.tang.0.json','["睿算超前古，神功格上圓。", "百川留禹跡，萬國戴堯天。", "既已櫜弓矢，誠宜播管弦。", "蹌蹌隨鳥獸，共樂太平年。"]'),
('39c8eb21-2fd1-42bb-9540-3ff56ea983c3','鼓吹曲辭 朱鷺','張籍','唐','唐诗','tang','','[]','翩翩兮朱鷺，來汎春塘棲綠樹。',62,'全唐诗/poet.tang.0.json','["翩翩兮朱鷺，來汎春塘棲綠樹。", "羽毛如翦色如染，遠飛欲下雙翅斂。", "避人引子入深壍，動處水紋開灩灩。", "誰知豪家網爾軀，不如飲啄江海隅。"]'),
('8d259d7b-98df-4576-b439-3cc6671bfc0b','鼓吹曲辭 艾如張','李賀','唐','唐诗','tang','','[]','錦襜褕，繡襠襦，強強飲啄哺爾雛。',80,'全唐诗/poet.tang.0.json','["錦襜褕，繡襠襦，強強飲啄哺爾雛。", "隴東臥穟滿風雨，莫信龍媒隴西去。", "齊人織網如素空，張在野春平碧中。", "網絲漠漠無形影，誤爾觸之傷首紅。", "艾葉綠花誰翦刻，中藏禍機不可測。"]'),
('fb6b3bf9-3154-4539-99f6-12b288444219','鼓吹曲辭 上之回','盧照鄰','唐','唐诗','tang','','[]','回中道路險，蕭關烽候多。',48,'全唐诗/poet.tang.0.json','["回中道路險，蕭關烽候多。", "五營屯北地，萬乘出西河。", "單于拜玉璽，天子按琱戈。", "振旅汾川曲，秋風橫大歌。"]'),
('ee3195f6-eb17-4e87-b714-f7cf07ff03f2','鼓吹曲辭 上之回','李白','唐','唐诗','tang','','["\u5fe7\u56fd\u5fe7\u6c11", "\u9f13\u5439\u66f2\u8f9e", "\u4e50\u5e9c"]','三十六離宮，樓臺與天通。',96,'全唐诗/poet.tang.0.json','["三十六離宮，樓臺與天通。", "閣道步行月，美人愁煙空。", "恩疎寵不及，桃李傷春風。", "淫樂意何極，金輿向回中。", "萬乘出黃道，千旗揚彩虹。", "前軍細柳北，後騎甘泉東。", "豈問渭川老，寧邀襄野童。", "秋暮瑤池宴，歸來樂未窮。"]'),
('0ca0cc8a-db1e-4e60-943a-7cf72e679248','鼓吹曲辭 上之回','李賀','唐','唐诗','tang','','[]','上之回，大旗喜。',48,'全唐诗/poet.tang.0.json','["上之回，大旗喜。", "懸虹彗，撻鳳尾。", "劒匣破，舞蛟龍。", "蚩尤死，鼓逢逢。", "天高慶雷齊墜地，地無驚煙海千里。"]'),
('154bc6b6-be47-4e42-a039-e6f6d22fd447','鼓吹曲辭 戰城南','盧照鄰','唐','唐诗','tang','','["\u6218\u4e89", "\u9f13\u5439\u66f2\u8f9e", "\u7231\u56fd", "\u4e50\u5e9c"]','將軍出紫塞，冒頓在烏貪。',48,'全唐诗/poet.tang.0.json','["將軍出紫塞，冒頓在烏貪。", "笳喧雁門北，陣翼龍城南。", "琱弓夜宛轉，鐵騎曉參潭。", "應須駐白日，爲待戰方酣。"]'),
('c0f1c8ed-bbf8-4ace-ac86-91e5e57d8ece','鼓吹曲辭 戰城南','李白','唐','唐诗','tang','','["\u5fe7\u56fd\u5fe7\u6c11", "\u6218\u4e89", "\u9f13\u5439\u66f2\u8f9e", "\u4e50\u5e9c", "\u8bbd\u523a"]','去年戰桑乾源，今年戰蔥河道。',146,'全唐诗/poet.tang.0.json','["去年戰桑乾源，今年戰蔥河道。", "洗兵條支海上波，放馬天山雪中草。", "萬里長征戰，三軍盡衰老。", "匈奴以殺戮爲耕作，古來唯見白骨黃沙田。", "秦家築城備胡處，漢家還有烽火然。", "烽火然不息，征戰無已時。", "野戰格鬬死，敗馬號鳴向天悲。", "烏鳶啄人腸，銜飛上挂枯樹枝。", "士卒塗草莽，將軍空爾爲。", "乃知兵者是凶器，聖人不得已而用之。"]'),
('f85f5813-4fa8-4ce8-be2d-a6664da153ee','鼓吹曲辭 戰城南','劉駕','唐','唐诗','tang','','[]','城南征戰多，城北無飢鵶。',48,'全唐诗/poet.tang.0.json','["城南征戰多，城北無飢鵶。", "白骨馬蹄下，誰言皆有家。", "城前水聲苦，倏忽流萬古。", "莫爭城外地，城裏有閑土。"]'),
('4e01deae-f2e1-403a-a615-97aaf7e78738','鼓吹曲辭 戰城南二首 一','僧貫休','唐','唐诗','tang','','[]','萬里桑乾傍，茫茫古蕃壤。',60,'全唐诗/poet.tang.0.json','["萬里桑乾傍，茫茫古蕃壤。", "將軍貌顦顇，撫劒悲年長。", "胡兵尚陵逼，久住亦非強。", "邯鄲少年輩，箇箇有伎倆。", "拖槍半夜去，雪片大如掌。"]'),
('241e52e3-22fe-4943-b65e-74117c33b8b7','鼓吹曲辭 戰城南二首 二','僧貫休','唐','唐诗','tang','','[]','磧中有陰兵，戰馬時驚蹶。',48,'全唐诗/poet.tang.0.json','["磧中有陰兵，戰馬時驚蹶。", "輕猛李陵心，摧殘蘇武節。", "黃金鎖子甲，風吹色如鐵。", "十載不封侯，茫茫向誰說。"]'),
('2099379f-db42-4de6-9013-0649e78c5408','鼓吹曲辭 巫山高','鄭世翼','唐','唐诗','tang','','[]','巫山凌太清，岧嶢類削成。',48,'全唐诗/poet.tang.0.json','["巫山凌太清，岧嶢類削成。", "霏霏暮雨合，靄靄朝雲生。", "危峰入鳥道，深谷瀉猿聲。", "別有幽棲客，淹留攀桂情。"]'),
('cbecbf52-7793-4e52-92d1-1a84c07b649c','鼓吹曲辭 巫山高二首 一','沈佺期','唐','唐诗','tang','','[]','巫山峰十二，環合隱昭回。',48,'全唐诗/poet.tang.0.json','["巫山峰十二，環合隱昭回。", "俯眺琵琶峽，平看雲雨臺。", "古槎天外倚，瀑水日邊來。", "何忽啼猨夜，荆王枕席開。"]'),
('37063ab6-a303-4864-b68d-9888d19a5124','鼓吹曲辭 巫山高二首 二','沈佺期','唐','唐诗','tang','','[]','神女向高唐，巫山下夕陽。',48,'全唐诗/poet.tang.0.json','["神女向高唐，巫山下夕陽。", "裴回作行雨，婉孌逐荆王。", "電影江前落，雷聲峽外長。", "霽雲無處所，臺館曉蒼蒼。"]'),
('efafe0cd-54fd-40a4-be7b-117a45d18ee1','鼓吹曲辭 巫山高','盧照鄰','唐','唐诗','tang','','[]','巫山望不極，望望下朝雰。',48,'全唐诗/poet.tang.0.json','["巫山望不極，望望下朝雰。", "莫辨啼猿樹，徒看神女雲。", "驚濤亂水脈，驟雨暗峰文。", "霑裳即此地，況復遠思君。"]'),
('9c3b9194-4120-405d-8ad3-35db9dd01379','鼓吹曲辭 巫山高','張循之','唐','唐诗','tang','','[]','巫山高不極，沓沓狀奇新。',48,'全唐诗/poet.tang.0.json','["巫山高不極，沓沓狀奇新。", "暗谷疑風雨，幽巖若鬼神。", "月明三峽曙，潮滿二江春。", "爲問陽臺夕，應知入夢人。"]'),
('d0be28b3-b020-4c2b-9d81-2ff24b4ef1f2','鼓吹曲辭 巫山高','劉方平','唐','唐诗','tang','','[]','楚國巫山秀，清猨日夜啼。',48,'全唐诗/poet.tang.0.json','["楚國巫山秀，清猨日夜啼。", "萬重春樹合，十二碧峰齊。", "峽出朝雲下，江來暮雨西。", "陽臺歸路直，不畏向家迷。"]'),
('e607091f-25b1-4d3b-96f0-f5e8fa16bea1','鼓吹曲辭 巫山高','皇甫冉','唐','唐诗','tang','','[]','巫峽見巴東，迢迢半出空。',48,'全唐诗/poet.tang.0.json','["巫峽見巴東，迢迢半出空。", "雲藏神女館，雨到楚王宮。", "朝暮泉聲落，寒暄樹色同。", "清猨不可聽，偏在九秋中。"]'),
('a5a4b9de-6628-40ce-8e63-6e433f69997d','鼓吹曲辭 巫山高','李端','唐','唐诗','tang','','[]','巫山十二峰，皆在碧虛中。',48,'全唐诗/poet.tang.0.json','["巫山十二峰，皆在碧虛中。", "回合雲藏日，霏微雨帶風。", "猨聲寒過水，樹色暮連空。", "愁向高唐望，清秋見楚宮。"]'),
('f4dbb46b-ddc5-4e16-9c82-0bdd6bc9a0ab','鼓吹曲辭 巫山高','于濆','唐','唐诗','tang','','[]','何山無朝雲，彼雲亦悠揚。',60,'全唐诗/poet.tang.0.json','["何山無朝雲，彼雲亦悠揚。", "何山無暮雨，彼雨亦蒼茫。", "宋玉恃才者，憑雲構高唐。", "自重文賦名，荒淫歸楚襄。", "峨峨十二峰，永作妖鬼鄉。"]'),
('df99dd63-0832-4715-8e63-ce89452560a1','鼓吹曲辭 巫山高二首 一','孟郊','唐','唐诗','tang','','["\u5199\u5c71", "\u4f20\u8bf4", "\u5199\u666f", "\u63cf\u5199\u5c71"]','巴山上峽重復重，陽臺碧峭十二峰。',64,'全唐诗/poet.tang.0.json','["巴山上峽重復重，陽臺碧峭十二峰。", "荆王獵時逢暮雨，夜臥高丘夢神女。", "輕紅流煙溼豔姿，行雲飛去明星稀。", "目極魂斷望不見，猨啼三聲淚霑衣。"]'),
('26e48437-716e-4d92-85e1-cd258121753f','鼓吹曲辭 巫山高二首 二','孟郊','唐','唐诗','tang','','[]','見盡數萬里，不聞三聲猨。',48,'全唐诗/poet.tang.0.json','["見盡數萬里，不聞三聲猨。", "但飛蕭蕭雨，中有亭亭魂。", "千載楚襄恨，遺文宋玉言。", "至今青冥裏，雲結深閨門。"]'),
('5f4eb2fc-17fd-4302-88e6-4bda6fcff473','鼓吹曲辭 巫山高','李賀','唐','唐诗','tang','','["\u5199\u5c71", "\u5199\u666f", "\u63cf\u5199\u5c71"]','碧叢叢，高插天，大江翻瀾神曳煙。',64,'全唐诗/poet.tang.0.json','["碧叢叢，高插天，大江翻瀾神曳煙。", "楚魂尋夢風颸然，曉風飛雨生苔錢。", "瑤姬一去一千年，丁香笻竹啼老猨。", "古祠近月蟾桂寒，椒花墜紅溼雲間。"]'),
('ee1c6140-7f86-4c71-ac6b-26abdbe9aa12','鼓吹曲辭 巫山高','僧齊己','唐','唐诗','tang','','[]','巫山高，巫女妖。',88,'全唐诗/poet.tang.0.json','["巫山高，巫女妖。", "雨爲暮兮雲爲朝，楚王顦顇魂欲銷。", "秋猨嗥嗥日將夕，紅霞紫煙凝老壁。", "千巖萬壑花皆坼，但恐芳菲無正色。", "不知今古行人行，幾人經此無秋情。", "雲深廟遠不可覓，十二峰頭插天碧。"]'),
('0f7504df-cda2-4fe2-bc63-867ec2e418e7','鼓吹曲辭 將進酒','李白','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u9ec4\u6cb3", "\u548f\u7269", "\u6292\u60c5", "\u9f13\u5439\u66f2\u8f9e", "\u4e50\u5e9c"]','君不見黃河之水天上來，奔流到海不復回。',204,'全唐诗/poet.tang.0.json','["君不見黃河之水天上來，奔流到海不復回。", "君不見高堂明鏡悲白髮，朝如青絲暮成雪。", "人生得意須盡歡，莫使金尊空對月。", "天生我材必有用，千金散盡還復來。", "烹羊宰牛且爲樂，會須一飲三百杯。", "岑夫子，丹丘生，將進酒，杯莫停。", "與君歌一曲，請君爲我側耳聽。", "鐘鼓饌玉不足貴，但願長醉不復醒。", "古來聖賢皆寂寞，惟有飲者留其名。", "陳王昔時宴平樂，斗酒十千恣歡謔。", "主人何爲言少錢，徑須酤取對君酌。", "五花馬，千金裘，呼兒將出換美酒，與爾同銷萬古愁。"]'),
('2c1d7719-593f-489d-ae78-3e1e34a66412','鼓吹曲辭 將進酒','李賀','唐','唐诗','tang','','[]','將進酒，將進酒。',148,'全唐诗/poet.tang.0.json','["將進酒，將進酒。", "酒中有毒酖主父，言之主父傷主母。", "母爲妾地父妾天，仰天俯地不忍言。", "佯爲僵踣主父前，主父不知加妾鞭。", "旁人知妾爲主說，主將淚洗鞭頭血。", "推摧主母牽下堂，扶妾遣升堂上牀。", "將進酒，酒中無毒令主壽。", "願主回思歸主母，遣妾如此事主父。", "妾爲此事人偶知，自慙不密方自悲。", "主今顛倒安置妾，貪天僭地誰不爲。"]'),
('4d22a2f9-a696-435c-8d2e-7c7e1b3c1af9','鼓吹曲辭 將進酒','李賀','唐','唐诗','tang','','["\u5bb4\u996e", "\u4eba\u751f", "\u9f13\u5439\u66f2\u8f9e", "\u4e50\u5e9c", "\u8bbd\u55bb"]','瑠璃鍾，琥珀濃，小槽酒滴真珠紅。',81,'全唐诗/poet.tang.0.json','["瑠璃鍾，琥珀濃，小槽酒滴真珠紅。", "烹龍炮鳳玉脂泣，羅屏繡幕圍香風。", "吹龍笛，擊鼉鼓，皓齒歌，細腰舞。", "況是青春日將暮，桃花亂落如紅雨。", "勸君終日酩酊醉，酒不到劉伶墳上土。"]'),
('d4c03bc1-0596-4177-88ba-e42a97b0a7d9','鼓吹曲辭 君馬黃','李白','唐','唐诗','tang','','["\u77e5\u5df1", "\u9f13\u5439\u66f2\u8f9e", "\u4e50\u5e9c"]','君馬黃，我馬白。',80,'全唐诗/poet.tang.0.json','["君馬黃，我馬白。", "馬色雖不同，人心本無隔。", "共作遊冶盤，雙行洛陽陌。", "長劒既照曜，高冠何赩赫。", "各有千金裘，俱爲五侯客。", "猛虎落陷穽，壯夫時屈厄。", "相知在急難，獨好亦何益。"]'),
('315098e7-6da6-4435-9fed-f3ed5b80875d','鼓吹曲辭 芳樹','沈佺期','唐','唐诗','tang','','[]','何地早芳菲？宛在長門殿。',48,'全唐诗/poet.tang.0.json','["何地早芳菲？宛在長門殿。", "夭桃色若綬，穠李光如練。", "啼鳥弄花疎，遊蠭飲香徧。", "歎息春風起，飄零君不見。"]'),
('768bbe02-89b7-4ba7-b107-56da218e4c67','鼓吹曲辭 芳樹','盧照鄰','唐','唐诗','tang','','[]','芳樹本多奇，年華復在斯。',48,'全唐诗/poet.tang.0.json','["芳樹本多奇，年華復在斯。", "結翠成新幄，開紅滿舊枝。", "風歸花歷亂，日度影參差。", "容色朝朝落，思君君不知。"]'),
('39b2b613-94a2-492b-aaaa-cee6c34a6c41','鼓吹曲辭 芳樹','徐彥伯','唐','唐诗','tang','','[]','玉花珍簟上，金縷畫屏開。',56,'全唐诗/poet.tang.0.json','["玉花珍簟上，金縷畫屏開。", "曉月憐箏柱，春風憶鏡臺。", "箏柱春風吹曉月，芳樹落花朝暝歇。", "藳砧刀頭未有時，攀條拭淚坐相思。"]'),
('c4501ca9-2069-4e6b-90c7-908f094f4fd1','鼓吹曲辭 芳樹','韋應物','唐','唐诗','tang','','[]','迢迢芳園樹，列映清池曲。',48,'全唐诗/poet.tang.0.json','["迢迢芳園樹，列映清池曲。", "對此傷人心，還如故時綠。", "風條灑餘靄，露葉承新旭。", "佳人不再攀，下有往來躅。"]'),
('d5eb2f6f-4806-41cf-ac0f-9764b3911007','鼓吹曲辭 芳樹','元稹','唐','唐诗','tang','','[]','芳樹已寥落，孤英尤可嘉。',96,'全唐诗/poet.tang.0.json','["芳樹已寥落，孤英尤可嘉。", "可憐團團葉，蓋覆深深花。", "遊蠭競攢刺，鬬雀亦紛拏。", "天生細碎物，不愛好光華。", "非無殲殄法，念爾有生涯。", "春雷一聲發，驚燕亦驚蛇。", "清池養神蔡，已復長蝦蟆。", "雨露貴平施，吾其春草芽。"]'),
('6ba9e234-c171-4129-ab2e-b52db1026621','鼓吹曲辭 芳樹','羅隱','唐','唐诗','tang','','[]','細蘂慢逐風，暖香閑破鼻。',161,'全唐诗/poet.tang.0.json','["細蘂慢逐風，暖香閑破鼻。", "青帝固有心，時時動人意。", "去年高枝猶壓地，今年低枝已顦顇。", "吾所以見造化之權，變通之理。", "春夏作頭，秋冬爲尾。", "循環反覆無窮已，今生長短同一軌。", "若使威可以制，力可以止，秦皇不肯斂手下沙丘，孟賁不合低頭入蒿里。", "伊人彊猛猶如此，顧我勞生何足恃？", "但願開素袍，傾綠蟻，陶陶兀兀大醉於青冥白晝間。", "任他上是天，下是地。"]'),
('f61de6f0-8b47-4b5f-8344-b95849bd556d','鼓吹曲辭 有所思','沈佺期','唐','唐诗','tang','','[]','君子事行役，再空芳歲期。',48,'全唐诗/poet.tang.0.json','["君子事行役，再空芳歲期。", "美人曠延佇，萬里浮雲思。", "園槿綻紅豔，郊桑柔綠滋。", "坐看長夏晚，秋月生羅幃。"]'),
('4f876a76-9628-4cc3-91da-124444b562f1','鼓吹曲辭 有所思','李白','唐','唐诗','tang','','[]','我思仙人，乃在碧海之東隅。',59,'全唐诗/poet.tang.0.json','["我思仙人，乃在碧海之東隅。", "海寒多天風，白波連山倒蓬壺。", "長鯨噴湧不可涉，撫心茫茫淚如珠。", "西來青鳥東飛去，願寄一書謝麻姑。"]'),
('e71eb5f9-d4a1-44dd-b2ad-bffe671f51dd','鼓吹曲辭 有所思','孟郊','唐','唐诗','tang','','[]','桔槔烽火晝不滅，客路迢迢信難越。',48,'全唐诗/poet.tang.0.json','["桔槔烽火晝不滅，客路迢迢信難越。", "古鎮刀攢萬片霜，寒江浪起千堆雪。", "此時西去定如何，空使南心遠淒切。"]'),
('b9629e5e-c8bc-47e6-ae9f-2eba96a7fbda','鼓吹曲辭 有所思','盧仝','唐','唐诗','tang','','["\u7231\u60c5"]','當時我醉美人家，美人顏色嬌如花。',152,'全唐诗/poet.tang.0.json','["當時我醉美人家，美人顏色嬌如花。", "今日美人棄我去，青樓珠箔天之涯。", "天涯娟娟常娥月，三五二八盈又缺。", "翠眉蟬鬢生別離，一望不見心斷絕。", "心斷絕，幾千里，夢中醉臥巫山雲。", "覺來淚滴湘江水，湘江兩岸花木深。", "美人不見愁人心，含愁更奏綠綺琴，調高弦絕無知音。", "美人兮美人！不知爲暮雨兮爲朝雲。", "相思一夜梅花發，忽到窗前疑是君。"]'),
('95f31821-6665-4832-9780-ee1348df07cb','鼓吹曲辭 有所思','韋應物','唐','唐诗','tang','','[]','借問江上柳，青青爲誰春。',48,'全唐诗/poet.tang.0.json','["借問江上柳，青青爲誰春。", "空遊昨日地，不見昨日人。", "繚繞萬家井，往來車馬塵。", "莫道無相識，要非心所親。"]'),
('ea6c5a06-ed63-49f3-82aa-bb7bbded3ee5','鼓吹曲辭 有所思','劉氏雲','唐','唐诗','tang','','[]','朝亦有所思，暮亦有所思。',56,'全唐诗/poet.tang.0.json','["朝亦有所思，暮亦有所思。", "登樓望君處，藹藹浮雲飛。", "浮雲遮卻陽關道，向晚誰知妾懷抱。", "玉井蒼苔春院深，桐花落地無人掃。"]'),
('0bfac3e5-6cc6-49c6-892e-e290aa5c5923','鼓吹曲辭 雉子班','李白','唐','唐诗','tang','','[]','辟邪伎作鼓吹驚，雉子班之奏曲成。',96,'全唐诗/poet.tang.0.json','["辟邪伎作鼓吹驚，雉子班之奏曲成。", "喔咿振迅欲飛鳴，扇錦翼，雄風生。", "雙雌同飲啄，趫悍誰能爭。", "乍向草中耿介死，不求黃金籠下生。", "天地至廣大，何惜遂物情。", "善卷讓天子，務光亦逃名。", "所貴曠士懷，朗然合太清。"]'),
('f0cdc4dd-068d-4edd-a358-ecf71b0a17e3','鼓吹曲辭 臨高臺','褚亮','唐','唐诗','tang','','[]','高臺暫俯臨，飛翼聳輕音。',48,'全唐诗/poet.tang.0.json','["高臺暫俯臨，飛翼聳輕音。", "浮光隨日度，漾影逐波深。", "迥瞰周平野，開懷暢遠襟。", "獨此三休上，還傷千歲心。"]'),
('1cd853ef-8a04-4d1c-9c94-bffe4f97a00c','鼓吹曲辭 臨高臺','王勃','唐','唐诗','tang','','[]','臨高臺，高臺迢遞絕浮埃。',282,'全唐诗/poet.tang.0.json','["臨高臺，高臺迢遞絕浮埃。", "瑤軒綺構何崔嵬，鸞歌鳳吹清且哀。", "俯瞰長安道，萋萋御溝草。", "斜對甘泉路，蒼蒼茂陵樹。", "高臺四望同，帝鄉佳氣鬱蔥蔥。", "紫閣丹樓紛照曜，璧房錦殿相玲瓏。", "東彌長樂觀，西指未央宮。", "赤城映朝日，綠樹搖春風。", "旗亭百隊開新市，甲第千甍分戚里。", "朱輪翠蓋不勝春，疊樹層楹相對起。", "復有青樓大道中，繡戶文窗雕綺櫳。", "錦衣晝不襞，羅幃夕未空。", "歌屏朝揜翠，妝鏡晚窺紅。", "爲吾安寶髻，蛾眉罷花叢。", "狹路塵間黯將暮，雲間月色明如素。", "鴛鴦池上兩兩飛，鳳皇樓下雙雙度。", "物色正如此，佳期那不顧。", "銀鞍繡轂盛繁華，可憐今夜宿倡家。", "倡家少婦不須嚬，東園桃李片時春。", "君看舊日高臺處，柏梁銅雀生黃塵。"]'),
('7d3a1f16-ac20-4258-b134-a57b42713d8e','鼓吹曲辭 臨高臺','僧貫休','唐','唐诗','tang','','[]','涼風吹遠念，使我升高臺。',48,'全唐诗/poet.tang.0.json','["涼風吹遠念，使我升高臺。", "寧知數片雲，不是舊山來。", "故人天一涯，久客殊未回。", "雁來不得書，空寄聲哀哀。"]'),
('de4ba9d3-ed18-45cd-baec-58e8e002f9f7','鼓吹曲辭 黃雀行','莊南傑','唐','唐诗','tang','','[]','穿屋穿牆不知止，爭樹爭巢入營死。',64,'全唐诗/poet.tang.0.json','["穿屋穿牆不知止，爭樹爭巢入營死。", "林間公子挾彈弓，一丸致斃花叢裏。", "小雛黃口未有知，青天不解高高飛。", "虞人設網當要路，白日啾嘲禍萬機。"]'),
('8446acb8-23da-451a-958b-120cdfc8b52d','鼓吹曲辭 釣竿篇','沈佺期','唐','唐诗','tang','','[]','朝日斂紅煙，垂竿向綠川。',72,'全唐诗/poet.tang.0.json','["朝日斂紅煙，垂竿向綠川。", "人疑天上坐，魚似鏡中懸。", "避檝時驚透，猜鉤每誤牽。", "湍危不理轄，潭靜欲留船。", "釣玉君徒尚，徵金我未賢。", "爲看芳餌下，貪得會無全。"]'),
('1795ede6-16e1-4ef7-8d14-9ce9a4c917a5','鼓吹曲辭 凱歌六首 一','岑參','唐','唐诗','tang','','[]','漢將承恩西破戎，捷書先奏未央宮。',32,'全唐诗/poet.tang.0.json','["漢將承恩西破戎，捷書先奏未央宮。", "天子預開麟閣待，祗今誰數貳師功。"]'),
('436ddce1-56b4-4d4b-a0e0-2101cf9cebb3','鼓吹曲辭 凱歌六首 二','岑參','唐','唐诗','tang','','[]','官軍西出過樓蘭，營幕傍臨月窟寒。',32,'全唐诗/poet.tang.0.json','["官軍西出過樓蘭，營幕傍臨月窟寒。", "蒲海曉霜凝劒尾，蔥山夜雪撲旌竿。"]'),
('fd06ba1d-9d8e-4b20-884b-bcf4c93507a6','鼓吹曲辭 凱歌六首 三','岑參','唐','唐诗','tang','','[]','鳴笳擂鼓擁回軍，破國平蕃昔未聞。',32,'全唐诗/poet.tang.0.json','["鳴笳擂鼓擁回軍，破國平蕃昔未聞。", "大夫鵲印搖邊月，天將龍旗掣海雲。"]'),
('38a20ab5-1090-4c1c-8d7c-6faaf729bf1a','鼓吹曲辭 凱歌六首 四','岑參','唐','唐诗','tang','','[]','月落轅門鼓角鳴，千羣面縛出蕃城。',32,'全唐诗/poet.tang.0.json','["月落轅門鼓角鳴，千羣面縛出蕃城。", "洗兵魚海雲迎陣，秣馬龍堆月照營。"]'),
('598114d3-1644-44f3-b235-14bd3ad2de87','鼓吹曲辭 凱歌六首 五','岑參','唐','唐诗','tang','','[]','蕃軍遙見漢家營，滿谷連山徧哭聲。',32,'全唐诗/poet.tang.0.json','["蕃軍遙見漢家營，滿谷連山徧哭聲。", "萬箭千刀一夜殺，平明流血浸空城。"]'),
('ddf67260-7dcb-405a-824e-f11c3c9fea2f','鼓吹曲辭 凱歌六首 六','岑參','唐','唐诗','tang','','[]','暮雨旌旗溼未乾，胡塵白草日光寒。',32,'全唐诗/poet.tang.0.json','["暮雨旌旗溼未乾，胡塵白草日光寒。", "昨日將軍連曉戰，蕃軍只見馬空鞍。"]'),
('df56529b-2c90-46a3-baf8-223faff1c1af','鼓吹曲辭 鼓吹鐃歌 晉陽武','柳宗元','唐','唐诗','tang','','[]','晉陽武，奮義威。',104,'全唐诗/poet.tang.0.json','["晉陽武，奮義威。", "煬之渝，德焉歸。", "氓畢屠，綏者誰。", "皇烈烈，專天機。", "號以仁，揚其旗。", "日之升，九土晞。", "斥田圻，流洪輝。", "有其二，翼餘隋。", "斮梟驁，連熊螭。", "枯以肉，勍者羸。", "后土蕩，玄穹彌。", "合之育，莽然施。", "惟德輔，慶無期。"]'),
('a8626b26-a3c0-41d5-ae27-963cbb263b3c','鼓吹曲辭 鼓吹鐃歌 獸之窮','柳宗元','唐','唐诗','tang','','[]','獸之窮，奔大麓。',92,'全唐诗/poet.tang.0.json','["獸之窮，奔大麓。", "天厚黃德，狙獷服。", "甲之櫜弓，弭矢箙。", "皇旅靖，敵逾蹙。", "自亡其徒，匪予戮。", "屈𧹁猛，虔慄慄。", "縻以尺組，噉以秩。", "黎之陽，土茫茫。", "富兵戎，盈倉箱。", "乏者德，莫能享。", "驅豺兕，授我疆。"]'),
('03a00289-c6dd-427b-98d4-1432aaabcbd2','鼓吹曲辭 鼓吹鐃歌 戰武牢','柳宗元','唐','唐诗','tang','','[]','戰武牢，動河朔。',74,'全唐诗/poet.tang.0.json','["戰武牢，動河朔。", "逆之助，圖掎角。", "怒鷇麛，抗喬嶽。", "翹萌牙，傲霜雹。", "王謀內定，申掌握。", "鋪施芟夷，二主縛。", "憚華戎，廓封略。", "命之瞢，卑以斮。", "歸有德，唯先覺。"]'),
('578adc6f-5d30-4eb7-875c-748536fdd0cd','鼓吹曲辭 鼓吹鐃歌 涇水黃','柳宗元','唐','唐诗','tang','','["\u548f\u53f2", "\u6c34"]','涇水黃，隴野茫。',105,'全唐诗/poet.tang.0.json','["涇水黃，隴野茫。", "負太白，騰天狼。", "有鳥鷙立，羽翼張。", "鉤喙決前，鉅趯傍。", "怒飛飢嘯，翾不可當。", "老雄死，子復良。", "巢岐飲渭，肆翱翔。", "頓地紘，提天綱。", "列缺掉幟，招搖耀鋩。", "鬼神來助，夢嘉祥。", "腦塗原野，魂飛揚。", "星辰復，恢一方。"]'),
('cc07032c-9261-4b47-9bf4-b35ed3be83a2','鼓吹曲辭 鼓吹鐃歌 奔鯨沛','柳宗元','唐','唐诗','tang','','[]','奔鯨沛，盪海垠。',82,'全唐诗/poet.tang.0.json','["奔鯨沛，盪海垠。", "吐霓翳日，腥浮雲。", "帝怒下顧，哀墊昏。", "[授]以神柄，推元臣。", "手援天矛，截修鱗。", "披攘蒙霿，開海門。", "地平水靜，浮天垠。", "羲和顯耀，乘清氛。", "赫炎溥暢，融大鈞。"]'),
('cccc58b6-dfdb-425f-804a-3bf29a755a83','鼓吹曲辭 鼓吹鐃歌 苞枿','柳宗元','唐','唐诗','tang','','[]','苞枿𪒶矣，惟根之蟠。',134,'全唐诗/poet.tang.0.json','["苞枿𪒶矣，惟根之蟠。", "彌巴蔽荆，負南極以安。", "曰我舊梁氏，輯綏艱難。", "江漢之阻，都邑固以完。", "聖人作，神武用。", "有臣勇智，奮不以衆。", "投跡死地，謀猷縱。", "化敵爲家，慮則中。", "浩浩海裔，不威而同。", "係縲降王，定厥功。", "澶漫萬里，宣唐風。", "蠻夷九譯，咸來從。", "凱旋金奏，象形容。", "震赫萬國，罔不龔。"]'),
('e1264668-8b25-4c5a-9260-904b20979589','鼓吹曲辭 鼓吹鐃歌 河右平','柳宗元','唐','唐诗','tang','','[]','河右澶漫，頑爲之魁。',93,'全唐诗/poet.tang.0.json','["河右澶漫，頑爲之魁。", "王師如雷震，崑崙以頹。", "上聾下聰，驁不可迴。", "助讎抗有德，惟人之災。", "乃潰乃奮，執縛歸厥命。", "萬室蒙其仁，一夫則病。", "濡以鴻澤，皇之聖。", "威畏德懷，功以定。", "順之于理，物咸遂厥性。"]'),
('21173c18-b7d0-4c57-a29b-3cde7a7a0af4','鼓吹曲辭 鼓吹鐃歌 鐵山碎','柳宗元','唐','唐诗','tang','','[]','鐵山碎，大漠舒。',101,'全唐诗/poet.tang.0.json','["鐵山碎，大漠舒。", "二虜勁，連穹廬。", "背北海，專坤隅。", "歲來侵邊，或傅于都。", "天子命元帥，奮其雄圖。", "破定襄，降魁渠。", "窮竟窟宅，斥余吾。", "百蠻破膽，邊氓蘇。", "威武輝耀，明鬼區。", "利澤彌萬祀，功不可踰。", "官臣拜手，惟帝之謨。"]'),
('7b0a825b-9e1e-4f34-b831-49ce8fd7f97c','鼓吹曲辭 鼓吹鐃歌 靖本邦','柳宗元','唐','唐诗','tang','','[]','本邦伊晉，惟時不靖。',70,'全唐诗/poet.tang.0.json','["本邦伊晉，惟時不靖。", "根柢之搖，枝葉攸病。", "守臣不任，勩於神聖。", "惟鉞之興，翦焉則定。", "洪惟我理，式和以敬。", "羣頑既夷，庶績咸正。", "皇謨載大，惟人之慶。"]'),
('dbde2fca-6bfe-4f14-bf89-5df0f900b277','鼓吹曲辭 鼓吹鐃歌 吐谷渾','柳宗元','唐','唐诗','tang','','[]','吐谷渾盛彊，背西海以夸。',156,'全唐诗/poet.tang.0.json','["吐谷渾盛彊，背西海以夸。", "歲侵擾我疆，退匿險且遐。", "帝謂神武師，往征靖皇家。", "烈烈斾其旗，熊虎雜龍蛇。", "王旅千萬人，銜枚默無譁。", "束刃踰山徼，張翼縱漠沙。", "一舉刈羶腥，尸骸積如麻。", "除惡務本根，況敢遺萌芽。", "洋洋西海水，威命窮天涯。", "係虜來王都，犒樂窮休嘉。", "登高望還師，竟野如春華。", "行者靡不歸，親戚讙要遮。", "凱旋獻清廟，萬國思無邪。"]'),
('f9acb857-f038-4a86-a5a5-8a3266306b8e','鼓吹曲辭 鼓吹鐃歌 高昌','柳宗元','唐','唐诗','tang','','[]','麴氏雄西北，別絕臣外區。',132,'全唐诗/poet.tang.0.json','["麴氏雄西北，別絕臣外區。", "既恃遠且險，縱傲不我虞。", "烈烈王者師，熊螭以爲徒。", "龍旂飜海浪，馹騎馳坤隅。", "賁育搏嬰兒，一掃不復餘。", "平沙際天極，但見黃雲驅。", "臣靖執長纓，智勇伏囚拘。", "文皇南面坐，夷狄千羣趨。", "咸稱天子神，往古不得俱。", "獻號天可汗，以覆我國都。", "兵戎不交害，各保性與軀。"]'),
('d402fecd-b9e6-422c-bba2-d85184b69622','鼓吹曲辭 鼓吹鐃歌 東蠻','柳宗元','唐','唐诗','tang','','[]','東蠻有謝氏，冠帶理海中。',132,'全唐诗/poet.tang.0.json','["東蠻有謝氏，冠帶理海中。", "自言我異世，雖聖莫能通。", "王卒如飛翰，鵬鶱駭羣龍。", "轟然自天墜，乃信神武功。", "繫虜君臣人，累累來自東。", "無思不服從，唐業如山崇。", "百辟拜稽首，咸願圖形容。", "如周王會書，永永傳無窮。", "睢盱萬狀乖，咿嗢九譯重。", "廣輪撫四海，浩浩知皇風。", "歌詩鐃鼓間，以壯我元戎。"]'),
('bde2cd8e-b62c-4b95-b396-94467a949e6b','橫吹曲辭 隴頭','張籍','唐','唐诗','tang','','[]','隴頭已斷人不行，胡騎夜入涼州城。',80,'全唐诗/poet.tang.0.json','["隴頭已斷人不行，胡騎夜入涼州城。", "漢家處處格鬬死，一朝盡沒隴西地。", "驅我邊人胡中去，散放牛羊食禾黍。", "去年中國養子孫，今著氈裘學胡語。", "誰能更使李輕車，收取涼州屬漢家。"]'),
('cc0d85da-2fc0-4cd0-9163-b23561e07541','橫吹曲辭 隴頭吟','王維','唐','唐诗','tang','','["\u60b2\u6124", "\u611f\u4f24", "\u8fb9\u585e"]','長安少年遊俠客，夜上戍樓看太白。',80,'全唐诗/poet.tang.0.json','["長安少年遊俠客，夜上戍樓看太白。", "隴頭明月迥臨關，隴上行人夜吹笛。", "關西老將不勝愁，駐馬聽之雙淚流。", "身經大小百餘戰，麾下偏裨萬戶侯。", "蘇武纔爲典屬國，節旄空盡海西頭。"]'),
('b423f06b-4c05-4892-a409-7933ccf2edf8','橫吹曲辭 隴頭吟','翁綬','唐','唐诗','tang','','[]','隴水潺湲隴樹黃，征人隴上盡思鄉。',64,'全唐诗/poet.tang.0.json','["隴水潺湲隴樹黃，征人隴上盡思鄉。", "馬嘶斜日朔風急，雁過寒雲邊思長。", "殘月出林明劒戟，平沙隔水見牛羊。", "橫行俱足封侯者，誰斬樓蘭獻未央。"]'),
('7dbf19d4-6bb7-4e82-8d6a-c2cf8ac02ec7','橫吹曲辭 隴頭水','楊師道','唐','唐诗','tang','','[]','隴頭秋月明，隴水帶關城。',84,'全唐诗/poet.tang.0.json','["隴頭秋月明，隴水帶關城。", "笳添離別曲，風送斷腸聲。", "映雪峰猶暗，乘冰馬屢驚。", "霧中寒雁至，沙上轉蓬輕。", "天山傳羽檄，漢地急徵兵。", "陣開都護道，劒聚伏波營。", "於茲覺無度，方共濯胡纓。"]'),
('f5b4927a-9a37-4e40-87ee-e75fff02d48a','橫吹曲辭 隴頭水','盧照鄰','唐','唐诗','tang','','[]','隴坂高無極，征人一望鄉。',48,'全唐诗/poet.tang.0.json','["隴坂高無極，征人一望鄉。", "關河別去水，沙塞斷歸腸。", "馬繫千年樹，旌懸九月霜。", "從來共嗚咽，皆是爲勤王。"]'),
('25651b06-a58e-405f-a539-a86385e96468','橫吹曲辭 隴頭水','王建','唐','唐诗','tang','','[]','隴水何年隴頭別，不在山中亦嗚咽。',96,'全唐诗/poet.tang.0.json','["隴水何年隴頭別，不在山中亦嗚咽。", "征人塞耳馬不行，未到隴頭聞水聲。", "謂是西流入蒲海，還聞北海繞龍城。", "隴東隴西多屈曲，野麋飲水長簇簇。", "胡兵夜回水傍住，憶著來時磨劒處。", "向前無井復無泉，放馬回看隴頭樹。"]'),
('de0c30f3-bf7b-4870-b0fa-53222f2d27a0','橫吹曲辭 隴頭水','于濆','唐','唐诗','tang','','[]','借問隴頭水，終年恨何事。',48,'全唐诗/poet.tang.0.json','["借問隴頭水，終年恨何事。", "深疑嗚咽聲，中有征人淚。", "昨日上山下，達曙不能寐。", "何處接長波？東流入清渭。"]'),
('d531f315-bcc5-45b6-af4d-8752eef92780','橫吹曲辭 隴頭水 一','僧皎然','唐','唐诗','tang','','[]','隴頭心欲絕，隴水不堪聞。',48,'全唐诗/poet.tang.0.json','["隴頭心欲絕，隴水不堪聞。", "碎影搖槍壘，寒聲咽帳軍。", "素從鹽海積，綠帶柳城分。", "日落天邊望，逶迤入塞雲。"]'),
('16178e3c-c37a-4d17-baaf-ff160cbe4d98','橫吹曲辭 隴頭水 二','僧皎然','唐','唐诗','tang','','[]','秦隴逼氐羌，征人去未央。',48,'全唐诗/poet.tang.0.json','["秦隴逼氐羌，征人去未央。", "如何幽咽水，幷欲斷君腸。", "西注悲窮漠，東分憶故鄉。", "旅魂聲攪亂，無夢到遼陽。"]'),
('5e38232f-f517-43be-8d90-4945ae90b92b','橫吹曲辭 隴頭水','鮑溶','唐','唐诗','tang','','[]','隴頭水，千古不堪聞。',34,'全唐诗/poet.tang.0.json','["隴頭水，千古不堪聞。", "生歸蘇屬國，死別李將軍。", "細響風凋草，清哀雁落雲。"]'),
('ca2d41ce-a190-4d9b-b000-1670b6ffc9f6','橫吹曲辭 隴頭水','羅隱','唐','唐诗','tang','','[]','借問隴頭水，年年恨何事。',48,'全唐诗/poet.tang.0.json','["借問隴頭水，年年恨何事。", "全疑嗚咽聲，中有征人淚。", "自古無長策，況我非深智。", "何計謝潺湲，一宵空不寐。"]'),
('ed0d4f1c-f300-48b1-8139-706fb3a1aa2c','橫吹曲辭 出關','魏徵','唐','唐诗','tang','','[]','中原還逐鹿，投筆事戎軒。',120,'全唐诗/poet.tang.0.json','["中原還逐鹿，投筆事戎軒。", "縱橫計不就，慷慨志猶存。", "策杖謁天子，驅馬出關門。", "請纓羈南越，憑軾下東藩。", "鬱紆陟高岫，出沒望平原。", "古木吟寒鳥，空山啼夜猨。", "既傷千里目，還驚九折魂。", "豈不憚艱險，深懷國士恩。", "季布無二諾，侯嬴重一言。", "人生感意氣，功名誰復論。"]'),
('9f918987-407c-4c93-a9dd-a3d975988a70','橫吹曲辭 入關','賈馳','唐','唐诗','tang','','[]','河上微風來，關頭樹初溼。',36,'全唐诗/poet.tang.0.json','["河上微風來，關頭樹初溼。", "今朝關城吏，又見孤客入。", "上國誰與期，西來徒自急。"]'),
('c3699e7b-dd2c-4d73-8e85-30e42f7363da','橫吹曲辭 入關','張祜','唐','唐诗','tang','','[]','都城連百二，雄險北回環。',48,'全唐诗/poet.tang.0.json','["都城連百二，雄險北回環。", "地勢遙尊岳，河流側讓關。", "秦皇曾虎視，漢祖亦龍顏。", "何事梟兇輩，干戈自不閑。"]'),
('095c38dc-90fd-452f-812f-7dbf7c5662a2','橫吹曲辭 出塞','竇威','唐','唐诗','tang','','[]','匈奴屢不平，漢將欲縱橫。',48,'全唐诗/poet.tang.0.json','["匈奴屢不平，漢將欲縱橫。", "看雲方結陣，却月始連營。", "潛軍度馬邑，揚斾掩龍城。", "會勒燕然石，方傳車騎名。"]'),
('252c40ba-d76c-4893-925b-41883a6f254c','橫吹曲辭 出塞','陳子昂','唐','唐诗','tang','','["\u9001\u522b", "\u5c06\u519b", "\u8c6a\u8fc8", "\u8d5e\u7f8e"]','忽聞天上將，關塞重橫行。',72,'全唐诗/poet.tang.0.json','["忽聞天上將，關塞重橫行。", "始返樓蘭國，還向朔方城。", "黃金裝戰馬，白羽集神兵。", "星月開天陣，山川列地營。", "晚風吹畫角，春色耀飛旌。", "寧知班定遠，獨是一書生。"]'),
('57239e87-5c37-4c28-b253-a7bc96649ea4','橫吹曲辭 出塞','張易之','唐','唐诗','tang','','[]','俠客重恩光，驄馬飾金裝。',84,'全唐诗/poet.tang.0.json','["俠客重恩光，驄馬飾金裝。", "瞥聞傳羽檄，馳突救邊荒。", "轉戰磨筓地，橫行戴斗鄉。", "將軍占太白，小婦怨流黃。", "騕褭青絲騎，娉婷紅粉妝。", "一春鶯度曲，八月雁成行。", "誰堪坐秋思，羅袖拂空牀。"]'),
('1c22b677-c55e-4870-ace3-3450f93b17c1','橫吹曲辭 出塞','沈佺期','唐','唐诗','tang','','[]','十年通大漠，萬里出長平。',50,'全唐诗/poet.tang.0.json','["十年通大漠，萬里出長平。", "寒日生戈劒，陰雲搖斾旌。", "飢烏啼舊壘，疲馬戀空城。", "辛苦[皋蘭]北，胡霜損漢兵。"]'),
('e4fdb460-0944-4976-85a9-527bc87f7d7a','橫吹曲辭 出塞','王維','唐','唐诗','tang','','["\u8fb9\u585e"]','居延城外獵天驕，白草連天野火燒。',64,'全唐诗/poet.tang.0.json','["居延城外獵天驕，白草連天野火燒。", "暮雲空磧時驅馬，秋日平原好射鵰。", "護羌校尉朝乘障，破虜將軍夜渡遼。", "玉靶角弓珠勒馬，漢家將賜霍嫖姚。"]'),
('2d0385e7-0c72-423f-a538-f66acc9d4c46','橫吹曲辭 出塞 一','王昌齡','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u6218\u4e89", "\u5199\u666f", "\u5fe7\u56fd\u5fe7\u6c11", "\u7231\u56fd", "\u4e50\u5e9c"]','秦時明月漢時關，萬里長征人未還。',32,'全唐诗/poet.tang.0.json','["秦時明月漢時關，萬里長征人未還。", "但使龍城飛將在，不教胡馬度陰山。"]'),
('762e0a43-b8ed-4a11-bb82-28958998d354','橫吹曲辭 出塞 二','王昌齡','唐','唐诗','tang','','["\u9ec4\u6cb3", "\u6292\u60c5"]','白花垣上望京師，黃河水流無盡時。',32,'全唐诗/poet.tang.0.json','["白花垣上望京師，黃河水流無盡時。", "窮秋曠野行人絕，馬首東來知是誰。"]'),
('b2898783-b22c-4ded-b6c0-492b879a3b2d','橫吹曲辭 出塞','馬戴','唐','唐诗','tang','','["\u6218\u4e89", "\u8fb9\u585e"]','金帶連環束戰袍，馬頭衝雪度臨洮。',32,'全唐诗/poet.tang.0.json','["金帶連環束戰袍，馬頭衝雪度臨洮。", "卷旗夜劫單于帳，亂斫胡兵缺寶刀。"]'),
('acd96031-2a20-4c02-bed0-033329160c8d','橫吹曲辭 前出塞九首 一','杜甫','唐','唐诗','tang','','[]','戚戚去故里，悠悠赴交河。',48,'全唐诗/poet.tang.0.json','["戚戚去故里，悠悠赴交河。", "公家有程期，亡命嬰禍羅。", "君已富土境，開邊一何多？", "棄絕父母恩，吞聲行負戈。"]'),
('d572cc60-44fc-40c3-9c2f-08e966153fdd','橫吹曲辭 前出塞九首 二','杜甫','唐','唐诗','tang','','[]','出門日已遠，不受徒旅欺。',48,'全唐诗/poet.tang.0.json','["出門日已遠，不受徒旅欺。", "骨肉恩豈斷，男兒死無時。", "走馬脫轡頭，手中挑青絲。", "捷下萬仞岡，俯身試搴旗。"]'),
('d8e0db16-f56c-4180-bc8f-9724551bd8fc','橫吹曲辭 前出塞九首 三','杜甫','唐','唐诗','tang','','[]','磨刀嗚咽水，水赤刃傷手。',48,'全唐诗/poet.tang.0.json','["磨刀嗚咽水，水赤刃傷手。", "欲輕腸斷聲，心緒亂已久。", "丈夫誓許國，憤惋復何有？", "功名圖麒麟，戰骨當速朽。"]'),
('ef9d3efd-0eb2-413e-a455-2ee05bc16f7d','橫吹曲辭 前出塞九首 四','杜甫','唐','唐诗','tang','','[]','送徒既有長，遠戍亦有身。',48,'全唐诗/poet.tang.0.json','["送徒既有長，遠戍亦有身。", "生死向前去，不勞吏怒嗔。", "路逢相識人，附書與六親。", "哀哉兩決絕，不復同苦辛。"]'),
('d98f9148-c34c-47fb-9ec5-256813983782','橫吹曲辭 前出塞九首 五','杜甫','唐','唐诗','tang','','[]','迢迢萬餘里，領我赴三軍。',48,'全唐诗/poet.tang.0.json','["迢迢萬餘里，領我赴三軍。", "軍中異苦樂，主將寧盡聞。", "隔河見胡騎，倏忽數百羣。", "我始爲奴僕，幾時樹功勳。"]'),
('5683781e-f55a-49ad-8c3a-de7a2f217a35','橫吹曲辭 前出塞九首 六','杜甫','唐','唐诗','tang','','["\u54f2\u7406", "\u8bae\u8bba", "\u6218\u4e89"]','挽弓當挽彊，用箭當用長。',48,'全唐诗/poet.tang.0.json','["挽弓當挽彊，用箭當用長。", "射人先射馬，擒賊先擒王。", "殺人亦有限，列國自有疆。", "苟能制侵陵，豈在多殺傷。"]'),
('68f3ddee-deaa-484e-b375-0b6eed8bb3b9','橫吹曲辭 前出塞九首 七','杜甫','唐','唐诗','tang','','[]','驅馬天雨雪，軍行入高山。',48,'全唐诗/poet.tang.0.json','["驅馬天雨雪，軍行入高山。", "逕危抱寒石，指落曾冰間。", "已去漢月遠，何時築城還？", "浮雲暮南征，可望不可攀。"]'),
('673d52b8-9294-415e-a813-70dbb937e446','橫吹曲辭 前出塞九首 八','杜甫','唐','唐诗','tang','','[]','單于寇我壘，百里風塵昏。',48,'全唐诗/poet.tang.0.json','["單于寇我壘，百里風塵昏。", "雄劒四五動，彼軍爲我奔。", "虜其名王歸，繫頸授轅門。", "潛身備行列，一勝何足論。"]'),
('90f09f62-6f50-4e25-a5ba-a20b6a345311','橫吹曲辭 前出塞九首 九','杜甫','唐','唐诗','tang','','[]','從軍十年餘，能無分寸功。',48,'全唐诗/poet.tang.0.json','["從軍十年餘，能無分寸功。", "衆人貴苟得，欲語羞雷同。", "中原有鬬爭，況在狄與戎。", "丈夫四方志，安可辭固窮。"]'),
('72fc17eb-8b81-4de1-b38e-eb035f412a2b','橫吹曲辭 後出塞五首 一','杜甫','唐','唐诗','tang','','[]','男兒生世間，及壯當封侯。',84,'全唐诗/poet.tang.0.json','["男兒生世間，及壯當封侯。", "戰伐有功業，焉能守舊丘。", "召募赴薊門，軍動不可留。", "千金買馬鞭，百金裝刀頭。", "閭里送我行，親戚擁道周。", "斑白居上列，酒酣進庶羞。", "少年別有贈，含笑看吳鉤。"]'),
('be5ce2f9-2aaf-40b1-8f05-1a5817447ed3','橫吹曲辭 後出塞五首 二','杜甫','唐','唐诗','tang','','[]','朝進東門營，暮上河陽橋。',72,'全唐诗/poet.tang.0.json','["朝進東門營，暮上河陽橋。", "落日照大旗，馬鳴風蕭蕭。", "平沙列萬幕，部伍各見招。", "中天懸明月，令嚴夜寂寥。", "悲笳數聲動，壯士慘不驕。", "借問大將誰，恐是霍嫖姚。"]'),
('dffcc914-3b19-401d-963b-59c75a017857','橫吹曲辭 後出塞五首 三','杜甫','唐','唐诗','tang','','[]','古人重守邊，今人重高勳。',72,'全唐诗/poet.tang.0.json','["古人重守邊，今人重高勳。", "豈知英雄主，出師亙長雲。", "六合已一家，四夷且孤軍。", "遂使貔虎士，奮身勇所聞。", "拔劒擊大荒，日牧胡馬羣。", "誓開玄冥北，持以奉吾君。"]'),
('3e5677e0-c5ef-4f85-8cf0-1cbb318caba3','橫吹曲辭 後出塞五首 四','杜甫','唐','唐诗','tang','','[]','獻凱日繼踵，兩蕃靜無虞。',72,'全唐诗/poet.tang.0.json','["獻凱日繼踵，兩蕃靜無虞。", "漁陽豪俠地，擊鼓吹笙竽。", "雲帆轉遼海，粳稻來東吳。", "越羅與楚練，照耀輿臺軀。", "主將位益崇，氣驕陵上都。", "邊人不敢議，議者死路衢。"]'),
('f0beb32d-c5fb-4a7b-a4b9-14f24dcdc148','橫吹曲辭 後出塞五首 五','杜甫','唐','唐诗','tang','','[]','我本良家子，出師亦多門。',72,'全唐诗/poet.tang.0.json','["我本良家子，出師亦多門。", "將驕益愁思，身貴不足論。", "躍馬二十年，恐辜明主恩。", "坐見幽州騎，長驅河洛昏。", "中夜間道歸，故里但空村。", "惡名幸脫免，窮老無兒孫。"]'),
('2490ba49-411c-4172-bb14-75bba4ebe6e8','橫吹曲辭 出塞','皇甫冉','唐','唐诗','tang','','[]','吹角出塞門，前瞻即胡地。',48,'全唐诗/poet.tang.0.json','["吹角出塞門，前瞻即胡地。", "三軍盡回首，皆灑望鄉淚。", "轉念關山長，行看風景異。", "由來征戍客，各負輕生義。"]'),
('bcdf6f13-4cb9-418f-9279-c690522e0a27','橫吹曲辭 出塞','王之渙','唐','唐诗','tang','','["\u5c71\u6c34", "\u5199\u666f", "\u5510\u8bd7\u4e09\u767e\u9996", "\u4e50\u5e9c", "\u601d\u4e61", "\u8fb9\u585e"]','黃砂直上白雲間，一片孤城萬仞山。',32,'全唐诗/poet.tang.0.json','["黃砂直上白雲間，一片孤城萬仞山。", "羌笛何須怨楊柳，春風不度玉門關。"]'),
('02da7d16-a042-4720-95e6-f4528b25db22','橫吹曲辭 出塞','耿[湋]','唐','唐诗','tang','','[]','漢家邊事重，竇憲出臨戎。',48,'全唐诗/poet.tang.0.json','["漢家邊事重，竇憲出臨戎。", "絕漠秋山在，陽關舊路通。", "列營依茂草，吹角向高風。", "更就燕然石，看銘破虜功。"]'),
('66c91188-9381-4c8c-a58a-55b575e30e7e','橫吹曲辭 出塞','張籍','唐','唐诗','tang','','[]','秋塞雪初下，將軍遠出師。',48,'全唐诗/poet.tang.0.json','["秋塞雪初下，將軍遠出師。", "分營長記火，放馬不收旗。", "月冷邊帳溼，沙昏夜探遲。", "征人皆白首，誰見滅胡時。"]'),
('431d41ca-23ac-4372-961a-2433f18d1318','橫吹曲辭 出塞','劉駕','唐','唐诗','tang','','[]','胡風不開花，四氣多作雪。',72,'全唐诗/poet.tang.0.json','["胡風不開花，四氣多作雪。", "北人尚凍死，況我本南越。", "古來犬羊地，巡狩無遺轍。", "九土耕不盡，武皇猶征伐。", "中天有高閣，圖畫何時歇？", "坐恐塞上山，低於砂中骨。"]'),
('4ece9f6a-9b24-427a-9ef7-dce93f2f388e','橫吹曲辭 出塞曲','劉濟','唐','唐诗','tang','','[]','將軍在重圍，音信絕不通。',96,'全唐诗/poet.tang.0.json','["將軍在重圍，音信絕不通。", "羽書如流星，飛人甘泉宮。", "倚是幷州兒，少年心膽雄。", "一朝隨召募，百戰爭王公。", "去年桑乾北，今年桑乾東。", "死是征人死，功是將軍功。", "汗馬牧秋月，疲兵臥霜風。", "仍聞左賢王，更欲圖雲中。"]'),
('74f0a8c9-85dc-4c78-b342-91128d6302f1','橫吹曲辭 出塞曲 一','于鵠','唐','唐诗','tang','','[]','微雪將軍出，吹笳天未明。',48,'全唐诗/poet.tang.0.json','["微雪將軍出，吹笳天未明。", "觀兵登古戍，斬將對雙旌。", "分陣瞻山勢，潛軍制馬鳴。", "如今新史上，已有滅胡名。"]'),
('db605400-358d-4cb3-93af-2b6316ae9620','橫吹曲辭 出塞曲 二','于鵠','唐','唐诗','tang','','[]','單于驕愛獵，放火到軍城。',48,'全唐诗/poet.tang.0.json','["單于驕愛獵，放火到軍城。", "待月調新弩，防秋置遠營。", "空山朱戟影，寒磧鐵衣聲。", "逢著降胡說，陰山有伏兵。"]'),
('e3e9b8e1-20e3-4118-982f-2c86532449e3','橫吹曲辭 出塞曲 一','僧貫休','唐','唐诗','tang','','[]','埽盡狂胡跡，回戈望故關。',48,'全唐诗/poet.tang.0.json','["埽盡狂胡跡，回戈望故關。", "相逢唯死鬬，豈易得生還。", "縱宴參胡樂，收兵過雪山。", "不封十萬戶，此事亦應閑。"]'),
('de9b3a1a-925d-445a-9e23-d03b0f64d388','橫吹曲辭 出塞曲 二','僧貫休','唐','唐诗','tang','','[]','玉帳將軍意，慇懃把酒論。',48,'全唐诗/poet.tang.0.json','["玉帳將軍意，慇懃把酒論。", "功高寧在我，陣沒與招魂。", "塞色干戈束，軍容喜氣屯。", "男兒今始是，敢出玉關門。"]'),
('8ff26c9f-21a5-4f39-a073-48588fa2d692','橫吹曲辭 出塞曲 三','僧貫休','唐','唐诗','tang','','[]','回首隴山頭，連天草木秋。',48,'全唐诗/poet.tang.0.json','["回首隴山頭，連天草木秋。", "聖君應入夢，半路遣封侯。", "水不擔陰雪，柴令倒戍樓。", "歸來麟閣上，春色滿皇州。"]'),
('7351d633-de1e-4ea8-a6e3-f273b0c5dfe4','橫吹曲辭 入塞','劉希夷','唐','唐诗','tang','','[]','將軍陷虜圍，邊務息戎機。',48,'全唐诗/poet.tang.0.json','["將軍陷虜圍，邊務息戎機。", "霜雪交河盡，旌旗入塞飛。", "曉光隨馬度，春色伴人歸。", "課績朝明主，臨軒拜武威。"]'),
('b589b292-8d99-4cc9-9680-59b25cf3a7ce','橫吹曲辭 入塞曲','耿[湋]','唐','唐诗','tang','','[]','將軍帶十圍，重錦製戎衣。',72,'全唐诗/poet.tang.0.json','["將軍帶十圍，重錦製戎衣。", "猨臂銷弓力，虯鬚長劒威。", "首登平樂宴，新破大宛歸。", "樓上姝姬笑，門前問客稀。", "暮烽玄菟急，秋草紫騮肥。", "未奉君主詔，高槐晝掩扉。"]'),
('5dd824cf-e4bc-4a99-a85a-48e2688ebbb2','橫吹曲辭 入塞曲 一','僧貫休','唐','唐诗','tang','','[]','單于烽火動，都護去天涯。',48,'全唐诗/poet.tang.0.json','["單于烽火動，都護去天涯。", "別賜黃金甲，親臨白玉墀。", "塞垣須靜謐，師旅審安危。", "定遠條支寵，如今勝古時。"]'),
('f5c68f7a-8b75-42f3-b211-39bad532530b','橫吹曲辭 入塞曲 二','僧貫休','唐','唐诗','tang','','[]','方見將軍貴，分明對冕旒。',48,'全唐诗/poet.tang.0.json','["方見將軍貴，分明對冕旒。", "聖恩如遠被，狂虜不難收。", "臣節唯期死，功勳敢望侯。", "終辭修里第，從此出皇州。"]'),
('c3158200-d1f5-4b2b-9da9-d392e57f8555','橫吹曲辭 入塞曲 三','僧貫休','唐','唐诗','tang','','[]','百里精兵動，參差便渡遼。',48,'全唐诗/poet.tang.0.json','["百里精兵動，參差便渡遼。", "如何好白日，亦照此天驕。", "遠樹深疑賊，驚蓬迥似鵰。", "凱歌何日唱？磧路共天遙。"]'),
('6281fbf0-c461-4efe-ac5d-26e86d33fc49','橫吹曲辭 入塞曲 一','沈彬','唐','唐诗','tang','','[]','欲爲皇王服遠戎，萬人金甲鼓鼙中。',64,'全唐诗/poet.tang.0.json','["欲爲皇王服遠戎，萬人金甲鼓鼙中。", "陣雲暗塞三邊黑，兵血愁天一片紅。", "半夜飜營旗攪月，深秋防戍劒磨風。", "謗書未及明君爇，臥骨將軍已歿功。"]'),
('888fd3d3-d777-401d-8b4a-e94d3ab3607f','橫吹曲辭 入塞曲 二','沈彬','唐','唐诗','tang','','[]','苦戰沙間臥箭痕，戍樓閑上望星文。',64,'全唐诗/poet.tang.0.json','["苦戰沙間臥箭痕，戍樓閑上望星文。", "生希國澤分偏將，死奪河源荅聖君。", "鳶覰敗兵眠白草，馬驚邊鬼哭陰雲。", "功多地遠無人紀，漢閣笙歌日又曛。"]'),
('70b41da6-9b4d-4392-b0fb-23ef70a1cd78','橫吹曲辭 折楊柳','盧照鄰','唐','唐诗','tang','','[]','倡樓啓曙扉，園柳正依依。',48,'全唐诗/poet.tang.0.json','["倡樓啓曙扉，園柳正依依。", "鳥鳴知歲隔，條變識春歸。", "露葉疑啼臉，風花亂舞衣。", "攀折聊將寄，軍中書信稀。"]'),
('34bac317-4e11-40fa-abae-731bfb0e8d9c','橫吹曲辭 折楊柳','沈佺期','唐','唐诗','tang','','[]','玉窗朝日映，羅帳春風吹。',48,'全唐诗/poet.tang.0.json','["玉窗朝日映，羅帳春風吹。", "拭淚攀楊柳，長條宛地垂。", "白花飛歷亂，黃鳥思參差。", "妾自肝腸斷，旁人那得知。"]'),
('5d5532a1-5286-4ccb-abdc-6118ad48504d','橫吹曲辭 折楊柳','喬知之','唐','唐诗','tang','','[]','可憐濯濯春楊柳，攀折將來就纖手。',32,'全唐诗/poet.tang.0.json','["可憐濯濯春楊柳，攀折將來就纖手。", "妾容與此同盛衰，何必君恩獨能久。"]'),
('35c4618c-3896-45f8-9b24-51764c90383f','橫吹曲辭 折楊柳','劉憲','唐','唐诗','tang','','[]','沙塞三河道，金閨二月春。',48,'全唐诗/poet.tang.0.json','["沙塞三河道，金閨二月春。", "碧煙楊柳色，紅粉綺羅人。", "露葉憐啼臉，風花思舞巾。", "攀持君不見，爲聽曲中新。"]'),
('1e77033d-2c4f-4e60-8d42-3b1529f3c93c','橫吹曲辭 折楊柳','崔湜','唐','唐诗','tang','','[]','二月風光半，三邊戍不還。',48,'全唐诗/poet.tang.0.json','["二月風光半，三邊戍不還。", "年華妾自惜，楊柳爲君攀。", "落絮緣衫袖，垂條拂髻鬟。", "那堪音信斷，流涕望陽關。"]'),
('0e651edd-1bc8-49c9-bd85-b49df84c9743','橫吹曲辭 折楊柳','韋承慶','唐','唐诗','tang','','[]','萬里邊城地，三春楊柳節。',48,'全唐诗/poet.tang.0.json','["萬里邊城地，三春楊柳節。", "葉似鏡中眉，花如關外雪。", "征人遠鄉思，倡婦高樓別。", "不忍擲年華，含情寄攀折。"]'),
('ba115d1b-606c-4751-af66-e617b670babd','橫吹曲辭 折楊柳','歐陽瑾','唐','唐诗','tang','','[]','垂柳拂妝臺，葳蕤葉半開。',48,'全唐诗/poet.tang.0.json','["垂柳拂妝臺，葳蕤葉半開。", "年華枝上見，邊思曲中來。", "嫩色宜新雨，輕花伴落梅。", "朝朝倦攀折，征戍幾時回。"]'),
('afb30a8c-345b-471d-bf80-9f1828f8e097','橫吹曲辭 折楊柳','張祜','唐','唐诗','tang','','[]','紅粉青樓曙，垂楊仲月春。',48,'全唐诗/poet.tang.0.json','["紅粉青樓曙，垂楊仲月春。", "懷君重攀折，非妾妒腰身。", "舞帶縈絲斷，嬌娥向葉嚬。", "橫吹凡幾曲，獨自最愁人。"]'),
('83057247-91ce-43d8-8aee-2eccfdcc8773','橫吹曲辭 折楊柳','張九齡','唐','唐诗','tang','','[]','纖纖折楊柳，持此寄情人。',48,'全唐诗/poet.tang.0.json','["纖纖折楊柳，持此寄情人。", "一枝何足貴，憐是故園春。", "遲景那能久，流芳不及新。", "更愁征戍客，鬢老邊城塵。"]'),
('1fd7fb7a-8fd1-45bc-9dcb-803c52590d34','橫吹曲辭 折楊柳','余延壽','唐','唐诗','tang','','[]','大道連國門，東西種楊柳。',96,'全唐诗/poet.tang.0.json','["大道連國門，東西種楊柳。", "葳蕤君不見，褭娜垂來久。", "緣枝棲暝禽，雄去雌獨吟。", "餘花怨春盡，微月起秋陰。", "坐望窗中蝶，起攀枝上葉。", "好風吹長條，妸娜何如妾。", "妾見柳園新，高樓四五春。", "莫吹胡塞曲，愁殺隴頭人。"]'),
('e70730a9-552c-481c-aadc-364713afd410','橫吹曲辭 折楊柳','李白','唐','唐诗','tang','','["\u601d\u5ff5", "\u6625\u5929", "\u5973\u5b50", "\u4e50\u5e9c", "\u6a2a\u5439\u66f2\u8f9e"]','垂楊拂綠水，搖豔東風年。',48,'全唐诗/poet.tang.0.json','["垂楊拂綠水，搖豔東風年。", "花明玉關雪，葉暖金窗煙。", "美人結長恨，相對心悽然。", "攀條折春色，遠寄龍庭前。"]'),
('c8e50d0a-dd19-4fa2-b07e-95882090e9d7','橫吹曲辭 折楊柳 一','孟郊','唐','唐诗','tang','','[]','楊柳多短枝，短枝多別離。',72,'全唐诗/poet.tang.0.json','["楊柳多短枝，短枝多別離。", "贈遠累攀折，柔條安得垂。", "青春有定節，離別無定時。", "但恐人別促，不怨來遲遲。", "莫言短枝條，中有長相思。", "朱顏與綠楊，幷在別離期。"]'),
('8f3bd134-ac28-4961-b0c9-141140f72e47','橫吹曲辭 折楊柳 二','孟郊','唐','唐诗','tang','','[]','樓上春風過，風前楊柳歌。',48,'全唐诗/poet.tang.0.json','["樓上春風過，風前楊柳歌。", "枝疎緣別苦，曲怨爲年多。", "花驚燕地雪，葉映楚池波。", "誰堪別離此，征戍在交河。"]'),
('5b2c85ac-3edd-43b7-aa6d-b32c31d01bd0','橫吹曲辭 折楊柳','李端','唐','唐诗','tang','','[]','東城攀柳葉，柳葉低著草。',120,'全唐诗/poet.tang.0.json','["東城攀柳葉，柳葉低著草。", "少壯莫輕年，輕年有人老。", "柳發徧川崗，登高堪斷腸。", "雨煙輕漠漠，何樹近君鄉？", "贈君折楊柳，顏色豈能久。", "上客莫霑巾，佳人正回首。", "新柳送君行，古柳傷君情。", "突兀臨荒渡，婆娑出舊營。", "隋家兩岸盡，陶宅五株平。", "日暮偏愁望，春山有鳥聲。"]'),
('32744451-b4f4-47d1-866c-44b2675377c3','橫吹曲辭 折楊柳','翁綬','唐','唐诗','tang','','[]','紫陌金堤映綺羅，遊人處處動離歌。',64,'全唐诗/poet.tang.0.json','["紫陌金堤映綺羅，遊人處處動離歌。", "陰移古戍迷荒草，花帶殘陽落遠波。", "臺上少年吹白雪，樓中思婦斂青蛾。", "殷勤攀折贈行客，此去關山雨雪多。"]'),
('f79c370b-2d76-4435-a1f5-b02ead762def','橫吹曲辭 望行人','王建','唐','唐诗','tang','','[]','自從江樹秋，日日上江樓。',48,'全唐诗/poet.tang.0.json','["自從江樹秋，日日上江樓。", "夢見離珠浦，書來在桂州。", "不同魚比目，終恨水分流。", "久不開明鏡，多應是白頭。"]'),
('ce87b1d6-f5db-47fd-a979-034eb4888e26','橫吹曲辭 望行人','張籍','唐','唐诗','tang','','[]','秋風窗下起，旅雁向南飛。',48,'全唐诗/poet.tang.0.json','["秋風窗下起，旅雁向南飛。", "日日出門望，家家行客歸。", "無因見邊使，空待寄寒衣。", "獨閉青樓暮，煙深鳥雀稀。"]'),
('2d399e98-b466-4b4b-a451-5ab18ce88f35','橫吹曲辭 關山月','盧照鄰','唐','唐诗','tang','','[]','塞垣通碣石，虜障抵祈連。',48,'全唐诗/poet.tang.0.json','["塞垣通碣石，虜障抵祈連。", "相思在萬里，明月正孤懸。", "影移金岫北，光斷玉門前。", "寄書謝中婦，時看鴻雁天。"]'),
('31df356e-d9f2-4984-8f0e-66349cab666e','橫吹曲辭 關山月','沈佺期','唐','唐诗','tang','','[]','漢月生遼海，曈曨出半暉。',48,'全唐诗/poet.tang.0.json','["漢月生遼海，曈曨出半暉。", "合昏玄兔郡，中夜白登圍。", "暈落關山迥，光合霜霰微。", "將軍聽曉角，戰馬欲南歸。"]'),
('0167687e-8325-48bf-8da4-3749c9ce0a74','橫吹曲辭 關山月','李白','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u4e2d\u79cb", "\u8fb9\u585e", "\u5c71", "\u601d\u4e61", "\u4e50\u5e9c"]','明月出天山，蒼茫雲海間。',72,'全唐诗/poet.tang.0.json','["明月出天山，蒼茫雲海間。", "長風幾萬里，吹度玉門關。", "漢下白登道，胡窺青海灣。", "由來征戰地，不見有人還。", "戍客望邊色，思歸多苦顏。", "高樓當此夜，歎息未應閑。"]'),
('da42362f-b22f-4ca6-a18e-69284623c195','橫吹曲辭 關山月','長孫佐輔','唐','唐诗','tang','','[]','淒淒還切切，戍客多離別。',144,'全唐诗/poet.tang.0.json','["淒淒還切切，戍客多離別。", "何處最傷心？關山見秋月。", "關月竟如何？由來遠近過。", "始經玄兔塞，終繞白狼河。", "忽憶秦樓婦，流光應共有。", "已得竝蛾眉，還知攬纖手。", "去歲照同行，比翼復連形。", "今宵照獨立，顧影自煢煢。", "餘暉漸西落，夜夜看如昨。", "借問映旌旗，何如鑒帷幕。", "拂曉朔風悲，蓬驚雁不飛。", "幾時征戍罷，還向月中歸。"]'),
('ea0efc2b-125c-4680-a02b-16da31a0908b','橫吹曲辭 關山月','耿[湋]','唐','唐诗','tang','','[]','月明邊徼靜，戍客望鄉時。',48,'全唐诗/poet.tang.0.json','["月明邊徼靜，戍客望鄉時。", "塞古柳衰盡，關寒榆發遲。", "蒼蒼萬里道，戚戚十年悲。", "今夜青樓上，還應照所思。"]'),
('6795674b-74d6-4ac8-94ef-792c9892c714','橫吹曲辭 關山月二首 一','戴叔倫','唐','唐诗','tang','','[]','月出照關山，秋風人未還。',24,'全唐诗/poet.tang.0.json','["月出照關山，秋風人未還。", "清光無遠近，鄉淚半書間。"]'),
('d8a62427-62ef-45a8-9b30-e0fc90d5b78f','橫吹曲辭 關山月二首 二','戴叔倫','唐','唐诗','tang','','[]','一雁過連營，繁霜覆古城。',24,'全唐诗/poet.tang.0.json','["一雁過連營，繁霜覆古城。", "胡笳在何處？半夜起邊聲。"]'),
('b14de1b5-e97d-4ff0-a6d5-02468166e04d','橫吹曲辭 關山月','崔融','唐','唐诗','tang','','[]','月生西海上，氣逐邊風壯。',48,'全唐诗/poet.tang.0.json','["月生西海上，氣逐邊風壯。", "萬里度關山，蒼茫非一狀。", "漢兵開郡國，胡馬窺亭障。", "夜夜聞悲笳，征人起南望。"]'),
('bfa56f27-ecce-4c1e-81a0-439155849540','橫吹曲辭 關山月','李端','唐','唐诗','tang','','[]','露溼月蒼蒼，關頭榆葉黃。',48,'全唐诗/poet.tang.0.json','["露溼月蒼蒼，關頭榆葉黃。", "回輪照海遠，分彩上樓長。", "水凍頻移幕，兵疲數望鄉。", "祗應城影外，萬里共如霜。"]'),
('f3fde978-e64b-4480-994a-ac04f81d5adc','橫吹曲辭 關山月','王建','唐','唐诗','tang','','[]','關山月，營開道白前軍發。',44,'全唐诗/poet.tang.0.json','["關山月，營開道白前軍發。", "凍輪當磧光悠悠，照見三堆兩堆骨。", "邊風割面天欲明，金莎嶺西看看沒。"]'),
('10ef9dd5-f761-4463-9d90-fa9a426ac89c','橫吹曲辭 關山月','張籍','唐','唐诗','tang','','[]','秋月朗朗關山上，山中行人馬蹄響。',112,'全唐诗/poet.tang.0.json','["秋月朗朗關山上，山中行人馬蹄響。", "關山秋來雨雪多，行人見月唱邊歌。", "海邊漠漠天氣白，胡兒夜度黃龍磧。", "軍中探騎暮出城，伏兵暗處低旌戟。", "溪水連地霜草平，野駞尋水磧中鳴。", "隴頭風急雁不下，沙場苦戰多流星。", "可憐萬國關山道，年年戰骨多秋草。"]'),
('f73ad3c7-1f64-4825-b47d-c1e5a570758e','橫吹曲辭 關山月','翁綬','唐','唐诗','tang','','[]','裴回漢月滿邊州，照盡天涯到隴頭。',64,'全唐诗/poet.tang.0.json','["裴回漢月滿邊州，照盡天涯到隴頭。", "影轉銀河寰海靜，光分玉塞古今愁。", "笳吹遠戍孤烽滅，雁下平沙萬里秋。", "況是故園搖落夜，那堪少婦獨登樓。"]'),
('fe228ab0-4162-418d-8d88-3c760016ebfe','橫吹曲辭 關山月','鮑氏君[徽]微','唐','唐诗','tang','','[]','高高秋月明，北照遼陽城。',72,'全唐诗/poet.tang.0.json','["高高秋月明，北照遼陽城。", "塞迥光初滿，風多暈更生。", "征人望鄉思，戰馬聞鞞驚。", "朔風悲邊草，胡沙昏虜營。", "霜疑匣中劒，風憊原上旌。", "早晚謁金闕，不聞刁斗聲。"]'),
('ef02ddad-16dc-47e8-b7fc-f5afd4c8c593','橫吹曲辭 洛陽道','于武陵','唐','唐诗','tang','','[]','浮世若浮雲，千回故復新。',48,'全唐诗/poet.tang.0.json','["浮世若浮雲，千回故復新。", "旋添青草冢，更有白頭人。", "歲暮客將老，雪晴山欲春。", "行行車與馬，不盡洛陽塵。"]'),
('9997e88a-f75c-47ec-a336-359bb426fcf4','橫吹曲辭 洛陽道','鄭渥','唐','唐诗','tang','','[]','客亭門外路東西，多少喧騰事不齊。',64,'全唐诗/poet.tang.0.json','["客亭門外路東西，多少喧騰事不齊。", "楊柳惹鞭公子醉，紵麻掩淚魯人迷。", "通宵塵土飛山月，是處經營夾御堤。", "頃刻知音幾存歿，半回依約認輪蹄。"]'),
('7f968ba8-1a23-4916-8b55-97f03e8cfe1e','橫吹曲辭 洛陽陌','李白','唐','唐诗','tang','','[]','白玉誰家郎，回車渡天津。',24,'全唐诗/poet.tang.1000.json','["白玉誰家郎，回車渡天津。", "看花東上陌，驚動洛陽人。"]'),
('c62ec987-4594-4d23-b0b1-868fcfbd7127','橫吹曲辭 長安道','崔顥','唐','唐诗','tang','','[]','長安甲第高入雲，誰家居住霍將軍。',80,'全唐诗/poet.tang.1000.json','["長安甲第高入雲，誰家居住霍將軍。", "日晚朝回擁賓從，路傍拜揖何紛紛。", "莫言炙手手可熱，須臾火盡灰亦滅。", "莫言貧賤即可欺，人生富貴自有時。", "一朝天子賜顏色，世上悠悠應始知。"]'),
('b3f85bae-5866-43c9-a99f-fd09db0cd459','橫吹曲辭 長安道','孟郊','唐','唐诗','tang','','[]','胡風激秦樹，賤子風中泣。',48,'全唐诗/poet.tang.1000.json','["胡風激秦樹，賤子風中泣。", "家家朱門開，得見不可入。", "長安十二衢，投樹鳥亦急。", "高閣何人家？笙簧正喧吸。"]'),
('c8b8e2e8-9352-4d4a-ad32-f66c1e622fff','橫吹曲辭 長安道','顧況','唐','唐诗','tang','','[]','長安道，人無衣，馬無草，何不歸來山中老。',20,'全唐诗/poet.tang.1000.json','["長安道，人無衣，馬無草，何不歸來山中老。"]'),
('99a30357-99b0-4446-b35d-61a530b2c621','橫吹曲辭 長安道','聶夷中','唐','唐诗','tang','','[]','此地無駐馬，夜中猶走輪。',24,'全唐诗/poet.tang.1000.json','["此地無駐馬，夜中猶走輪。", "所以路旁草，少於衣上塵。"]'),
('1ab8a232-27bf-4de3-b67c-28e4735fea7f','橫吹曲辭 長安道','韋應物','唐','唐诗','tang','','[]','漢家宮殿含雲煙，兩宮十里相連延。',224,'全唐诗/poet.tang.1000.json','["漢家宮殿含雲煙，兩宮十里相連延。", "晨霞出沒弄丹闕，春雨依微自甘泉。", "春雨依微春尚早，長安貴遊愛芳草。", "寶馬橫來下建章，香車却轉避馳道。", "貴遊誰最貴，衛霍世難比。", "何能蒙主恩？幸遇邊塵起。", "歸來甲第拱皇居，朱門峨峨臨九衢。", "中有流蘇合歡之寶帳，一百二十鳳皇羅列含明珠。", "下有錦鋪翠被之粲爛，博山吐香五雲散。", "麗人綺閣情飄颻，頭上鴛釵雙翠翹。", "低鬟曳袖回春雪，聚黛一聲愁碧霄。", "山珍海錯棄藩籬，烹犢炰羔如折葵。", "既請列侯封部曲，還將金印授廬兒。", "歡榮若此何所苦，但苦白日西南馳。"]'),
('cca28bc8-2689-4419-bf3b-e5fef10f5db5','橫吹曲辭 長安道','白居易','唐','唐诗','tang','','[]','花枝缺處青樓開，豔歌一曲酒一杯。',51,'全唐诗/poet.tang.1000.json','["花枝缺處青樓開，豔歌一曲酒一杯。", "美人勸我急行樂，自古朱顏不再來。", "君不見外州客，長安道，一回來，一回老。"]'),
('ceec82c4-c989-407d-9ef4-476c34a0d92a','橫吹曲辭 長安道','薛能','唐','唐诗','tang','','[]','汲汲復營營，東西連兩京。',72,'全唐诗/poet.tang.1000.json','["汲汲復營營，東西連兩京。", "關繻古若在，山岳累應成。", "各自有身事，不相知姓名。", "交馳喧衆類，分散入重城。", "此路去無盡，萬方人始生。", "空餘片言苦，來往覓劉楨。"]'),
('3b26fac4-9f06-4ba0-9c7a-6a7be1300830','橫吹曲辭 長安道','僧貫休','唐','唐诗','tang','','[]','憧憧合合，八表一轍。',86,'全唐诗/poet.tang.1000.json','["憧憧合合，八表一轍。", "黃塵霧合，車馬火熱。", "名湯風雨，利輾霜雪。", "千車萬駄，半宿關月。", "上有堯禹，下有夔契。", "紫氣銀輪兮常覆金闕，仙掌捧日兮濁河澄澈。", "愚將草木兮有言，與華封人兮不別。"]'),
('5da08f58-6acd-43e7-9fac-464b2f167280','橫吹曲辭 長安道','沈佺期','唐','唐诗','tang','','[]','秦地平如掌，層城出雲漢。',48,'全唐诗/poet.tang.1000.json','["秦地平如掌，層城出雲漢。", "樓閣九衢春，車馬千門旦。", "綠柳開復合，紅塵聚還散。", "日晚鬬雞回，經過狹斜看。"]'),
('d39a3dfa-9d38-4b9f-9a13-d3063b0b47bd','橫吹曲辭 梅花落','盧照鄰','唐','唐诗','tang','','["\u8fb9\u585e", "\u6885\u82b1", "\u5c06\u58eb"]','梅嶺花初發，天山雪未開。',48,'全唐诗/poet.tang.1000.json','["梅嶺花初發，天山雪未開。", "雪處疑花滿，花邊似雪回。", "因風入舞袖，雜粉向妝臺。", "匈奴幾萬里，春至不知來。"]'),
('cee17360-6fa9-4406-9794-394ac59be538','橫吹曲辭 梅花落','沈佺期','唐','唐诗','tang','','[]','鐵騎幾時回，金閨怨早梅。',48,'全唐诗/poet.tang.1000.json','["鐵騎幾時回，金閨怨早梅。", "雪中花已落，風暖葉應開。", "夕逐新春管，香迎小歲杯。", "感時何足貴，書裏報輪臺。"]'),
('00522c4a-6d4b-48a8-bc12-cc5dd744feca','橫吹曲辭 梅花落','劉方平','唐','唐诗','tang','','[]','新歲芳梅樹，繁苞四面同。',48,'全唐诗/poet.tang.1000.json','["新歲芳梅樹，繁苞四面同。", "春風吹漸落，一夜幾枝空。", "小婦今如此，長城恨不窮。", "莫將遼海雪，來比後庭中。"]'),
('43d23382-d543-4aba-8a11-ed524328785d','橫吹曲辭 紫騮馬','盧照鄰','唐','唐诗','tang','','[]','騮馬照金鞍，轉戰入皐蘭。',48,'全唐诗/poet.tang.1000.json','["騮馬照金鞍，轉戰入皐蘭。", "塞門風稍急，長城水正寒。", "雪暗鳴珂重，山長噴玉難。", "不辭橫絕漠，流血幾時乾。"]'),
('49016fc5-51cc-4d01-896d-a6e14768ce6e','橫吹曲辭 紫騮馬','李白','唐','唐诗','tang','','["\u5199\u9a6c", "\u4e50\u5e9c", "\u6a2a\u5439\u66f2\u8f9e", "\u601d\u4e61", "\u8fb9\u585e", "\u9a6c"]','紫騮行且嘶，雙飜碧玉蹄。',48,'全唐诗/poet.tang.1000.json','["紫騮行且嘶，雙飜碧玉蹄。", "臨流不肎渡，似惜錦障泥。", "白雪關山遠，黃雲海樹迷。", "揮鞭萬里去，安得念春閨。"]'),
('0d876872-31d8-49d7-a9cf-efbf71e5827b','橫吹曲辭 紫騮馬','李益','唐','唐诗','tang','','[]','爭場看鬬雞，白鼻紫騧嘶。',48,'全唐诗/poet.tang.1000.json','["爭場看鬬雞，白鼻紫騧嘶。", "漳水春歸晚，叢臺日向低。", "歇鞍珠作汗，試劒玉如泥。", "爲謝紅梁燕，年年妾獨棲。"]'),
('890d8eee-81f6-40f8-8887-810b30665d5f','橫吹曲辭 紫騮馬','秦韜玉','唐','唐诗','tang','','[]','渥洼奇骨本難求，況是豪家重紫騮。',64,'全唐诗/poet.tang.1000.json','["渥洼奇骨本難求，況是豪家重紫騮。", "臕大宜懸銀壓銙，力渾欺却玉銜頭。", "生獰弄影風隨起，躞蹀衝塵汗滿溝。", "若遇丈夫皆調御，任從騎取覓封侯。"]'),
('0919893a-6302-4409-87ac-c1208e2e2f87','橫吹曲辭 驄馬','李羣玉','唐','唐诗','tang','','[]','浮雲何權奇，絕足勢未知。',96,'全唐诗/poet.tang.1000.json','["浮雲何權奇，絕足勢未知。", "長嘶青海風，躞蹀振雲絲。", "由來渥洼種，本是蒼龍兒。", "穆滿不再活，無人崑閬騎。", "君識躍嶠怯，寧勞耀金羈。", "青芻與白水，空笑駑駘肥。", "伯樂儻一見，應驚耳長垂。", "當思八荒外，逐日向瑤池。"]'),
('0f1e20b5-a8e4-45cd-a1e2-45710eec46fb','橫吹曲辭 驄馬曲','紀唐天','唐','唐诗','tang','','[]','連錢出塞蹋沙蓬，豈比當時御史驄。',64,'全唐诗/poet.tang.1000.json','["連錢出塞蹋沙蓬，豈比當時御史驄。", "逐北自諳深磧路，連嘶誰念靜邊功。", "登山每與青雲合，弄影應知碧草同。", "今日虜平將換妾，不如羅袖舞春風。"]'),
('a61fdeb6-e633-4c36-bb30-d57d1e392c1c','橫吹曲辭 雨雪曲','李端','唐','唐诗','tang','','[]','天山一丈雪，雜雨夜霏霏。',48,'全唐诗/poet.tang.1000.json','["天山一丈雪，雜雨夜霏霏。", "溼馬胡歌亂，經烽漢火微。", "丁零蘇武別，疎勒范羌歸。", "若著關頭過，長榆葉定稀。"]'),
('db40b5ca-03a8-4d1f-a4e4-cde477bee05e','橫吹曲辭 雨雪曲','翁綬','唐','唐诗','tang','','[]','邊聲四合殷河流，雨雪飛來徧隴頭。',48,'全唐诗/poet.tang.1000.json','["邊聲四合殷河流，雨雪飛來徧隴頭。", "鐵嶺探人迷鳥道，陰山飛將溼貂裘。", "斜飄旌斾過戎帳，半雜風沙入戍樓。"]'),
('1aa5a8ef-0eb9-4029-b228-bc979d9f332e','橫吹曲辭 劉生','盧照鄰','唐','唐诗','tang','','[]','劉生氣不平，抱劒欲專征。',48,'全唐诗/poet.tang.1000.json','["劉生氣不平，抱劒欲專征。", "報恩爲豪俠，死難在橫行。", "翠羽裝劒鞘，黃金飾馬纓。", "但令一顧重，不吝百身輕。"]'),
('8e1a40e5-4dea-4e85-bd84-3228170fc287','橫吹曲辭 雍臺歌','溫庭筠','唐','唐诗','tang','','[]','太子池南樓百尺，八窗新樹疎簾隔。',64,'全唐诗/poet.tang.1000.json','["太子池南樓百尺，八窗新樹疎簾隔。", "黃金鋪首畫鉤陳，羽葆亭童拂交戟。", "盤紆闌楯臨高臺，帳殿臨流鸞扇開。", "早雁聲鳴細波起，映花鹵簿龍飛回。"]'),
('aef25d83-2ce0-4cb7-a958-65b5cc7a1620','橫吹曲辭 捉搦歌','張祜','唐','唐诗','tang','','[]','門上關，牆上棘，窗中女子聲唧唧，洛陽大道徒自直。',76,'全唐诗/poet.tang.1000.json','["門上關，牆上棘，窗中女子聲唧唧，洛陽大道徒自直。", "女子心在婆舍側，嗚嗚籠鳥觸四隅。", "養男男娶婦，養女女嫁夫。", "阿婆六十翁七十，不知女子長日泣，從他嫁去無悒悒。"]'),
('e74b2d34-c0a4-4049-a02d-b2d9aa00fd80','橫吹曲辭 幽州胡馬客歌','李白','唐','唐诗','tang','','["\u538c\u6076", "\u6218\u4e89", "\u751f\u6d3b", "\u8fb9\u585e", "\u4eba\u6c11"]','幽州胡馬客，綠眼虎皮冠。',168,'全唐诗/poet.tang.1000.json','["幽州胡馬客，綠眼虎皮冠。", "笑拂兩隻箭，萬人不可干。", "彎弓若轉月，白雁落雲端。", "雙雙掉鞭行，遊獵向樓蘭。", "出門不顧後，報國死何難。", "天驕五單于，狼戾好凶殘。", "牛馬散北海，割鮮若虎餐。", "雖居燕支山，不道朔雪寒。", "婦女馬上笑，顏如赬玉盤。", "飜入射鳥獸，花月醉雕鞍。", "旄頭四光芒，爭戰若蜂攢。", "白刃灑赤血，流沙爲之丹。", "名將古誰是，疲兵良可歎。", "何時天狼滅？父子得閑安。"]'),
('c5f83ccf-1f85-4b43-87e5-b24df8131f39','橫吹曲辭 白鼻騧','李白','唐','唐诗','tang','','["\u6292\u60c5", "\u8c6a\u8fc8", "\u5199\u666f"]','銀鞍白鼻騧，綠地障泥錦。',28,'全唐诗/poet.tang.1000.json','["銀鞍白鼻騧，綠地障泥錦。", "細雨春風花落時，揮鞭且就胡姬飲。"]'),
('b412160a-39d1-46f6-8e10-424610aea93e','橫吹曲辭 白鼻騧','張祜','唐','唐诗','tang','','[]','爲底胡姬酒，長來白鼻騧。',24,'全唐诗/poet.tang.1000.json','["爲底胡姬酒，長來白鼻騧。", "摘蓮拋水上，郎意在浮花。"]'),
('173dc126-6533-471f-bf00-5fc637471b64','相和歌辭 箜篌引','李賀','唐','唐诗','tang','','[]','公乎公乎，提壺將焉如？',100,'全唐诗/poet.tang.1000.json','["公乎公乎，提壺將焉如？", "屈平沈湘不足慕，徐衍入海誠爲愚。", "公乎公乎，牀有菅席盤有魚。", "北里有賢兄，東鄰有小姑。", "隴畝油油黍與葫，瓦甒濁醪蟻浮浮。", "黍可食，醪可飲，公乎公乎其奈居。", "被髮奔流竟何如？賢兄小姑哭嗚嗚。"]'),
('bf5f4147-1e1c-4bb6-84ab-0e6a6a402325','相和歌辭 公無渡河','李白','唐','唐诗','tang','','["\u9ec4\u6cb3", "\u76f8\u548c\u6b4c\u8f9e", "\u4e50\u5e9c"]','黃河西來決崐崘，咆吼萬里觸龍門。',134,'全唐诗/poet.tang.1000.json','["黃河西來決崐崘，咆吼萬里觸龍門。", "波滔天，堯咨嗟。", "大禹理百川，兒啼不窺家。", "殺湍湮洪水，九州始蠶麻。", "其害乃去，茫然風沙。", "被髮之叟狂而癡，清晨徑流欲奚爲。", "旁人不惜妻止之，公無渡河苦渡之。", "虎可搏，河難憑。", "公果溺死流海湄，有長鯨白齒若雪山。", "公乎公乎，挂骨於其間，箜篌所悲竟不還。"]'),
('98ce6f68-fa8f-42b6-a5d6-5447079d3a04','相和歌辭 公無渡河','王建','唐','唐诗','tang','','[]','渡頭惡天兩岸遠，波濤塞川如疊坂。',88,'全唐诗/poet.tang.1000.json','["渡頭惡天兩岸遠，波濤塞川如疊坂。", "幸無白刃驅向前，何用將身自棄捐。", "蛟龍齧屍魚食血，黃泥直下無青天。", "男兒縱輕婦人語，惜君性命還須取。", "婦人無力挽斷衣，舟沈身死悔難追，公無渡河公自爲。"]'),
('19afaf8e-aaa5-4a06-9e92-5fc4cdecb40c','相和歌辭 公無渡河','溫庭筠','唐','唐诗','tang','','["\u9ec4\u6cb3", "\u548f\u7269", "\u548f\u7269\u8bd7"]','黃河怒浪連天來，大響谹谹如殷雷。',96,'全唐诗/poet.tang.1000.json','["黃河怒浪連天來，大響谹谹如殷雷。", "龍伯驅風不敢上，百川噴雪高崔嵬。", "二十五弦何太哀？請公勿渡立裴回。", "下有狂蛟鋸爲尾，裂帆截櫂磨霜齒。", "神錐鑿石塞神潭，白馬䟃𧽼赤塵起。", "公乎躍馬揚玉鞭，滅沒高蹄日千里。"]'),
('5fe01760-2d47-4df6-b61d-518cf952af9d','相和歌辭 公無渡河','王叡','唐','唐诗','tang','','[]','濁波洋洋兮凝曉霧，公無渡河兮公苦渡。',104,'全唐诗/poet.tang.1000.json','["濁波洋洋兮凝曉霧，公無渡河兮公苦渡。", "風號水激兮呼不聞，提壺看入兮中流去。", "浪擺衣裳兮隨步沒，沈屍深入兮蛟螭窟。", "蛟螭盡醉兮君血乾，推出黃沙兮泛君骨。", "當時君死妾何適？遂就波瀾合魂魄。", "願持精衛銜石心，窮取河源塞泉脈。"]'),
('edc474d8-bb0f-469e-9367-328d9aefb568','相和歌辭 江南曲','宋之問','唐','唐诗','tang','','[]','妾住越城南，離居不自堪。',48,'全唐诗/poet.tang.1000.json','["妾住越城南，離居不自堪。", "採花驚曙鳥，摘葉餧春蠶。", "嬾結茱萸帶，愁安玳瑁簪。", "侍臣消瘦盡，日暮碧江潭。"]'),
('0ba4d426-8dd5-4a77-9566-98d96222417f','相和歌辭 江南曲','劉眘虛','唐','唐诗','tang','','[]','美人何蕩漾，湖上風月長。',48,'全唐诗/poet.tang.1000.json','["美人何蕩漾，湖上風月長。", "玉手欲有贈，裴回雙鳴璫。", "歌聲隨淥水，怨色起朝陽。", "日暮還家望，雲波橫洞房。"]'),
('681ba31a-2c38-484a-ab65-f2b93d5e70c8','相和歌辭 江南曲','丁仙芝','唐','唐诗','tang','','[]','長干斜路北，近浦是兒家。',120,'全唐诗/poet.tang.1000.json','["長干斜路北，近浦是兒家。", "有意來相訪，明朝出浣紗。", "發向橫塘口，船開值急流。", "知郎舊時意，且請攏船頭。", "昨暝逗南陵，風聲波浪阻。", "入浦不逢人，歸家誰信汝。", "未曉已成妝，乘潮去茫茫。", "因從京口渡，使報邵陵王。", "始下芙蓉樓，言發琅邪岸。", "急爲打船開，惡許傍人見。"]'),
('14fb10e9-07e9-4b03-97ad-680f40db3518','相和歌辭 江南曲八首 一','劉希夷','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','暮宿南洲草，晨行北岸林。',60,'全唐诗/poet.tang.1000.json','["暮宿南洲草，晨行北岸林。", "日懸滄海闊，水隔洞庭深。", "煙景無留意，風波有異潯。", "歲遊難極目，春戲易爲心。", "朝夕無榮遇，芳菲已滿襟。"]'),
('26b530b0-e610-4d5c-b8a1-0d7a9b648dac','相和歌辭 江南曲八首 二','劉希夷','唐','唐诗','tang','','[]','豔唱潮初落，江花露未晞。',60,'全唐诗/poet.tang.1000.json','["豔唱潮初落，江花露未晞。", "春洲驚翡翠，朱服弄芳菲。", "畫舫煙中淺，青陽日際微。", "錦帆衝浪溼，羅袖拂行衣。", "含情罷所采，相歎惜流暉。"]'),
('c3966527-45c8-469f-8d74-cc906151e51a','相和歌辭 江南曲八首 三','劉希夷','唐','唐诗','tang','','[]','君爲隴西客，妾遇江南春。',60,'全唐诗/poet.tang.1000.json','["君爲隴西客，妾遇江南春。", "朝遊含靈果，夕采弄風蘋。", "果氣時不歇，蘋花日自新。", "以此江南物，持贈隴西人。", "空盈萬里懷，欲贈竟無因。"]'),
('5641758a-d34f-4d86-8631-5f0b17869fc3','相和歌辭 江南曲八首 四','劉希夷','唐','唐诗','tang','','[]','皓如楚江月，靄若吳岫雲。',60,'全唐诗/poet.tang.1000.json','["皓如楚江月，靄若吳岫雲。", "波中自皎鏡，山上亦氛氳。", "明月留照妾，輕雲持贈君。", "山川各離散，光氣乃殊分。", "天涯一爲別，江北自相聞。"]'),
('ae6937be-51cb-4b1f-b735-cfa0644fd547','相和歌辭 江南曲八首 五','劉希夷','唐','唐诗','tang','','[]','艤舟乘潮去，風帆振草涼。',60,'全唐诗/poet.tang.1000.json','["艤舟乘潮去，風帆振草涼。", "潮平見楚甸，天際望維揚。", "洄泝經千里，煙波接兩鄉。", "雲明江嶼出，日照海流長。", "此中逢歲晏，浦樹落花芳。"]'),
('03999410-ba31-4a8a-8718-340aa7d38735','相和歌辭 江南曲八首 六','劉希夷','唐','唐诗','tang','','[]','暮春三月晴，維揚吳楚城。',68,'全唐诗/poet.tang.1000.json','["暮春三月晴，維揚吳楚城。", "城臨大江汜，迴映洞浦清。", "晴雲曲金閣，珠樓碧煙裏。", "月明芳樹羣鳥飛，風過長林雜花起。", "可憐離別誰家子，於此一至情何已。"]'),
('0f7c6229-2a76-4879-821a-62a021153b46','相和歌辭 江南曲八首 七','劉希夷','唐','唐诗','tang','','[]','北堂紅草盛丰茸，南湖碧水照芙蓉。',64,'全唐诗/poet.tang.1000.json','["北堂紅草盛丰茸，南湖碧水照芙蓉。", "朝遊暮起金花盡，漸覺羅裳珠露濃。", "自惜妍華三五歲，已歎關山千萬重。", "人情一去無還日，欲贈懷芳怨不逢。"]'),
('368cbc24-d33d-4ef5-9940-c16acc077d73','相和歌辭 江南曲八首 八','劉希夷','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','憶昔江南年盛時，平生怨在長洲曲。',64,'全唐诗/poet.tang.1000.json','["憶昔江南年盛時，平生怨在長洲曲。", "冠蓋星繁湘水上，衝風摽落洞庭淥。", "落花舞袖紅紛紛，朝霞高閣洗晴雲。", "誰言此處嬋娟子，珠玉爲心以奉君。"]'),
('1e1e7436-6f97-47ee-8d91-e540fe2b1edc','相和歌辭 江南曲','于鵠','唐','唐诗','tang','','["\u601d\u5ff5", "\u5973\u5b50", "\u90ca\u6e38"]','偶向江邊采白蘋，還隨女伴賽江神。',32,'全唐诗/poet.tang.1000.json','["偶向江邊采白蘋，還隨女伴賽江神。", "衆中不敢分明語，暗擲金錢卜遠人。"]'),
('bb111748-d8f1-4a5e-b618-b70272a7a642','相和歌辭 江南曲','李益','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u95fa\u6028", "\u4e50\u5e9c"]','嫁得瞿塘賈，朝朝誤妾期。',24,'全唐诗/poet.tang.1000.json','["嫁得瞿塘賈，朝朝誤妾期。", "早知潮有信，嫁與弄潮兒。"]'),
('17cd4a8b-9987-47b8-9d44-034c98f8f939','相和歌辭 江南曲','李賀','唐','唐诗','tang','','[]','汀洲白蘋草，柳惲乘馬歸。',48,'全唐诗/poet.tang.1000.json','["汀洲白蘋草，柳惲乘馬歸。", "江頭樝樹香，岸上蝴蝶飛。", "酒杯若葉露，玉軫蜀桐虛。", "朱樓通水陌，沙暖一雙魚。"]'),
('7236d790-13a8-44f2-8770-9802bb525db4','相和歌辭 江南曲','李商隱','唐','唐诗','tang','','[]','郎船安兩槳，儂舸動雙橈。',48,'全唐诗/poet.tang.1000.json','["郎船安兩槳，儂舸動雙橈。", "埽黛開宮額，裁裙約楚腰。", "乖期方積思，臨醉欲拚嬌。", "莫以采菱唱，欲羨秦臺簫。"]'),
('9d10fdb5-9d0a-4c80-9e21-27f82b929c9f','相和歌辭 江南曲','韓翃','唐','唐诗','tang','','[]','長樂花枝雨點消，江城日暮好相邀。',32,'全唐诗/poet.tang.1000.json','["長樂花枝雨點消，江城日暮好相邀。", "春樓不閉葳蕤鎖，綠水回通宛轉橋。"]'),
('809c98e4-2997-4bfa-bb77-b5a64b696a26','相和歌辭 江南曲','溫庭筠','唐','唐诗','tang','','[]','妾家白蘋浦，日上芙蓉檝。',240,'全唐诗/poet.tang.1000.json','["妾家白蘋浦，日上芙蓉檝。", "軋軋搖槳聲，移舟入茭葉。", "溪長茭葉深，作底難相尋。", "避郎郎不見，鸂鶒自浮沈。", "拾萍萍無根，采蓮蓮有子。", "不作浮萍生，寧作藕花死。", "岸傍騎馬郎，烏帽紫游韁。", "含愁復含笑，回首問橫塘。", "妾住金陵步，門前朱雀航。", "流蘇持作帳，芙蓉持作梁。", "出入金犢幰，兄弟侍中郎。", "前年學歌舞，定得郎相許。", "連娟眉繞山，依約腰如杵。", "鳳管悲若咽，鸞弦嬌欲語。", "扇薄露紅鈆，羅輕壓金縷。", "明月西南樓，珠簾玳瑁鉤。", "橫波巧能笑，彎蛾不識愁。", "花開子留樹，草長根依土。", "早聞金溝遠，底事歸郎許。", "不學楊白花，朝朝淚如雨。"]'),
('c0f731fe-706b-4e7e-a27c-db14c06686e9','相和歌辭 江南曲','張籍','唐','唐诗','tang','','["\u957f\u6c5f"]','江南人家多橘樹，吳姬舟上織白紵。',112,'全唐诗/poet.tang.1000.json','["江南人家多橘樹，吳姬舟上織白紵。", "土地卑溼饒蟲蛇，連木爲牌入江住。", "江村亥日長爲市，落帆渡橋來浦裏。", "青莎覆城竹爲屋，無井家家飲潮水。", "長江午日酤春酒，高高酒旗懸江口。", "倡樓兩岸懸水柵，夜唱竹枝留北客。", "江南風土歡樂多，悠悠處處盡經過。"]'),
('163e6b84-544c-426c-820f-0b6bac718a2d','相和歌辭 江南曲','羅隱','唐','唐诗','tang','','[]','江煙溼雨鮫綃輭，漠漠遠山眉黛淺。',80,'全唐诗/poet.tang.1000.json','["江煙溼雨鮫綃輭，漠漠遠山眉黛淺。", "水國多愁又有情，夜槽壓酒銀船滿。", "綳絲採怨凝曉空，吳王臺榭春夢中。", "鴛鴦鸂鶒喚不起，平鋪淥水眠東風。", "西陵路邊月悄悄，油壁輕車嫁蘇小。"]'),
('ee8b870e-a2de-45e4-8fa6-a805e3ae1f7c','相和歌辭 江南曲','陸龜蒙','唐','唐诗','tang','','[]','爲愛江南雪，涉江聊采蘋。',72,'全唐诗/poet.tang.1000.json','["爲愛江南雪，涉江聊采蘋。", "水深煙浩浩，空對雙車輪。", "車輪明月團，車蓋浮雲盤。", "雲月徒自好，水中行路難。", "遙遙洛陽道，夾岸生春草。", "寄語櫂船郎，莫誇風浪好。"]'),
('490c972f-cb5e-4289-a26f-c65b2aff10b0','相和歌辭 江南曲 一','陸龜蒙','唐','唐诗','tang','','[]','魚戲蓮葉間，參差隱葉扇。',24,'全唐诗/poet.tang.1000.json','["魚戲蓮葉間，參差隱葉扇。", "鵁鶄鸀鳿窺，瀲灩無因見。"]'),
('7420cc4b-1eb0-4532-9261-c1d70fbfe100','相和歌辭 江南曲 二','陸龜蒙','唐','唐诗','tang','','[]','魚戲蓮葉東，初霞射紅尾。',24,'全唐诗/poet.tang.1000.json','["魚戲蓮葉東，初霞射紅尾。", "傍臨謝山側，恰值清風起。"]'),
('97b95df2-6c44-40aa-bd1c-f06aee6ceecf','相和歌辭 江南曲 三','陸龜蒙','唐','唐诗','tang','','[]','魚戲蓮葉西，盤盤舞波急。',24,'全唐诗/poet.tang.1000.json','["魚戲蓮葉西，盤盤舞波急。", "潛依曲岸涼，正對斜光入。"]'),
('49e10d3e-1925-4cb0-8fec-a96b79ed1ee8','相和歌辭 江南曲 四','陸龜蒙','唐','唐诗','tang','','[]','魚戲蓮葉南，欹危午煙疊。',24,'全唐诗/poet.tang.1000.json','["魚戲蓮葉南，欹危午煙疊。", "光搖越鳥巢，影亂吳娃檝。"]'),
('ee469591-8d2e-4541-8613-094aaf82d305','相和歌辭 江南曲 五','陸龜蒙','唐','唐诗','tang','','[]','魚戲蓮葉北，澄陽動微漣。',24,'全唐诗/poet.tang.1000.json','["魚戲蓮葉北，澄陽動微漣。", "回看帝子渚，稍背鄂君船。"]'),
('a39a22f1-14e7-4819-951f-9058b30590fa','相和歌辭 度關山','李端','唐','唐诗','tang','','[]','雁塞日初晴，胡關雪復平。',48,'全唐诗/poet.tang.1000.json','["雁塞日初晴，胡關雪復平。", "危竿緣廣漠，古竇傍長城。", "拔劒金星出，彎弧玉羽鳴。", "誰知係虜者，賈誼是書生。"]'),
('af064f9d-ff81-401e-b209-e6c98d94d4f2','相和歌辭 關山曲 一','馬戴','唐','唐诗','tang','','[]','金鎖耀兜鍪，黃雲拂紫騮。',48,'全唐诗/poet.tang.1000.json','["金鎖耀兜鍪，黃雲拂紫騮。", "叛羌旗下戮，陷壁夜中收。", "霜霰戎衣故，關河磧氣秋。", "箭創殊未合，更遣擊蘭州。"]'),
('12981488-9d66-47cf-9c20-7c1efe64f199','相和歌辭 關山曲 二','馬戴','唐','唐诗','tang','','[]','火發龍山北，中宵易左賢。',48,'全唐诗/poet.tang.1000.json','["火發龍山北，中宵易左賢。", "勒兵臨漢水，驚雁散胡天。", "木落防河急，軍孤受敵偏。", "猶聞漢皇怒，按劒待開邊。"]'),
('3d7fc8a1-0d5c-4a78-924c-01b1889059f8','相和歌辭 登高丘而望遠','李白','唐','唐诗','tang','','["\u76f8\u548c\u6b4c\u8f9e", "\u767b\u9ad8", "\u8054\u60f3", "\u4e50\u5e9c"]','登高丘而望遠海，六鼇骨已霜，三山流安在。',91,'全唐诗/poet.tang.1000.json','["登高丘而望遠海，六鼇骨已霜，三山流安在。", "扶桑半摧折，白日沈光彩。", "銀臺金闕如夢中，秦皇漢武空相待。", "精衛費木石，黿鼉無所憑。", "君不見驪山茂陵盡灰滅，牧羊之子來攀登。", "盜賊劫寶玉，精靈竟何能。"]'),
('3e457b1c-8c36-46fe-bca9-14cf644ec9ca','相和歌辭 蒿里','僧貫休','唐','唐诗','tang','','[]','兔不遲，烏更急，但恐穆王八駿，著鞭不及。',95,'全唐诗/poet.tang.1000.json','["兔不遲，烏更急，但恐穆王八駿，著鞭不及。", "所以蒿里，墳出蕺蕺，氣凌雲天，龍騰鳳集，盡爲風消土喫，狐掇蟻拾。", "黃金不啼玉不泣，白楊騷屑。", "亂風愁月，折碑石人。", "莽穢榛沒，牛羊窸窣。", "時見牧童兒，弄枯骨。"]'),
('aa7d3545-a694-4336-8852-5d491c106b50','相和歌辭 輓歌','趙微明','唐','唐诗','tang','','[]','寒日蒿上明，淒淒郭東路。',60,'全唐诗/poet.tang.1000.json','["寒日蒿上明，淒淒郭東路。", "素車誰家子，丹旐引將去。", "原下荆棘叢，叢邊有新墓。", "人間痛傷別，此是長別處。", "曠野何蕭條，青松白楊樹。"]'),
('bcd31207-66ec-44c9-9890-1c70b6e8ea69','相和歌辭 輓歌二首 一','于鵠','唐','唐诗','tang','','[]','陰風吹黃蒿，輓歌渡秋水。',24,'全唐诗/poet.tang.1000.json','["陰風吹黃蒿，輓歌渡秋水。", "車馬却歸城，孤墳月明裏。"]'),
('5f4c3465-566a-4a92-886d-20155ea07a0e','相和歌辭 輓歌二首 二','于鵠','唐','唐诗','tang','','[]','雙轍出郭門，緜緜東西道。',72,'全唐诗/poet.tang.1000.json','["雙轍出郭門，緜緜東西道。", "送死多於生，幾人得終老。", "見人切肺肝，不如歸山好。", "不聞哀哭聲，默默安懷抱。", "時盡從物化，又免生憂擾。", "世間壽者稀，盡爲悲傷惱。"]'),
('947e5189-4418-49fd-898a-9f7118777a2e','相和歌辭 輓歌','孟雲卿','唐','唐诗','tang','','[]','草草門巷喧，塗車儼成位。',96,'全唐诗/poet.tang.1000.json','["草草門巷喧，塗車儼成位。", "冥寞何所須，盡我生人意。", "北邙路非遠，此別終天地。", "臨穴頻撫棺，至哀反無淚。", "爾形未衰老，爾息猶童穉。", "骨肉不可離，皇天若容易。", "房帷即虛張，庭宇爲哀次。", "薤露歌若斯，人生盡如寄。"]'),
('3f3870ea-0cc1-4829-971c-b9f5fc7283a9','相和歌辭 輓歌','白居易','唐','唐诗','tang','','[]','丹旐何飛揚，素驂亦悲鳴。',100,'全唐诗/poet.tang.1000.json','["丹旐何飛揚，素驂亦悲鳴。", "晨光照閭巷，輀車儼欲行。", "蕭條九月天，哀輓出重城。", "借問送者誰，妻子與弟兄。", "蒼蒼上古原，峨峨開新塋。", "含酸一慟哭，異口同哀聲。", "舊壟轉蕪絕，新墳日羅列。", "春風草綠北邙山，此地年年生死別。"]'),
('14617b67-715a-4a36-bd2d-49c12aade4f1','相和歌辭 對酒','崔國輔','唐','唐诗','tang','','[]','行行日將夕，荒村古冢無人跡。',62,'全唐诗/poet.tang.1000.json','["行行日將夕，荒村古冢無人跡。", "朦朧荆棘一鳥飛，屢唱提壺酤酒喫。", "古人不達酒不足，遺恨精靈傳此曲。", "寄言當代諸少年，平生且盡杯中淥。"]'),
('8e959f72-69b2-4d3e-82b7-8a5a017c9a4d','相和歌辭 對酒二首 一','李白','唐','唐诗','tang','','["\u76f8\u548c\u6b4c\u8f9e", "\u4eba\u751f", "\u4e50\u5e9c", "\u611f\u6168"]','松子棲金華，安期入蓬海。',60,'全唐诗/poet.tang.1000.json','["松子棲金華，安期入蓬海。", "此人古之仙，羽化竟何在？", "浮生速流電，倏忽變光彩。", "天地無凋換，容顏有遷改。", "對酒不肯飲，含情欲誰待。"]'),
('0e943ad5-c823-4036-935d-e5d20f3c6ab1','相和歌辭 對酒二首 二','李白','唐','唐诗','tang','','[]','勸君莫拒杯，春風笑人來。',84,'全唐诗/poet.tang.1000.json','["勸君莫拒杯，春風笑人來。", "桃李如舊識，傾花向我開。", "流鶯啼碧樹，明月窺金罍。", "昨來朱顏子，今日白髮催。", "棘生石虎殿，鹿走姑蘇臺。", "自古帝王宅，城闕閉黃埃。", "君若不飲酒，昔人安在哉。"]'),
('e7abc715-139b-4987-b57d-c7dacdd8fe6b','相和歌辭 陌上桑','李白','唐','唐诗','tang','','["\u76f8\u548c\u6b4c\u8f9e", "\u5199\u4eba", "\u5fe0\u8d1e", "\u4e50\u5e9c", "\u8d5e\u7f8e"]','美女渭橋東，春還事蠶作。',108,'全唐诗/poet.tang.1000.json','["美女渭橋東，春還事蠶作。", "五馬如飛龍，青絲結金絡。", "不知誰家子，調笑來相謔。", "妾本秦羅敷，玉顏豔名都。", "綠條映素手，采桑向城隅。", "使君且不顧，況復論秋胡。", "寒螿愛碧草，鳴鳳棲青梧。", "託心自有處，但怪傍人愚。", "徒令白日暮，高駕空踟躕。"]'),
('2d7db01d-48b4-4f83-8627-41b98b7321a9','相和歌辭 陌上桑','常建','唐','唐诗','tang','','[]','翳翳陌上桑，南枝交北堂。',36,'全唐诗/poet.tang.1000.json','["翳翳陌上桑，南枝交北堂。", "美人金梯出，素手自提筐。", "非但畏蠶飢，盈盈嬌路傍。"]'),
('b1372dba-e0d3-4c51-9d76-cb7809667d5f','相和歌辭 陌上桑','陸龜蒙','唐','唐诗','tang','','[]','皓齒還如貝色含，長眉亦似煙華貼。',32,'全唐诗/poet.tang.1000.json','["皓齒還如貝色含，長眉亦似煙華貼。", "鄰娃盡著繡襠襦，獨自提筐采蠶葉。"]'),
('34008677-edfe-404c-92e8-547a08a9c815','相和歌辭 采桑','郎大家宋氏','唐','唐诗','tang','','[]','春來南雁歸，日去西蠶遠。',24,'全唐诗/poet.tang.1000.json','["春來南雁歸，日去西蠶遠。", "妾思紛何極，客遊殊未返。"]'),
('d4e3c78d-a404-4910-8e0d-aca1f0a29f2b','相和歌辭 采桑','劉希夷','唐','唐诗','tang','','[]','楊柳送行人，青青西入秦。',120,'全唐诗/poet.tang.1000.json','["楊柳送行人，青青西入秦。", "秦家采桑女，樓上不勝春。", "盈盈灞水曲，步步春芳綠。", "紅臉耀明珠，絳脣含白玉。", "回首渭橋東，遙憐樹色同。", "青絲嬌落日，緗綺弄春風。", "攜籠長歎息，逶迤戀春色。", "看花若有情，倚樹疑無力。", "薄暮思悠悠，使君南陌頭。", "相逢不相識，歸去夢青樓。"]'),
('2eb294ff-6032-4f91-afd7-f7b0260d1480','相和歌辭 采桑','李彥暐','唐','唐诗','tang','','[]','采桑畏日高，不待春眠足。',48,'全唐诗/poet.tang.1000.json','["采桑畏日高，不待春眠足。", "攀條有餘愁，那矜貌如玉。", "千金豈不贈，五馬空踟躅。", "何以變真性，幽篁雪中綠。"]'),
('81d604a7-0eb8-4a36-9a8d-a9cb7a31f312','相和歌辭 采桑','王建','唐','唐诗','tang','','[]','鳥鳴桑葉間，葉綠條復柔。',48,'全唐诗/poet.tang.1000.json','["鳥鳴桑葉間，葉綠條復柔。", "攀看去手近，放下長長鉤。", "黃花蓋野田，白馬少年遊。", "所念豈回顧，良人在高樓。"]'),
('08cf0ce8-bd26-4bab-a4d2-5bc43acf8376','相和歌辭 日出行','李白','唐','唐诗','tang','','["\u8bf4\u7406", "\u6292\u60c5", "\u53d9\u4e8b"]','日出東方隈，似從地底來。',128,'全唐诗/poet.tang.1000.json','["日出東方隈，似從地底來。", "歷天又入海，六龍所舍安在哉？", "其始與終古不息，人非元氣安能與之久裴回。", "草不謝榮於春風，木不怨落於秋天。", "誰揮鞭策驅四運，萬物興歇皆自然。", "羲和羲和，汝奚汩沒於荒淫之波。", "魯陽何德？駐景揮戈。", "逆道違天，矯誣實多。", "吾將囊括大塊，浩然與溟涬同科。"]'),
('7af5f435-0357-4ff6-ab62-97417d87a31a','相和歌辭 日出行','李賀','唐','唐诗','tang','','["\u9ec4\u6cb3"]','白日下崐崘，發光如舒絲。',81,'全唐诗/poet.tang.1000.json','["白日下崐崘，發光如舒絲。", "徒照葵藿心，不照遊子悲。", "折折黃河曲，日從中央轉。", "暘谷耳曾聞，若木眼不見。", "奈何鑠石，胡爲銷人。", "羿彎弓屬矢那不中，足令久不得奔，詎教晨光夕昏。"]'),
('6da7aaf4-ed2a-49b3-97d9-b33860fa6283','相和歌辭 王昭君','崔國輔','唐','唐诗','tang','','[]','漢使南還盡，胡中妾獨存。',24,'全唐诗/poet.tang.1000.json','["漢使南還盡，胡中妾獨存。", "紫臺緜望絕，秋草不堪論。"]'),
('db7616cc-91ef-47be-92e6-66a0cf9d06bc','相和歌辭 王昭君','崔國輔','唐','唐诗','tang','','[]','一回望月一回悲，望月月移人不移。',32,'全唐诗/poet.tang.1000.json','["一回望月一回悲，望月月移人不移。", "何時得見漢朝使？爲妾傳書斬畫師。"]'),
('95039e34-843d-473f-a835-9355b2d766e8','相和歌辭 王昭君','盧照鄰','唐','唐诗','tang','','[]','合殿恩中絕，交河使漸稀。',48,'全唐诗/poet.tang.1000.json','["合殿恩中絕，交河使漸稀。", "肝腸辭玉輦，形影向金微。", "漢宮草應綠，胡庭沙正飛。", "願逐三秋雁，年年一度歸。"]'),
('ebb0f4eb-6bff-4311-8737-c7f82b8258f8','相和歌辭 王昭君','駱賓王','唐','唐诗','tang','','[]','斂容辭豹尾，緘怨度龍鱗。',48,'全唐诗/poet.tang.1000.json','["斂容辭豹尾，緘怨度龍鱗。", "金鈿明漢月，玉箸染胡塵。", "妝鏡菱花暗，愁眉柳葉嚬。", "惟有清笳曲，時聞芳樹春。"]'),
('f7867962-cf6d-4ac7-b097-3c053429b6bc','相和歌辭 王昭君','沈佺期','唐','唐诗','tang','','[]','非君惜鸞殿，非妾妬蛾眉。',48,'全唐诗/poet.tang.1000.json','["非君惜鸞殿，非妾妬蛾眉。", "薄命由驕虜，無情是畫師。", "嫁來胡地惡，不竝漢宮時。", "心苦無聊賴，何堪上馬辭。"]'),
('28961dad-9610-4863-97e5-ed7f94802432','相和歌辭 王昭君','梁獻','唐','唐诗','tang','','[]','圖畫失天真，容華坐誤人。',48,'全唐诗/poet.tang.1000.json','["圖畫失天真，容華坐誤人。", "君恩不可再，妾命在和親。", "淚點關山月，衣銷邊塞塵。", "一聞陽鳥至，思絕漢宮春。"]'),
('f43fea55-bab0-4d3a-bf40-f3664667f8e5','相和歌辭 王昭君','上官儀','唐','唐诗','tang','','[]','玉關春色晚，金河路幾千。',48,'全唐诗/poet.tang.1000.json','["玉關春色晚，金河路幾千。", "琴悲桂條上，笛怨柳花前。", "霧掩臨妝月，風驚入鬢蟬。", "緘書待還使，淚盡白雲天。"]'),
('674553ed-a7c1-4287-9bf8-3fccf70db348','相和歌辭 王昭君','董思恭','唐','唐诗','tang','','[]','琵琶馬上彈，行路曲中難。',48,'全唐诗/poet.tang.1000.json','["琵琶馬上彈，行路曲中難。", "漢月正南遠，燕山直北寒。", "髻鬟風拂散，眉黛雪霑殘。", "斟酌紅顏盡，何勞鏡裏看。"]'),
('2e334ed8-698b-4297-ab7a-64cc5b4c45ef','相和歌辭 王昭君','顧朝陽','唐','唐诗','tang','','[]','莫將鉛粉匣，不用鏡花光。',48,'全唐诗/poet.tang.1000.json','["莫將鉛粉匣，不用鏡花光。", "一去邊城路，何情更畫妝。", "影銷胡地月，衣盡漢宮香。", "妾死非關命，祗緣怨斷腸。"]'),
('36597939-2dd3-4fd3-8bb9-cb4bdfd1c0f6','相和歌辭 王昭君三首 一','東方虯','唐','唐诗','tang','','[]','漢道初全盛，朝廷足武臣。',24,'全唐诗/poet.tang.1000.json','["漢道初全盛，朝廷足武臣。", "何須薄命妾，辛苦事和親。"]'),
('9ceaf4b9-1baf-4fa1-ab59-a749cde469e2','相和歌辭 王昭君三首 二','東方虯','唐','唐诗','tang','','[]','揜涕辭丹鳳，銜悲向白龍。',24,'全唐诗/poet.tang.1000.json','["揜涕辭丹鳳，銜悲向白龍。", "單于浪驚喜，無復舊時容。"]'),
('bbeea8e4-80b4-4dbf-801c-642990725c35','相和歌辭 王昭君三首 三','東方虯','唐','唐诗','tang','','[]','胡地無花草，春來不似春。',24,'全唐诗/poet.tang.1000.json','["胡地無花草，春來不似春。", "自然衣帶緩，非是爲腰身。"]'),
('94f427e0-5458-4671-b38e-4810ec5c200e','相和歌辭 王昭君三首 一','郭元振','唐','唐诗','tang','','[]','自嫁單于國，長銜漢掖悲。',24,'全唐诗/poet.tang.1000.json','["自嫁單于國，長銜漢掖悲。", "容顏日顦顇，有甚畫圖時。"]'),
('73edcbbc-36f8-46da-ab45-87e127ca5b5b','相和歌辭 王昭君三首 二','郭元振','唐','唐诗','tang','','[]','厭踐冰霜域，嗟爲邊塞人。',24,'全唐诗/poet.tang.1000.json','["厭踐冰霜域，嗟爲邊塞人。", "思從漢南獵，一見漢家塵。"]'),
('b263cbc5-dd18-48af-a7d2-694e836d8408','相和歌辭 王昭君三首 三','郭元振','唐','唐诗','tang','','[]','聞有南河信，傳聞殺畫師。',24,'全唐诗/poet.tang.1000.json','["聞有南河信，傳聞殺畫師。", "始知君惠重，更遣畫蛾眉。"]'),
('417dd972-fc55-4972-b698-e5e595453dbd','相和歌辭 王昭君','劉長卿','唐','唐诗','tang','','["\u9ec4\u6cb3"]','自矜妖豔色，不顧丹青人。',108,'全唐诗/poet.tang.1000.json','["自矜妖豔色，不顧丹青人。", "那知粉繢能相負，却使容華飜誤身。", "上馬辭君嫁驕虜，玉顏對人啼不語。", "北風雁急浮清秋，萬里獨見黃河流。", "纖腰不復漢宮寵，雙蛾長向胡天愁。", "琵琶弦中苦調多，蕭蕭羌笛聲相和。", "可憐一曲傳樂府，能使千秋傷綺羅。"]'),
('7351694b-3849-44b6-a7b6-8f46e00f8041','相和歌辭 王昭君二首 一','李白','唐','唐诗','tang','','["\u76f8\u548c\u6b4c\u8f9e", "\u5199\u4eba", "\u4e50\u5e9c"]','漢家秦地月，流影照明妃。',72,'全唐诗/poet.tang.1000.json','["漢家秦地月，流影照明妃。", "一上玉關道，天涯去不歸。", "漢月還從東海出，明妃西嫁無來日。", "燕支長寒雪作花，蛾眉顦顇沒胡沙。", "生乏黃金枉圖畫，死留青冢使人嗟。"]'),
('d859edea-5188-4d7f-b4c2-f281d106bd59','相和歌辭 王昭君二首 二','李白','唐','唐诗','tang','','[]','昭君拂玉鞍，上馬啼紅頰。',24,'全唐诗/poet.tang.1000.json','["昭君拂玉鞍，上馬啼紅頰。", "今日漢宮人，明朝胡地妾。"]'),
('232f0a0b-3dea-4f47-aaa5-d3b34de7f4a2','相和歌辭 王昭君','儲光羲','唐','唐诗','tang','','[]','日暮驚沙亂雪飛，傍人相勸易羅衣。',32,'全唐诗/poet.tang.1000.json','["日暮驚沙亂雪飛，傍人相勸易羅衣。", "強來前帳看歌舞，共待單于夜獵歸。"]'),
('baee79b5-b12e-4782-a0a6-33f6d2262a69','相和歌辭 王昭君','僧皎然','唐','唐诗','tang','','[]','自倚嬋娟望主恩，誰知美惡忽相飜。',32,'全唐诗/poet.tang.1000.json','["自倚嬋娟望主恩，誰知美惡忽相飜。", "黃金不買漢宮貌，青冢空埋胡地魂。"]'),
('5ea39dca-10f3-40f2-b644-29dc9bc71e40','相和歌辭 王昭君二首 一','白居易','唐','唐诗','tang','','[]','滿面胡沙滿鬢風，眉銷殘黛臉銷紅。',32,'全唐诗/poet.tang.1000.json','["滿面胡沙滿鬢風，眉銷殘黛臉銷紅。", "愁苦辛勤顦顇盡，如今却似畫圖中。"]'),
('fd60e7b9-e73b-4145-b28c-10f144257800','相和歌辭 王昭君二首 二','白居易','唐','唐诗','tang','','[]','漢使却回憑寄語，黃金何日贖蛾眉？君王若問妾顏色，莫道不如宮裏時。',32,'全唐诗/poet.tang.1000.json','["漢使却回憑寄語，黃金何日贖蛾眉？君王若問妾顏色，莫道不如宮裏時。"]'),
('bdb8856c-15c6-487f-8932-c2dd589aa833','相和歌辭 王昭君','令狐楚','唐','唐诗','tang','','[]','錦車天外去，毳幕雲中開。',24,'全唐诗/poet.tang.1000.json','["錦車天外去，毳幕雲中開。", "魏闕蒼龍遠，蕭關赤雁哀。"]'),
('dd999d6e-1a59-43f9-845c-2805dc2977da','相和歌辭 王昭君','張仲素','唐','唐诗','tang','','[]','仙娥今下嫁，驕子自同和。',24,'全唐诗/poet.tang.1000.json','["仙娥今下嫁，驕子自同和。", "劒戟歸田盡，牛羊繞塞多。"]'),
('ea2769d1-dfb2-4dc3-a86f-65a2f962a166','相和歌辭 王昭君','李商隱','唐','唐诗','tang','','[]','毛延壽畫欲通神，忍爲黃金不爲人。',32,'全唐诗/poet.tang.1000.json','["毛延壽畫欲通神，忍爲黃金不爲人。", "馬上琵琶行萬里，漢宮長有隔生春。"]'),
('8e4dd8bd-be62-478f-bd88-f6db89276125','相和歌辭 明妃曲','王偃','唐','唐诗','tang','','["\u9ec4\u6cb3"]','北望單于日半斜，明君馬上泣胡沙。',32,'全唐诗/poet.tang.1000.json','["北望單于日半斜，明君馬上泣胡沙。", "一雙淚滴黃河水，應得東流入漢家。"]'),
('f166c3ae-20ba-4c3c-98bc-86748fe65ec0','相和歌辭 昭君詞','張文琮','唐','唐诗','tang','','[]','戒途飛萬里，回首望三秦。',48,'全唐诗/poet.tang.1000.json','["戒途飛萬里，回首望三秦。", "忽見天山雪，還疑上苑春。", "玉痕垂淚粉，羅袂拂胡塵。", "爲得胡中曲，還悲遠嫁人。"]'),
('1dcbf1f9-1f83-4336-aa0a-3bfc9669eeff','相和歌辭 昭君詞','陳昭','唐','唐诗','tang','','[]','跨鞍今永訣，垂淚別親賓。',48,'全唐诗/poet.tang.1000.json','["跨鞍今永訣，垂淚別親賓。", "漢地行將遠，胡關逐望新。", "交河擁塞路，隴首暗沙塵。", "唯有孤明月，猶能遠送人。"]'),
('4c21addf-505a-4646-ba87-7c04278d68ff','相和歌辭 昭君詞','戴叔倫','唐','唐诗','tang','','[]','漢宮若遠近，路在寒沙上。',24,'全唐诗/poet.tang.1000.json','["漢宮若遠近，路在寒沙上。", "到死不得歸，何人共南望。"]'),
('156ce7cd-387c-48ea-80c3-9263138ee066','相和歌辭 昭君詞','李端','唐','唐诗','tang','','[]','李陵初送子卿回，漢月明明照帳來。',32,'全唐诗/poet.tang.1000.json','["李陵初送子卿回，漢月明明照帳來。", "憶著長安舊遊處，千門萬戶玉樓臺。"]'),
('8434304f-056e-45be-8558-b028cdcc4133','相和歌辭 楚妃歎','張籍','唐','唐诗','tang','','[]','湘雲初起江沈沈，君王遙在雲夢林。',80,'全唐诗/poet.tang.1000.json','["湘雲初起江沈沈，君王遙在雲夢林。", "江南雨多旌旗暗，臺下朝朝春水深。", "章華殿前朝萬國，君心獨自終無極。", "楚兵滿地能逐禽，誰用一身繼筋力。", "西江若飜雲夢中，麋鹿死盡應還宮。"]'),
('2b7e4088-5605-41dc-8565-bcce73c7dfad','相和歌辭 楚妃怨','張籍','唐','唐诗','tang','','[]','梧桐葉下黃金井，橫架轆轤牽素綆。',32,'全唐诗/poet.tang.1000.json','["梧桐葉下黃金井，橫架轆轤牽素綆。", "美人初起天未明，手拂銀缾秋水冷。"]'),
('9579b49c-f49e-4433-8010-4ce223233acc','相和歌辭 王子喬','宋之問','唐','唐诗','tang','','[]','王子喬，愛神仙，七月七日上賓天。',60,'全唐诗/poet.tang.1000.json','["王子喬，愛神仙，七月七日上賓天。", "白虎搖瑟鳳吹笙，乘騎雲氣吸日精。", "吸日精，長不歸，遺廟今在而人非。", "空望山頭草，草露溼君衣。"]'),
('b5502113-3846-45a2-8334-e91c0d1e22ee','相和歌辭 蜀國弦','李賀','唐','唐诗','tang','','["\u79bb\u522b", "\u6292\u60c5", "\u5c71\u6c34", "\u5199\u666f"]','楓香晚華靜，錦水南山影。',48,'全唐诗/poet.tang.1000.json','["楓香晚華靜，錦水南山影。", "驚石墜猨哀，竹雲愁半嶺。", "涼月生秋浦，玉沙鱗鱗光。", "誰家紅淚客，不忍過瞿塘。"]'),
('24eec460-2dda-41a7-8104-e590096f3e03','相和歌辭 長歌行','李白','唐','唐诗','tang','','["\u76f8\u548c\u6b4c\u8f9e", "\u7406\u60f3", "\u4e50\u5e9c", "\u5efa\u529f\u7acb\u4e1a"]','桃李得日開，榮華照當年。',120,'全唐诗/poet.tang.1000.json','["桃李得日開，榮華照當年。", "東風動百物，草木盡欲言。", "枯枝無醜葉，涸水吐清泉。", "大力運天地，羲和無停鞭。", "功名不早著，竹帛將何宣？", "桃李務青春，誰能貫白日。", "富貴與神仙，蹉跎成兩失。", "金石猶銷鑠，風霜無久質。", "畏落日月後，強歡歌與酒。", "秋霜不惜人，倏忽侵蒲柳。"]'),
('ade97a3d-abfa-483d-914b-8969d5046dc2','相和歌辭 長歌行','王昌齡','唐','唐诗','tang','','[]','曠野饒悲風，颼颼黃蒿草。',96,'全唐诗/poet.tang.1000.json','["曠野饒悲風，颼颼黃蒿草。", "繫馬停白楊，誰知我懷抱。", "所是同袍者，相逢盡衰老。", "況登漢家陵，南望長安道。", "下有枯樹根，上有鼷鼠窠。", "高皇子孫盡，千古無人過。", "寶玉頻發掘，精靈其奈何？", "人生須達命，有酒且長歌。"]'),
('48f70126-c9e2-4d4d-8a3f-e1e76539c15d','相和歌辭 短歌行','聶夷中','唐','唐诗','tang','','[]','八月木蔭薄，十葉三墮枝。',108,'全唐诗/poet.tang.1000.json','["八月木蔭薄，十葉三墮枝。", "人生過五十，亦已同此時。", "朝出東郭門，嘉樹鬱參差。", "暮出西郭門，原草已離披。", "南鄰好臺榭，北鄰善歌吹。", "榮華忽消歇，四顧令人悲。", "生死與榮辱，四者乃常期。", "古人恥其名，沒世無人知。", "無言鬢似霜，勿謂髮如絲。"]'),
('308de8c1-a614-42e8-aff9-11cb4a5c08d2','相和歌辭 短歌行','李白','唐','唐诗','tang','','["\u60dc\u65f6", "\u76f8\u548c\u6b4c\u8f9e", "\u4eba\u751f", "\u65f6\u95f4"]','白日何短短，百年苦易滿。',84,'全唐诗/poet.tang.1000.json','["白日何短短，百年苦易滿。", "蒼穹浩茫茫，萬劫太極長。", "麻姑垂兩鬢，一半已成霜。", "天公見玉女，大笑億千場。", "吾欲攪六龍，回車挂扶桑。", "北斗酌美酒，勸龍各一觴。", "富貴非所願，爲人駐頹光。"]'),
('4eb5e933-ca5a-40f4-975f-a33c670908d8','相和歌辭 短歌行六首 一','顧況','唐','唐诗','tang','','[]','城邊路，今人犂田昔人墓。',56,'全唐诗/poet.tang.1000.json','["城邊路，今人犂田昔人墓。", "岸上沙，昔時江水今人家。", "今人昔人共長歎，四氣相催節回換。", "明月皎皎入華池，白雲離離度清漢。"]'),
('16dea403-c108-4546-89a5-18e8f1d3373c','相和歌辭 短歌行六首 二','顧況','唐','唐诗','tang','','[]','我欲升天天隔霄，我思渡水水無橋。',48,'全唐诗/poet.tang.1000.json','["我欲升天天隔霄，我思渡水水無橋。", "我欲上山山路險，我欲汲井井泉遙。", "越人翠被今何夕，獨立沙邊江草碧。"]'),
('39f54c2d-a0a9-4121-b7df-958ce2b4824e','相和歌辭 短歌行六首 三','顧況','唐','唐诗','tang','','[]','新繫青絲百尺繩，心在君家轆轤上。',32,'全唐诗/poet.tang.1000.json','["新繫青絲百尺繩，心在君家轆轤上。", "我心皎潔君不知，轆轤一轉一惆悵。"]'),
('06bb6ddd-5f47-42f0-a020-b7671ad56bdf','相和歌辭 短歌行六首 四','顧況','唐','唐诗','tang','','[]','何處春風吹曉幕？江南綠水通朱閣。',32,'全唐诗/poet.tang.1000.json','["何處春風吹曉幕？江南綠水通朱閣。", "美人二八面如花，泣向東風畏花落。"]'),
('e62d0639-d93d-48ca-a865-de2531a4667d','相和歌辭 短歌行六首 五','顧況','唐','唐诗','tang','','[]','臨春風，聽春鳥。',32,'全唐诗/poet.tang.1000.json','["臨春風，聽春鳥。", "別時多，見時少。", "愁人夜永不得眠，瑤井玉繩相向曉。"]'),
('733338ce-0d59-4820-ab16-d779ef50018b','相和歌辭 短歌行六首 六','顧況','唐','唐诗','tang','','[]','軒轅皇帝初得仙，鼎湖一去三千年。',56,'全唐诗/poet.tang.1000.json','["軒轅皇帝初得仙，鼎湖一去三千年。", "周流三十六洞天，洞中日月星辰連。", "騎龍駕景遊八極，軒轅弓劒無人識，東海青童寄消息。"]'),
('c7c59c41-b87d-4c9f-8efd-f6189ebe72e8','相和歌辭 短歌行','王建','唐','唐诗','tang','','["\u60dc\u65f6", "\u6bcd\u4eb2"]','人初生，日初出。',72,'全唐诗/poet.tang.1000.json','["人初生，日初出。", "上山遲，下山疾。", "百年三萬六千朝，夜裏分將彊半日。", "有歌有舞間早爲，昨日健於今日時。", "人家見生男女好，不知男女催人老。", "短歌行，無樂聲。"]'),
('e475f6f8-5b6a-4387-834f-acd87e595561','相和歌辭 短歌行','張籍','唐','唐诗','tang','','[]','青天蕩蕩高且虛，上有白日無根株。',64,'全唐诗/poet.tang.1000.json','["青天蕩蕩高且虛，上有白日無根株。", "流光暫出還入地，催我少年不須臾。", "與君相逢不寂寞，衰老不復如今樂。", "玉卮盛酒置君前，再拜願君千萬年。"]'),
('f8ec87e7-3074-40dd-8d87-a260dad83ae7','相和歌辭 短歌行二首 一','白居易','唐','唐诗','tang','','[]','曈曈太陽如火色，上行千里下一刻。',128,'全唐诗/poet.tang.1000.json','["曈曈太陽如火色，上行千里下一刻。", "出爲白晝入爲夜，圜轉如珠住不得。", "住不得，可奈何？爲君舉酒歌短歌。", "歌聲苦，詞亦苦，四座少年君聽取。", "今夕未竟明夕催，秋風纔往春風回。", "人無根蔕時不駐，朱顏白日相隳頹。", "勸君且強笑一面，勸君復強飲一杯。", "人生不得長歡樂，年少須臾老到來。"]'),
('6358b620-0c4b-4bd3-ae41-b93271318a05','相和歌辭 短歌行二首 二','白居易','唐','唐诗','tang','','[]','世人求富貴，多爲身嗜欲。',168,'全唐诗/poet.tang.1000.json','["世人求富貴，多爲身嗜欲。", "盛衰不自由，得失常相逐。", "問君少年日，苦學將干祿。", "負笈塵中遊，抱書雪前宿。", "布衾不周體，藜茄纔充腹。", "三十登宦途，五十被朝服。", "奴溫已挾纊，馬肥初食粟。", "未敢議歡遊，尚爲名檢束。", "耳目聾暗後，堂上調絲竹。", "牙齒缺落時，盤中堆酒肉。", "彼來此已去，外餘中不足。", "少壯與榮華，相避如寒燠。", "青雲去地遠，白日終天速。", "從古無奈何，短歌聽一曲。"]'),
('e9800b0e-760e-4437-b733-d9eed56aef6b','相和歌辭 短歌行','陸龜蒙','唐','唐诗','tang','','[]','爪牙在身上，陷穽猶可制。',48,'全唐诗/poet.tang.1000.json','["爪牙在身上，陷穽猶可制。", "爪牙在胷中，劒戟無所畏。", "人言畏猛虎，誰是撩頭斃。", "祗見古來心，姦雄暗相噬。"]'),
('344b8022-5073-4b18-a099-ee3e1f12412b','相和歌辭 短歌行','僧皎然','唐','唐诗','tang','','[]','古人若不死，吾亦何所悲。',100,'全唐诗/poet.tang.1000.json','["古人若不死，吾亦何所悲。", "蕭蕭煙雨九原上，白楊青松葬者誰。", "貴賤同一塵，死生同一指。", "人生在世共如此，何異浮雲與流水。", "短歌行，短歌無窮日已傾。", "鄴宮梁苑徒有名，春草秋風傷我情。", "何爲不學金仙侶？一悟空王無死生。"]'),
('863d795c-9a4b-4775-95f3-f7747b354a84','相和歌辭 銅雀臺','王無競','唐','唐诗','tang','','[]','北登銅雀上，西望青松郭。',72,'全唐诗/poet.tang.1000.json','["北登銅雀上，西望青松郭。", "繐帳空蒼蒼，陵田紛漠漠。", "平生事已變，歌吹宛猶昨。", "長袖拂玉麈，遺情結羅幕。", "妾怨在朝露，君恩豈中薄。", "高臺奏曲終，曲終淚橫落。"]'),
('4b253a52-9aae-494e-8dea-269686ea97b2','相和歌辭 銅雀臺','鄭愔','唐','唐诗','tang','','[]','日斜漳浦望，風起鄴臺寒。',48,'全唐诗/poet.tang.1000.json','["日斜漳浦望，風起鄴臺寒。", "玉座平生晚，金尊妓吹闌。", "舞餘依帳泣，歌罷向陵看。", "蕭索松風暮，愁煙入井闌。"]'),
('c04a73af-b692-4a86-8817-878f0c2b39d6','相和歌辭 銅雀臺','劉長卿','唐','唐诗','tang','','[]','嬌愛更何日？高臺空數層。',107,'全唐诗/poet.tang.1000.json','["嬌愛更何日？高臺空數層。", "含啼映雙袖，不忍看西陵。", "漳河東流無復來，百花輦路爲蒼苔。", "青樓月夜長寂寞，碧雲日暮空裴回。", "君不見鄴中萬事非昔時，古人何在今人悲。", "春風不逐君王去，草色年年舊宮路。", "宮中歌舞已浮雲，空指行人往來處。"]'),
('154e934d-23b0-4ea2-83e4-6a824032eace','相和歌辭 銅雀臺','賈至','唐','唐诗','tang','','[]','日暮銅雀靜，西陵鳥雀歸。',48,'全唐诗/poet.tang.1000.json','["日暮銅雀靜，西陵鳥雀歸。", "撫弦心斷絕，聽管淚霏霏。", "靈几臨朝奠，空牀卷夜衣。", "蒼蒼川上月，應照妾魂飛。"]'),
('93ce9873-3063-43d5-ac58-1f2d65197e63','相和歌辭 銅雀臺','羅隱','唐','唐诗','tang','','[]','強歌強舞竟難勝，花落花開淚滿繒。',32,'全唐诗/poet.tang.1000.json','["強歌強舞竟難勝，花落花開淚滿繒。", "祗合當年伴君死，免教顦顇望西陵。"]'),
('04231364-d4bf-46f7-b732-239b593e20a1','相和歌辭 銅雀臺','薛能','唐','唐诗','tang','','[]','魏帝當時銅雀臺，黃花深映棘叢開。',32,'全唐诗/poet.tang.1000.json','["魏帝當時銅雀臺，黃花深映棘叢開。", "人生富貴須回首，此地豈無歌舞來。"]'),
('d8e2dbe6-d9a2-4fa0-a548-5d98d6e29ebc','相和歌辭 銅雀臺','張氏琰','唐','唐诗','tang','','[]','君王冥寞不可見，銅雀歌舞空裴回。',44,'全唐诗/poet.tang.1000.json','["君王冥寞不可見，銅雀歌舞空裴回。", "西陵嘖嘖悲宿鳥，空殿沈沈閉青苔。", "青苔無人跡，紅粉空相哀。"]'),
('57fc2199-fe36-4b4e-8ec5-9a4118206894','相和歌辭 銅雀臺','梁氏瓊','唐','唐诗','tang','','[]','歌扇向陵開，齊行奠玉杯。',48,'全唐诗/poet.tang.1000.json','["歌扇向陵開，齊行奠玉杯。", "舞時飛燕列，夢裏片雲來。", "月色空餘恨，松聲暮更哀。", "誰憐未死妾，掩袂下銅臺。"]'),
('07350b9f-fa3c-4d1b-8f99-363c11f9873d','相和歌辭 銅雀妓 一','王勃','唐','唐诗','tang','','[]','妾本深宮妓，曾城閉九重。',48,'全唐诗/poet.tang.1000.json','["妾本深宮妓，曾城閉九重。", "君王歡愛盡，歌舞爲誰容。", "錦衾不復襞，羅衣誰再縫。", "高臺西北望，流涕向青松。"]'),
('0c5f92d1-f239-4403-923b-c25bcb20b679','相和歌辭 銅雀妓 二','王勃','唐','唐诗','tang','','[]','金鳳鄰銅雀，漳河望鄴城。',48,'全唐诗/poet.tang.1000.json','["金鳳鄰銅雀，漳河望鄴城。", "君王無處所，臺榭若平生。", "舞筵紛可就，歌梁儼未傾。", "西陵松檟冷，誰見綺羅情。"]'),
('9e31f573-be01-432b-882c-d181c575dde7','相和歌辭 銅雀妓','沈佺期','唐','唐诗','tang','','[]','昔年分鼎地，今日望陵臺。',48,'全唐诗/poet.tang.1000.json','["昔年分鼎地，今日望陵臺。", "一旦雄圖盡，千秋遺令開。", "綺羅君不見，歌舞妾空來。", "恩共漳河水，東流無重迴。"]'),
('5b5e6525-dd53-496d-9fb7-73e6a57257f4','相和歌辭 銅雀妓','喬知之','唐','唐诗','tang','','[]','金閣惜分香，鈆華不重妝。',48,'全唐诗/poet.tang.1000.json','["金閣惜分香，鈆華不重妝。", "空餘歌舞地，猶是爲君王。", "哀弦調已絕，豔曲不須長。", "共看西陵暮，秋煙生白楊。"]'),
('11df6c7b-ed87-4560-a226-9f2bbf774712','相和歌辭 銅雀妓','王適','唐','唐诗','tang','','[]','日暮銅雀迥，幽聲玉座清。',36,'全唐诗/poet.tang.1000.json','["日暮銅雀迥，幽聲玉座清。", "蕭森松柏望，委鬱綺羅情。", "君恩不再重，妾舞爲誰輕。"]'),
('08c567b5-dbee-4056-a1f4-712d2eca77c3','相和歌辭 銅雀妓','歐陽詹','唐','唐诗','tang','','[]','蕭條登古臺，回首黃金屋。',48,'全唐诗/poet.tang.1000.json','["蕭條登古臺，回首黃金屋。", "落葉不歸林，高陵永爲谷。", "妝容徒自麗，舞態閱誰目。", "惆悵繐帷前，歌聲苦於哭。"]'),
('7efb56b2-728f-4899-846f-4203c618194e','相和歌辭 銅雀妓','袁暉','唐','唐诗','tang','','[]','君愛本相饒，從來事舞腰。',48,'全唐诗/poet.tang.1000.json','["君愛本相饒，從來事舞腰。", "那堪攀玉座，腸斷望陵朝。", "怨著情無主，哀凝曲不調。", "況臨松日暮，悲吹坐蕭蕭。"]'),
('c7e721a1-9169-46c6-bbf3-970fef076539','相和歌辭 銅雀妓','劉商','唐','唐诗','tang','','[]','魏主矜蛾眉，美人美於玉。',132,'全唐诗/poet.tang.1000.json','["魏主矜蛾眉，美人美於玉。", "高臺無晝夜，歌舞竟未足。", "盛色如轉圜，夕陽落深谷。", "仍令身歿後，尚足平生慾。", "紅粉橫淚痕，調弦空向屋。", "舉頭君不在，唯見西陵木。", "玉輦豈再來，嬌鬟爲誰綠。", "那堪秋風裏，更舞陽春曲。", "曲終情不勝，闌干向西哭。", "臺邊生野草，來去罥羅縠。", "況復陵寢間，雙雙見麋鹿。"]'),
('2f6e3b2d-dc26-4be1-bf64-0710c7eaa7cd','相和歌辭 銅雀妓','李賀','唐','唐诗','tang','','[]','佳人一壺酒，秋容滿千里。',48,'全唐诗/poet.tang.1000.json','["佳人一壺酒，秋容滿千里。", "石馬臥新煙，憂來何所似？", "歌聲且潛弄，陵樹風自起。", "長裾壓高臺，淚眼看花机。"]'),
('58f2aafa-f8bd-4f82-8931-61397b827a1c','相和歌辭 銅雀妓','吳燭','唐','唐诗','tang','','[]','秋色西陵滿綠蕪，繁弦急管彊歡娛。',32,'全唐诗/poet.tang.1000.json','["秋色西陵滿綠蕪，繁弦急管彊歡娛。", "長舒羅袖不成舞，却向風前承淚珠。"]'),
('46e5e3dd-ca66-42e2-bb91-6cac9bd4e71c','相和歌辭 銅雀妓','朱光弼','唐','唐诗','tang','','[]','魏王銅雀妓，日暮管弦清。',24,'全唐诗/poet.tang.1000.json','["魏王銅雀妓，日暮管弦清。", "一見西陵樹，悲心舞不成。"]'),
('c0bd84c8-d587-4cf5-88b3-4b2450e3eae9','相和歌辭 銅雀妓','朱放','唐','唐诗','tang','','[]','恨唱歌聲咽，愁飜舞袖遲。',24,'全唐诗/poet.tang.1000.json','["恨唱歌聲咽，愁飜舞袖遲。", "西陵日欲暮，是妾斷腸時。"]'),
('b0c486a5-19d2-4475-869f-6dd767e348e7','相和歌辭 銅雀妓','僧皎然','唐','唐诗','tang','','[]','彊開尊酒向陵看，憶得君王舊日歡。',32,'全唐诗/poet.tang.1000.json','["彊開尊酒向陵看，憶得君王舊日歡。", "不覺餘歌悲自斷，非關豔曲轉聲難。"]'),
('b4a2ae5f-6ea2-4e26-a6b2-a28bb38adc74','相和歌辭 雀臺怨','馬戴','唐','唐诗','tang','','[]','魏宮歌舞地，蝶戲鳥還鳴。',48,'全唐诗/poet.tang.1000.json','["魏宮歌舞地，蝶戲鳥還鳴。", "玉座人難到，銅臺雨滴平。", "西陵樹不見，漳浦草空生。", "萬恨盡埋此，徒懸千載名。"]'),
('9ed3d8a1-b456-4deb-a76d-5ebe314e3da4','相和歌辭 雀臺怨','程氏長文','唐','唐诗','tang','','[]','君王去後行人絕，蕭竽不響歌喉咽。',64,'全唐诗/poet.tang.1000.json','["君王去後行人絕，蕭竽不響歌喉咽。", "雄劒無威光彩沈，寶琴零落金星滅。", "玉階寂寂墜秋露，月照當時歌舞處。", "當時歌舞人不迴，化爲今日西陵灰。"]'),
('a131e1c4-ee2b-484e-9a8e-90b39b5bb28d','相和歌辭 置酒行','李益','唐','唐诗','tang','','[]','置酒命所歡，憑觴遂爲戚。',96,'全唐诗/poet.tang.1000.json','["置酒命所歡，憑觴遂爲戚。", "日往不再來，茲辰坐成昔。", "百齡非長久，五十將半百。", "胡爲勞我形，已鬚還復白。", "西山鸞鶴顧，矯矯煙霧翮。", "明霞發金丹，陰洞潛水碧。", "安得凌風羽，崦嵫駐靈魄。", "兀然坐衰老，慙歎東陵柏。"]'),
('49b09ac0-497e-4ce2-8a06-0df3c449c8d5','相和歌辭 置酒行','陸龜蒙','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','落塵花片排香痕，闌珊醉露棲愁魂。',64,'全唐诗/poet.tang.1000.json','["落塵花片排香痕，闌珊醉露棲愁魂。", "洞庭波色惜不得，東風領入黃金尊。", "千筠擲毫春譜大，碧舞紅啼相唱和。", "安知寂寞西海頭，青𥳇未垂孤鳳餓。"]'),
('caa5cc79-ac6f-4c2f-8579-0fd050c93ee8','相和歌辭 長歌續短歌','李賀','唐','唐诗','tang','','["\u6292\u60c5", "\u4ed5\u9014", "\u6124\u61d1"]','長歌破衣襟，短歌斷白髮。',84,'全唐诗/poet.tang.1000.json','["長歌破衣襟，短歌斷白髮。", "秦王不可見，旦夕成內熱。", "渴飲壺中酒，飢拔隴頭粟。", "淒淒四月蘭，千里一時綠。", "夜峰何離離，月明落石底。", "裴回沿石尋，照出高峰外。", "不得與之遊，歌成鬢先改。"]'),
('7a1591ac-b91b-4120-8b25-da3d40eb75a0','相和歌辭 猛虎行','儲光羲','唐','唐诗','tang','','[]','寒亦不憂雪，飢亦不食人。',96,'全唐诗/poet.tang.1000.json','["寒亦不憂雪，飢亦不食人。", "人血豈不甘，所惡傷明神。", "太室爲我宅，孟門爲我鄰。", "百獸爲我膳，五龍爲我賓。", "蒙馬一何威，浮江亦以仁。", "綵章耀朝日，牙爪雄武臣。", "高雲逐氣浮，厚地隨聲振。", "君能賈餘勇，日夕長相親。"]'),
('a6e5e21e-44a8-4e30-b824-ef6344e9d531','相和歌辭 猛虎行','李白','唐','唐诗','tang','','["\u5fe7\u56fd\u5fe7\u6c11", "\u76f8\u548c\u6b4c\u8f9e", "\u4e50\u5e9c"]','朝作猛虎行，暮作猛虎吟。',340,'全唐诗/poet.tang.1000.json','["朝作猛虎行，暮作猛虎吟。", "腸斷非關隴頭水，淚下不爲雍門琴。", "旌旗繽紛兩河道，戰鼓驚山欲傾倒。", "秦人半作燕地囚，胡馬飜銜洛陽草。", "一輸一失關下兵，朝降夕叛幽薊城。", "巨鼇未斬海水動，魚龍奔走安得寧。", "頗似楚漢時，飜覆無定止。", "朝過博浪沙，暮入淮陰市。", "張良未遇韓信貧，劉項存亡在兩臣。", "暫到下邳受兵略，來投漂母作主人。", "賢哲栖栖古如此，今時亦棄青雲士。", "有策不敢犯龍鱗，竄身南國避胡塵。", "寶書長劒挂高閣，金鞍駿馬散故人。", "昨日方爲宣城客，掣鈴交通二千石。", "有時六博快壯心，繞牀三帀呼一擲。", "楚人每道張旭奇，心藏風雲世莫知。", "三吳邦伯多顧盼，四海雄俠皆相推。", "蕭曹曾作沛中吏，攀龍附鳳當有時。", "溧陽酒樓三月春，楊花漠漠愁殺人。", "胡人綠眼吹玉笛，吳歌白紵飛梁塵。", "丈夫相見且爲樂，槌牛撾鼓會衆賓。", "我從此去釣東海，得魚笑寄情相親。"]'),
('be3b0c39-a142-4603-9e85-ef1d56587c5f','相和歌辭 猛虎行','韩愈','唐','唐诗','tang','','[]','猛虎雖云惡，亦各有匹儕。',192,'全唐诗/poet.tang.1000.json','["猛虎雖云惡，亦各有匹儕。", "羣行深谷間，百獸望風低。", "身食黃熊父，子食赤豹麛。", "擇肉於熊羆，肎視兔與貍。", "正晝當谷眠，眼有百步威。", "自矜無當對，氣性縱以乖。", "朝怒殺其子，暮還飧其妃。", "匹儕四散走，猛虎還孤棲。", "狐鳴門四旁，烏鵲從噪之。", "出逐猴入居，虎不知所歸。", "誰云猛虎惡，中路正悲啼。", "豹來銜其尾，熊來攫其頤。", "猛虎死不辭，但慙前所爲。", "虎坐無助死，況如汝細微。", "故當結以信，親當結以私。", "親故且不保，人誰信汝爲。"]'),
('64fb5abd-0cad-47a0-8b99-d94291fbc63f','相和歌辭 猛虎行','張籍','唐','唐诗','tang','','[]','南山北山樹冥冥，猛虎白日繞林行。',80,'全唐诗/poet.tang.1000.json','["南山北山樹冥冥，猛虎白日繞林行。", "向晚一身當道食，山中麋鹿盡無聲。", "年年養子在深谷，雌雄上山不相逐。", "谷中近窟有山村，長向村家取黃犢。", "五陵年少不敢射，空來林下看行跡。"]'),
('03ab8d68-3b2a-4180-8592-cd523ee54570','相和歌辭 猛虎行','李賀','唐','唐诗','tang','','["\u6cf0\u5c71"]','長戈莫舂，彊弩莫烹。',81,'全唐诗/poet.tang.1000.json','["長戈莫舂，彊弩莫烹。", "乳孫哺子，教得生獰。", "舉頭爲城，掉尾爲旌。", "東海黃公，愁見夜行。", "道逢騶虞，牛哀不平。", "生何用尺刀，壁上雷鳴。", "泰山之下，婦人哭聲。", "官家有程，吏不敢聽。"]'),
('01b862ce-196c-4e2b-beea-1a9cf63e0f84','相和歌辭 猛虎行','僧齊己','唐','唐诗','tang','','[]','磨爾牙，錯爾爪，狐莫威，兔莫狡，飲來吞噬取腸飽。',40,'全唐诗/poet.tang.1000.json','["磨爾牙，錯爾爪，狐莫威，兔莫狡，飲來吞噬取腸飽。", "橫行不怕日月明，皇天產爾爲生獰。"]'),
('355093ed-7265-43e2-b1c6-32da0aaef1ee','相和歌辭 君子行','僧齊己','唐','唐诗','tang','','[]','聖人不生，麟龍何瑞？',52,'全唐诗/poet.tang.1000.json','["聖人不生，麟龍何瑞？", "梧桐不高，鳳皇何止？", "吾聞古之有君子，行藏以時，進退求己。", "榮必爲天下榮，恥必爲天下恥。"]'),
('09788f19-1e11-4394-a543-0edf2cfdcae9','相和歌辭 燕歌行','高適','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996"]','漢家煙塵在東北，漢將辭家破殘賊。',225,'全唐诗/poet.tang.1000.json','["漢家煙塵在東北，漢將辭家破殘賊。", "男兒本自重橫行，天子非常賜顏色。", "摐金伐鼓下榆關，旌旗逶迤碣石間。", "校尉羽書飛瀚海，單于獵火照狼山。", "山川蕭條極邊土，胡騎憑凌雜風雨。", "戰士軍前半死生，美人帳下猶歌舞。", "大漠窮秋塞草衰，孤城落日鬬兵稀。", "身當恩遇常輕敵，力盡關山未解圍。", "鐵衣遠戍辛勤久，玉箸應啼別離後。", "少婦城南欲斷腸，征人薊北空回首。", "邊風飄飄那可度，絕域蒼茫更何有。", "殺氣三日作陣雲，寒聲一夜傳刁斗。", "相看白刃血紛紛，死節從來豈顧勳。", "君不見沙場征戰苦，至今猶憶李將軍。"]'),
('56c66dee-7bd0-403b-81a4-6b5d552e776d','相和歌辭 燕歌行','賈至','唐','唐诗','tang','','[]','國之重鎮惟幽都，東威九夷制北胡。',256,'全唐诗/poet.tang.1000.json','["國之重鎮惟幽都，東威九夷制北胡。", "五軍精卒三十萬，百戰百勝擒單于。", "前臨滹沲後沮水，崇山沃野亙千里。", "昔時燕王重賢士，黃金築臺從隗始。", "倏忽興王定薊丘，漢家又以封王侯。", "蕭條魏晉爲橫流，鮮卑竊據朝五州。", "我唐區夏餘十紀，軍容武備赫萬祀。", "彤弓黃鉞授元帥，墾耕大漠爲內地。", "季秋膠折邊草腓，治兵羽獵因出師。", "千營萬隊連旌旗，望之如火忽雷馳。", "匈奴懾竄窮髮北，大荒萬里無塵飛。", "隋家昔爲天下宰，窮兵黷武征遼海。", "南風不競多死聲，鼓臥旗折黃雲橫。", "六軍將士皆死盡，戰馬空鞍歸故營。", "時遷道革天下平，白環入貢滄海清。", "自有農夫已高枕，無勞校尉重橫行。"]'),
('c680a907-39d1-4968-b638-3bdb6c97eb9b','相和歌辭 燕歌行','陶翰','唐','唐诗','tang','','[]','請君留楚調，聽我吟燕歌。',96,'全唐诗/poet.tang.1000.json','["請君留楚調，聽我吟燕歌。", "家在遼水頭，邊風意氣多。", "出身爲漢將，正值戎未和。", "雪中凌天山，冰上渡交河。", "大小百餘戰，封侯竟蹉跎。", "歸來霸陵下，故舊無相過。", "雄劒委塵匣，空門唯雀羅。", "玉篸還趙女，寶瑟付齊娥。"]'),
('38438036-586a-47f6-a4c0-d75bc30801c0','相和歌辭 從軍行二首 一','虞世南','唐','唐诗','tang','','["\u9ec4\u6cb3"]','塗山烽候驚，弭節度龍城。',108,'全唐诗/poet.tang.1000.json','["塗山烽候驚，弭節度龍城。", "冀馬樓蘭將，燕犀上谷兵。", "劒寒花不落，弓曉月逾明。", "凜凜嚴霜節，冰壯黃河絕。", "蔽日卷征蓬，浮天散飛雪。", "全兵值月滿，精騎乘膠折。", "結髮早驅馳，辛苦事旌麾。", "馬凍重關冷，輪摧九折危。", "獨有西山將，年年屬數奇。"]'),
('5bbafaa2-8360-49eb-85d1-3c2fc9259e1a','相和歌辭 從軍行二首 二','虞世南','唐','唐诗','tang','','[]','爟火發金微，連營出武威。',96,'全唐诗/poet.tang.1000.json','["爟火發金微，連營出武威。", "孤城寒雲起，絕陣虜塵飛。", "俠客吸龍劒，惡少縵胡衣。", "朝摩骨都壘，夜解谷蠡圍。", "蕭關遠無極，蒲海廣難依。", "沙磴離旌斷，晴川候馬歸。", "交河梁已畢，燕山斾欲飛。", "方知萬里相，侯服有光輝。"]'),
('5f9937c7-3bfe-44bd-b5f3-414f5679c8c6','相和歌辭 從軍行','駱賓王','唐','唐诗','tang','','[]','平生一顧念，意氣溢三軍。',48,'全唐诗/poet.tang.1000.json','["平生一顧念，意氣溢三軍。", "野日分戈影，天星合劒文。", "弓弦抱漢月，馬足踐胡塵。", "不求生入塞，唯當死報君。"]'),
('d9bb3556-f0d9-4989-afdd-0163fb826a01','相和歌辭 從軍行','劉希夷','唐','唐诗','tang','','["\u9ec4\u6cb3"]','秋來風瑟瑟，羣馬胡行疾。',108,'全唐诗/poet.tang.1000.json','["秋來風瑟瑟，羣馬胡行疾。", "嚴城晝不開，伏兵暗相失。", "天子廟堂拜，將軍玉門出。", "紛紛伊洛間，戎馬數千匹。", "軍門壓黃河，兵氣衝白日。", "平生懷伏劒，忼慨既投筆。", "南登漢月孤，北走燕雲密。", "近取韓彭計，早知孫吳術。", "丈夫清萬里，誰能埽一室。"]'),
('97aa4fd9-61d5-4a58-918b-e1f756547676','相和歌辭 從軍行','喬知之','唐','唐诗','tang','','[]','南庭結白露，北風埽黃葉。',144,'全唐诗/poet.tang.1000.json','["南庭結白露，北風埽黃葉。", "此時鴻燕來，驚鳴催思妾。", "曲房理鍼線，平碪擣文練。", "鴛綺裁易成，龍鄉信難見。", "窈窕九重閨，寂寞十年啼。", "紗窗白雲宿，羅幌月光棲。", "雲月曉微微，愁思流黃機。", "玉霜凍珠履，金吹薄羅衣。", "漢家已得地，君去將何事？", "宛轉結蠶書，寂寞無雁使。", "生平荷恩信，本爲容華進。", "況復落紅顏，蟬聲催綠鬢。"]'),
('0ed53ef4-30ca-41ac-a629-d778e5cc2bfa','相和歌辭 從軍行','李頎','唐','唐诗','tang','','["\u751f\u6d3b", "\u51ac\u5929", "\u5510\u8bd7\u4e09\u767e\u9996", "\u4e50\u5e9c", "\u8fb9\u585e", "\u76f8\u548c\u6b4c\u8f9e"]','白日登山望烽火，昏黃飲馬傍交河。',96,'全唐诗/poet.tang.1000.json','["白日登山望烽火，昏黃飲馬傍交河。", "行人刁斗風砂暗，公主琵琶幽怨多。", "野營萬里無城郭，雨雪紛紛連大漠。", "胡雁哀鳴夜夜飛，胡兒眼淚雙雙落。", "聞道玉門猶被遮，應將性命逐輕車。", "年年戰骨埋荒外，空見蒲萄入漢家。"]'),
('b830967d-95c5-499a-b17f-0a4c38f4b23f','相和歌辭 從軍行三首 一','李約','唐','唐诗','tang','','[]','看圖閑教陣，畫地靜論邊。',48,'全唐诗/poet.tang.1000.json','["看圖閑教陣，畫地靜論邊。", "烏壘天西戍，鷹姿塞上川。", "路長須算日，書遠每題年。", "無復生還望，飜思未別前。"]'),
('8cd901c3-39ed-4565-9fa5-9be388f13f6d','相和歌辭 從軍行三首 二','李約','唐','唐诗','tang','','[]','柵高三面鬬，箭盡舉烽頻。',48,'全唐诗/poet.tang.1000.json','["柵高三面鬬，箭盡舉烽頻。", "營柳和煙暮，關榆帶雪春。", "邊城多老將，磧路少歸人。", "點盡三河卒，年年添塞塵。"]'),
('7c79a705-fd5b-48b1-bc25-3d8658cd634c','相和歌辭 從軍行三首 三','李約','唐','唐诗','tang','','[]','候火起雕城，塵砂擁戰聲。',48,'全唐诗/poet.tang.1000.json','["候火起雕城，塵砂擁戰聲。", "遊軍藏漢幟，降騎說蕃情。", "霜降滮池淺，秋深太白明。", "嫖姚方虎視，不覺請添兵。"]'),
('8b41afb4-d737-43e1-9f79-1a8101eaa87e','相和歌辭 從軍行','戎昱','唐','唐诗','tang','','[]','昔從李都尉，雙鞬照馬蹄。',108,'全唐诗/poet.tang.1000.json','["昔從李都尉，雙鞬照馬蹄。", "擒生黑山北，殺敵黃雲西。", "太白沈虜地，邊草復萋萋。", "歸來邯鄲市，百尺青樓梯。", "感激然諾重，平生膽力齊。", "芳筵暮歌發，豔粉輕鬟低。", "半醉秋風起，鐵騎門前嘶。", "遠戍報烽火，孤城嚴鼓鼙。", "揮鞭望塵去，少婦莫含啼。"]'),
('dea3f4f6-88ed-4653-9d06-ba5fa73e14d9','相和歌辭 從軍行','厲玄','唐','唐诗','tang','','[]','邊草早不春，劒花增濘塵。',48,'全唐诗/poet.tang.1000.json','["邊草早不春，劒花增濘塵。", "廣場收驥尾，清瀚怯龍鱗。", "帆色已歸越，松聲厭避秦。", "幾時逢范蠡，處處是通津。"]'),
('7ecea79a-d35e-443e-b67b-9af2a3da6933','相和歌辭 從軍行二首 一','李白','唐','唐诗','tang','','["\u6218\u4e89", "\u4e50\u5e9c", "\u5efa\u529f\u7acb\u4e1a"]','從軍玉門道，逐虜金微山。',48,'全唐诗/poet.tang.1000.json','["從軍玉門道，逐虜金微山。", "笛奏梅花曲，刀開明月環。", "鼓聲鳴海上，兵氣擁雲間。", "願斬單于首，長驅靜鐵關。"]'),
('c480c5e2-1052-4bdc-9fca-44d38c5a2fda','相和歌辭 從軍行二首 二','李白','唐','唐诗','tang','','["\u6218\u4e89", "\u8fb9\u585e", "\u76f8\u548c\u6b4c\u8f9e"]','百戰沙場碎鐵衣，城南已合數重圍。',32,'全唐诗/poet.tang.1000.json','["百戰沙場碎鐵衣，城南已合數重圍。", "突營射殺呼延將，獨領殘兵千騎歸。"]'),
('9b137850-33f6-4386-a282-c7ca62f00af6','相和歌辭 從軍行','王維','唐','唐诗','tang','','["\u6218\u4e89", "\u8c6a\u8fc8", "\u8fb9\u585e"]','吹角動行人，喧喧行人起。',48,'全唐诗/poet.tang.1000.json','["吹角動行人，喧喧行人起。", "笳鳴馬嘶亂，爭渡金河水。", "日暮沙漠垂，戰聲煙塵裏。", "盡繫名王頸，歸來報天子。"]'),
('6382d668-2787-4a30-b0f2-c58a3b3b9f25','相和歌辭 從軍行','王昌齡','唐','唐诗','tang','','[]','向夕臨大荒，朔風軫歸慮。',84,'全唐诗/poet.tang.1000.json','["向夕臨大荒，朔風軫歸慮。", "平沙萬里餘，飛鳥宿何處？", "虜騎獵長原，翩翩傍河去。", "邊聲搖白草，海氣生黃霧。", "百戰苦風塵，十年履霜露。", "雖投定遠筆，未坐將軍樹。", "早知行路難，悔不理章句。"]'),
('10936c86-53b1-4d8b-ac56-861934572d14','相和歌辭 從軍行 二','王昌齡','唐','唐诗','tang','','[]','烽火城西百尺樓，黃昏獨上海風秋。',32,'全唐诗/poet.tang.1000.json','["烽火城西百尺樓，黃昏獨上海風秋。", "更吹橫笛關山月，誰解金閨萬里愁。"]'),
('f5a35d99-b904-4c04-a5a7-e57bc6b50f2c','相和歌辭 從軍行 三','王昌齡','唐','唐诗','tang','','[]','琵琶起舞換新聲，總是關山舊別情。',32,'全唐诗/poet.tang.1000.json','["琵琶起舞換新聲，總是關山舊別情。", "撩亂邊愁彈不盡，高高秋月下長城。"]'),
('0edc1f37-50aa-48ac-9fb3-1def51c4319c','相和歌辭 從軍行 四','王昌齡','唐','唐诗','tang','','["\u6218\u4e89", "\u5c71\u6c34", "\u4e00\u5e74\u7ea7\u4e0b\u518c", "\u8fb9\u585e", "\u9ad8\u4e2d\u53e4\u8bd7", "\u58ee\u5fd7"]','青海長雲暗雪山，孤城遙望雁門關。',32,'全唐诗/poet.tang.1000.json','["青海長雲暗雪山，孤城遙望雁門關。", "黃沙百戰穿金甲，不破樓蘭終不還。"]'),
('2dd705fa-a22f-4505-95f0-280927205b9a','相和歌辭 從軍行','盧綸','唐','唐诗','tang','','[]','二十在邊城，軍中得勇名。',72,'全唐诗/poet.tang.1000.json','["二十在邊城，軍中得勇名。", "卷旗收敗馬，斷磧擁殘兵。", "覆陣烏鳶起，燒山草木明。", "塞閑思遠獵，師老厭分營。", "雪嶺無人跡，冰河足雁聲。", "李陵甘此沒，惆悵漢公卿。"]'),
('9bc6f8db-332d-417d-9ec9-75b882f77478','相和歌辭 從軍行六首 一','劉長卿','唐','唐诗','tang','','[]','迴看虜騎合，城下漢兵稀。',36,'全唐诗/poet.tang.1000.json','["迴看虜騎合，城下漢兵稀。", "白刃兩相向，黃雲愁不飛。", "手中無尺鐵，徒欲突重圍。"]'),
('b6013b1e-b78f-494b-8dac-26e2edd6dcda','相和歌辭 從軍行六首 二','劉長卿','唐','唐诗','tang','','[]','落日更蕭條，北方動枯草。',36,'全唐诗/poet.tang.1000.json','["落日更蕭條，北方動枯草。", "將軍追虜騎，夜失陰山道。", "戰敗仍樹勳，韓彭但空老。"]'),
('c4dd63d6-00ff-4a02-92d5-c9b6e4f240af','相和歌辭 從軍行六首 三','劉長卿','唐','唐诗','tang','','[]','草枯秋塞上，望見漁陽郭。',36,'全唐诗/poet.tang.1000.json','["草枯秋塞上，望見漁陽郭。", "胡馬嘶一聲，漢兵淚雙落。", "誰爲吮癰者，此事令人薄。"]'),
('19bd94a6-543b-45a8-8ebb-d9c6d02aa122','相和歌辭 從軍行六首 四','劉長卿','唐','唐诗','tang','','[]','目極雁門道，青青邊草春。',36,'全唐诗/poet.tang.1000.json','["目極雁門道，青青邊草春。", "一身事征戰，匹馬同辛勤。", "末路成白首，功歸天下人。"]'),
('3148011f-5d66-4700-8f35-82ac811d9b65','相和歌辭 從軍行六首 五','劉長卿','唐','唐诗','tang','','[]','倚劒白日暮，望鄉登戍樓。',36,'全唐诗/poet.tang.1000.json','["倚劒白日暮，望鄉登戍樓。", "北風吹羌笛，此夜關山愁。", "迴首不無意，滹河空自流。"]'),
('b3acf8eb-5401-4982-b1a9-a836e4abe5fb','相和歌辭 從軍行六首 六','劉長卿','唐','唐诗','tang','','[]','黃沙一萬里，白首無人憐。',36,'全唐诗/poet.tang.1000.json','["黃沙一萬里，白首無人憐。", "報國劒已折，歸鄉身幸全。", "單于古臺下，邊色寒蒼然。"]'),
('86a92819-b1bd-4d41-b5e1-05430f2f58d1','相和歌辭 從軍行','杜頠','唐','唐诗','tang','','[]','秋草馬蹄輕，角弓持弦急。',96,'全唐诗/poet.tang.1000.json','["秋草馬蹄輕，角弓持弦急。", "去爲龍城候，正值胡兵襲。", "軍氣橫大荒，戰酣日將入。", "長風金鼓動，白霧鐵衣溼。", "四起愁邊聲，南轅時佇立。", "斷蓬孤自轉，寒雁飛相及。", "萬里雲沙漲，路平冰霰澀。", "夜聞漢使歸，獨向刀環泣。"]'),
('79407adb-5787-406f-a068-c7755cb7fc82','相和歌辭 從軍行 一','僧皎然','唐','唐诗','tang','','[]','候騎出紛紛，元戎霍冠軍。',48,'全唐诗/poet.tang.1000.json','["候騎出紛紛，元戎霍冠軍。", "漢鞞秋聒地，羌火晝燒雲。", "萬里戍城合，三邊羽檄分。", "烏孫驅未盡，肯顧遼陽勳。"]'),
('bd80bc2d-ea1e-45d0-85d1-be102ecc5715','相和歌辭 從軍行 二','僧皎然','唐','唐诗','tang','','[]','漢斾拂丹霄，漢軍新破遼。',48,'全唐诗/poet.tang.1000.json','["漢斾拂丹霄，漢軍新破遼。", "紅塵驅鹵簿，白羽擁嫖姚。", "戰苦軍猶樂，功高將不驕。", "至今丁令塞，朔吹空蕭蕭。"]'),
('242e50b4-c693-43ec-a914-4ad30f48ba63','相和歌辭 從軍行 三','僧皎然','唐','唐诗','tang','','[]','百萬逐呼韓，頻年不解鞍。',48,'全唐诗/poet.tang.1000.json','["百萬逐呼韓，頻年不解鞍。", "兵屯絕漠暗，馬飲濁河乾。", "破虜功未錄，勞師力已殫。", "須防肘腋下，飛禍出無端。"]'),
('4323278f-f341-427b-bbb0-4b13d7cdb5f9','相和歌辭 從軍行 四','僧皎然','唐','唐诗','tang','','[]','飛將下天來，奇謀閫外裁。',48,'全唐诗/poet.tang.1000.json','["飛將下天來，奇謀閫外裁。", "水心龍劒動，地肺雁山開。", "望氣燕師銳，當鋒虜陣摧。", "從今射鵰騎，不敢過雲堆。"]'),
('2d514174-194c-4606-afc1-d17e38e0c47f','相和歌辭 從軍行 五','僧皎然','唐','唐诗','tang','','[]','黃紙君王詔，青泥校尉書。',48,'全唐诗/poet.tang.1000.json','["黃紙君王詔，青泥校尉書。", "誓師張虎落，選將擐犀渠。", "霧暗津浦失，天寒塞柳疎。", "橫行十萬騎，欲埽虜塵餘。"]'),
('81d3df08-a37a-4b38-911c-8a91e95f4463','相和歌辭 從軍行','王建','唐','唐诗','tang','','[]','漢軍逐單于，日沒處河曲。',96,'全唐诗/poet.tang.1000.json','["漢軍逐單于，日沒處河曲。", "浮雲道傍起，行子車下宿。", "槍城圍鼓角，氊帳依山谷。", "馬上懸壺漿，刀頭分頓肉。", "來時高堂上，父母親結束。", "回首不見家，風吹破衣服。", "金創生肢節，相與拔箭鏃。", "聞道西涼州，家家婦人哭。"]'),
('895c3a39-3388-42e9-94f7-386fa16edcec','相和歌辭 從軍行','張祜','唐','唐诗','tang','','[]','少年金紫就光輝，直指邊城虎翼飛。',64,'全唐诗/poet.tang.1000.json','["少年金紫就光輝，直指邊城虎翼飛。", "一卷旌收千騎虜，萬全身出百重圍。", "黃雲斷塞尋鷹去，白草連天射雁歸。", "白首漢廷刀筆吏，丈夫功業本相依。"]'),
('62613bbc-4f00-412c-84eb-e2a8bd1a8a9d','相和歌辭 從軍行五首 一','令狐楚','唐','唐诗','tang','','[]','荒雞隔水啼，汗馬逐風嘶。',24,'全唐诗/poet.tang.1000.json','["荒雞隔水啼，汗馬逐風嘶。", "終日隨征斾，何時罷鼓鼙。"]'),
('7fb4ee37-2d51-4a40-ad76-f14154635378','相和歌辭 從軍行五首 二','令狐楚','唐','唐诗','tang','','[]','孤心眠夜雪，滿眼是秋沙。',24,'全唐诗/poet.tang.1000.json','["孤心眠夜雪，滿眼是秋沙。", "萬里猶防塞，三年不見家。"]'),
('473a6b6f-4060-4a94-b8df-ee99062fe291','相和歌辭 從軍行五首 三','令狐楚','唐','唐诗','tang','','[]','却望冰河闊，前登雪嶺高。',24,'全唐诗/poet.tang.1000.json','["却望冰河闊，前登雪嶺高。", "征人幾多在，又擬戰臨洮。"]'),
('2624f908-0651-480b-9132-d3b258a20c7e','相和歌辭 從軍行五首 四','令狐楚','唐','唐诗','tang','','[]','胡風千里驚，漢月五更明。',24,'全唐诗/poet.tang.1000.json','["胡風千里驚，漢月五更明。", "縱有還家夢，猶聞出塞聲。"]'),
('ea5be606-2fc0-44cf-bd0b-a4dc72afdae8','相和歌辭 從軍行五首 五','令狐楚','唐','唐诗','tang','','[]','暮雪連青海，陰雲覆白山。',24,'全唐诗/poet.tang.1000.json','["暮雪連青海，陰雲覆白山。", "可憐班定遠，出入玉門關。"]'),
('a6e31a8e-4d7f-4e78-a9d5-88aaf1499945','相和歌辭 從軍行三首 一','王涯','唐','唐诗','tang','','[]','旌甲從軍久，風雲識陣難。',24,'全唐诗/poet.tang.1000.json','["旌甲從軍久，風雲識陣難。", "今朝韓信計，日下斬成安。"]'),
('843c9ce2-7636-4312-8b92-10a943e45ae4','相和歌辭 從軍行三首 二','王涯','唐','唐诗','tang','','[]','燕頷多奇相，狼頭敢犯邊。',24,'全唐诗/poet.tang.1000.json','["燕頷多奇相，狼頭敢犯邊。", "寄言班定遠，正是立功年。"]'),
('7380cd0a-fc58-4f0a-83a6-2e88fe68a24a','相和歌辭 從軍行三首 三','王涯','唐','唐诗','tang','','[]','旄頭夜落捷書飛，來奏金門著賜衣。',32,'全唐诗/poet.tang.1000.json','["旄頭夜落捷書飛，來奏金門著賜衣。", "白馬將軍頻破敵，黃龍戍卒幾時歸。"]'),
('9cac30d1-12da-43d9-8773-ec5a4648c782','相和歌辭 從軍有苦樂行','李益','唐','唐诗','tang','','[]','勞者且勿歌，我欲送君觴。',216,'全唐诗/poet.tang.1000.json','["勞者且勿歌，我欲送君觴。", "從軍有苦樂，此曲樂未央。", "僕本居隴上，隴水斷人腸。", "東過秦宮路，宮路入咸陽。", "時逢漢帝出，諫獵至長楊。", "詎馳游俠窟，非結少年場。", "一旦承嘉惠，輕命重恩光。", "秉筆參帷帟，從軍至朔方。", "邊地多陰風，草木自淒涼。", "斷絕海雲去，出沒胡沙長。", "參差引雁翼，隱轔騰軍裝。", "劒文夜如水，馬汗凍成霜。", "俠氣五都少，矜功六郡良。", "山河起目前，睚眦死路傍。", "北逐驅獯虜，西臨復舊疆。", "昔還賦餘資，今出乃贏糧。", "一矢弢夏服，我弓不再張。", "寄言丈夫雄，苦樂身自當。"]'),
('1f1d62a1-a288-4626-9f12-c25f766a9748','相和歌辭 苦戰遠征人','鮑溶','唐','唐诗','tang','','[]','征人歌古曲，攜手上河梁。',144,'全唐诗/poet.tang.1000.json','["征人歌古曲，攜手上河梁。", "李陵死別處，杳杳玄冥鄉。", "憶昔從此路，連年征鬼方。", "久行迷漢曆，三洗氊衣裳。", "百戰身且在，微功信難忘。", "遠承雲臺議，非勢孰敢當。", "落日弔李廣，白身過河陽。", "閑弓失月影，勞劒無龍光。", "去日始束髮，今來髮成霜。", "虛名乃閑事，生見父母鄉。", "掩抑大風歌，裴回少年場。", "誠哉古人言，鳥盡良弓藏。"]'),
('60d2e463-c18a-4b48-b68c-517e2b27810c','相和歌辭 苦哉行五首 一','戎昱','唐','唐诗','tang','','[]','彼鼠侵我廚，縱貍授梁肉。',72,'全唐诗/poet.tang.1000.json','["彼鼠侵我廚，縱貍授梁肉。", "鼠雖爲君却，貍食自須足。", "冀雪大國恥，飜是大國辱。", "羶腥逼綺羅，甎瓦雜珠玉。", "登樓非騁望，目笑是心哭。", "何意天樂中，至今奏胡曲。"]'),
('e17a17a8-d1a9-4168-bfed-e09cb2e7a6c0','相和歌辭 苦哉行五首 二','戎昱','唐','唐诗','tang','','[]','官軍收洛陽，家住洛陽里。',72,'全唐诗/poet.tang.1000.json','["官軍收洛陽，家住洛陽里。", "夫壻與兄弟，目前見傷死。", "吞聲不許哭，還譴衣羅綺。", "上馬隨匈奴，數秋黃塵裏。", "生爲名家女，死作塞垣鬼。", "鄉國無還期，天津哭流水。"]'),
('b7c2cc3f-1d9b-4b80-8c9a-b6271ba0efcd','相和歌辭 苦哉行五首 三','戎昱','唐','唐诗','tang','','[]','登樓望天衢，目極淚盈睫。',72,'全唐诗/poet.tang.1000.json','["登樓望天衢，目極淚盈睫。", "彊笑無笑容，須妝舊花靨。", "昔年買奴僕，奴僕來碎葉。", "豈意未死間，自爲匈奴妾。", "一生忽至此，萬事痛苦業。", "得出塞垣飛，不如彼蜂蝶。"]'),
('e821821e-67cc-4b11-a399-7a0b5ad83b80','相和歌辭 苦哉行五首 四','戎昱','唐','唐诗','tang','','[]','妾家青河邊，七葉承貂蟬。',120,'全唐诗/poet.tang.1000.json','["妾家青河邊，七葉承貂蟬。", "身爲最小女，偏得渾家憐。", "親戚不相識，幽閨十五年。", "有時最遠出，祗到中門前。", "前年狂胡來，懼死飜生全。", "今秋官軍至，豈意遭戈鋋。", "匈奴爲先鋒，長鼻黃髮拳。", "彎弓獵生人，百步牛羊羶。", "脫身落虎口，不及歸黃泉。", "苦哉難重陳，暗哭蒼蒼天。"]'),
('ab297624-e30f-41ea-b3ca-f1ef347dd26a','相和歌辭 苦哉行五首 五','戎昱','唐','唐诗','tang','','[]','可汗奉親詔，今月歸燕山。',74,'全唐诗/poet.tang.1000.json','["可汗奉親詔，今月歸燕山。", "忽如亂刀劒，[攪]妾心腸間。", "出戶望北荒，迢迢玉門關。", "生人爲死別，有去無時還。", "漢月割妾心，胡風凋妾顏。", "去去斷絕魂，叫天天不聞。"]'),
('91b3edc5-ea9c-427c-ba79-38e56cb42142','相和歌辭 鞠歌行','李白','唐','唐诗','tang','','["\u4ed5\u9014", "\u76f8\u548c\u6b4c\u8f9e", "\u611f\u4f24", "\u4e50\u5e9c"]','玉不自言如桃李，魚目笑之卞和恥。',134,'全唐诗/poet.tang.1000.json','["玉不自言如桃李，魚目笑之卞和恥。", "楚國青蠅何太多？連城白璧遭讒毀。", "荆山長號泣血人，忠臣死爲刖足鬼。", "聽曲知甯戚，[夷]吾因小妻。", "秦穆五羊皮，買死百里奚。", "洗拂青雲上，當時賤如泥。", "朝歌鼓刀叟，虎變蟠溪中。", "一舉釣六合，逐荒營丘東。", "平生渭水曲，誰識此老翁。", "奈何今之人，雙目送征鴻。"]'),
('f2eff0a0-8283-40e5-95ed-81bf510f2f06','相和歌辭 前苦寒行二首 一','杜甫','唐','唐诗','tang','','[]','漢時長安雪一丈，牛馬毛寒縮如蝟。',64,'全唐诗/poet.tang.1000.json','["漢時長安雪一丈，牛馬毛寒縮如蝟。", "楚江巫峽冰入懷，虎豹哀號又堪記。", "秦城老翁荆揚客，慣習炎蒸歲絺綌。", "玄冥祝融氣或交，手持白羽未敢釋。"]'),
('631a60e3-994f-4e3f-a3e9-6cf6e9325840','相和歌辭 前苦寒行二首 二','杜甫','唐','唐诗','tang','','[]','去年白帝雪在山，今年白帝雪在地。',64,'全唐诗/poet.tang.1000.json','["去年白帝雪在山，今年白帝雪在地。", "凍埋蛟龍南浦縮，寒刮肌膚北風利。", "楚人四時皆麻衣，楚天萬里無晶輝。", "三足之烏足恐斷，羲和送將安所歸。"]'),
('8cffb647-6edb-4da1-be1b-806e1b3dfe42','相和歌辭 後苦寒行二首 一','杜甫','唐','唐诗','tang','','[]','南紀巫廬瘴不絕，太古以來無尺雪。',32,'全唐诗/poet.tang.1000.json','["南紀巫廬瘴不絕，太古以來無尺雪。", "蠻夷長老怨苦寒，崐崘天關凍應折。"]'),
('90891e87-5130-4437-8fb2-6223e1f04d3f','相和歌辭 後苦寒行二首 二','杜甫','唐','唐诗','tang','','[]','晚來江門失大木，猛風中夜吹白屋。',56,'全唐诗/poet.tang.1000.json','["晚來江門失大木，猛風中夜吹白屋。", "天兵斷斬青海戎，殺氣南行動坤軸，不爾苦寒何太酷？", "巴東之峽生凌凘，彼蒼迴軒人得知。"]'),
('051a325b-0ad3-42b1-89dc-8c9d09cf45d5','相和歌辭 苦寒行','劉駕','唐','唐诗','tang','','[]','嚴寒動八荒，莿莿無休時。',60,'全唐诗/poet.tang.1000.json','["嚴寒動八荒，莿莿無休時。", "陽烏不自暖，雪壓扶桑枝。", "歲暮寒益壯，青春安得歸。", "朔雁到南海，越禽何處飛？", "誰言貧士歎，不爲身無衣。"]'),
('51c2f843-6831-4226-acf5-93a92e4981a1','相和歌辭  苦寒行','僧貫休','唐','唐诗','tang','','["\u9ec4\u6cb3"]','北風北風，職何嚴毒。',78,'全唐诗/poet.tang.1000.json','["北風北風，職何嚴毒。", "摧壯士心，縮金烏足。", "凍雲囂囂礙雪，一片下不得。", "聲繞枯桑，根在沙塞。", "黃河徹底，頑直到海。", "一氣搏束，萬物無態。", "唯有吾庭前杉松樹枝，枝枝健在。"]'),
('d74898fe-e94d-452c-a8c8-3b878f110d0f','相和歌辭  苦寒行','僧齊己','唐','唐诗','tang','','["\u5fe7\u56fd\u5fe7\u6c11", "\u54f2\u7406", "\u51ac\u5929"]','冰峰撐空寒矗矗，雪凝水凍埋海陸。',78,'全唐诗/poet.tang.1000.json','["冰峰撐空寒矗矗，雪凝水凍埋海陸。", "殺物之性，傷人之慾。", "既不能斷絕蒺藜荆棘之根株，又不能展鳳皇麒麟之拳跼。", "如此則何如爲和煦，爲膏雨。", "自然天下之榮枯，融融於萬戶。"]'),
('2ac203a8-6e70-4b78-ad75-9acacae9b04a','相和歌辭  北上行','李白','唐','唐诗','tang','','["\u9ec4\u6cb3", "\u6101\u82e6", "\u6218\u4e89", "\u4eba\u6c11", "\u540c\u60c5"]','北上何所苦，北上緣太行。',168,'全唐诗/poet.tang.1000.json','["北上何所苦，北上緣太行。", "磴道盤且峻，巉巖凌穹蒼。", "馬足蹶側石，車輪摧高岡。", "沙塵接幽州，烽火連朔方。", "殺氣毒劒戟，嚴風裂衣裳。", "奔鯨夾黃河，鑿齒屯洛陽。", "前行無歸日，返顧思舊鄉。", "慘戚冰雪裏，悲號絕中腸。", "尺布不掩體，皮膚劇枯桑。", "汲水澗谷阻，采薪隴坂長。", "猛虎又掉尾，磨牙皓秋霜。", "草木不可湌，飢飲零露漿。", "歎此北上苦，停驂爲之傷。", "何日王道平？開顏覩天光。"]'),
('ee380cd0-fea2-4baa-92b7-c82c834265e6','相和歌辭  豫章行','李白','唐','唐诗','tang','','["\u76f8\u548c\u6b4c\u8f9e", "\u6218\u4e89", "\u4e50\u5e9c", "\u540c\u60c5"]','胡風吹代馬，北擁魯陽關。',132,'全唐诗/poet.tang.1000.json','["胡風吹代馬，北擁魯陽關。", "吳兵照海雪，西討何時還？", "半渡上遼津，黃雲慘無顏。", "老母與子別，呼天野草間。", "白馬繞旌旗，悲鳴相追攀。", "白楊秋月苦，早落豫章山。", "本爲休明人，斬虜素不閑。", "豈惜戰鬬死，爲君埽兇頑。", "精感石沒羽，豈忘憚險艱。", "樓船若鯨飛，波蕩落星灣。", "此曲不可奏，三軍鬢成斑。"]'),
('1d87134d-4841-48b3-bb14-cdefa15cfe99','相和歌辭  董逃行','元稹','唐','唐诗','tang','','[]','董逃董逃董卓逃，揩鏗戈甲聲勞嘈。',132,'全唐诗/poet.tang.1000.json','["董逃董逃董卓逃，揩鏗戈甲聲勞嘈。", "剜剜深臍脂燄燄，人皆數歎曰。", "爾獨不憶年年取我身上膏，膏銷骨盡煙火死。", "長安城中賊毛起，城門四走公卿士。", "走勸劉虞作天子，劉虞不敢作天子。", "曹瞞纂亂從此始，董逃董逃人莫喜。", "勝負飜環相枕倚，縫綴難成裁破易。", "何況曲針不能伸巧指，欲學裁縫須準擬。"]'),
('99e999f8-b07a-4142-be3d-c61182662afe','相和歌辭  董逃行','張籍','唐','唐诗','tang','','[]','洛陽城頭火曈曈，亂兵燒我天子宮。',76,'全唐诗/poet.tang.1000.json','["洛陽城頭火曈曈，亂兵燒我天子宮。", "宮城南面有深山，盡將老幼藏其間。", "重巖爲屋橡爲食，丁男夜行候消息。", "聞道官軍猶掠人，舊里如今歸未得。", "董逃行，漢家幾時重太平。"]'),
('ea4f954e-f947-4ea6-a7ce-24425dcf7fea','相和歌辭  相逢行','崔顥','唐','唐诗','tang','','[]','妾年初二八，家住洛橋頭。',72,'全唐诗/poet.tang.1000.json','["妾年初二八，家住洛橋頭。", "玉戶臨馳道，朱門近御溝。", "使君何假問，夫壻大長秋。", "女弟新承寵，諸兄近拜侯。", "春生百子殿，花發五城樓。", "出入千門裏，年年樂未休。"]'),
('82ed411b-a2e4-4e0b-94fb-b73c350e7f6f','相和歌辭 相逢行二首 一','李白','唐','唐诗','tang','','["\u9057\u61be", "\u76f8\u548c\u6b4c\u8f9e", "\u7406\u60f3", "\u4e50\u5e9c", "\u79ef\u6781"]','朝騎五花馬，謁帝出銀臺。',204,'全唐诗/poet.tang.1000.json','["朝騎五花馬，謁帝出銀臺。", "秀色誰家子，雲車珠箔開。", "金鞭遙指點，玉勒近遲回。", "夾轂相借問，疑從天上來。", "憐腸愁欲斷，斜日復相催。", "下車何輕盈，飄然似落梅。", "邀入青綺門，當歌共銜杯。", "銜杯映歌扇，似月雲中見。", "相見不相親，不如不相見。", "相見情已深，未語可知心。", "胡爲守空閨，孤眠愁錦衾。", "錦衾與羅幃，纏緜會有時。", "春風正澹蕩，暮雨來何遲？", "願因三青鳥，更報長相思。", "光景不待人，須臾髮成絲。", "當年失行樂，老去徒傷悲。", "持此道密意，無令曠佳期。"]'),
('b26b1959-9880-4d5c-9c8a-baef9a5ea015','相和歌辭 相逢行二首 二','李白','唐','唐诗','tang','','[]','相逢紅塵內，高揖黃金鞭。',24,'全唐诗/poet.tang.1000.json','["相逢紅塵內，高揖黃金鞭。", "萬戶垂楊裏，君家阿那邊。"]'),
('4d6973c8-af8f-4d6f-a5a1-b118bfe79d1e','相和歌辭 相逢行','韋應物','唐','唐诗','tang','','[]','二十登漢朝，英聲邁今古。',72,'全唐诗/poet.tang.1000.json','["二十登漢朝，英聲邁今古。", "適從東方來，又欲謁明主。", "猶酣新豐酒，尚帶霸陵雨。", "邂逅兩相逢，別來間寒暑。", "寧知白日晚，暫向花間語。", "忽聞長樂鐘，走馬東西去。"]'),
('c61f1af4-8a39-4edf-b40d-b60a64e37522','相和歌辭 三婦豔詩','董思恭','唐','唐诗','tang','','[]','大婦裁紈素，中婦弄明璫。',36,'全唐诗/poet.tang.1000.json','["大婦裁紈素，中婦弄明璫。", "小婦多姿態，登樓紅粉妝。", "丈人且安坐，初日漸流光。"]'),
('1489e5d3-0e01-4f6e-9c33-515bbff5fd6e','相和歌辭 中婦織流黃','虞世南','唐','唐诗','tang','','[]','寒閨織素錦，含怨斂雙蛾。',48,'全唐诗/poet.tang.1000.json','["寒閨織素錦，含怨斂雙蛾。", "綜新交縷澀，經脆斷絲多。", "衣香逐舉袖，釧動應鳴梭。", "還恐裁縫罷，無信達交河。"]'),
('c63ca3bc-5291-4de9-871f-ed28329cb645','相和歌辭 難忘曲','李賀','唐','唐诗','tang','','[]','夾道開洞門，弱楊低畫戟。',48,'全唐诗/poet.tang.1000.json','["夾道開洞門，弱楊低畫戟。", "簾影竹葉起，簫聲吹日色。", "蠭語繞妝鏡，拂蛾學春碧。", "亂繫丁香梢，滿闌花向夕。"]'),
('5f34d119-60d9-4762-87c7-7d84d0baa8ff','相和歌辭 塘上行','李賀','唐','唐诗','tang','','[]','藕花涼露溼，花缺藕根澀。',24,'全唐诗/poet.tang.1000.json','["藕花涼露溼，花缺藕根澀。", "飛下雌鴛鴦，塘水聲溢溢。"]'),
('5043109d-30c1-4c03-a6b5-c04c46051954','相和歌辭 苦辛行','戎昱','唐','唐诗','tang','','[]','且莫奏短歌，聽余苦辛詞。',200,'全唐诗/poet.tang.1000.json','["且莫奏短歌，聽余苦辛詞。", "如今刀筆士，不及屠酤兒。", "少年無事學詩賦，豈意文章復相誤。", "東西南北少知音，終年竟歲悲行路。", "仰面訴天天不聞，低頭告地地不言。", "天地生我尚如此，陌上他人何足論。", "誰謂西江深，涉之固無憂。", "誰謂南山高，可以登之遊。", "險巇惟有世間路，一嚮令人堪白頭。", "貴人立意不可測，等閑桃李成荆棘。", "風塵之士深可親，心如雞犬能依人。", "悲來卻憶漢天子，不棄相如家舊貧。", "飲酒酒能散羇愁，誰家有酒判一醉，萬事從他江水流。"]'),
('809cc96a-74a8-4569-a88d-c218523e0d3c','相和歌辭 秋胡行','高適','唐','唐诗','tang','','[]','妾本邯鄲未嫁時，容華倚翠人未知。',256,'全唐诗/poet.tang.1000.json','["妾本邯鄲未嫁時，容華倚翠人未知。", "一朝結髮從君子，將妾迢迢東路陲。", "時逢大道無難阻，君方遊宦從陳汝。", "蕙樓獨臥頻度春，彩落辭君幾徂暑。", "三月垂楊蠶未眠，攜籠結侶南陌邊。", "道逢行子不相識，贈妾黃金買少年。", "妾家夫壻輕離久，寸心誓與長相守。", "願言行路莫多情，送妾貞心在人口。", "日暮蠶飢相命歸，攜籠端飾來庭闈。", "勞心苦力終無恨，所冀君恩那可依。", "聞說行人已歸止，乃是向來贈金子。", "相看顏色不復言，相顧懷慙有何已。", "從來自隱無疑背，直爲君情也相會。", "如何咫尺仍有情，況復迢迢千里外。", "此時顧恩不顧身，念君此日赴河津。", "莫道向來不得意，故欲留規誡後人。"]'),
('adce5e88-590f-4588-b15b-177368149d8b','相和歌辭 善哉行','僧貫休','唐','唐诗','tang','','["\u6000\u4eba", "\u5973\u5b50", "\u5199\u9e1f", "\u9e1f"]','有美一人兮婉如清揚，識曲別音兮令姿煌煌。',62,'全唐诗/poet.tang.1000.json','["有美一人兮婉如清揚，識曲別音兮令姿煌煌。", "繡袂捧琴兮登君子堂，如彼萱草兮使我憂忘。", "欲贈之以紫玉尺，白銀璫，久不見之兮湘水茫茫。"]'),
('8ac1fb39-17d3-4dae-b046-94dfd282aa77','相和歌辭 善哉行','僧齊己','唐','唐诗','tang','','[]','大鵬刷翮謝溟渤，青雲萬層高突出。',64,'全唐诗/poet.tang.1000.json','["大鵬刷翮謝溟渤，青雲萬層高突出。", "下視秋濤空渺瀰，舊處魚龍皆細物。", "人生在世何容易，眼濁心昏信生死。", "願除嗜慾待身輕，攜手同尋列仙事。"]'),
('397d3ca6-87eb-49f5-ac12-65687c07ce8c','相和歌辭 來日大難','李白','唐','唐诗','tang','','[]','來日一身，攜糧負薪。',122,'全唐诗/poet.tang.1000.json','["來日一身，攜糧負薪。", "道長食盡，苦口焦脣。", "今日醉飽，樂過千春。", "仙人相存，誘我遠學。", "海陵三山，陸憩五嶽。", "乘龍上三天，飛目瞻兩角。", "授以神藥，金丹滿握。", "蟪蛄蒙恩，深媿短促。", "思填東海，彊銜一木。", "道重天地，軒師廣成。", "蟬翼九五，以求長生。", "下士大笑，如蒼蠅聲。"]'),
('652f32ba-492d-4b39-9216-aca92a6e9370','相和歌辭 當來日大難','元稹','唐','唐诗','tang','','[]','當來日大難行，前有坂，後有坑，大梁側，小梁傾，兩軸相絞，兩輪相撐，大牛豎，小牛橫，烏啄牛背，足跌力獰。',98,'全唐诗/poet.tang.1000.json','["當來日大難行，前有坂，後有坑，大梁側，小梁傾，兩軸相絞，兩輪相撐，大牛豎，小牛橫，烏啄牛背，足跌力獰。", "當來日大難行，太行雖險，險可使平。", "輪軸自撓，牽制不停。", "泥潦漸久，荆棘旋生。", "行必不得，不如不行。"]'),
('9c00d63a-b248-45a7-ad8b-d40f0c52b857','相和歌辭 隴西行','王維','唐','唐诗','tang','','["\u6218\u4e89", "\u8fb9\u585e"]','十里一走馬，五里一揚鞭。',36,'全唐诗/poet.tang.1000.json','["十里一走馬，五里一揚鞭。", "都護軍書至，匈奴圍酒泉。", "關山正飛雪，烽戍斷無煙。"]'),
('cfb724d3-b6ef-4c81-a5c7-ef90595445ad','相和歌辭 隴西行','耿[湋]','唐','唐诗','tang','','[]','雪下陽關路，人稀隴戍頭。',48,'全唐诗/poet.tang.1000.json','["雪下陽關路，人稀隴戍頭。", "封狐猶未翦，邊將豈無羞。", "白草三冬色，黃雲萬里愁。", "因思李都尉，畢竟不封侯。"]'),
('dad3755e-883c-4022-83a4-4a47583c8112','相和歌辭 隴西行','長孫佐輔','唐','唐诗','tang','','[]','陰雲凝朔氣，隴上正飛雪。',96,'全唐诗/poet.tang.1000.json','["陰雲凝朔氣，隴上正飛雪。", "四月草不生，北風勁如切。", "朝來羽書急，夜救長城窟。", "道隘行不前，相呼抱鞍歇。", "人寒指欲墮，馬凍蹄亦裂。", "射雁旋充飢，斧冰還止渴。", "寧辭解圍鬬，但恐乘疲沒。", "早晚邊候空，歸來養羸卒。"]'),
('c30e1abf-008b-4c36-8359-3793eb92ba45','相和歌辭 東門行','柳宗元','唐','唐诗','tang','','[]','漢家三十六將軍，東方雷動橫陣雲。',144,'全唐诗/poet.tang.1000.json','["漢家三十六將軍，東方雷動橫陣雲。", "雞鳴函谷客如霧，貌同心異不可數。", "赤丸夜語飛電光，徼巡司隸眠如羊。", "當街一叱百吏走，馮敬胷中函匕首。", "兇徒側耳潛愜心，悍臣破膽皆杜口。", "魏王臥內藏兵符，子西掩袂真無辜。", "羌胡轂下一朝起，敵國舟中非所擬。", "安陵誰辨削礪功，韓國詎明深井里。", "絕咽斷骨那下補，萬金寵贈不如土。"]'),
('42f91423-ebde-4604-84a1-fef1bff26ba7','相和歌辭 飲馬長城窟行','太宗皇帝','唐','唐诗','tang','','["\u6218\u4e89", "\u751f\u6d3b", "\u51ac\u5929", "\u7231\u56fd", "\u8fb9\u585e"]','塞外悲風切，交河冰已結。',120,'全唐诗/poet.tang.1000.json','["塞外悲風切，交河冰已結。", "瀚海百重波，陰山千里雪。", "迥戍危烽火，層巒引高節。", "悠悠卷斾旌，飲馬出長城。", "寒沙連騎迹，朔吹斷邊聲。", "胡塵清玉塞，羌笛韻金鉦。", "絕寞干戈戢，車徒振原隰。", "都尉反龍堆，將軍旋馬邑。", "揚麾氛霧靜，紀石功名立。", "荒裔一戎衣，雲臺凱歌入。"]'),
('8944162e-0986-4d0b-b9f9-ce0b899c0298','相和歌辭 飲馬長城窟行','虞世南','唐','唐诗','tang','','[]','馳馬渡河干，流深馬渡難。',96,'全唐诗/poet.tang.1000.json','["馳馬渡河干，流深馬渡難。", "前逢錦車使，都護在樓蘭。", "輕騎猶銜勒，疑兵尚解鞍。", "溫池下絕澗，棧道接危巒。", "拓地勳未賞，亡城律詎寬。", "有月關猶暗，經春隴尚寒。", "雲昏無復影，冰合不聞湍。", "懷君不可遇，聊持報一餐。"]'),
('4b20b87c-18e6-4769-b07e-72665771fd11','相和歌辭 飲馬長城窟行','袁朗','唐','唐诗','tang','','[]','朔風動秋草，清蹕長安道。',180,'全唐诗/poet.tang.1000.json','["朔風動秋草，清蹕長安道。", "長城連不窮，所以隔華戎。", "規模惟聖作，荷負曉成功。", "鳥庭已向內，龍荒更鑿空。", "玉關塵卷靜，金微路已通。", "湯征隨北怨，舜詠起南風。", "畫野功初立，綏邊事云集。", "朝服踐狼居，凱歌旋馬邑。", "山響傳鳳吹，霜華藻瓊鈒。", "屬國擁節歸，單于款關入。", "日落寒雲起，驚沙被原隰。", "零落葉已寒，河流清且急。", "四時徭役盡，千載干戈戢。", "太平今若斯，汗馬竟無施。", "惟當事筆研，歸去草封禪。"]'),
('b84b8b0b-9447-467f-819f-0ddf0f00a03a','相和歌辭 飲馬長城窟行','王翰','唐','唐诗','tang','','[]','長安少年無遠圖，一生惟羨執金吾。',224,'全唐诗/poet.tang.1000.json','["長安少年無遠圖，一生惟羨執金吾。", "騏驎前殿拜天子，走馬爲君西擊胡。", "胡沙獵獵吹人面，漢虜相逢不相見。", "遙聞鼙鼓動地來，傳道單于夜猶戰。", "此時顧恩寧顧身，爲君一行摧萬人。", "壯士揮戈回白日，單于濺血染朱輪。", "回來飲馬長城窟，長安道傍多白骨。", "問之耆老何代人，云是秦王築城卒。", "黃昏塞北無人煙，鬼哭啾啾聲沸天。", "無罪見誅功不賞，孤魂流落此城邊。", "當昔秦王按劒起，諸侯膝行不敢視。", "富國彊兵二十年，築怨興徭九千里。", "秦王築城何太愚，天實亡秦非北胡。", "一朝禍起蕭牆內，渭水咸陽不復都。"]'),
('06bd32a2-f9f5-4bfe-a55e-fadd67afc789','相和歌辭 飲馬長城窟行','王建','唐','唐诗','tang','','[]','長城窟，長城窟邊多馬骨。',92,'全唐诗/poet.tang.1000.json','["長城窟，長城窟邊多馬骨。", "古來此地無井泉，賴得秦家築城卒。", "征人飲馬愁不回，長城變作望鄉堆。", "蹄跡未乾人去近，續後馬來泥汙盡。", "枕弓睡著待水生，不見陰山在前陣。", "馬蹄足脫裝馬頭，健兒戰死誰封侯。"]'),
('13f88c40-f660-4910-8d8c-7c29cfcd416e','相和歌辭 飲馬長城窟行','僧子蘭','唐','唐诗','tang','','[]','游客長城下，飲馬長城窟。',72,'全唐诗/poet.tang.1000.json','["游客長城下，飲馬長城窟。", "馬嘶聞水腥，爲浸征人骨。", "豈不是流泉，終不成潺湲。", "洗盡骨上土，不洗骨中冤。", "骨若比流水，四海有還魂。", "空流嗚咽聲，聲中疑是言。"]'),
('c8b006af-ed1c-4206-8647-24e8623ca5b2','相和歌辭 上留田','李白','唐','唐诗','tang','','["\u76f8\u548c\u6b4c\u8f9e", "\u4e50\u5e9c", "\u8bbd\u523a"]','行至上留田，孤墳何崢嶸。',195,'全唐诗/poet.tang.1000.json','["行至上留田，孤墳何崢嶸。", "積此萬古恨，春草不復生。", "悲風四邊來，腸斷白楊聲。", "借問誰家地，埋沒蒿里塋。", "古老向余言，言是上留田。", "蓬科馬鬣今已平，昔之弟死兄不葬。", "他人於此舉銘旌，一鳥死，百鳥鳴，一獸死，百獸驚。", "桓山之禽別離苦，欲去迴翔不能征。", "田氏倉卒骨肉分，青天白日摧紫荆。", "交柯之木本同形，東枝顦顇西枝榮。", "無心之物尚如此，參商胡乃尋天兵。", "孤竹延陵，讓國揚名。", "高風緬邈，頹波激清。", "尺布之謠，塞耳不能聽。"]'),
('11b61b50-be30-4816-ac5a-5345e9a5fba6','相和歌辭 上留田','僧貫休','唐','唐诗','tang','','[]','父不父，兄不兄，上留田，蝥賊生。',68,'全唐诗/poet.tang.1000.json','["父不父，兄不兄，上留田，蝥賊生。", "徒陟岡，淚崢嶸，我欲使諸凡鳥雀，盡變爲鶺鴒。", "我欲使諸凡草木，盡變爲田荆。", "鄰人歌，鄰人歌，古風清，清風生。"]'),
('8f4ff5d9-6454-4e9a-94e9-9baca2276713','相和歌辭 安樂宮','李賀','唐','唐诗','tang','','[]','深井桐烏起，尚復牽清水。',60,'全唐诗/poet.tang.1000.json','["深井桐烏起，尚復牽清水。", "未盥邵陵王，瓶中弄長翠。", "新城安樂宮，宮如鳳皇翅。", "歌迴蠟版鳴，大綰提壺使。", "綠繁悲水曲，茱萸別秋子。"]'),
('308d0334-e166-4f5c-b33d-230b799e99bf','相和歌辭 放歌行','王昌齡','唐','唐诗','tang','','[]','南渡洛陽津，西望十二樓。',144,'全唐诗/poet.tang.1000.json','["南渡洛陽津，西望十二樓。", "明堂坐天子，月朔朝諸侯。", "清樂動千門，皇風被九州。", "慶雲從東來，泱漭抱日流。", "升平貴論道，文墨將何求。", "有詔徵草澤，微臣獻謀猷。", "冠冕如星羅，拜揖曹與周。", "望塵非吾事，入賦且遲留。", "幸蒙國士識，因脫負薪裘。", "今者放歌行，以慰梁父愁。", "但營數斗祿，奉養毋豐羞。", "若得金膏遂，飛雲亦可儔。"]'),
('af9e3b23-756d-4567-8ca2-fb91d9cd6e91','相和歌辭 野田黃雀行','李白','唐','唐诗','tang','','["\u4e50\u5e9c", "\u89c4\u529d", "\u5199\u9e1f", "\u76f8\u548c\u6b4c\u8f9e", "\u9e1f"]','遊莫逐炎洲翠，棲莫近吳宮燕。',30,'全唐诗/poet.tang.1000.json','["遊莫逐炎洲翠，棲莫近吳宮燕。", "吳宮火起焚爾窠，炎洲逐翠遭網羅。"]'),
('73d28ad8-e8fe-402a-8597-df3c3c6c539d','相和歌辭 野田黃雀行','儲光羲','唐','唐诗','tang','','[]','嘖嘖野田雀，不知軀體微。',84,'全唐诗/poet.tang.1000.json','["嘖嘖野田雀，不知軀體微。", "閑穿深蒿裏，爭食復爭飛。", "窮老一頹舍，棗多桑樹稀。", "無棗猶可食，無桑何以衣。", "蕭條空倉暮，相引時來歸。", "邪路豈不捷，渚田豈不肥。", "水長路且壞，惻惻與心違。"]'),
('d4721e5f-67be-44b3-8895-f604912c470b','相和歌辭 野田黃雀行','僧貫休','唐','唐诗','tang','','[]','高樹風多，吹爾巢落。',71,'全唐诗/poet.tang.1000.json','["高樹風多，吹爾巢落。", "深蒿葉暖，宜爾依薄。", "莫近鴞類，珠網亦惡。", "飲野田之清水，食野田之黃粟。", "深花中睡，𡋯土裏浴。", "如此即全勝啄太倉之穀，而更穿人屋。"]'),
('508776ed-7243-4d07-b409-8e02a9eea87b','相和歌辭 野田黃雀行','僧齊己','唐','唐诗','tang','','[]','雙雙野田雀，上下同飲啄。',48,'全唐诗/poet.tang.1000.json','["雙雙野田雀，上下同飲啄。", "暖去棲蓬蒿，寒歸傍籬落。", "殷勤避羅網，乍可遇鵰鶚。", "鵰鶚雖不仁，分明在寥廓。"]'),
('d8ff176a-ba69-4277-a54e-9e515bc19304','相和歌辭 雁門太守行','李賀','唐','唐诗','tang','','["\u6218\u4e89", "\u521d\u4e2d\u53e4\u8bd7", "\u4e50\u5e9c", "\u4e5d\u5e74\u7ea7\u4e0b\u518c(\u8bfe\u5916)", "\u8fb9\u585e", "\u62df\u53e4"]','黑雲壓城城欲摧，甲光向月金鱗開。',64,'全唐诗/poet.tang.1000.json','["黑雲壓城城欲摧，甲光向月金鱗開。", "角聲滿天秋色裏，塞上燕支凝夜紫。", "半卷紅旗臨易水，霜重鼓寒聲不起。", "報君黃金臺上意，提攜玉龍爲君死。"]'),
('5901d95d-baf0-46dd-9a29-fd3c020c0a70','相和歌辭 雁門太守行','張祜','唐','唐诗','tang','','[]','城頭月沒霜如水，趚趚蹋沙人似鬼。',72,'全唐诗/poet.tang.1000.json','["城頭月沒霜如水，趚趚蹋沙人似鬼。", "燈前拭淚試香裘，長引一聲殘漏子。", "駝囊瀉酒酒一杯，前頭啑血心不回。", "寄語年少妻莫哀，魚金虎竹天上來，雁門山邊骨成灰。"]'),
('8c067a87-d475-491d-8786-b811118cfce2','相和歌辭 雁門太守行','莊南傑','唐','唐诗','tang','','[]','旌旗閃閃搖天末，長笛橫吹虜塵闊。',64,'全唐诗/poet.tang.1000.json','["旌旗閃閃搖天末，長笛橫吹虜塵闊。", "跨下嘶風白練獰，腰間切玉青蛇活。", "擊革摐金燧牛尾，犬羊兵敗如山死。", "九泉寂寞葬秋蟲，溼雲荒草啼秋思。"]'),
('b39a2f1c-b07b-43c6-8f88-fa8ef3b06e4b','相和歌辭 飛來雙白鶴','虞世南','唐','唐诗','tang','','[]','飛來雙白鶴，奮翼遠凌煙。',120,'全唐诗/poet.tang.1000.json','["飛來雙白鶴，奮翼遠凌煙。", "雙棲集紫蓋，一舉背青田。", "颺影過伊洛，流聲入管弦。", "鳴羣倒景外，刷羽閬風前。", "映海疑浮雪，拂澗瀉飛泉。", "燕雀寧知去，蜉蝣不識還。", "何言別儔侶，從此間山川。", "顧步已相失，裴回反自憐。", "危心猶警露，哀響詎聞天。", "無因振六翮，輕舉復隨仙。"]'),
('eeafa160-a9d9-484d-9cbe-01a796260aa2','相和歌辭 門有車馬客行','虞世南','唐','唐诗','tang','','[]','財雄重交結，戚里擅豪華。',148,'全唐诗/poet.tang.1000.json','["財雄重交結，戚里擅豪華。", "曲臺臨上路，高門抵狹斜。", "赭汗千金馬，繡轂五香車。", "白鶴隨飛蓋，朱鷺入鳴笳。", "夏蓮開劒水，春桃發露花。", "輕裙染回雪，浮蟻泛流霞。", "高談辨飛兔，摛藻握靈蛇。", "逢恩借羽翼，失路委泥沙。", "曖曖風煙晚，路長歸騎遠。", "日斜青瑣第，塵飛金谷苑。", "危弦促柱奏巴渝，遺簪墮珥解羅襦。", "如何守直道，飜使谷名愚。"]'),
('78f8699c-a199-4dde-8be3-79fb887a596d','相和歌辭 門有車馬客行','李白','唐','唐诗','tang','','["\u65e0\u5948", "\u4e50\u5e9c", "\u5f52\u4e61", "\u6124\u6168", "\u76f8\u548c\u6b4c\u8f9e"]','門有車馬客，金鞍曜朱輪。',156,'全唐诗/poet.tang.1000.json','["門有車馬客，金鞍曜朱輪。", "謂從丹霄落，乃是故鄉親。", "呼兒埽中堂，坐客論悲辛。", "對酒兩不飲，停觴淚盈巾。", "歎我萬里遊，飄颻三十春。", "空談霸王略，紫綬不挂身。", "雄劒藏玉匣，陰符生素塵。", "廓落無所合，流離湘水濱。", "借問宗黨間，多爲泉下人。", "生苦百戰役，死託萬鬼鄰。", "北風揚胡沙，埋翳周與秦。", "大運且如此，蒼穹寧匪仁。", "惻愴竟何道？存亡任大鈞。"]'),
('f7503243-ce66-4f2b-a874-19edc104aa67','相和歌辭 蜀道難','張文琮','唐','唐诗','tang','','[]','梁山鎮地險，積石阻雲端。',48,'全唐诗/poet.tang.1000.json','["梁山鎮地險，積石阻雲端。", "深谷下寥廓，層巖上鬱盤。", "飛梁架絕嶺，棧道接危巒。", "攬轡獨長息，方知斯路難。"]'),
('e117d224-39ca-4eba-a047-0d36ce8b8c26','相和歌辭 蜀道難','李白','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u5c71\u6c34", "\u6292\u60c5", "\u4e50\u5e9c", "\u76f8\u548c\u6b4c\u8f9e"]','噫吁嚱！危乎高哉！蜀道之難難於上青天！蠶叢及魚鳧，開國何茫然。',339,'全唐诗/poet.tang.1000.json','["噫吁嚱！危乎高哉！蜀道之難難於上青天！蠶叢及魚鳧，開國何茫然。", "爾來四萬八千歲，乃與秦塞通人煙。", "西當太白有鳥道，可以橫絕峨眉巔。", "地崩山摧壯士死，然後天梯石棧方鉤連。", "上有六龍迴日之高標，下有衝波逆折之迴川。", "黃鶴之飛尚不得，猨猱欲度愁攀緣。", "青泥何盤盤，百步九折縈巖巒。", "捫參歷井仰脅息，以手撫膺坐長歎。", "問君西遊何時還？畏途巉巖不可攀。", "但見悲鳥號枯木，雄飛呼雌繞林間。", "又聞子規啼夜月，愁空山，蜀道之難難於上青天！使人聽此彫朱顏。", "連峰去天不盈尺，枯松倒挂倚絕壁。", "飛湍瀑流相喧豗，砅崖轉石萬壑雷。", "其嶮也若此，嗟爾遠道之人胡爲乎來哉？", "劒閣崢嶸而崔嵬，一夫當關，萬夫莫開。", "所守或匪親，化爲狼與豺。", "朝避猛虎，夕避長蛇。", "磨牙吮血，殺人如麻。", "錦城雖云樂，不如早還家。", "蜀道之難難於上青天，側身西望長咨嗟。"]'),
('73727332-47c2-459f-b186-fef59872a906','相和歌辭 櫂歌行','駱賓王','唐','唐诗','tang','','[]','寫月圖黃罷，凌波拾翠通。',72,'全唐诗/poet.tang.1000.json','["寫月圖黃罷，凌波拾翠通。", "鏡花搖芰日，衣麝入荷風。", "葉密舟難蕩，蓮疎浦易空。", "鳳媒羞自託，鴛翼恨難窮。", "秋帳燈花翠，倡樓粉色紅。", "相思無別曲，幷在櫂歌中。"]'),
('96b213f7-21b6-47a8-936c-39dde6ca7969','相和歌辭 櫂歌行','徐堅','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','櫂女飾銀鉤，新妝下翠樓。',108,'全唐诗/poet.tang.1000.json','["櫂女飾銀鉤，新妝下翠樓。", "霜絲青桂檝，蘭栧紫霞舟。", "水落金陵曙，風起洞庭秋。", "扣船過曲浦，飛帆越回流。", "影入桃花浪，香飄杜若洲。", "洲長殊未返，蕭散雲霞晚。", "日下大江平，煙生歸岸遠。", "岸遠聞潮波，爭途遊戲多。", "因聲趙津女，來聽采菱歌。"]'),
('108740be-423c-4371-a03e-b47c329323db','相和歌辭 胡無人行','徐彥伯','唐','唐诗','tang','','[]','十月繁霜下，征人遠鑿空。',48,'全唐诗/poet.tang.1000.json','["十月繁霜下，征人遠鑿空。", "雲搖錦更節，海照角端弓。", "暗磧埋砂樹，衝飆卷塞蓬。", "方隨膜拜入，歌舞玉門中。"]'),
('2bf0ee92-7f9a-4a6a-842c-82c7903e8b77','相和歌辭 胡無人行','聶夷中','唐','唐诗','tang','','[]','男兒徇大義，立節不沽名。',96,'全唐诗/poet.tang.1000.json','["男兒徇大義，立節不沽名。", "腰間懸陸離，大歌胡無行。", "不讀戰國書，不覽黃石經。", "醉臥咸陽樓，夢入受降城。", "更願生羽翼，飛身入青冥。", "請攜天子劒，斫下旄頭星。", "自然胡無人，雖有無戰爭。", "悠哉典屬國，驅羊老一生。"]'),
('44a1f752-1141-4011-8fee-be45b5100d07','相和歌辭 胡無人行','李白','唐','唐诗','tang','','["\u6218\u4e89", "\u8c6a\u8fc8"]','嚴風吹霜海草彫，筋幹精堅胡馬驕。',151,'全唐诗/poet.tang.1000.json','["嚴風吹霜海草彫，筋幹精堅胡馬驕。", "漢家戰士三十萬，將軍兼領霍嫖姚。", "流星白羽腰間插，劒花秋蓮光出匣。", "天兵照雪下玉關，虜箭如沙射金甲。", "雲龍風虎盡交迴，太白入月敵可摧。", "敵可摧，旄頭滅，履胡之腸涉胡血。", "懸胡青天上，埋胡紫[塞]旁。", "胡無人，漢道昌，陛下之壽三千霜。", "但歌大風雲飛揚，安得猛士兮守四方。", "胡無人，漢道昌。"]'),
('45cf3f1a-85b6-4fbe-ad2d-9ccb544dc070','相和歌辭 胡無人行','僧貫休','唐','唐诗','tang','','[]','霍嫖姚，趙充國，天子將之平朔漠。',88,'全唐诗/poet.tang.1000.json','["霍嫖姚，趙充國，天子將之平朔漠。", "肉胡之肉，燼胡帳幄。", "千里萬里，惟留胡之空殼。", "邊風蕭蕭，榆葉初落。", "殺氣晝赤，枯骨夜哭。", "將軍既立殊勳，遂有胡無人曲。", "我聞之，天子富有四海，德被無垠。"]'),
('85a83aa1-746f-4baa-bc0f-deaf8de5fdcd','相和歌辭 白頭吟','劉希夷','唐','唐诗','tang','','["\u9752\u6625", "\u82b1", "\u5199\u82b1", "\u76f8\u548c\u6b4c\u8f9e", "\u611f\u4f24"]','洛陽城東桃李花，飛來飛去落誰家。',208,'全唐诗/poet.tang.1000.json','["洛陽城東桃李花，飛來飛去落誰家。", "洛陽女兒惜顏色，行逢落花長歎息。", "今年花落顏色改，明年花開復誰在。", "已見松柏摧爲薪，更聞桑田變成海。", "古人無復洛城東，今人還對落花風。", "年年歲歲花相似，歲歲年年人不同。", "寄言全盛紅顏子，須憐半死白頭翁。", "此翁白頭真可憐，伊昔紅顏美少年。", "公子王孫芳樹下，清歌妙舞落花前。", "光祿池臺文錦繡，將軍樓閣畫神仙。", "一朝臥病無人識，三春行樂在誰邊。", "宛轉蛾眉能幾時，須臾白髮亂如絲。", "但看舊來歌舞地，惟有黃昏鳥雀悲。"]'),
('1592dabe-c91f-48c0-b409-768223174833','相和歌辭 白頭吟二首 一','李白','唐','唐诗','tang','','["\u6292\u60c5", "\u5973\u5b50", "\u4e50\u5e9c", "\u76f8\u548c\u6b4c\u8f9e", "\u5931\u610f"]','錦水東北流，波蕩雙鴛鴦。',212,'全唐诗/poet.tang.1000.json','["錦水東北流，波蕩雙鴛鴦。", "雄巢漢宮樹，雌弄秦草芳。", "寧同萬死碎綺翼，不忍雲間兩分張。", "此時阿嬌正嬌妬，獨坐長門愁日暮。", "但願君恩顧妾深，豈惜黃金將買賦。", "相如作賦得黃金，丈夫好新多異心。", "一朝將聘茂陵女，文君因贈白頭吟。", "東流不作西歸水，落花辭條歸故林。", "兔絲固無情，隨風任顛倒。", "誰使女蘿枝，而來彊縈抱。", "兩草猶一心，人心不如草。", "莫卷龍須席，從他生網絲。", "且留琥珀枕，或有夢來時。", "覆水再收豈滿杯，棄妾已去難重回。", "古時得意不相負，祗今惟見青陵臺。"]'),
('1f85b405-4320-4281-aba7-61db92674d02','相和歌辭 白頭吟二首 二','李白','唐','唐诗','tang','','[]','錦水東流碧，波蕩雙鴛鴦。',292,'全唐诗/poet.tang.1000.json','["錦水東流碧，波蕩雙鴛鴦。", "雄巢漢宮樹，雌弄秦草芳。", "相如去蜀謁武帝，赤車駟馬生輝光。", "一朝再覽大人作，萬乘忽欲凌雲翔。", "聞道阿嬌失恩寵，千金買賦要君王。", "相如不憶貧賤日，官高金多聘私室。", "茂陵姝子皆見求，文君歡愛徒此畢。", "淚如雙泉水，行墮紫羅襟。", "五起雞三唱，清晨白頭吟。", "長吁不整綠雲鬢，仰訴青天哀怨深。", "城崩杞梁妻，誰道土無心。", "東流不作西歸水，落花辭枝羞故林。", "頭上玉燕釵，是妾嫁時物。", "贈君表相思，羅袖幸時拂。", "莫卷龍須席，從他生網絲。", "且留琥珀枕，還有夢來時。", "鷫鸘裘在錦屏上，自君一挂無由披。", "妾有秦樓鏡，照心勝照井。", "願持照新人，雙對可憐影。", "覆水却收不滿杯，相如還謝文君回。", "古來得意不相負，祗今惟有青陵臺。"]'),
('3be2078f-0534-4264-89fb-244a8da74e34','相和歌辭 白頭吟','張籍','唐','唐诗','tang','','[]','請君膝上琴，彈我白頭吟。',124,'全唐诗/poet.tang.1000.json','["請君膝上琴，彈我白頭吟。", "憶昔君前嬌笑語，兩情宛轉如縈素。", "宮中爲我起高樓，更開華池種芳樹。", "春天百草秋始衰，棄我不待白頭時。", "羅襦玉珥色未暗，今朝已道不相宜。", "揚州青銅作明鏡，暗中持照不見影。", "人心回互自無窮，眼前好惡那能定。", "君恩已去若再返，菖蒲花生月長滿。"]'),
('78a9e1c4-c843-4e03-88cc-b440584c700a','相和歌辭 反白頭吟','白居易','唐','唐诗','tang','','[]','炎炎者烈火，營營者小蠅。',120,'全唐诗/poet.tang.1000.json','["炎炎者烈火，營營者小蠅。", "火不熱真玉，蠅不點清冰。", "此苟無所受，彼莫能相仍。", "乃知物性中，各有能不能。", "古稱怨報死，則人有所懲。", "懲淫或應可，在道未爲弘。", "譬如蜩鷃徒，啾啾啅龍鵬。", "宜當委之去，寥廓高飛騰。", "豈能泥塵下，區區酬怨憎。", "胡爲作自苦，吞悲仍撫膺。"]'),
('3e627ebd-0fd3-4669-a32c-5d108d5d4ce6','相和歌辭 決絕[詞]三首 一','元稹','唐','唐诗','tang','','[]','乍可爲天上牽牛織女星，不願爲庭前紅槿枝。',124,'全唐诗/poet.tang.1000.json','["乍可爲天上牽牛織女星，不願爲庭前紅槿枝。", "七月七日一相見，故心終不移。", "那能朝開暮飛去，一任東西南北吹。", "分不兩相守，恨不兩相思。", "對面且如此，背面當何知。", "春風撩亂伯勞語，此時拋去時。", "握手苦相問，竟不言後期。", "君情既決絕，妾意已參差。", "借如死生別，安得長苦悲。"]'),
('1fcf1381-8137-43b2-8863-bc92e00f50c8','相和歌辭 決絕[詞]三首 二','元稹','唐','唐诗','tang','','[]','噫春冰之將泮，何余懷之獨結。',156,'全唐诗/poet.tang.1000.json','["噫春冰之將泮，何余懷之獨結。", "有美一人，於焉曠絕。", "一日不見，比一日於三年，況三年之曠別。", "水得風兮小而已波，筍在苞兮高不見節。", "矧桃李之當春，競衆人之攀折。", "我自顧悠悠而若雲，又安能保君皓皓之如雪。", "感破鏡之分明，覩淚痕之餘血。", "幸他人之既不我先，又安能使他人之終不我奪。", "已焉哉！織女別黃姑，一年一度暫相見，彼此隔河何事無。"]'),
('1dbf0b9d-bdb3-4ee1-9bbf-005087cefe54','相和歌辭 決絕[詞]三首 三','元稹','唐','唐诗','tang','','[]','夜夜相抱眠，幽懷尚沈結。',100,'全唐诗/poet.tang.1000.json','["夜夜相抱眠，幽懷尚沈結。", "那堪一年事，長遣一宵說。", "但感久相思，何暇暫相悅。", "虹橋薄夜成，龍駕侵晨列。", "生憎野鵲往遲回，死恨天雞識時節。", "曙色漸曈曨，華星次明滅。", "一去又一年，一年何時徹。", "有此迢遰期，不如生死別。"]'),
('990af3fd-2638-434e-aaaf-9eeffa6554c0','相和歌辭 梁甫吟','李白','唐','唐诗','tang','','["\u6292\u60c5", "\u5178\u6545", "\u5199\u4eba", "\u548f\u53f2\u6000\u53e4", "\u5148\u79e6\u81f3\u516d\u671d"]','長嘯梁甫吟，何時見陽春？',338,'全唐诗/poet.tang.1000.json','["長嘯梁甫吟，何時見陽春？", "君不見朝歌屠叟辭棘津，八十西來釣渭濱。", "寧羞白髮照淥水，逢時吐氣思經綸。", "廣張三千六百鈞，風雅暗與文王親。", "大賢虎變愚不測，當年頗似尋常人。", "君不見高陽酒徒起草中，長揖山東隆準公。", "入門不拜騁雄辨，兩女輟洗來趨風。", "東下齊城七十二，指麾楚漢如旋蓬。", "狂生落拓尚如此，何況壯士當羣雄。", "我欲攀龍見明主，雷公砰訇震天鼓。", "帝旁投壺多玉女，三時大笑開電光。", "倏爍晦冥起風雨，閶闔九門不可通。", "以額叩關閽者怒，白日不照吾精誠。", "杞國無事憂天傾，䝟貐磨牙競人肉。", "騶虞不折生草莖，手接飛猱搏彫虎。", "側足焦原未言苦，智者可卷愚者豪。", "世人見我輕鴻毛，力排南山三壯士，齊相殺之費二桃。", "吳楚弄兵無劇孟，亞夫咍爾爲徒勞。", "梁父吟，梁父吟，聲正悲。", "張公兩龍劒，神物合有時。", "風雲感會起屠釣，大人𡸣屼當安之。"]'),
('7b028d90-1546-4874-9888-1c57a3f3cb2d','相和歌辭 東武吟','李白','唐','唐诗','tang','','["\u4ed5\u9014", "\u65e0\u5948", "\u76f8\u548c\u6b4c\u8f9e", "\u4e50\u5e9c"]','好古笑流俗，素聞賢達風。',204,'全唐诗/poet.tang.1000.json','["好古笑流俗，素聞賢達風。", "方希佐明主，長揖辭成功。", "白日在高天，回光燭微躬。", "恭承鳳皇詔，歘起雲蘿中。", "清切紫霄迥，優游丹禁通。", "君王賜顏色，聲價凌煙虹。", "乘輿擁翠蓋，扈從金城東。", "寶馬麗絕景，錦衣入新豐。", "倚巖望松雪，對酒鳴絲桐。", "因學揚子雲，獻賦甘泉宮。", "天書美片善，清芬播無窮。", "歸來入咸陽，談笑皆王公。", "一朝去金馬，飄落成飛蓬。", "賓友日疎散，玉尊亦已空。", "才力猶可倚，不慙世上雄。", "閑作東武吟，曲盡情未終。", "書此謝知己，吾尋黃綺翁。"]'),
('4de9d2cb-62f8-49b2-9914-17c1060ec6ba','相和歌辭 怨詩二首 一','薛奇童','唐','唐诗','tang','','[]','日晚梧桐落，微寒入禁垣。',48,'全唐诗/poet.tang.1000.json','["日晚梧桐落，微寒入禁垣。", "月懸三雀觀，霜度萬秋門。", "豔舞矜新寵，愁容泣舊恩。", "不堪深殿裏，簾外欲黃昏。"]'),
('c8dc78e8-eca3-43fe-8957-c9c634f4b747','相和歌辭 怨詩二首 二','薛奇童','唐','唐诗','tang','','[]','禁苑春風起，流鶯繞合歡。',48,'全唐诗/poet.tang.1000.json','["禁苑春風起，流鶯繞合歡。", "玉窗通日氣，珠箔卷輕寒。", "楊葉垂金砌，梨花入井闌。", "君王好長袖，新作舞衣寬。"]'),
('be665b74-bf5e-484d-b86b-85764fe4ee85','相和歌辭 怨詩','張汯','唐','唐诗','tang','','[]','去年離別雁初歸，今夜裁縫螢已飛。',32,'全唐诗/poet.tang.1000.json','["去年離別雁初歸，今夜裁縫螢已飛。", "征客近來音信斷，不知何處寄寒衣。"]'),
('093f8db9-b5a9-40b5-86ee-703ac046b675','相和歌辭 怨詩','劉元濟','唐','唐诗','tang','','[]','玉關芳信斷，蘭閨錦字新。',48,'全唐诗/poet.tang.1000.json','["玉關芳信斷，蘭閨錦字新。", "愁來好自抑，念切已含嚬。", "虛牖風驚夢，空牀月厭人。", "歸期儻可促，勿度柳園春。"]'),
('9709148e-d077-4032-90b4-f561a7e27ea1','相和歌辭 怨詩三首 一','李暇','唐','唐诗','tang','','[]','羅敷初總髻，蕙芳正嬌小。',24,'全唐诗/poet.tang.1000.json','["羅敷初總髻，蕙芳正嬌小。", "月落始歸船，春眠恆著曉。"]'),
('1d5a1080-bad4-49d8-b2cf-d9e2f6a3308c','相和歌辭 怨詩三首 二','李暇','唐','唐诗','tang','','[]','何處期郎遊？小苑花臺間。',24,'全唐诗/poet.tang.1000.json','["何處期郎遊？小苑花臺間。", "相憶不可見，且復乘月還。"]'),
('f9a61da1-8c80-4698-b345-391cff7b3ac4','相和歌辭 怨詩三首 三','李暇','唐','唐诗','tang','','[]','別來花照路，別後露垂葉。',24,'全唐诗/poet.tang.1000.json','["別來花照路，別後露垂葉。", "歌舞須及時，如何坐悲妾。"]'),
('162cbb9f-bbde-41a4-95b0-0be89ecabc99','相和歌辭 怨詩二首 一','崔國輔','唐','唐诗','tang','','[]','樓前桃李疎，池上芙蓉落。',24,'全唐诗/poet.tang.1000.json','["樓前桃李疎，池上芙蓉落。", "織錦猶未成，蟲聲入羅幕。"]'),
('b52a6b7c-7890-4224-aa1a-cc9cab9b2e34','相和歌辭 怨詩二首 二','崔國輔','唐','唐诗','tang','','[]','妾有羅衣裳，秦王在時作。',24,'全唐诗/poet.tang.1000.json','["妾有羅衣裳，秦王在時作。", "爲舞春風多，秋來不堪著。"]'),
('474eec78-7561-4f35-b428-1a437bb4adc6','相和歌辭 怨詩','孟郊','唐','唐诗','tang','','[]','試妾與君淚，兩處滴池水。',24,'全唐诗/poet.tang.1000.json','["試妾與君淚，兩處滴池水。", "看取芙蓉花，今年爲誰死。"]'),
('4ecae1f7-266b-4e80-878c-8b3d51618347','相和歌辭 怨詩','劉义','唐','唐诗','tang','','[]','君莫嫌醜婦，醜婦死守貞。',48,'全唐诗/poet.tang.1000.json','["君莫嫌醜婦，醜婦死守貞。", "山頭一怪石，長作望夫名。", "鳥有竝翼飛，獸有比肩行。", "丈夫不立義，豈如鳥獸情。"]'),
('863f8e58-3a82-40a7-927d-f1679f50c1ab','相和歌辭 怨詩','鮑溶','唐','唐诗','tang','','[]','女蘿寄松柏，綠蔓花緜緜。',132,'全唐诗/poet.tang.1000.json','["女蘿寄松柏，綠蔓花緜緜。", "三五定君婚，結髮早移天。", "肅肅羊雁禮，泠泠琴瑟篇。", "恭承采蘩祀，敢效同居賢。", "皎日不留景，良時如逝川。", "秋心還遺愛，春貌無歸妍。", "翠袖洗朱粉，碧階對綺錢。", "新人易如玉，廢瑟難爲弦。", "寄羨蕣華木，榮名香閣前。", "豈無搖落苦，貴與根蒂連。", "希君舊光景，照妾薄暮年。"]'),
('01188e4a-475f-42c3-b021-80e71dec225e','相和歌辭 怨詩','白居易','唐','唐诗','tang','','[]','奪寵心那慣，尋思倚殿門。',24,'全唐诗/poet.tang.1000.json','["奪寵心那慣，尋思倚殿門。", "不知移舊愛，何處作新恩。"]'),
('30ae2659-78b4-43d7-abfe-a64810398af9','相和歌辭 怨詩二首 一','姚氏月華','唐','唐诗','tang','','[]','春水悠悠春水綠，對此思君淚相續。',32,'全唐诗/poet.tang.1000.json','["春水悠悠春水綠，對此思君淚相續。", "羞將離恨向東風，理盡秦箏不成曲。"]'),
('bf95c800-adcc-4719-9d39-efffa1c48448','相和歌辭 怨詩二首 二','姚氏月華','唐','唐诗','tang','','[]','與君形影分胡越，玉枕終年對離別。',32,'全唐诗/poet.tang.1000.json','["與君形影分胡越，玉枕終年對離別。", "登臺北望煙雨深，回身泣向寥天月。"]'),
('4721fda8-9013-4d52-98c0-47d848cf2596','相和歌辭 怨歌行','虞世南','唐','唐诗','tang','','[]','紫殿秋風冷，彫甍白日沈。',84,'全唐诗/poet.tang.1000.json','["紫殿秋風冷，彫甍白日沈。", "裁紈悽斷曲，織素別離心。", "掖庭羞改畫，長門不惜金。", "寵移恩稍薄，情疎恨轉深。", "香銷翠羽帳，弦斷鳳皇琴。", "鏡前紅粉歇，階上綠苔侵。", "誰言掩歌扇，飜作白頭吟。"]'),
('6f0612fa-9e28-431f-8a02-b511a6d6cc47','相和歌辭 怨歌行','李白','唐','唐诗','tang','','["\u6292\u60c5", "\u5973\u5b50", "\u4e50\u5e9c", "\u76f8\u548c\u6b4c\u8f9e", "\u5931\u610f"]','十五入漢宮，花顏笑春紅。',108,'全唐诗/poet.tang.1000.json','["十五入漢宮，花顏笑春紅。", "君王選玉色，侍寢金屏中。", "薦枕嬌夕月，卷衣戀春風。", "寧知趙飛燕，奪寵恨無窮。", "沈憂能傷人，綠鬢成霜蓬。", "一朝不得意，世事徒爲空。", "鷫鸘換美酒，舞衣罷雕籠。", "寒苦不忍言，爲君奏絲桐。", "腸斷弦亦絕，悲心夜忡忡。"]'),
('c0f319bd-70b8-4e2b-ad82-9ed3d84ed7b0','相和歌辭 怨歌行','吳少微','唐','唐诗','tang','','[]','城南有怨婦，含怨倚蘭叢。',194,'全唐诗/poet.tang.1000.json','["城南有怨婦，含怨倚蘭叢。", "自謂二八時，歌舞入漢宮。", "皇恩弄幸玉堂中，綠陌黃花催夜酒。", "錦衣羅袂逐春風，建章西宮煥若神。", "燕趙美女二千人，君王厭德不忘新。", "況羣豔冶紛來陳，是時別君不再見。", "三十三春長信殿，長信重門晝掩關。", "清房曉帳幽且閑，綺窗蟲網氛塵色。", "文軒鶯對桃李顏，天王貴宮不貯老。", "浩然淚隕今來還，自憐轉晚暮。", "試逐佳遊芳草路，小腰麗女奪人奇。", "金鞍少年曾不顧，歸來誰爲夫。", "請謝西家婦，莫辭先醉解羅襦。"]'),
('50558d78-9650-4a09-8f68-44beb2b2ede9','相和歌辭 明月照高樓','雍陶','唐','唐诗','tang','','[]','朗月何高高，樓中簾影寒。',96,'全唐诗/poet.tang.1000.json','["朗月何高高，樓中簾影寒。", "一婦獨含歎，四坐誰成歡。", "時節屢已移，遊旅杳不還。", "滄溟倘未涸，妾淚終不乾。", "君若無定雲，妾若不動山。", "雲行出山易，山逐雲去難。", "願爲邊塞塵，因風委君顏。", "君顏良洗多，盪妾濁水間。"]'),
('cf091288-2149-4e06-8619-261985ad8fca','相和歌辭 長門怨','徐賢妃','唐','唐诗','tang','','[]','舊愛柏梁臺，新寵昭陽殿。',48,'全唐诗/poet.tang.1000.json','["舊愛柏梁臺，新寵昭陽殿。", "守分辭方輦，含情泣團扇。", "一朝歌舞榮，夙昔詩書賤。", "頹恩誠已矣，覆水難重薦。"]'),
('899aec8f-0f35-4125-8580-13171f22bca6','相和歌辭 長門怨','沈佺期','唐','唐诗','tang','','[]','月皎風泠泠，長門次掖庭。',48,'全唐诗/poet.tang.1000.json','["月皎風泠泠，長門次掖庭。", "玉階聞墜葉，羅幌見飛螢。", "清露凝珠綴，流塵下翠屏。", "妾心君未察，秋歎劇繁星。"]'),
('af7bc37f-eb0a-400a-872c-d30dbe966713','相和歌辭 長門怨','吳少微','唐','唐诗','tang','','[]','月出映曾城，孤圜上太清。',72,'全唐诗/poet.tang.1000.json','["月出映曾城，孤圜上太清。", "君王春愛歇，枕席涼風生。", "怨咽不能寢，踟躕步前楹。", "空階白露色，百草寒蟲鳴。", "念昔金房裏，猶嫌玉座輕。", "如何嬌所誤，長夜泣恩情。"]'),
('7df4c1ad-5232-4df5-98c1-05f46dfc7d87','相和歌辭 長門怨','張脩之','唐','唐诗','tang','','[]','長門落景盡，洞房秋月明。',36,'全唐诗/poet.tang.1000.json','["長門落景盡，洞房秋月明。", "玉階草路積，金屋網塵生。", "妾妬今應改，君恩昔未平。"]'),
('c6670b5c-674e-499d-ac03-6e90a067ed88','相和歌辭 長門怨','裴交泰','唐','唐诗','tang','','[]','自閉長門經幾秋，羅衣溼盡淚還流。',32,'全唐诗/poet.tang.1000.json','["自閉長門經幾秋，羅衣溼盡淚還流。", "一種蛾眉明月夜，南宮歌管北宮愁。"]'),
('edc3b878-d8ef-4855-9d99-0d6b787d5c02','相和歌辭 長門怨','劉皁','唐','唐诗','tang','','[]','宮殿沈沈月欲分，昭陽更漏不堪聞。',32,'全唐诗/poet.tang.1000.json','["宮殿沈沈月欲分，昭陽更漏不堪聞。", "珊瑚枕上千行淚，不是思君是恨君。"]'),
('061171ce-6d25-4e81-9d19-89a2b916416a','相和歌辭 長門怨','袁暉','唐','唐诗','tang','','[]','早知君愛歇，本自無縈妬。',48,'全唐诗/poet.tang.1000.json','["早知君愛歇，本自無縈妬。", "誰使恩情深，今來反相誤。", "愁眠羅帳曉，泣坐金閨暮。", "獨有夢中魂，猶言意如故。"]'),
('ccbc1933-eaa7-45ab-a8b9-92c5d745aacc','相和歌辭 長門怨','劉言史','唐','唐诗','tang','','[]','獨坐爐邊結夜愁，暫時恩去亦難留。',32,'全唐诗/poet.tang.1000.json','["獨坐爐邊結夜愁，暫時恩去亦難留。", "手持金箸垂紅淚，亂撥寒灰不舉頭。"]'),
('4adbd576-58b6-4d4a-9242-475231293909','相和歌辭 長門怨二首 一','李白','唐','唐诗','tang','','[]','天回北斗挂西樓，金屋無人螢火流。',32,'全唐诗/poet.tang.1000.json','["天回北斗挂西樓，金屋無人螢火流。", "月光欲到長門殿，別作深宮一段愁。"]'),
('533fc8a0-b5f9-422b-9267-ecab0ad01140','相和歌辭 長門怨二首 二','李白','唐','唐诗','tang','','[]','桂殿長愁不記春，黃金四屋起秋塵。',32,'全唐诗/poet.tang.1000.json','["桂殿長愁不記春，黃金四屋起秋塵。", "夜懸明鏡青天上，獨照長門宮裏人。"]'),
('841631b4-7f64-439a-9f9d-487086aa2c12','相和歌辭 長門怨','李華','唐','唐诗','tang','','[]','弱體鴛鴦薦，啼妝翡翠衾。',48,'全唐诗/poet.tang.1000.json','["弱體鴛鴦薦，啼妝翡翠衾。", "鴉鳴秋殿曉，人靜禁門深。", "每憶椒房寵，那堪永巷陰。", "日驚羅帶緩，非復舊來心。"]'),
('cd5b1644-b2ea-4d34-9a5a-26c07dc2f260','相和歌辭 長門怨','岑參','唐','唐诗','tang','','[]','君王嫌妾妬，閉妾在長門。',48,'全唐诗/poet.tang.1000.json','["君王嫌妾妬，閉妾在長門。", "舞袖垂新寵，愁眉結舊恩。", "綠錢生履跡，紅粉溼啼痕。", "羞被桃花笑，看春獨不言。"]'),
('d8f3462b-2c7d-42da-af77-e35b4464099d','相和歌辭 長門怨','齊澣','唐','唐诗','tang','','[]','煢煢孤思逼，寂寂長門夕。',48,'全唐诗/poet.tang.1000.json','["煢煢孤思逼，寂寂長門夕。", "妾妬亦非深，君恩那不惜。", "攜琴就玉階，調悲聲未諧。", "將心託明月，流影入君懷。"]'),
('6fb02922-4117-43c0-9ef1-e71f845228cf','相和歌辭 長門怨','劉長卿','唐','唐诗','tang','','[]','何事長門閉，珠簾只自垂。',48,'全唐诗/poet.tang.1000.json','["何事長門閉，珠簾只自垂。", "月移深殿早，春向後宮遲。", "蕙草生閑地，梨花發舊枝。", "芳菲自恩幸，看却被風吹。"]'),
('7c5bf4fe-7668-44af-b43a-e4e43d84ac6e','相和歌辭 長門怨','僧皎然','唐','唐诗','tang','','[]','春風日日閉長門，搖蕩春心自夢魂。',32,'全唐诗/poet.tang.1000.json','["春風日日閉長門，搖蕩春心自夢魂。", "若遣花開只笑妾，不如桃李正無言。"]'),
('7d25f355-cbc3-4f18-ab8f-f605472ba32d','相和歌辭 長門怨','盧綸','唐','唐诗','tang','','[]','空宮古廊殿，寒月照斜暉。',24,'全唐诗/poet.tang.1000.json','["空宮古廊殿，寒月照斜暉。", "臥聽未央曲，滿箱歌舞衣。"]'),
('d2a631cf-0c02-46f1-9bfb-8cce798979c8','相和歌辭 長門怨','戴叔倫','唐','唐诗','tang','','[]','自憶專房寵，曾居第一流。',48,'全唐诗/poet.tang.1000.json','["自憶專房寵，曾居第一流。", "移恩向何處？暫妬不容收。", "夜久絲管絕，月明宮殿秋。", "空將舊時意，長望鳳皇樓。"]'),
('d400f2fa-d0ca-4817-9216-6d3c606b7430','相和歌辭 長門怨','劉駕','唐','唐诗','tang','','[]','御泉長繞鳳皇樓，只是恩波別處流。',32,'全唐诗/poet.tang.1000.json','["御泉長繞鳳皇樓，只是恩波別處流。", "閑揲舞衣歸未得，夜來砧杵六宮秋。"]'),
('ef189d28-9750-49f2-8813-f70bee5e45b2','相和歌辭 長門怨 一','高蟾','唐','唐诗','tang','','[]','天上何勞萬古春，君前誰是百年人。',64,'全唐诗/poet.tang.1000.json','["天上何勞萬古春，君前誰是百年人。", "魂銷尚媿金爐燼，思起猶慙玉輦塵。", "煙翠薄情攀不得，星芒浮豔采無因。", "可憐明鏡來相向，何似恩光朝夕新。"]'),
('7bcef096-9150-4d38-8a92-d2443de404d3','相和歌辭 長門怨 二','高蟾','唐','唐诗','tang','','[]','天上鳳皇休寄夢，人間鸚鵡舊堪悲。',32,'全唐诗/poet.tang.1000.json','["天上鳳皇休寄夢，人間鸚鵡舊堪悲。", "平生心緒無人識，一隻金梭萬丈絲。"]'),
('8da65d04-e82f-479d-9759-0b445caeff1b','相和歌辭 長門怨','張祜','唐','唐诗','tang','','[]','日映宮牆柳色寒，笙歌遙指碧雲端。',32,'全唐诗/poet.tang.1000.json','["日映宮牆柳色寒，笙歌遙指碧雲端。", "珠鉛滴盡無心語，彊把花枝冷笑看。"]'),
('79160aff-5f8e-4949-b3cd-269b8a43f8fd','相和歌辭 長門怨二首 一','鄭谷','唐','唐诗','tang','','[]','閑把羅衣泣鳳皇，先朝曾教舞霓裳。',32,'全唐诗/poet.tang.1000.json','["閑把羅衣泣鳳皇，先朝曾教舞霓裳。", "春來却羨庭花落，得逐晴風出禁牆。"]'),
('28f8b6e2-2c56-4a12-8195-07e83798fc80','相和歌辭 長門怨二首 二','鄭谷','唐','唐诗','tang','','[]','流水君恩共不回，杏花爭忍埽成堆。',32,'全唐诗/poet.tang.1000.json','["流水君恩共不回，杏花爭忍埽成堆。", "殘春未必多煙雨，淚滴閑階長綠苔。"]'),
('d5abcffa-ec7a-4422-9d49-09a96d0bcda4','相和歌辭 長門怨二首 一','劉氏媛','唐','唐诗','tang','','[]','雨滴梧桐秋夜長，愁心和雨到昭陽。',32,'全唐诗/poet.tang.1000.json','["雨滴梧桐秋夜長，愁心和雨到昭陽。", "淚痕不學君恩斷，拭却千行更萬行。"]'),
('e55d71d3-785b-4f4a-9086-765c4641f5ee','相和歌辭 長門怨二首 二','劉氏媛','唐','唐诗','tang','','[]','學畫蛾眉獨出羣，當時人道便承恩。',32,'全唐诗/poet.tang.1000.json','["學畫蛾眉獨出羣，當時人道便承恩。", "經年不見君王面，花落黃昏空掩門。"]'),
('5b3f2fc0-a992-4e27-8404-005465c98f8d','相和歌辭 阿嬌怨','劉禹錫','唐','唐诗','tang','','[]','望見葳蕤舉翠華，試開金屋埽庭花。',32,'全唐诗/poet.tang.1000.json','["望見葳蕤舉翠華，試開金屋埽庭花。", "須臾宮女傳來信，云幸平陽公主家。"]'),
('34ef326b-c8ec-4feb-bc66-24611dfdf939','相和歌辭 班倢伃','徐彥伯','唐','唐诗','tang','','[]','君恩忽斷絕，妾思終未央。',48,'全唐诗/poet.tang.1000.json','["君恩忽斷絕，妾思終未央。", "巾櫛不可見，枕席空餘香。", "窗暗網羅白，階秋苔蘚黃。", "應門寂已閉，流涕向昭陽。"]'),
('307ff50e-f4b5-453e-adb6-fd921432365e','相和歌辭 班倢伃','嚴識玄','唐','唐诗','tang','','[]','賤妾如桃李，君王若歲時。',48,'全唐诗/poet.tang.1000.json','["賤妾如桃李，君王若歲時。", "秋風一已勁，搖落不勝悲。", "寂寂蒼苔滿，沈沈綠草滋。", "榮華非此日，指輦競何辭。"]'),
('5ab180d2-87ce-418a-afdf-3a473f42a7d4','相和歌辭 班倢伃三首 一','王維','唐','唐诗','tang','','[]','玉窗螢影度，金殿人聲絕。',24,'全唐诗/poet.tang.1000.json','["玉窗螢影度，金殿人聲絕。", "秋夜守羅幃，孤燈耿不滅。"]'),
('704cd99c-171d-4b5f-bbdc-0d21d559d83d','相和歌辭 班倢伃三首 二','王維','唐','唐诗','tang','','[]','宮殿生秋草，君王恩幸疎。',24,'全唐诗/poet.tang.1000.json','["宮殿生秋草，君王恩幸疎。", "那堪聞鳳吹，門外度金輿。"]'),
('2bbf8f35-26a3-4cbf-aa3c-4ccab73da8b0','相和歌辭 班倢伃三首 三','王維','唐','唐诗','tang','','[]','怪來妝閣閉，朝下不相迎。',24,'全唐诗/poet.tang.1000.json','["怪來妝閣閉，朝下不相迎。", "總向春園裏，花間語笑聲。"]'),
('d52e48bb-b264-4c1e-b75d-933b99d7ab4f','相和歌辭 倢伃怨','崔湜','唐','唐诗','tang','','[]','不分君恩斷，新妝視鏡中。',48,'全唐诗/poet.tang.1000.json','["不分君恩斷，新妝視鏡中。", "容華尚春日，嬌愛已秋風。", "枕席臨窗曉，幃屏向月空。", "年年後庭樹，榮落在深宮。"]'),
('1a35a870-6e18-4b98-8770-50bc0d64cee5','相和歌辭 倢伃怨','崔國輔','唐','唐诗','tang','','[]','長信宮中草，年年愁處生。',24,'全唐诗/poet.tang.1000.json','["長信宮中草，年年愁處生。", "故侵珠履跡，不使玉階行。"]'),
('054d55fe-ff0b-4c2e-aba2-a6b76121d513','相和歌辭 倢伃怨','張烜','唐','唐诗','tang','','[]','賤妾裁紈扇，初搖明月姿。',48,'全唐诗/poet.tang.1000.json','["賤妾裁紈扇，初搖明月姿。", "君王看舞席，坐起秋風時。", "玉樹清御路，金陳翳垂絲。", "昭陽無分理，愁寂任前期。"]'),
('8035eb5a-81dc-407b-b63c-54025b68d700','相和歌辭 倢伃怨','劉方平','唐','唐诗','tang','','[]','夕殿別君王，宮深月似霜。',48,'全唐诗/poet.tang.1000.json','["夕殿別君王，宮深月似霜。", "人愁在長信，螢出向昭陽。", "露裛紅蘭死，秋彫碧樹傷。", "惟當合歡扇，從此篋中藏。"]'),
('d39fbf99-0c3f-47e9-bbe0-1799700376c2','相和歌辭 倢伃怨','王沈','唐','唐诗','tang','','[]','長信梨花暗欲棲，應門上籥草萋萋。',32,'全唐诗/poet.tang.1000.json','["長信梨花暗欲棲，應門上籥草萋萋。", "春風吹花亂撲戶，班倢車聲不至啼。"]'),
('fba448cb-8ff0-44cf-9ad9-c0127f7e6d7d','相和歌辭 倢伃怨','皇甫冉','唐','唐诗','tang','','[]','由來詠團扇，今與值秋風。',48,'全唐诗/poet.tang.1000.json','["由來詠團扇，今與值秋風。", "事逐時皆往，恩無日再中。", "早鴻聞上苑，寒露下深宮。", "顏色年年謝，相如賦豈工。"]'),
('e491c2f2-7780-4ec0-92e8-8591e15c6f3b','相和歌辭 倢伃怨','陸龜蒙','唐','唐诗','tang','','[]','妾貌非傾國，君王忽然寵。',48,'全唐诗/poet.tang.1000.json','["妾貌非傾國，君王忽然寵。", "南山掌上來，不及新恩重。", "後宮多窈窕，日日學新聲。", "一落君王耳，南山又須輕。"]'),
('8f712fbf-f528-49d6-84e8-5e1f66a96c33','相和歌辭 倢伃怨','翁綬','唐','唐诗','tang','','[]','讒謗潛來起百憂，朝承恩寵暮仇讐。',64,'全唐诗/poet.tang.1000.json','["讒謗潛來起百憂，朝承恩寵暮仇讐。", "火燒白玉非因玷，霜翦紅蘭不待秋。", "花落昭陽誰共輦，月明長信獨登樓。", "繁華事逐東流水，團扇悲歌萬古愁。"]'),
('966cfa33-295a-478b-b341-eb8270b5a2f5','相和歌辭 倢伃怨','劉氏雲','唐','唐诗','tang','','[]','君恩不可見，妾豈如秋扇。',40,'全唐诗/poet.tang.1000.json','["君恩不可見，妾豈如秋扇。", "秋扇尚有時，妾身永微賤。", "莫言朝花不復落，嬌容幾奪昭陽殿。"]'),
('7642e6c9-6fb2-4c6e-b7c8-800251357436','相和歌辭 長信怨','王諲','唐','唐诗','tang','','[]','飛燕倚身輕，爭人巧笑名。',48,'全唐诗/poet.tang.1000.json','["飛燕倚身輕，爭人巧笑名。", "生君棄妾意，增妾怨君情。", "日落昭陽殿，秋來長信城。", "寥寥金殿裏，歌吹夜無聲。"]'),
('f0847590-fbf2-410e-b666-699161c54582','相和歌辭 長信怨 一','王昌齡','唐','唐诗','tang','','[]','金井梧桐秋葉黃，珠簾不卷夜來霜。',32,'全唐诗/poet.tang.1000.json','["金井梧桐秋葉黃，珠簾不卷夜來霜。", "金爐玉枕無顏色，臥聽南宮清漏長。"]'),
('1b6f2389-2d09-4d51-982a-e7efb35113c5','相和歌辭 長信怨 二','王昌齡','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996"]','奉帚平明金殿開，暫將團扇共裴回。',32,'全唐诗/poet.tang.1000.json','["奉帚平明金殿開，暫將團扇共裴回。", "玉顏不及寒鵶色，猶帶昭陽日影來。"]'),
('38bf60e6-4d6f-4e72-a646-420198611898','相和歌辭 長信怨','李白','唐','唐诗','tang','','[]','月皎昭陽殿，霜清長信宮。',48,'全唐诗/poet.tang.1000.json','["月皎昭陽殿，霜清長信宮。", "天行乘玉輦，飛燕與君同。", "更有留情處，承恩樂未窮。", "誰憐團扇妾，獨坐怨秋風。"]'),
('489e9d6a-f619-4103-acde-0ba0bdfca086','相和歌辭 蛾眉怨','王翰','唐','唐诗','tang','','[]','君不見宜春苑中九華殿，飛閣連連直如髮。',323,'全唐诗/poet.tang.1000.json','["君不見宜春苑中九華殿，飛閣連連直如髮。", "白日全含朱鳥窗，流雲半入蒼龍闕。", "宮中綵女夜無事，學鳳吹簫弄清越。", "珠簾北卷待涼風，繡戶南開向明月。", "忽聞天子憶蛾眉，寶鳳銜花揲兩螭。", "傳聲走馬開金屋，夾路鳴環上玉墀。", "長樂彤庭宴華寢，三千美人曳光錦。", "燈前含笑更羅衣，帳裏承恩薦瑤枕。", "不意君心半路迴，求仙別作望仙臺。", "倉琅禁闥遙相憶，紫翠巖房晝不開。", "欲向人間種桃實，先從海底覓蓬萊。", "蓬萊可求不可上，孤舟縹緲知何往？", "黃金作盤銅作莖，晴天白露掌中擎。", "王母嫣然感君意，雲車雨斾欲相迎。", "飛簾觀前空怨慕，少君何事須相誤。", "一朝埋沒茂陵田，賤妾蛾眉不重顧。", "宮車晚出向南山，仙衛逶迤去不還。", "朝晡泣對麒麟樹，樹下蒼苔日漸斑。", "人生百年夜將半，對酒長歌莫長歎。", "賸知白日不可思，一死一生何足算。"]'),
('f93545e7-747e-4d12-a6c8-e484c46b2860','相和歌辭 玉階怨','李白','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u5b64\u72ec", "\u5bab\u6028", "\u4e50\u5e9c"]','玉階生白露，夜久侵羅襪。',24,'全唐诗/poet.tang.1000.json','["玉階生白露，夜久侵羅襪。", "却下水精簾，玲瓏望秋月。"]'),
('8ffcd0a6-9349-4254-b0b5-ad6ed2f25dd6','相和歌辭 宮怨','長孫佐輔','唐','唐诗','tang','','[]','窗前好樹名玫瑰，去年花落今年開。',224,'全唐诗/poet.tang.1000.json','["窗前好樹名玫瑰，去年花落今年開。", "無情春色尚識返，君心忽斷何時來？", "憶昔妝成候仙仗，宮瑣玲瓏日新上。", "拊心却笑西子嚬，掩鼻誰憂鄭姬謗。", "草染文章衣下履，花黏甲乙牀前帳。", "三千玉貌休自誇，十二金釵獨相向。", "盛衰傾奪欲何如，嬌愛飜悲逐佞諛。", "重遠豈能慙沼鵠，棄前方見泣船魚。", "看籠不記熏龍腦，詠扇空曾禿鼠須。", "始意類蘿新託柏，終傷如薺却甘荼。", "深院獨開還獨閉，鸚鵡驚飛苔覆地。", "滿箱舊賜前日衣，漬枕新垂夜來淚。", "痕多開鏡照還悲，綠髻青蛾尚未衰。", "莫道新縑長絕比，猶逢故劒會相追。"]'),
('e73b4b4a-718f-47c2-bedb-b8d8e213a60e','相和歌辭 宮怨','李益','唐','唐诗','tang','','["\u95fa\u6028"]','露溼晴花宮殿香，月明歌吹在昭陽。',32,'全唐诗/poet.tang.1000.json','["露溼晴花宮殿香，月明歌吹在昭陽。", "似將海水添宮漏，共滴長門一夜長。"]'),
('08c59931-b896-4d53-9230-b6da16cdc0b1','相和歌辭 宮怨','于濆','唐','唐诗','tang','','[]','妾家望江口，少年家財厚。',120,'全唐诗/poet.tang.1000.json','["妾家望江口，少年家財厚。", "臨江起珠樓，不賣文君酒。", "當年樂貞獨，巢燕時爲友。", "父兄未許人，畏妾事姑舅。", "西牆鄰宋玉，窺見妾眉宇。", "一旦及天聰，恩光生戶牖。", "謂言入漢宮，富貴可長久。", "君王縱有情，不奈陳皇后。", "誰憐頰似桃，孰知腰勝柳。", "今日在長門，從來不如醜。"]'),
('f3c423cd-2c34-406d-baf4-30b4dbf8f87f','相和歌辭 宮怨 一','柯崇','唐','唐诗','tang','','[]','塵滿金爐不炷香，黃昏獨自立重廊。',32,'全唐诗/poet.tang.1000.json','["塵滿金爐不炷香，黃昏獨自立重廊。", "笙歌何處承恩寵？一一隨風入上陽。"]'),
('25867091-31bf-4731-b537-79b44af26988','相和歌辭 宮怨 二','柯崇','唐','唐诗','tang','','[]','長門槐柳半蕭疎，玉輦沈思恨有餘。',32,'全唐诗/poet.tang.1000.json','["長門槐柳半蕭疎，玉輦沈思恨有餘。", "紅淚旋銷傾國態，黃金誰爲達相如。"]'),
('63d1777f-79b2-4d73-8c80-e1c748a28310','相和歌辭 雜怨三首 一','聶夷中','唐','唐诗','tang','','[]','生在綺羅下，豈識漁陽道。',48,'全唐诗/poet.tang.1000.json','["生在綺羅下，豈識漁陽道。", "良人自戍來，夜夜夢中到。", "漁陽萬里遠，近於中門限。", "中門逾有時，漁陽常在眼。"]'),
('35976b04-a1c4-4346-bc19-4f6eccd925b5','相和歌辭 雜怨三首 二','聶夷中','唐','唐诗','tang','','[]','良人昨日去，明日又不還。',24,'全唐诗/poet.tang.1000.json','["良人昨日去，明日又不還。", "別時各有淚，零落青樓前。"]'),
('dcb16ddd-7704-45a3-bd9f-a78066c896b0','相和歌辭 雜怨三首 三','聶夷中','唐','唐诗','tang','','[]','君淚濡羅巾，妾淚滴路塵。',36,'全唐诗/poet.tang.1000.json','["君淚濡羅巾，妾淚滴路塵。", "羅巾今在手，日得隨妾身。", "路塵如因飛，得上君車輪。"]'),
('4f7d77aa-39ab-4b24-b32f-97f2b4fe1ecb','相和歌辭 雜怨三首 一','孟郊','唐','唐诗','tang','','[]','夭桃花清晨，遊女紅粉新。',48,'全唐诗/poet.tang.1000.json','["夭桃花清晨，遊女紅粉新。", "夭桃花薄暮，遊女紅粉故。", "樹有百年花，人無一定顏。", "花送人老盡，人悲花自閑。"]'),
('d3e5f871-de01-40fa-a728-8657b5831f85','相和歌辭 雜怨三首 二','孟郊','唐','唐诗','tang','','[]','貧女鏡不明，寒花日少容。',60,'全唐诗/poet.tang.1000.json','["貧女鏡不明，寒花日少容。", "暗蛩有虛織，短線無長縫。", "浪水不可照，狂夫不可從。", "浪水多散影，狂夫多異蹤。", "持此一生薄，空成百恨濃。"]'),
('1c3a5c44-e3c4-4cf9-a3e2-59c22ad8a19d','相和歌辭 雜怨三首 三','孟郊','唐','唐诗','tang','','[]','憶人莫至悲，至悲空自衰。',48,'全唐诗/poet.tang.1000.json','["憶人莫至悲，至悲空自衰。", "寄人莫翦衣，翦衣未必歸。", "朝爲雙蒂花，暮爲四散飛。", "花落却繞樹，遊子不顧期。"]'),
('bf3e6229-1f5d-4166-9ade-19d7c3f12635','相和歌辭 子夜春歌','王翰','唐','唐诗','tang','','[]','春氣滿林香，春遊不可忘。',48,'全唐诗/poet.tang.1000.json','["春氣滿林香，春遊不可忘。", "落花吹欲盡，垂柳折還長。", "桑女淮南曲，金鞍塞北裝。", "行行小垂手，日暮渭川陽。"]'),
('f3cb8917-c2b2-4619-9fa4-0f548a512bae','相和歌辭 子夜冬歌','崔國輔','唐','唐诗','tang','','[]','寂寥抱冬心，裁羅又褧褧。',24,'全唐诗/poet.tang.1000.json','["寂寥抱冬心，裁羅又褧褧。", "夜久頻挑燈，霜寒剪刀冷。"]'),
('df4de5cf-ac53-4137-b2be-34b163ec4d73','相和歌辭 子夜冬歌','薛耀','唐','唐诗','tang','','[]','朔風扣羣木，巖霜凋百草。',24,'全唐诗/poet.tang.1000.json','["朔風扣羣木，巖霜凋百草。", "借問月中人，安得長不老。"]'),
('b4f19aab-ff6a-40e2-b499-e43a45f7515c','相和歌辭 子夜四時歌六首 春歌二首 一','郭元振','唐','唐诗','tang','','[]','青樓含日光，綠池起風色。',24,'全唐诗/poet.tang.1000.json','["青樓含日光，綠池起風色。", "贈子同心花，殷勤此何極。"]'),
('ea32c92c-589f-40ce-8a57-32d133e364a8','相和歌辭 子夜四時歌六首 春歌二首 二','郭元振','唐','唐诗','tang','','[]','陌頭楊柳枝，已被春風吹。',24,'全唐诗/poet.tang.1000.json','["陌頭楊柳枝，已被春風吹。", "妾心正斷絕，君懷那得知。"]'),
('4113e9d5-2bdc-4951-addb-7e182fd75cc2','相和歌辭 子夜四時歌六首 秋歌二首 一','郭元振','唐','唐诗','tang','','[]','邀歡空佇立，望美頻迴顧。',24,'全唐诗/poet.tang.1000.json','["邀歡空佇立，望美頻迴顧。", "何時復採菱？江中密相遇。"]'),
('f2d99429-122c-47c4-a117-06779c58a4f5','相和歌辭 子夜四時歌六首 秋歌二首 二','郭元振','唐','唐诗','tang','','[]','辟惡茱萸囊，延年菊花酒。',12,'全唐诗/poet.tang.1000.json','["辟惡茱萸囊，延年菊花酒。"]'),
('a58dc2b0-7454-4599-aa4c-a06605f39978','相和歌辭 子夜四時歌六首 冬歌二首 一','郭元振','唐','唐诗','tang','','[]','北極嚴氣升，南至溫風謝。',24,'全唐诗/poet.tang.1000.json','["北極嚴氣升，南至溫風謝。", "調絲競短歌，拂枕憐長夜。"]'),
('7201ac2c-75bd-495d-a203-339fb042959a','相和歌辭 子夜四時歌六首 冬歌二首 二','郭元振','唐','唐诗','tang','','[]','帷橫雙翡翠，被卷兩鴛鴦。',24,'全唐诗/poet.tang.1000.json','["帷橫雙翡翠，被卷兩鴛鴦。", "婉態不自得，宛轉君王牀。"]'),
('4e92a96d-aa74-4153-8314-b6df22d1e18a','相和歌辭 子夜四時歌四首 春歌','李白','唐','唐诗','tang','','["\u6e05\u5546\u66f2\u8f9e", "\u6625\u5929", "\u5973\u5b50", "\u5510\u8bd7\u4e09\u767e\u9996", "\u4e50\u5e9c", "\u8d5e\u7f8e"]','秦地羅敷女，采桑綠水邊。',36,'全唐诗/poet.tang.1000.json','["秦地羅敷女，采桑綠水邊。", "素手青條上，紅妝白日鮮。", "蠶飢妾欲去，五馬莫留連。"]'),
('4bd5be2b-5788-42c0-a300-9d106a73d46e','相和歌辭 子夜四時歌四首 夏歌','李白','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u6e05\u5546\u66f2\u8f9e", "\u590f\u5929", "\u4e50\u5e9c", "\u54f2\u7406", "\u5199\u4eba"]','鏡湖三百里，菡萏發荷花。',36,'全唐诗/poet.tang.1000.json','["鏡湖三百里，菡萏發荷花。", "五月西施采，人看隘若邪。", "迴舟不待月，歸去越王家。"]'),
('49194c4b-b775-4d21-a506-fc0a2ff308f1','相和歌辭 子夜四時歌四首 秋歌','李白','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u601d\u5ff5", "\u6e05\u5546\u66f2\u8f9e", "\u5987\u5973", "\u79cb\u5929", "\u4e50\u5e9c"]','長安一片月，萬戶擣衣聲。',36,'全唐诗/poet.tang.1000.json','["長安一片月，萬戶擣衣聲。", "秋風吹不盡，總是玉關情。", "何日平胡虜？良人罷遠征。"]'),
('35319d7e-9cf6-43b0-bfa3-991cf82a49f9','相和歌辭 子夜四時歌四首 冬歌','李白','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u601d\u5ff5", "\u6e05\u5546\u66f2\u8f9e", "\u5987\u5973", "\u51ac\u5929", "\u4e50\u5e9c"]','明朝驛使發，一夜絮征袍。',36,'全唐诗/poet.tang.1000.json','["明朝驛使發，一夜絮征袍。", "素手抽針冷，那堪把剪刀。", "裁縫寄遠道，幾日到臨洮。"]'),
('051a3fc4-b7c9-4345-a255-2e7887b448e5','相和歌辭 子夜四時歌四首 春歌','陸龜蒙','唐','唐诗','tang','','[]','山連翠羽屏，草接煙華席。',24,'全唐诗/poet.tang.1000.json','["山連翠羽屏，草接煙華席。", "望盡南飛燕，佳人斷信息。"]'),
('6335b64e-eb8c-4bfb-af43-04079f2bdd4c','相和歌辭 子夜四時歌四首 夏歌','陸龜蒙','唐','唐诗','tang','','[]','蘭眼擡露斜，鶯脣映花老。',24,'全唐诗/poet.tang.1000.json','["蘭眼擡露斜，鶯脣映花老。", "金龍傾漏盡，玉井敲冰早。"]'),
('8bb369b9-1505-409f-823c-346f3502e29f','相和歌辭 子夜四時歌四首 秋歌','陸龜蒙','唐','唐诗','tang','','[]','涼漢清泬寥，衰林怨風雨。',24,'全唐诗/poet.tang.1000.json','["涼漢清泬寥，衰林怨風雨。", "愁聽絡緯唱，似與羇魂語。"]'),
('94c281fc-90b7-47c8-8e6e-a18445b158fb','相和歌辭 子夜四時歌四首 冬歌','陸龜蒙','唐','唐诗','tang','','[]','南光走冷圭，北籟號空木。',24,'全唐诗/poet.tang.1000.json','["南光走冷圭，北籟號空木。", "年年任霜霰，不減篔簹綠。"]'),
('4e3884c7-3768-4f7d-abab-164219e603a1','相和歌辭 大子夜歌二首 一','陸龜蒙','唐','唐诗','tang','','[]','歌謠數百種，子夜最可憐。',24,'全唐诗/poet.tang.1000.json','["歌謠數百種，子夜最可憐。", "慷慨吐清音，明轉出天然。"]'),
('a473d2c3-e90d-447a-aa53-adb3b478290d','相和歌辭 大子夜歌二首 二','陸龜蒙','唐','唐诗','tang','','["\u6e05\u5546\u66f2\u8f9e", "\u97f3\u4e50", "\u4e50\u5e9c"]','絲竹發歌響，假器揚清音。',24,'全唐诗/poet.tang.1000.json','["絲竹發歌響，假器揚清音。", "不知歌謠妙，聲勢出口心。"]'),
('7a18b4c1-5ce6-46b6-84ee-86fec16eb74a','相和歌辭 子夜警歌二首 一','陸龜蒙','唐','唐诗','tang','','[]','鏤椀傳綠酒，雕爐熏紫煙。',24,'全唐诗/poet.tang.1000.json','["鏤椀傳綠酒，雕爐熏紫煙。", "誰知苦寒調，共作白雪弦。"]'),
('0129f4a2-76ec-4ed8-a385-a5142a49e274','相和歌辭 子夜警歌二首 二','陸龜蒙','唐','唐诗','tang','','[]','恃愛如欲進，含羞出不前。',24,'全唐诗/poet.tang.1000.json','["恃愛如欲進，含羞出不前。", "朱口發豔歌，玉指弄嬌弦。"]'),
('cd2f806d-530b-4172-8012-db5a51f95cbd','相和歌辭 丁督護歌','李白','唐','唐诗','tang','','["\u6e05\u5546\u66f2\u8f9e", "\u4e50\u5e9c", "\u519c\u6c11"]','雲陽上征去，兩岸饒商賈。',72,'全唐诗/poet.tang.1000.json','["雲陽上征去，兩岸饒商賈。", "吳牛喘月時，拖船一何苦。", "水濁不可飲，壺漿半成土。", "一唱都護歌，心摧淚如雨。", "萬人鑿盤石，無由達江滸。", "君看石芒碭，掩淚悲千古。"]'),
('9f3a5091-8059-4f25-b30a-45381ca6d645','相和歌辭 團扇郎','張祜','唐','唐诗','tang','','[]','白團扇，今來此去捐。',22,'全唐诗/poet.tang.1000.json','["白團扇，今來此去捐。", "願得入郎手，團圓郎眼前。"]'),
('6db52079-cf43-4b08-ba0d-edbc69eebe29','相和歌辭 團扇郎','劉禹錫','唐','唐诗','tang','','[]','團扇復團扇，奉君清暑殿。',48,'全唐诗/poet.tang.1000.json','["團扇復團扇，奉君清暑殿。", "秋風入庭樹，從此不相見。", "上有乘鸞女，蒼蒼蟲網遍。", "明年入懷袖，別是機中練。"]'),
('78185292-1450-416c-bd9d-8403d9e69537','相和歌辭 碧玉歌','李暇','唐','唐诗','tang','','[]','碧玉上宮妓，出入千花林。',24,'全唐诗/poet.tang.1000.json','["碧玉上宮妓，出入千花林。", "珠被玳瑁牀，感郎情意深。"]'),
('2e8ddf82-3bbc-49aa-ac97-2abdd2cd760a','相和歌辭 懊惱曲','溫庭筠','唐','唐诗','tang','','["\u6b4c\u9882", "\u5199\u4eba", "\u7231\u60c5"]','藕絲作線難勝針，蘂粉染黃那得深。',128,'全唐诗/poet.tang.1000.json','["藕絲作線難勝針，蘂粉染黃那得深。", "玉白蘭芳不相顧，倡樓一笑輕千金。", "莫言自古皆如此，健劒刜鐘鉛繞指。", "三秋庭綠盡迎霜，惟有荷花守紅死。", "西江小吏朱斑輪，柳縷吐芽香玉春。", "兩股金釵已相許，不令獨作空城塵。", "悠悠楚水流如馬，恨紫愁紅滿平野。", "野土千年怨不平，至今燒作鴛鴦瓦。"]'),
('ae02eae3-4d12-45da-84a6-949f88a0bd48','相和歌辭 讀曲歌五首 一','張祜','唐','唐诗','tang','','[]','窗中獨自起，簾外獨自行。',24,'全唐诗/poet.tang.1000.json','["窗中獨自起，簾外獨自行。", "愁見蜘蛛織，尋思直到明。"]'),
('fe5ade0f-5f0b-48b0-b645-00de441422a8','相和歌辭 讀曲歌五首 二','張祜','唐','唐诗','tang','','[]','碓上米不舂，窗中絲罷絡。',24,'全唐诗/poet.tang.1000.json','["碓上米不舂，窗中絲罷絡。", "看渠駕去車，定是無四角。"]'),
('b3a8600d-8a45-441b-b9b1-36c08d87a691','相和歌辭 讀曲歌五首 三','張祜','唐','唐诗','tang','','[]','不見心相許，徒云脚漫勤。',24,'全唐诗/poet.tang.1000.json','["不見心相許，徒云脚漫勤。", "摘荷空摘葉，是底采蓮人。"]'),
('c2cde274-cda9-4603-8317-155ba71d9dc3','相和歌辭 讀曲歌五首 四','張祜','唐','唐诗','tang','','[]','窗外山魈立，知渠脚不多。',24,'全唐诗/poet.tang.1000.json','["窗外山魈立，知渠脚不多。", "三更機底下，摸著是誰梭。"]'),
('06b84ebb-073f-4ff0-9796-a615ac5d13f3','相和歌辭 讀曲歌五首 五','張祜','唐','唐诗','tang','','[]','郎去摘黃瓜，郎來收赤棗。',24,'全唐诗/poet.tang.1000.json','["郎去摘黃瓜，郎來收赤棗。", "郎耕種麻地，今作西舍道。"]'),
('e56e4c5d-9552-4ec9-a4c5-a86e08e1ef6f','相和歌辭 春江花月夜二首 一','張子容','唐','唐诗','tang','','[]','林花發岸口，氣色動江新。',36,'全唐诗/poet.tang.1000.json','["林花發岸口，氣色動江新。", "此夜江中月，流光花上春。", "分明石潭裏，宜照浣紗人。"]'),
('6ed3a7f5-c68a-40ba-b28f-50ebbfac1091','相和歌辭 春江花月夜二首 二','張子容','唐','唐诗','tang','','[]','交甫憐瑤佩，仙妃難重期。',36,'全唐诗/poet.tang.1000.json','["交甫憐瑤佩，仙妃難重期。", "沈沈綠江晚，惆悵碧雲姿。", "初逢花上月，言是弄珠時。"]'),
('91019fe2-b58e-4320-a986-6a323847e944','相和歌辭 春江花月夜','張若虛','唐','唐诗','tang','','["\u957f\u6c5f", "\u601d\u5ff5", "\u6e05\u5546\u66f2\u8f9e", "\u6708\u4eae", "\u6625\u5929", "\u4e50\u5e9c"]','春江潮水連海平，海上明月共潮生。',288,'全唐诗/poet.tang.1000.json','["春江潮水連海平，海上明月共潮生。", "灩灩隨波千萬里，何處春江無月明？", "江流宛轉遶芳甸，月照花林皆似霰。", "空裏流霜不覺飛，汀上白沙看不見。", "江天一色無纖塵，皎皎空中孤月輪。", "江畔何人初見月？江月何年初照人？", "人生代代無窮已，江月年年望相似。", "不知江月待何人，但見長江送流水。", "白雲一片去悠悠，青楓浦上不勝愁。", "誰家今夜扁舟子，何處相思明月樓？", "可憐樓上月裴回，應照離人妝鏡臺。", "玉戶簾中卷不去，擣衣砧上拂還來。", "此時相望不相聞，願逐月華流照君。", "鴻雁長飛光不度，魚龍潛躍水成文。", "昨夜閑潭夢落花，可憐春半不還家。", "江水流春去欲盡，江潭落月復西斜。", "斜月沈沈藏海霧，碣石瀟湘無限路。", "不知乘月幾人歸，落月搖情滿江樹。"]'),
('c4912092-34c2-42fe-a9ff-b924b0dddf7f','相和歌辭 春江花月夜','溫庭筠','唐','唐诗','tang','','["\u957f\u6c5f"]','玉樹歌闌海雲黑，花庭忽作青蕪國。',160,'全唐诗/poet.tang.1000.json','["玉樹歌闌海雲黑，花庭忽作青蕪國。", "秦淮有水水無情，還向金陵漾春色。", "楊家二世安九重，不御華芝嫌六龍。", "百幅錦帆風力滿，連天展盡金芙蓉。", "珠翠丁星復明滅，龍頭劈浪哀笳發。", "千里涵空照水魂，萬枝破鼻團香雪。", "漏轉霞高滄海西，頗黎枕上聞天雞。", "蠻弦代雁曲如語，一醉昏昏天下迷。", "四方傾動煙塵起，猶在濃香夢魂裏。", "後主荒宮有曉鶯，飛來只隔西江水。"]'),
('d74e9598-2653-4bb2-99b6-34f0f916858b','相和歌辭 玉樹後庭花','張祜','唐','唐诗','tang','','[]','輕車何草草，獨唱後庭花。',24,'全唐诗/poet.tang.1000.json','["輕車何草草，獨唱後庭花。", "玉座誰爲主，徒悲張麗華。"]'),
('639d9810-3074-4ec3-9d03-058b016ff14b','相和歌辭 堂堂','溫庭筠','唐','唐诗','tang','','[]','錢塘岸上春如織，淼淼寒潮帶晴色。',64,'全唐诗/poet.tang.1000.json','["錢塘岸上春如織，淼淼寒潮帶晴色。", "淮南遊客馬連嘶，碧草迷人歸不得。", "風飄客意如吹煙，纖指殷勤傷雁弦。", "一曲堂堂紅燭筵，金鯨瀉酒如飛泉。"]'),
('407210c8-10a9-412e-8dcb-2740914ddf70','相和歌辭 三閣詞四首 一','劉禹錫','唐','唐诗','tang','','[]','貴人三閣上，日晏未梳頭。',24,'全唐诗/poet.tang.1000.json','["貴人三閣上，日晏未梳頭。", "不應有恨事，嬌甚却成愁。"]'),
('8ca59348-308c-46a9-8472-cea3b91d7718','相和歌辭 三閣詞四首 二','劉禹錫','唐','唐诗','tang','','[]','珠箔曲瓊鉤，子細見揚州。',24,'全唐诗/poet.tang.1000.json','["珠箔曲瓊鉤，子細見揚州。", "北兵那得度，浪語判悠悠。"]'),
('fa1ecb79-ccad-4a2a-9194-7b86f872f0d1','相和歌辭 三閣詞四首 三','劉禹錫','唐','唐诗','tang','','[]','沈香帖閣柱，金縷畫門楣。',24,'全唐诗/poet.tang.1000.json','["沈香帖閣柱，金縷畫門楣。", "回首降幡下，已見黍離離。"]'),
('2f94d44f-4079-460f-bdbd-474e5519bcf5','相和歌辭 三閣詞四首 四','劉禹錫','唐','唐诗','tang','','[]','三人出眢井，一身登檻車。',24,'全唐诗/poet.tang.1000.json','["三人出眢井，一身登檻車。", "朱門漫臨水，不可見鱸魚。"]'),
('14539ccd-fbfb-4002-950f-e299956306aa','相和歌辭 神弦曲','李賀','唐','唐诗','tang','','[]','西山日沒東山昏，旋風吹馬馬踏雲。',80,'全唐诗/poet.tang.1000.json','["西山日沒東山昏，旋風吹馬馬踏雲。", "畫弦素管聲淺繁，花裙綷䌨步秋塵。", "桂葉刷風桂墜子，青狸哭血寒狐死。", "古壁彩虬金帖尾，雨工騎入秋潭水。", "百年老鴞成木魅，笑聲碧火巢中起。"]'),
('74c51375-f0ae-45b3-8148-57b7e256b868','相和歌辭 神弦別曲','李賀','唐','唐诗','tang','','[]','巫山小女隔雲別，松花春風山上發。',64,'全唐诗/poet.tang.1000.json','["巫山小女隔雲別，松花春風山上發。", "綠蓋獨穿香逕歸，白馬花竿前孑孑。", "蜀江風澹水如羅，墮蘭誰泛相經過。", "南山桂樹爲君死，雲衫殘汙紅脂花。"]'),
('753a6185-3664-44b5-adf5-1571e086c288','相和歌辭 祠漁山神女歌 迎神','王維','唐','唐诗','tang','','[]','坎坎擊鼓，漁山之下。',59,'全唐诗/poet.tang.1000.json','["坎坎擊鼓，漁山之下。", "吹洞簫，望極浦。", "女巫進，紛屢舞。", "陳瑤席，湛清酤。", "風淒淒，又夜雨。", "不知神之來兮不來，使我心兮苦復苦。"]'),
('54e23ca8-53b1-4dc7-ac69-06e4067f5ab4','相和歌辭 祠漁山神女歌 送神','王維','唐','唐诗','tang','','[]','紛進舞兮堂前，目眷眷兮瓊筵。',61,'全唐诗/poet.tang.1000.json','["紛進舞兮堂前，目眷眷兮瓊筵。", "來不言兮意不傳，作暮雨兮愁空山。", "悲急管兮思繁弦，神之駕兮儼欲旋。", "倏雲收兮雨歇，山青青兮水潺湲。"]'),
('96b177ab-60c1-44cf-bd9a-50fe4c4fc1eb','相和歌辭 祠神歌 迎神','王叡','唐','唐诗','tang','','[]','蓪草頭花椰葉裙，蒲葵樹下舞蠻雲。',32,'全唐诗/poet.tang.1000.json','["蓪草頭花椰葉裙，蒲葵樹下舞蠻雲。", "引領望江遙滴酒，白蘋風起水生文。"]'),
('57ea34b3-5fb6-46b0-8686-c55fa62fdf55','相和歌辭 祠神歌 送神','王叡','唐','唐诗','tang','','[]','棖棖山響荅琵琶，酒溼青莎肉飼鵶。',32,'全唐诗/poet.tang.1000.json','["棖棖山響荅琵琶，酒溼青莎肉飼鵶。", "樹葉無聲神去後，紙錢灰出木綿花。"]'),
('d2a74a11-b43a-448c-9f5d-e895c9e60ec8','相和歌辭 烏夜啼','楊巨源','唐','唐诗','tang','','[]','可憐楊葉復楊花，雪淨煙深碧玉家。',48,'全唐诗/poet.tang.1000.json','["可憐楊葉復楊花，雪淨煙深碧玉家。", "烏棲不定枝條弱，城頭夜半聲啞啞。", "浮萍搖蕩門前水，任罥芙蓉莫墮沙。"]'),
('13451903-5007-4425-aacd-921c8124af6d','相和歌辭 烏夜啼','李白','唐','唐诗','tang','','["\u7231\u60c5", "\u8ffd\u5fc6", "\u5973\u5b50"]','黃雲城邊烏欲棲，歸飛啞啞枝上啼。',48,'全唐诗/poet.tang.1000.json','["黃雲城邊烏欲棲，歸飛啞啞枝上啼。", "機中織錦秦川女，碧紗如煙隔窗語。", "停梭悵然憶遠人，獨宿孤房淚如雨。"]'),
('1379e240-3f5a-4133-adfb-584726beff54','相和歌辭 烏夜啼二首 一','顧況','唐','唐诗','tang','','[]','玉房掣鎖聲翻葉，銀箭添泉遶霜堞。',72,'全唐诗/poet.tang.1000.json','["玉房掣鎖聲翻葉，銀箭添泉遶霜堞。", "畢逋發刺月銜城，八九雛飛其母驚。", "此是天上老鵶鳴，人間老鵶無此聲。", "搖雜佩，耿華燭，良夜羽人彈此曲，東方曈曈赤日旭。"]'),
('6eaddc9d-e02c-4dbf-b048-2ba87ef3cecd','相和歌辭 烏夜啼二首 二','顧況','唐','唐诗','tang','','[]','月出江林西，江林寂寂城鵶啼。',46,'全唐诗/poet.tang.1000.json','["月出江林西，江林寂寂城鵶啼。", "昔人何處爲此曲？今人何處聽不足。", "城寒月曉馳思深，江上青草爲誰綠。"]'),
('dc1124b1-22cb-4556-8078-54998b4973f7','相和歌辭 烏夜啼','李羣玉','唐','唐诗','tang','','[]','曾波隔夢渚，一望青楓林。',96,'全唐诗/poet.tang.1000.json','["曾波隔夢渚，一望青楓林。", "有烏在其間，達曉自悲吟。", "是時月黑天，四野煙雨深。", "如聞生離哭，其聲痛人心。", "悄悄夜正長，空山響哀音。", "遠客不可聽，坐愁華髮侵。", "既非蜀帝魂，恐是恆山禽。", "四子各分散，母聲猶至今。"]'),
('5c9f73b3-1088-48aa-b4c6-8506d0047799','相和歌辭 烏夜啼','聶夷中','唐','唐诗','tang','','[]','衆鳥各歸枝，烏烏爾不棲。',24,'全唐诗/poet.tang.1000.json','["衆鳥各歸枝，烏烏爾不棲。", "還應知妾恨，故向綠窗啼。"]'),
('c4dbdb10-93e6-4174-84d9-0ca91e4171a6','相和歌辭 烏夜啼','白居易','唐','唐诗','tang','','[]','城上歸時晚，庭前宿處危。',48,'全唐诗/poet.tang.1000.json','["城上歸時晚，庭前宿處危。", "月明無葉樹，霜滑有風枝。", "啼澀飢喉咽，飛低凍翅垂。", "畫堂鸚鵡鳥，冷暖不相知。"]'),
('5fcd98df-b017-4b6b-8c1d-441bab09b03c','相和歌辭 烏夜啼','王建','唐','唐诗','tang','','[]','庭樹烏，爾何不向別處棲？',84,'全唐诗/poet.tang.1000.json','["庭樹烏，爾何不向別處棲？", "夜夜夜半當戶啼。", "家人把燭出洞戶，驚棲失羣飛落樹。", "一飛直欲飛上天，回回不離舊棲處。", "未明重繞主人屋，欲下空中黑相觸。", "風飄雨溼亦不移，君家樹頭多好枝。"]'),
('1954c0fe-9100-4652-b9ee-4ae3dc34ac45','相和歌辭 烏夜啼','張祜','唐','唐诗','tang','','[]','忽忽南飛返，危弦共怨悽。',48,'全唐诗/poet.tang.1000.json','["忽忽南飛返，危弦共怨悽。", "暗霜移樹宿，殘夜遶枝啼。", "咽絕聲重敍，愔淫思乍迷。", "不妨還報喜，誤使玉顏低。"]'),
('4a650c60-d583-479e-b014-f72ae071cdc4','相和歌辭 烏棲曲','李白','唐','唐诗','tang','','[]','姑蘇臺上烏棲時，吳王宮裏醉西施。',32,'全唐诗/poet.tang.1000.json','["姑蘇臺上烏棲時，吳王宮裏醉西施。", "吳歌楚舞歡未畢，青山猶銜半邊日。"]'),
('61b19827-d759-4f46-ad60-4c95661e7021','相和歌辭 烏棲曲','李端','唐','唐诗','tang','','[]','白馬逐牛車，黃昏入狹斜。',44,'全唐诗/poet.tang.1000.json','["白馬逐牛車，黃昏入狹斜。", "狹斜柳樹烏爭宿，爭枝未得飛上屋。", "東房少婦壻從軍，每聽烏啼知夜分。"]'),
('84e93985-8694-48cd-af67-054478b5a597','相和歌辭 烏棲曲','王建','唐','唐诗','tang','','[]','章華宮人夜上樓，君王望月西山頭。',32,'全唐诗/poet.tang.1000.json','["章華宮人夜上樓，君王望月西山頭。", "夜深宮殿門不鎖，白露滿山山葉墮。"]'),
('f859f612-323e-45ba-aad9-18cf91428424','相和歌辭 烏棲曲','張籍','唐','唐诗','tang','','[]','西山作宮潮滿池，宮烏曉鳴茱萸枝。',32,'全唐诗/poet.tang.1000.json','["西山作宮潮滿池，宮烏曉鳴茱萸枝。", "吳姬自唱采蓮曲，君王昨夜舟中宿。"]'),
('14ac7bda-d0fc-47fd-b824-b71f6ebfe7b2','相和歌辭 棲烏曲二首 一','劉方平','唐','唐诗','tang','','[]','蛾眉曼臉傾城國，鳴環動佩新相識。',32,'全唐诗/poet.tang.1000.json','["蛾眉曼臉傾城國，鳴環動佩新相識。", "銀漢斜臨白玉堂，芙蓉行障掩燈光。"]'),
('08c6ae60-efc8-4fc0-b9c8-0aaed09a803f','相和歌辭 棲烏曲二首 二','劉方平','唐','唐诗','tang','','[]','畫舸雙艚錦爲纜，芙蓉花發蓮葉暗。',32,'全唐诗/poet.tang.1000.json','["畫舸雙艚錦爲纜，芙蓉花發蓮葉暗。", "門前月色映橫塘，感郎中夜渡瀟湘。"]'),
('7ac317e6-a69f-4e17-b73a-f7775331b25d','相和歌辭 莫愁樂','張祜','唐','唐诗','tang','','[]','儂居石城下，郎到石城遊。',24,'全唐诗/poet.tang.1000.json','["儂居石城下，郎到石城遊。", "自郎石城出，長在石城頭。"]'),
('5cecf507-4b41-428f-ba64-141d0c7492b7','相和歌辭 莫愁曲','李賀','唐','唐诗','tang','','[]','草生隴坂下，鵶噪城堞頭。',96,'全唐诗/poet.tang.1000.json','["草生隴坂下，鵶噪城堞頭。", "何人此城裏，城角栽石榴。", "青絲繫五馬，黃金絡雙牛。", "白魚駕蓮船，夜作十里遊。", "歸來無人識，暗上沈香樓。", "羅牀倚瑤瑟，殘月傾簾鉤。", "今日槿花落，明朝梧樹秋。", "若負平生意，何名作莫愁。"]'),
('aadd63e4-92bc-4d8d-9272-94e63ac260a8','相和歌辭 估客樂','李白','唐','唐诗','tang','','["\u5199\u4eba", "\u6f02\u6cca", "\u5199\u4eba\u8bd7"]','海客乘天風，將船遠行役。',24,'全唐诗/poet.tang.1000.json','["海客乘天風，將船遠行役。", "譬如雲中鳥，一去無蹤跡。"]'),
('49a7fdb4-f899-42a1-a13f-8397020dc267','相和歌辭 估客樂','元稹','唐','唐诗','tang','','[]','估客無住著，有利身即行。',288,'全唐诗/poet.tang.1000.json','["估客無住著，有利身即行。", "出門求火伴，入戶辭父兄。", "父兄相教示，求利莫求名。", "求名有所避，求利無不營。", "火伴相勒縛，賣假莫賣誠。", "交關少交假，交假本生輕。", "自茲相將去，誓死意不更。", "一解市頭語，便無鄉里情。", "鍮石打臂釧，糯米炊項瓔。", "歸來村中賣，敲作金玉聲。", "村中田舍娘，貴賤不敢爭。", "所費百錢本，已得十倍贏。", "顏色轉光淨，飲食亦甘馨。", "子本頻蕃息，貨賂日兼幷。", "求珠駕滄海，采玉上荆衡。", "北買党項馬，西擒吐蕃鸚。", "炎洲布火浣，蜀地錦織成。", "越婢脂肉滑，奚僮眉眼明。", "通算衣食費，不計遠近程。", "經營天下徧，却到長安城。", "城中東西市，聞客次第迎。", "迎客兼說客，多財爲勢傾。", "客心本明黠，聞語心已驚。", "先問十常侍，次求百公卿。"]'),
('bee0dc6f-92c2-4285-8e0a-8f36529025b7','相和歌辭 賈客樂','張籍','唐','唐诗','tang','','[]','金陵向西賈客多，船中生長樂風波。',128,'全唐诗/poet.tang.1000.json','["金陵向西賈客多，船中生長樂風波。", "欲發移船近江口，船頭祭神各澆酒。", "停杯共說遠行期，入蜀經蠻遠別離。", "金多衆中爲上客，夜夜算緡眠獨遲。", "秋江初月猩猩語，孤帆夜發滿湘渚。", "水工持檝防暗灘，直過山邊及前侶。", "年年逐利西復東，姓名不在縣籍中。", "農夫稅多長辛苦，棄業長爲販賣翁。"]'),
('33dfbf78-71db-4d5f-bba2-4832620a2f8f','相和歌辭 賈客詞','劉禹錫','唐','唐诗','tang','','[]','賈客無定遊，所遊惟利幷。',132,'全唐诗/poet.tang.1000.json','["賈客無定遊，所遊惟利幷。", "眩俗雜良苦，乘時知重輕。", "心計析秋毫，搖鉤侔懸衡。", "錐刀既無棄，轉化日已盈。", "邀福禱波神，施財遊化城。", "妻約雕金釧，女垂貫珠纓。", "高貲比封君，奇貨通倖卿。", "趨時鷙鳥思，藏鏹盤龍形。", "大艑浮通川，高樓次旗亭。", "行止皆有樂，關梁似無征。", "農夫何爲者？辛苦事寒耕。"]'),
('50e90a6b-8c23-493e-be1b-63ca5d30010c','相和歌辭 賈客詞','劉駕','唐','唐诗','tang','','[]','賈客燈下起，猶言發已遲。',72,'全唐诗/poet.tang.1000.json','["賈客燈下起，猶言發已遲。", "高山有疾路，暗行終不疑。", "寇盜伏其路，猛獸來相追。", "金玉四散去，空囊委路岐。", "揚州有大宅，白骨無地歸。", "少婦當此日，對鏡弄花枝。"]'),
('0dc28dbc-d080-47fc-b44a-229e310c187a','相和歌辭 襄陽樂','張祜','唐','唐诗','tang','','["\u957f\u6c5f"]','大堤花月夜，長江春水流。',24,'全唐诗/poet.tang.1000.json','["大堤花月夜，長江春水流。", "東風正上信，春夜特來遊。"]'),
('9322a025-9168-4abc-a815-1d4a235cee67','相和歌辭 襄陽曲二首 一','崔國輔','唐','唐诗','tang','','[]','蕙草嬌紅蕚，時光舞碧雞。',24,'全唐诗/poet.tang.1000.json','["蕙草嬌紅蕚，時光舞碧雞。", "城中美年少，相見白銅鞮。"]'),
('9b0a9bf8-1708-44c2-ad48-e7bbfd01583e','相和歌辭 襄陽曲二首 二','崔國輔','唐','唐诗','tang','','[]','少年襄陽地，來往襄陽城。',24,'全唐诗/poet.tang.1000.json','["少年襄陽地，來往襄陽城。", "城中輕薄子，知妾解秦箏。"]'),
('6b074b75-44be-4068-bc31-c4f2cea7287f','相和歌辭 襄陽曲','施肩吾','唐','唐诗','tang','','[]','大堤女兒郎莫尋，三三五五結同心。',32,'全唐诗/poet.tang.1000.json','["大堤女兒郎莫尋，三三五五結同心。", "清晨對鏡冶容色，意欲取郎千萬金。"]'),
('cecb680e-5015-4391-8108-4bde2026cd28','相和歌辭 襄陽曲','李端','唐','唐诗','tang','','[]','襄陽堤路長，草碧楊柳黃。',76,'全唐诗/poet.tang.1000.json','["襄陽堤路長，草碧楊柳黃。", "誰家女兒臨夜妝，紅羅帳裏有燈光。", "雀釵翠羽動明璫，欲出不出脂粉香。", "同居女伴正衣裳，中庭寒月白如霜。", "賈生十八稱才子，空得門前一斷腸。"]'),
('d05f4524-071a-4914-97f3-bed8e9683a48','相和歌辭 大堤曲','張柬之','唐','唐诗','tang','','[]','南國多佳人，莫若大堤女。',48,'全唐诗/poet.tang.1000.json','["南國多佳人，莫若大堤女。", "玉牀翠羽帳，寶袜蓮花炬。", "魂處自目成，色授開心許。", "迢迢不可見，日暮空愁予。"]'),
('55b11522-995c-490d-ada6-d82404b72473','相和歌辭 大堤曲','楊巨源','唐','唐诗','tang','','[]','二八嬋娟大堤女，開鑪相對依江渚。',128,'全唐诗/poet.tang.1000.json','["二八嬋娟大堤女，開鑪相對依江渚。", "待客登樓向水看，邀郎卷幔臨花語。", "細雨濛濛溼芰荷，巴東商侶挂帆多。", "自傳芳酒涴紅袖，誰調妍妝迴翠蛾。", "珍簟華燈夕陽後，當鑪理瑟矜纖手。", "月落星微五鼓聲，春風搖蕩窗前柳。", "歲歲逢迎沙岸間，北人多識綠雲鬟。", "無端嫁與五陵少，離別煙波傷玉顏。"]'),
('8c1974fa-bf89-4fec-9ea1-bdc9dff1cd6e','相和歌辭 大堤曲','李白','唐','唐诗','tang','','["\u89e6\u666f\u4f24\u60c5", "\u6e05\u5546\u66f2\u8f9e", "\u601d\u4e61", "\u4e50\u5e9c"]','漢水臨襄陽，花開大堤暖。',48,'全唐诗/poet.tang.1000.json','["漢水臨襄陽，花開大堤暖。", "佳期大堤下，淚向南雲滿。", "春風復無情，吹我夢魂散。", "不見眼中人，天長音信斷。"]'),
('64a84913-0d25-4120-8b74-8c2a8d8815c7','相和歌辭 大堤曲','李賀','唐','唐诗','tang','','["\u7231\u60c5", "\u5973\u5b50"]','妾家住橫塘，紅紗滿桂香。',80,'全唐诗/poet.tang.1000.json','["妾家住橫塘，紅紗滿桂香。", "青雲教綰頭上髻，明月與作耳邊璫。", "蓮風起，江畔春。", "大堤上，留北人。", "郎食鯉魚尾，妾食猩猩脣。", "莫指襄陽道，綠浦歸帆少。", "今日菖蒲花，明朝楓樹老。"]'),
('5022a1cb-449b-4dcc-8b78-33e9e5914d02','相和歌辭 大堤行','孟浩然','唐','唐诗','tang','','[]','大堤行樂處，車馬相馳突。',48,'全唐诗/poet.tang.1000.json','["大堤行樂處，車馬相馳突。", "歲歲春草生，踏青二三月。", "王孫挾珠彈，遊女矜羅韈。", "攜手今莫同，江花爲誰發。"]'),
('eba1e722-419d-4f72-9c78-07ab2d9bfa84','相和歌辭 三洲歌','溫庭筠','唐','唐诗','tang','','[]','團圓莫作波中月，潔白莫爲枝上雪。',64,'全唐诗/poet.tang.1000.json','["團圓莫作波中月，潔白莫爲枝上雪。", "月隨波動碎潾潾，雪似梅花不堪折。", "李娘十六青絲髮，畫帶雙花爲君結。", "門前有路輕離別，惟恐歸來舊香滅。"]'),
('eab098c6-ae6f-453c-9d58-43cd1f1e2abb','相和歌辭 拔蒲歌','張祜','唐','唐诗','tang','','[]','拔蒲來，領郎鏡湖邊。',34,'全唐诗/poet.tang.1000.json','["拔蒲來，領郎鏡湖邊。", "郎心在何處？莫趂新蓮去。", "拔得無心蒲，問郎看好無。"]'),
('b343dfb8-3432-42f9-affd-9d096f5b5b5e','相和歌辭 楊叛兒','李白','唐','唐诗','tang','','["\u4e50\u66f2", "\u6e05\u5546\u66f2\u8f9e", "\u4e50\u5e9c"]','君歌楊叛兒，妾勸新豐酒。',52,'全唐诗/poet.tang.1000.json','["君歌楊叛兒，妾勸新豐酒。", "何許最關人，烏啼白門柳。", "烏啼隱楊花，君醉留妾家。", "博山爐中沈香火，雙咽一氣凌紫霞。"]'),
('7788b533-8d77-41b7-a401-9e1f4cb66182','相和歌辭 常林歡','溫庭筠','唐','唐诗','tang','','[]','宜城酒熟花覆橋，沙晴綠鴨鳴咬咬。',64,'全唐诗/poet.tang.1000.json','["宜城酒熟花覆橋，沙晴綠鴨鳴咬咬。", "穠桑繞舍麥如尾，幽軋鳴機雙燕巢。", "馬聲特特荆門道，蠻水揚光色如草。", "錦薦金爐夢正長，東家呃喔雞鳴早。"]'),
('54b45313-84ba-446a-9cbe-f58304b1c29b','相和歌辭 江南弄','王勃','唐','唐诗','tang','','[]','江南弄，巫山連楚夢，行雨行雲幾相送。',66,'全唐诗/poet.tang.1000.json','["江南弄，巫山連楚夢，行雨行雲幾相送。", "瑤軒金谷上春時，玉童仙女無見期。", "紫露香煙眇難託，清風明月遙相思。", "遙相思，草徒綠，爲聽雙飛鳳凰曲。"]'),
('29d98345-e050-49c2-89cb-88dbdcd0af97','相和歌辭 江南弄','李賀','唐','唐诗','tang','','[]','江中綠霧起涼波，天上疊巘紅嵯峨。',64,'全唐诗/poet.tang.1000.json','["江中綠霧起涼波，天上疊巘紅嵯峨。", "水風浦雲生老竹，渚瞑蒲帆如一幅。", "鱸魚千頭酒百斛，酒中倒臥南山綠。", "吳歈越吟未終曲，江上團團帖寒玉。"]'),
('6d8fb7db-36fd-40f1-b120-dc58e0d8b039','相和歌辭 采蓮曲','崔國輔','唐','唐诗','tang','','[]','玉溆花紅發，金塘水碧流。',24,'全唐诗/poet.tang.1000.json','["玉溆花紅發，金塘水碧流。", "相逢畏相失，並著采蓮舟。"]'),
('3f27da66-1e73-4bee-91a4-9de2d9545fc2','相和歌辭 采蓮曲','徐彥伯','唐','唐诗','tang','','[]','妾家越水邊，搖艇入江煙。',48,'全唐诗/poet.tang.1000.json','["妾家越水邊，搖艇入江煙。", "既覓同心侶，復采同心蓮。", "折藕絲能脆，開花葉正圓。", "春歌弄明月，歸棹落花前。"]'),
('b98a1f96-5eaa-4d8d-ae39-4a7a38b6eb1e','相和歌辭 采蓮曲','李白','唐','唐诗','tang','','["\u6e05\u5546\u66f2\u8f9e", "\u5973\u5b50", "\u4e50\u5e9c", "\u8377\u82b1"]','若耶溪邊采蓮女，笑隔荷花共人語。',64,'全唐诗/poet.tang.1000.json','["若耶溪邊采蓮女，笑隔荷花共人語。", "日照新妝水底明，風飄香袖空中舉。", "岸上誰家遊冶郎，三三五五映垂楊。", "紫騮嘶入落花去，見此踟躕空斷腸。"]'),
('04adc73f-5d2d-4a17-9254-28a80a52069f','相和歌辭 采蓮曲','賀知章','唐','唐诗','tang','','[]','稽山罷霧鬱嵯峨，鏡水無風也自波。',32,'全唐诗/poet.tang.1000.json','["稽山罷霧鬱嵯峨，鏡水無風也自波。", "莫言春度芳菲盡，別有中流采芰荷。"]'),
('fc566dcd-4892-4c67-87ad-6f65ff3b4e04','相和歌辭 采蓮曲三首 一','王昌齡','唐','唐诗','tang','','[]','吳姬越豔楚王妃，爭弄蓮舟水溼衣。',32,'全唐诗/poet.tang.1000.json','["吳姬越豔楚王妃，爭弄蓮舟水溼衣。", "來時浦口花迎入，采罷江頭月送歸。"]'),
('eac61312-dec6-4712-a34a-9a71969af9d5','相和歌辭 采蓮曲三首 二','王昌齡','唐','唐诗','tang','','["\u5c11\u5973", "\u690d\u7269", "\u5199\u666f"]','荷葉羅裙一色裁，芙蓉向臉兩邊開。',32,'全唐诗/poet.tang.1000.json','["荷葉羅裙一色裁，芙蓉向臉兩邊開。", "亂入池中看不見，聞歌始覺有人來。"]'),
('efce77ad-b87b-4f3f-a33f-5732adb9440e','相和歌辭 采蓮曲三首 三','王昌齡','唐','唐诗','tang','','[]','越女作桂舟，還將桂爲檝。',36,'全唐诗/poet.tang.1000.json','["越女作桂舟，還將桂爲檝。", "湖上水渺漫，清江初可涉。", "摘取芙蓉花，莫摘芙蓉葉。"]'),
('2036833d-b04f-49fe-b709-3eccd090f147','相和歌辭 采蓮曲二首 一','戎昱','唐','唐诗','tang','','[]','雖聽采蓮曲，詎識采蓮心。',48,'全唐诗/poet.tang.1000.json','["雖聽采蓮曲，詎識采蓮心。", "漾檝愛花遠，回船愁浪深。", "煙生極浦色，日落半江陰。", "同侶憐波靜，看妝墮玉簪。"]'),
('6b2be4af-0264-4adc-80c4-0691ad752f41','相和歌辭 采蓮曲二首 二','戎昱','唐','唐诗','tang','','[]','涔陽女兒花滿頭，毿毿同汎木蘭舟。',32,'全唐诗/poet.tang.1000.json','["涔陽女兒花滿頭，毿毿同汎木蘭舟。", "春風日暮南湖裏，爭唱菱歌不肯休。"]'),
('bbe77207-c21e-4f74-9e94-fee4f8cb57fc','相和歌辭 采蓮曲','儲光羲','唐','唐诗','tang','','[]','淺渚荷花繁，深塘菱葉疎。',72,'全唐诗/poet.tang.1000.json','["淺渚荷花繁，深塘菱葉疎。", "獨往方自得，恥邀淇上姝。", "廣江無術阡，大澤絕方隅。", "浪中海童語，流下鮫人居。", "春雁時隱舟，新荷復滿湖。", "采采乘日暮，不思賢與愚。"]'),
('5aee2c13-785a-4735-8a13-069d126a37f6','相和歌辭 采蓮曲二首 一','鮑溶','唐','唐诗','tang','','[]','弄舟朅來南塘水，荷葉映身摘蓮子。',48,'全唐诗/poet.tang.1000.json','["弄舟朅來南塘水，荷葉映身摘蓮子。", "暑衣清淨鴛鴦喜，作浪舞花驚不起。", "殷勤護惜纖纖指，水菱初熟多新刺。"]'),
('4a4822fe-71f9-448f-923f-ea4061d09e2f','相和歌辭 采蓮曲二首 二','鮑溶','唐','唐诗','tang','','[]','采蓮朅來水無風，蓮潭如鏡松如龍。',40,'全唐诗/poet.tang.1000.json','["采蓮朅來水無風，蓮潭如鏡松如龍。", "夏衫短袖交斜紅，豔歌笑鬬新芙蓉，戲魚住聽蓮花東。"]'),
('9ee9b746-0c42-41af-bd85-630f391f7c59','相和歌辭 采蓮曲','張籍','唐','唐诗','tang','','["\u5730\u65b9", "\u5199\u83b2", "\u5199\u4eba", "\u5199\u4eba\u8bd7"]','秋江岸邊蓮子多，采蓮女兒凭船歌。',96,'全唐诗/poet.tang.1000.json','["秋江岸邊蓮子多，采蓮女兒凭船歌。", "青房圓實齊戢戢，爭前競折蕩漾波。", "試牽綠莖下尋藕，斷處絲多刺傷手。", "白練束腰袖半卷，不插玉釵妝梳淺。", "船中未滿度前洲，借問誰家家住遠。", "歸時共待暮潮上，自弄芙蓉還蕩槳。"]'),
('2d07a19f-fe9d-467d-a06a-a8795cb13783','相和歌辭 采蓮曲','白居易','唐','唐诗','tang','','["\u5973\u5b50", "\u7231\u60c5", "\u8377\u82b1"]','菱葉縈波荷颭風，荷花深處小船通。',32,'全唐诗/poet.tang.1000.json','["菱葉縈波荷颭風，荷花深處小船通。", "逢郎欲語低頭笑，碧玉搔頭落水中。"]'),
('a5f2d36f-9597-41a7-99cc-5ff88b7c8c79','相和歌辭 采蓮曲','僧齊己','唐','唐诗','tang','','[]','越江女，越江蓮。',76,'全唐诗/poet.tang.1000.json','["越江女，越江蓮。", "齊菡萏，雙嬋娟。", "嬉遊向何處？", "采摘且同船。", "浩唱發容與，清波生漪漣。", "時逢島嶼泊，幾共鴛鴦眠。", "襟袖既盈溢，馨香亦相傳。", "薄暮歸去來，苧羅生碧煙。"]'),
('1f0f728d-0c02-4fd4-9976-ba6f0cba1c12','相和歌辭 采蓮歸','王勃','唐','唐诗','tang','','[]','采蓮歸，綠水芙蓉衣，秋風起浪鳧雁飛。',242,'全唐诗/poet.tang.1000.json','["采蓮歸，綠水芙蓉衣，秋風起浪鳧雁飛。", "桂棹蘭橈下長浦，羅裙玉腕搖輕櫓。", "葉嶼花潭極望平，江謳越吹相思苦。", "相思苦，佳期不可駐。", "塞外征夫猶未還，江南采蓮今已暮。", "今已暮，摘蓮花，今渠那必盡倡家。", "官道城南把桑葉，何如江上采蓮花？", "蓮花復蓮花，花葉何重疊。", "葉翠本羞眉，花紅彊如頰。", "佳人不茲期，悵望別離時。", "牽花憐共蒂，折藕愛連絲。", "故情何處所？新物徒華滋。", "不惜南津交佩解，還羞北海雁書遲。", "采蓮歌有節，采蓮夜未歇。", "正逢浩蕩江上風，又值徘徊江上月。", "蓮浦夜相逢，吳姬越女何丰茸。", "共問寒江千里外，征客關山更幾重。"]'),
('2ff96bd0-5cde-4fff-aa80-de11819ccd23','相和歌辭 采蓮女','閻朝隱','唐','唐诗','tang','','[]','采蓮女，采蓮舟，春日春江碧水流。',44,'全唐诗/poet.tang.1000.json','["采蓮女，采蓮舟，春日春江碧水流。", "蓮衣承玉釧，蓮刺罥銀鉤。", "薄暮斂容歌一曲，氛氳香氣滿汀洲。"]'),
('3dabbe1b-2f16-498b-a1e7-be13ab466eca','相和歌辭 湖邊采蓮婦','李白','唐','唐诗','tang','','["\u5199\u4eba", "\u5987\u5973", "\u5199\u4eba\u8bd7"]','小姑織白紵，未解將人語。',48,'全唐诗/poet.tang.1000.json','["小姑織白紵，未解將人語。", "大嫂采芙蓉，溪湖千萬重。", "長兄行不在，莫使外人逢。", "願學秋胡婦，真心比古松。"]'),
('a782bd15-160a-4ffd-803e-35334740fbff','相和歌辭 張靜婉采蓮曲','溫庭筠','唐','唐诗','tang','','[]','蘭膏墜髮紅玉春，燕釵拖頸拋盤雲。',161,'全唐诗/poet.tang.1000.json','["蘭膏墜髮紅玉春，燕釵拖頸拋盤雲。", "城西楊柳向嬌晚，門前溝水波潾潾。", "麒麟公子朝天客，珮馬璫璫鐺度春陌。", "掌中無力舞衣輕，翦斷鮫綃破春碧。", "抱月飄煙一尺腰，麝臍龍髓憐嬌饒。", "秋羅拂衣碎光動，露重花多香不銷。", "鸂鶒膠膠塘水滿，綠萍如粟蓮莖短。", "一夜西風送雨來，粉痕零落愁紅淺。", "船頭折藕絲暗牽，藕根蓮子相留連。", "郎心似月月易缺，十五十六清光圓。"]'),
('ac2ea361-8c0d-4c98-b95e-bfcc95443067','相和歌辭 鳳笙曲','沈佺期','唐','唐诗','tang','','[]','憶昔王子晉，鳳笙遊雲空。',48,'全唐诗/poet.tang.1000.json','["憶昔王子晉，鳳笙遊雲空。", "揮手弄白日，安能戀青宮。", "豈無嬋娟子，結念羅帳中。", "憐壽不貴色，身世兩無窮。"]'),
('08746182-6421-4271-a4fd-35fef6bf09f5','相和歌辭 鳳吹笙曲','李白','唐','唐诗','tang','','["\u4e0d\u820d", "\u79bb\u522b", "\u9001\u522b"]','仙人十五愛吹笙，學得崑丘彩鳳鳴。',128,'全唐诗/poet.tang.1000.json','["仙人十五愛吹笙，學得崑丘彩鳳鳴。", "始聞鍊氣餐金液，復道朝天赴玉京。", "玉京迢迢幾千里，鳳笙去去無邊已。", "欲歎離聲發絳脣，更嗟別調流纖指。", "此時惜別詎堪聞，此地相看未忍分。", "重吟真曲和清吹，却奏仙歌響綠雲。", "綠雲紫氣向函關，訪道應尋緱氏山。", "莫學吹笙王子晉，一遇浮丘斷不還。"]'),
('11626f58-4066-4818-b22d-d23bd4b25a9b','相和歌辭 采菱曲','儲光羲','唐','唐诗','tang','','[]','濁水菱葉肥，清水菱葉鮮。',96,'全唐诗/poet.tang.1000.json','["濁水菱葉肥，清水菱葉鮮。", "義不游濁水，志士多苦言。", "潮沒具區藪，潦深雲夢田。", "朝隨北風去，暮逐南風還。", "浦口多漁家，相與邀我船。", "飯稻以終日，羹蓴將永年。", "方冬水物窮，又欲休山樊。", "盡室相隨從，所貴無憂患。"]'),
('303d9236-55b2-4dea-8967-74d66f440450','相和歌辭 采菱行','劉禹錫','唐','唐诗','tang','','[]','白馬湖平秋日光，紫菱如錦綵鸞翔。',160,'全唐诗/poet.tang.1000.json','["白馬湖平秋日光，紫菱如錦綵鸞翔。", "盪舟遊女滿中央，采菱不顧馬上郎。", "爭多逐勝紛相向，時轉蘭橈破輕浪。", "長鬟弱袂動參差，釵影釧文浮蕩漾。", "笑語哇咬顧晚暉，蓼花綠岸扣舷歸。", "歸來共到市橋步，野蔓繫船萍滿衣。", "家家竹樓臨廣陌，下有連檣多估客。", "攜觴薦芰夜經過，醉踏大堤相應歌。", "屈平祠下沅江水，月照寒波白煙起。", "一曲南音此地聞，長安北望三千里。"]'),
('c5a58448-98ea-4e6f-b2b3-d3c04f93d3fa','相和歌辭 陽春歌','李白','唐','唐诗','tang','','["\u6e05\u5546\u66f2\u8f9e", "\u6625\u5929", "\u4e50\u5e9c", "\u60dc\u6625"]','長安白日照春空，綠楊結煙桑褭風。',56,'全唐诗/poet.tang.1000.json','["長安白日照春空，綠楊結煙桑褭風。", "披香殿前花始紅，流芳發色繡戶中。", "繡戶中，相經過。", "飛燕皇后輕身舞，紫宮夫人絕世歌。"]'),
('fed32503-f4b9-47b0-8a8a-0d674b54aaa2','相和歌辭 陽春曲','溫庭筠','唐','唐诗','tang','','[]','雲母空窗曉煙薄，香昏龍氣凝輝閣。',64,'全唐诗/poet.tang.1000.json','["雲母空窗曉煙薄，香昏龍氣凝輝閣。", "霏霏霧雨杏花天，簾外春威著羅幕。", "曲欄伏檻金麒麟，沙苑芳郊連翠茵。", "廐馬何能齧芳草，路人不敢隨流塵。"]'),
('5fb6e6f3-551d-4f6b-8e7e-259bc409c3c0','相和歌辭 陽春曲','莊南傑','唐','唐诗','tang','','[]','紫錦紅囊香滿風，金鸞玉軾搖丁冬。',64,'全唐诗/poet.tang.1000.json','["紫錦紅囊香滿風，金鸞玉軾搖丁冬。", "沙鷗白羽翦晴碧，野桃紅豔燒春空。", "芳草綿延鎖平地，壠蝶雙雙舞幽翠。", "鳳叫龍吟白日長，落花聲底仙娥醉。"]'),
('249801a1-6d2e-4b26-9daf-10ab3aa0fa5b','相和歌辭 陽春曲','僧貫休','唐','唐诗','tang','','[]','爲口莫學阮嗣宗，不言是非非至公。',64,'全唐诗/poet.tang.1000.json','["爲口莫學阮嗣宗，不言是非非至公。", "爲手須似朱雲輩，折檻英風至今在。", "男兒結髮事君親，須斅前賢多慷慨。", "歷數雍熙房與杜，魏公姚公宋開府。"]'),
('a73d7bc0-d427-4363-9cff-b17eecd95e9d','相和歌辭 朝雲引','郎大家宋氏','唐','唐诗','tang','','[]','巴西巫峽指巴東，朝雲觸石上朝空。',50,'全唐诗/poet.tang.1000.json','["巴西巫峽指巴東，朝雲觸石上朝空。", "巫山巫峽高何已，行雨行雲一時起。", "一時起，三春暮。", "若言來，且就陽臺路。"]'),
('e1863f14-2d00-47ca-bb8c-3996c3bacb2a','相和歌辭 上雲樂','李白','唐','唐诗','tang','','["\u53d9\u4e8b", "\u795e\u8bdd", "\u4e50\u5e9c", "\u6742\u6b4c\u8c23\u8f9e"]','金天之西，白日所沒。',296,'全唐诗/poet.tang.1000.json','["金天之西，白日所沒。", "康老胡雛，生彼月窟。", "巉巖儀容，[戌]削風骨。", "碧玉炅炅雙目瞳，黃金拳拳兩鬢紅。", "華蓋垂下睫，嵩嶽臨上脣。", "不覩譎詭貌，豈知造化神。", "大道是文康之嚴父，元氣乃文康之老親。", "撫頂弄盤古，推車轉天輪。", "云見日月初生時，鑄冶火精與水銀。", "陽烏未出谷，顧兔半藏身。", "女媧戲黃土，團作愚下人。", "散在六合間，濛濛如沙塵。", "生死了不盡，誰明此胡是仙真。", "西海栽若木，東溟植扶桑。", "別來幾多時，枝葉萬里長。", "中國有七聖，半路頹鴻荒。", "陛下應運起，龍飛入咸陽。", "赤眉立盆子，白水興漢光。", "叱咤四海動，洪濤爲簸揚。", "舉足蹋紫微，天關自開張。", "老胡感至德，東來進仙倡。", "五色師子，九苞鳳凰。", "是老胡雞犬，鳴舞飛帝鄉。", "淋灕颯沓，進退成行。"]'),
('22abc39e-e43e-4644-97f0-08053b5fa3ee','相和歌辭 上雲樂','李賀','唐','唐诗','tang','','[]','飛香走紅滿天春，花龍盤盤上紫雲。',64,'全唐诗/poet.tang.1000.json','["飛香走紅滿天春，花龍盤盤上紫雲。", "三千宮女列金屋，五十弦瑟海上聞。", "大江碎碎銀沙路，嬴女機中斷煙素。", "斷煙素，縫舞衣，八月一日君前舞。"]'),
('df572f9e-bc85-4b4b-bf6a-05b06c3244dc','相和歌辭 鳳臺曲','王無競','唐','唐诗','tang','','[]','鳳臺何逶迤，嬴女管參差。',48,'全唐诗/poet.tang.1000.json','["鳳臺何逶迤，嬴女管參差。", "一旦綵雲至，身去無還期。", "遺曲此臺上，世人多學吹。", "一吹一落淚，至今憐玉姿。"]'),
('430909e6-8bce-4974-9700-05083ebb3bd3','相和歌辭 鳳臺曲','李白','唐','唐诗','tang','','[]','嘗聞秦帝女，傳得鳳凰聲。',48,'全唐诗/poet.tang.1000.json','["嘗聞秦帝女，傳得鳳凰聲。", "是日逢仙子，當時別有情。", "人吹彩簫去，天借綠雲迎。", "曲在身不返，空餘弄玉名。"]'),
('970e1233-9d3b-4ee6-92c1-1491ffc37bfa','相和歌辭 鳳凰曲','李白','唐','唐诗','tang','','[]','嬴女吹玉簫，吟弄天上春。',36,'全唐诗/poet.tang.1000.json','["嬴女吹玉簫，吟弄天上春。", "青鸞不獨去，更有攜手人。", "影滅彩雲斷，遺聲落西秦。"]'),
('0ffad7e2-6272-472d-a10d-7495d6de3e7f','相和歌辭 君道曲','李白','唐','唐诗','tang','','[]','大君若天覆，廣運無不至。',56,'全唐诗/poet.tang.1000.json','["大君若天覆，廣運無不至。", "軒后爪牙常先太山稽，如心之使臂。", "小白鴻翼於夷吾，劉葛魚水本無二。", "土扶可成牆，積德爲厚地。"]'),
('4da16564-5084-4550-a435-5373c8a82ae2','舞曲歌辭 吳俞兒舞歌 劒俞','陸龜蒙','唐','唐诗','tang','','[]','枝月喉，櫂霜脊，北斗離離在寒碧。',81,'全唐诗/poet.tang.1000.json','["枝月喉，櫂霜脊，北斗離離在寒碧。", "龍魂清，虎尾白，秋照海心同一色。", "纛影吒沙干影側，神豪髮直。", "四睨之人股佶栗，欲定不定定不得。", "舂牘殘，兒且止。", "狄胡有膽大如山，怖亦死。"]'),
('29d4e6ab-d0d6-4848-8457-3eeae711bfec','舞曲歌辭 吳俞兒舞歌 矛俞','陸龜蒙','唐','唐诗','tang','','[]','手盤風，頭背分，電光戰扇，欲刺敲心留半綫。',61,'全唐诗/poet.tang.1000.json','["手盤風，頭背分，電光戰扇，欲刺敲心留半綫。", "纏肩繞脰，𧞔合眩旋。", "卓植赴列，奪避中節。", "前衝函禮穴，上指孛彗滅，與君一用來有截。"]'),
('2df650b4-1432-4b09-b37d-1068b6f67955','舞曲歌辭 吳俞兒舞歌 弩俞','陸龜蒙','唐','唐诗','tang','','[]','牛來開弦，人爲置鏃。',68,'全唐诗/poet.tang.1000.json','["牛來開弦，人爲置鏃。", "捩機關，迸山谷。", "鹿駭澀，隼擊遲。", "析毫中睫，洞腋分龜。", "達堅壘，殘雄師。", "可以冠猛樂壯曲，抑揚蹈厲，有裂犀兕之氣者非公與。"]'),
('551ff4cc-f942-44ea-942a-9e97dedc5431','舞曲歌辭 東海有勇婦','李白','唐','唐诗','tang','','["\u6b4c\u9882", "\u4fa0\u4e49", "\u5987\u5973", "\u4e50\u5e9c", "\u821e\u66f2\u6b4c\u8f9e"]','梁山感杞妻，慟哭爲之傾。',228,'全唐诗/poet.tang.1000.json','["梁山感杞妻，慟哭爲之傾。", "金石忽暫開，都由激深情。", "東海有勇婦，何慙蘇子卿。", "學劒越處子，超騰若流星。", "捐軀報夫讐，萬死不顧生。", "白刃耀素雪，蒼天感精誠。", "十步兩躩躍，三呼一交兵。", "斬首掉國門，蹴踏五藏行。", "割此伉儷憤，粲然大義明。", "北海李使君，飛章奏天庭。", "舍罪警風俗，流芳播滄瀛。", "志在列女籍，竹帛已光榮。", "淳于免詔獄，漢主爲緹縈。", "津妾一櫂歌，脫父於嚴刑。", "十子若不肖，不如一女英。", "豫讓斬空衣，有心竟無成。", "要離殺慶忌，壯夫素所輕。", "妻子亦何辜，焚之買虛名。", "豈如東海婦，事立獨揚名。"]'),
('673630ef-4ca3-46fd-bfa7-99c842c5d502','舞曲歌辭 章和二年中','李賀','唐','唐诗','tang','','[]','雲蕭素，風拂拂，麥芒如篲黍和粟。',96,'全唐诗/poet.tang.1000.json','["雲蕭素，風拂拂，麥芒如篲黍和粟。", "關中父老百領襦，關東吏人乏詬租。", "健犢春耕土膏黑，菖蒲叢叢沿水脈。", "殷勤爲我下田鉏，百錢攜賞絲桐客。", "遊春漫光塢花白，野林散香神降席。", "拜神得壽獻天子，七星貫斷姮娥死。"]'),
('488a3222-a997-4caa-9dcd-f0833c98b8c9','舞曲歌辭 公莫舞歌','李賀','唐','唐诗','tang','','[]','方花古礎排九楹，刺豹淋血盛銀甖。',128,'全唐诗/poet.tang.1000.json','["方花古礎排九楹，刺豹淋血盛銀甖。", "華筵鼓吹無桐竹，長刀直立割鳴箏。", "橫楣麤錦生紅緯，日炙錦嫣王未醉。", "腰下三看寶玦光，項莊掉箾攔前起。", "材官小臣公莫舞，座上真人赤龍子。", "芒碭雲瑞抱天回，咸陽王氣清如水。", "鐵樞鐵楗重束關，大旗五丈撞雙環。", "漢王今日須秦印，絕臏刳腸臣不論。"]'),
('68880a1b-7d86-45b6-8eba-ef33f0687a14','舞曲歌辭 拂舞辭','李賀','唐','唐诗','tang','','[]','吳娥聲絕天，空雲閑裴回。',112,'全唐诗/poet.tang.1000.json','["吳娥聲絕天，空雲閑裴回。", "門外滿車馬，亦須生綠苔。", "尊有烏程酒，勸君千萬壽。", "全勝漢武錦樓上，曉望晴寒飲花露。", "東方日不破，天光無老時。", "丹成作蛇乘白霧，千年重化玉井龜。", "從蛇作龜二千載，吳堤綠草年年在。", "背有八卦稱神仙，邪鱗頑甲滑腥涎。"]'),
('73ef28f7-b681-4cc4-9edf-36484e085d5f','舞曲歌辭 白鳩辭','李白','唐','唐诗','tang','','[]','鏗鳴鐘，考朗鼓。',124,'全唐诗/poet.tang.1000.json','["鏗鳴鐘，考朗鼓。", "歌白鳩，引拂舞。", "白鳩之白誰與鄰，霜衣雪襟誠可珍。", "含哺七子能平均，食不咽，性安馴。", "首農政，鳴陽春。", "天子刻玉杖，鏤形賜耆人。", "白鷺亦白非純真，外潔其色心匪仁。", "闕五德，無司晨。", "胡爲啄我葭下之紫鱗，鷹鸇鵰鶚，貪而好殺。", "鳳皇雖大聖，不願以爲臣。"]'),
('8981911c-da27-4a25-bffb-a8cc1aa7cdfa','舞曲歌辭 獨漉篇','李白','唐','唐诗','tang','','["\u7231\u56fd"]','獨漉水中泥，水濁不見月。',142,'全唐诗/poet.tang.1000.json','["獨漉水中泥，水濁不見月。", "不見月尚可，水深行人沒。", "越鳥從南來，胡鷹亦北度。", "我欲彎弓向天射，惜其中道失歸路。", "落葉別樹，飄零隨風。", "客無所託，悲與此同。", "羅帷舒卷，似有人開。", "明月直入，無心可猜。", "雄劒挂壁，時時龍鳴。", "不斷犀象，繡澀苔生。", "國恥未雪，何由成名。", "神鷹夢澤，不顧鴟鳶。", "爲君一擊，摶鵬九天。"]'),
('ae2ca5e0-6550-4704-8c4f-41d44eb616ef','舞曲歌辭 獨漉歌','王建','唐','唐诗','tang','','["\u9ec4\u6cb3"]','獨獨漉漉，鼠食貓肉。',26,'全唐诗/poet.tang.1000.json','["獨獨漉漉，鼠食貓肉。", "烏日中，鶴露宿，黃河水直人心曲。"]'),
('6a5d7a69-ea86-4ae5-9803-916d1ab42243','舞曲歌辭 白紵辭二首 一','崔國輔','唐','唐诗','tang','','[]','洛陽梨花落如霰，河陽桃葉生復齊。',32,'全唐诗/poet.tang.1000.json','["洛陽梨花落如霰，河陽桃葉生復齊。", "坐恐玉樓春欲盡，紅綿粉絮裛妝啼。"]'),
('1c76eb85-1424-46f2-a5e8-67630b99e553','舞曲歌辭 白紵辭二首 二','崔國輔','唐','唐诗','tang','','[]','董賢女弟在椒風，窈窕繁華貴後宮。',32,'全唐诗/poet.tang.1000.json','["董賢女弟在椒風，窈窕繁華貴後宮。", "璧帶金釭皆翡翠，一朝零落變成空。"]'),
('027b81b2-f5e9-4357-b7d2-1ef89413539d','舞曲歌辭 白紵辭二首 一','楊衡','唐','唐诗','tang','','[]','玉纓翠珮雜輕羅，香汗微漬朱顏酡，爲君起唱白紵歌。',72,'全唐诗/poet.tang.1000.json','["玉纓翠珮雜輕羅，香汗微漬朱顏酡，爲君起唱白紵歌。", "清聲褭雲思繁多，凝笳哀琴時相和。", "金壺半傾芳夜促，梁塵霏霏暗紅燭。", "令君安坐聽終曲，墜葉飄花難再復。"]'),
('0cabe847-e6b0-4012-9629-20a965ef3778','舞曲歌辭 白紵辭二首 二','楊衡','唐','唐诗','tang','','[]','躡珠履，步瓊筵。',56,'全唐诗/poet.tang.1000.json','["躡珠履，步瓊筵。", "輕身起舞紅燭前，芳姿豔態妖且妍。", "迴眸轉袖暗催弦，涼風蕭蕭流水急。", "月華泛豔紅蓮溼，牽裙攬帶翻成泣。"]'),
('1e3e6d44-452e-4d2a-a4ef-1432ea95da22','舞曲歌辭 白紵辭三首 一','李白','唐','唐诗','tang','','[]','揚清歌，發皓齒，北方佳人東鄰子。',64,'全唐诗/poet.tang.1000.json','["揚清歌，發皓齒，北方佳人東鄰子。", "且吟白紵停淥水，長袖拂面爲君起。", "寒雲夜卷霜海空，胡風吹天飄塞鴻。", "玉顏滿堂樂未終，館娃日落歌吹濛。"]'),
('a1d0535f-ea83-4c32-afc7-6a2e6fd5ed64','舞曲歌辭 白紵辭三首 二','李白','唐','唐诗','tang','','[]','月寒江清夜沈沈，美人一笑千黃金。',64,'全唐诗/poet.tang.1000.json','["月寒江清夜沈沈，美人一笑千黃金。", "垂羅舞縠揚哀音，郢中白雪且莫吟，子夜吳歌動君心。", "動君心，冀君賞。", "願作天池雙鴦鴦，一朝飛去青雲上。"]'),
('b88b6153-68dc-4be5-8c54-d2b41ae658ea','舞曲歌辭 白紵辭三首 三','李白','唐','唐诗','tang','','[]','吳刀翦綵縫舞衣，明妝麗服奪春輝。',56,'全唐诗/poet.tang.1000.json','["吳刀翦綵縫舞衣，明妝麗服奪春輝。", "揚眉轉袖若雪飛，傾城獨立世所稀。", "激楚結風醉忘歸，高堂月落燭已微，玉釵挂纓君莫違。"]'),
('14039c2f-d729-44b8-9a3d-6872f26134e0','舞曲歌辭 白紵歌二首 一','王建','唐','唐诗','tang','','[]','天河漫漫北斗粲，宮中烏啼知夜半。',72,'全唐诗/poet.tang.1000.json','["天河漫漫北斗粲，宮中烏啼知夜半。", "新縫白紵舞衣成，來遲邀得吳王迎。", "低鬟轉面掩雙袖，玉釵浮動秋風生。", "酒多夜長夜未曉，月明燈光兩相照，後庭歌聲更窈窕。"]'),
('d179b5ca-f7ba-4b1b-8dae-311ef942a6e0','舞曲歌辭 白紵歌二首 二','王建','唐','唐诗','tang','','[]','館娃宮中春日暮，荔枝木瓜花滿樹。',88,'全唐诗/poet.tang.1000.json','["館娃宮中春日暮，荔枝木瓜花滿樹。", "城頭烏棲休擊鼓，青娥彈瑟白紵舞。", "夜天燑燑不見星，宮中火照西江明。", "美人醉起無次第，墮釵遺佩滿中庭。", "此時但願可君意，回晝爲宵亦不寐，年年奉君君莫棄。"]'),
('18174707-b8de-4a21-8b90-08b2a03a5ce8','舞曲歌辭 白紵歌','張籍','唐','唐诗','tang','','[]','皎皎白紵白且鮮，將作春衫稱少年。',64,'全唐诗/poet.tang.1000.json','["皎皎白紵白且鮮，將作春衫稱少年。", "裁縫長短不能定，自持刀尺向姑前。", "復恐蘭膏汙纖指，常遣傍人收墮珥。", "衣裳著時寒食下，還把玉鞭鞭白馬。"]'),
('8872bb07-22f7-4cd9-9e74-280338f0e83a','舞曲歌辭 白紵歌','柳宗元','唐','唐诗','tang','','[]','翠帷雙卷出傾城，龍劒破匣霜月明。',32,'全唐诗/poet.tang.1000.json','["翠帷雙卷出傾城，龍劒破匣霜月明。", "朱脣掩抑悄無聲，金簧玉磬宮中生。"]'),
('153dd336-48dc-4173-a668-e9b90b2304fb','舞曲歌辭 冬白紵歌','元稹','唐','唐诗','tang','','[]','吳宮夜長宮漏款，簾幕四垂燈焰暖。',112,'全唐诗/poet.tang.1000.json','["吳宮夜長宮漏款，簾幕四垂燈焰暖。", "西施自舞王自管，雪紵翻翻鶴翎散。", "促節牽繁舞腰嬾，舞腰嬾，王罷飲。", "蓋覆西施鳳花錦，身作匡牀臂爲枕。", "朝佩摐摐王晏寢，酒醒閽報門無事。", "子胥死後言爲諱，近王之臣諭王意。", "共笑越王窮惴惴，夜夜抱冰寒不睡。"]'),
('0a6340e9-f163-4ef8-95ef-ba841990a606','舞曲歌辭 霓裳辭十首 一','王建','唐','唐诗','tang','','[]','弟子部中留一色，聽風聽水作霓裳。',32,'全唐诗/poet.tang.1000.json','["弟子部中留一色，聽風聽水作霓裳。", "散聲未足重來授，直到牀前見上皇。"]'),
('e35cdd52-0037-44b4-880c-30f3ae13e7a1','舞曲歌辭 霓裳辭十首 二','王建','唐','唐诗','tang','','[]','中管五弦初半曲，遙教合上隔簾聽。',32,'全唐诗/poet.tang.1000.json','["中管五弦初半曲，遙教合上隔簾聽。", "一聲聲向天頭落，效得仙人夜唱經。"]'),
('a2ae5464-7458-4a82-bb87-7fee9dc2cda8','舞曲歌辭 霓裳辭十首 三','王建','唐','唐诗','tang','','[]','自直梨園得出稀，更番上曲不教歸。',32,'全唐诗/poet.tang.1000.json','["自直梨園得出稀，更番上曲不教歸。", "一時跪拜霓裳徹，立地階前賜紫衣。"]'),
('4d4046a1-74fa-49c7-99ff-b974cd2a31de','舞曲歌辭 霓裳辭十首 四','王建','唐','唐诗','tang','','[]','旋翻新譜聲初足，除却梨園未教人。',32,'全唐诗/poet.tang.1000.json','["旋翻新譜聲初足，除却梨園未教人。", "宣與書家分手寫，中官走馬賜功臣。"]'),
('fbd26b62-f2ad-4a69-94f5-7ec705622671','舞曲歌辭 霓裳辭十首 五','王建','唐','唐诗','tang','','[]','伴教霓裳有貴妃，從初直到曲成時。',32,'全唐诗/poet.tang.1000.json','["伴教霓裳有貴妃，從初直到曲成時。", "日長耳裏聞聲熟，拍數分毫錯總知。"]'),
('0a28ac61-d628-4b69-8c3e-5dfa084bcaae','舞曲歌辭 霓裳辭十首 六','王建','唐','唐诗','tang','','[]','弦索摐摐隔綵雲，五更初發一山聞。',32,'全唐诗/poet.tang.1000.json','["弦索摐摐隔綵雲，五更初發一山聞。", "武皇自送西王母，新換霓裳月色裙。"]'),
('6c1186ac-7c80-41c5-82ec-44fb797e183d','舞曲歌辭 霓裳辭十首 七','王建','唐','唐诗','tang','','[]','敕賜宮人澡浴回，遙看美女院門開。',32,'全唐诗/poet.tang.1000.json','["敕賜宮人澡浴回，遙看美女院門開。", "一山星月霓裳動，好字先從殿裏來。"]'),
('7d12fb3f-a2a0-4278-8a1c-2641995a3f83','舞曲歌辭 霓裳辭十首 八','王建','唐','唐诗','tang','','[]','傳呼法部按霓裳，新得承恩別作行。',32,'全唐诗/poet.tang.1000.json','["傳呼法部按霓裳，新得承恩別作行。", "應是貴妃樓上看，內人舁下綵羅箱。"]'),
('2d02a1d6-015c-4057-b9b6-b9460d5471dd','舞曲歌辭 霓裳辭十首 九','王建','唐','唐诗','tang','','[]','朝元閣上山風起，夜聽霓裳玉露寒。',32,'全唐诗/poet.tang.1000.json','["朝元閣上山風起，夜聽霓裳玉露寒。", "宮女月中更替立，黃金梯滑竝行難。"]'),
('485cbcc6-790e-4089-8fba-8e49957ff3d8','舞曲歌辭 霓裳辭十首 十','王建','唐','唐诗','tang','','[]','知向華清年月滿，山頭山底種長生。',32,'全唐诗/poet.tang.1000.json','["知向華清年月滿，山頭山底種長生。", "去時留下霓裳曲，總是離宮別館聲。"]'),
('4abce9fd-b9d9-4b3d-b30c-6f9203b04790','舞曲歌辭 柘枝詞','失撰人名','唐','唐诗','tang','','[]','將軍奉命即須行，塞外領彊兵。',28,'全唐诗/poet.tang.1000.json','["將軍奉命即須行，塞外領彊兵。", "聞道烽煙動，腰間寶劒匣中鳴。"]'),
('5f5de9fa-8f26-40e7-ab08-f1dad186aa93','舞曲歌辭 柘枝詞 一','薛能','唐','唐诗','tang','','[]','同營三十萬，震鼓伐西羌。',36,'全唐诗/poet.tang.1000.json','["同營三十萬，震鼓伐西羌。", "戰血黏秋草，征塵攪夕陽。", "歸來人不識，帝里獨戎裝。"]'),
('622f7ce8-2658-47bf-8d4f-a501009f4754','舞曲歌辭 柘枝詞 二','薛能','唐','唐诗','tang','','[]','懸軍征拓羯，內地隔蕭關。',36,'全唐诗/poet.tang.1000.json','["懸軍征拓羯，內地隔蕭關。", "日色崑崙上，風聲朔漠間。", "何當千萬騎，颯颯貳師還。"]'),
('0d722410-b3ba-4272-a9ae-ccd584cde3df','舞曲歌辭 柘枝詞 三','薛能','唐','唐诗','tang','','[]','意氣成功日，春風起絮天。',36,'全唐诗/poet.tang.1000.json','["意氣成功日，春風起絮天。", "樓臺新邸第，歌舞小嬋娟。", "急破催搖曳，羅衫半脫肩。"]'),
('99fc9acc-fbe7-4ecf-a3f3-5b9426ed68eb','舞曲歌辭 屈柘詞','溫庭筠','唐','唐诗','tang','','[]','楊柳縈橋綠，玫瑰拂地紅。',48,'全唐诗/poet.tang.1000.json','["楊柳縈橋綠，玫瑰拂地紅。", "繡衫金騕褭，花髻玉瓏璁。", "宿雨香潛潤，春流水暗通。", "畫樓初夢斷，晴日照湘風。"]'),
('82821220-44e6-465e-ae73-68f04886604a','琴曲歌辭 白雪歌','僧貫休','唐','唐诗','tang','','[]','列鼎佩金章，淚眼看風枝。',72,'全唐诗/poet.tang.1000.json','["列鼎佩金章，淚眼看風枝。", "却思食藜藿，身作屠沽兒。", "負米無遠近，所希升斗歸。", "爲人無貴賤，莫學雞狗肥。", "斯言如不忘，別更無光輝。", "斯言如或忘，即安用人爲。"]'),
('c5b74274-de21-482b-ae7a-b0d8200bbb18','琴曲歌辭 湘妃','劉長卿','唐','唐诗','tang','','[]','帝子不可見，秋風來暮思。',24,'全唐诗/poet.tang.1000.json','["帝子不可見，秋風來暮思。", "嬋娟湘江月，千載空蛾眉。"]'),
('f489fa6f-b73b-422e-848c-b894d73d1653','琴曲歌辭 湘妃','李賀','唐','唐诗','tang','','[]','筠竹千年老不死，長伴秦娥蓋湘水。',64,'全唐诗/poet.tang.1000.json','["筠竹千年老不死，長伴秦娥蓋湘水。", "蠻娘吟弄滿寒空，九山靜綠淚花紅。", "離鸞別鳳煙梧中，巫雲蜀雨遙相通。", "幽愁秋氣上青楓，涼夜波間吟古龍。"]'),
('dfe41fd5-0f8c-4a52-9ce5-8622202264ff','琴曲歌辭 湘妃怨','孟郊','唐','唐诗','tang','','[]','南巡竟不返，帝子怨逾積。',72,'全唐诗/poet.tang.1000.json','["南巡竟不返，帝子怨逾積。", "萬里喪蛾眉，瀟湘水空碧。", "冥冥荒山下，古廟收貞魄。", "喬木深青春，清光滿瑤席。", "搴芳徒有薦，靈意殊脈脈。", "玉佩不可親，裴回煙波夕。"]'),
('f6b7bd03-dfa1-4f65-886f-37c09bd9305f','琴曲歌辭 湘妃怨','陳羽','唐','唐诗','tang','','[]','二妃怨處雲沈沈，二妃哭處湘水深。',32,'全唐诗/poet.tang.1000.json','["二妃怨處雲沈沈，二妃哭處湘水深。", "商人酒滴廟前草，蕭颯風生斑竹林。"]'),
('cb5b6b57-47da-4cde-aa13-9a28bebc7fc4','琴曲歌辭 湘妃列女操','鮑溶','唐','唐诗','tang','','[]','有虞夫人哭虞後，淑女何事又傷離。',128,'全唐诗/poet.tang.1000.json','["有虞夫人哭虞後，淑女何事又傷離。", "竹上淚跡生不盡，寄哀雲和五十絲。", "雲和經奏鈞天曲，乍聽寶琴遙嗣續。", "三湘測測流急綠，秋夜露寒蜀帝飛。", "楓林月斜楚臣宿，更疑川宮日黃昏。", "闇攜女手殷勤言，環佩玲瓏有無間。", "終疑既遠雙悄悄，蒼梧舊雲豈難召。", "老猨心寒不可嘯，目眄眄兮意蹉跎。"]'),
('17a6046a-8569-4e63-a8a3-4f34e3d6a18e','琴曲歌辭 湘夫人','鄒紹先','唐','唐诗','tang','','[]','楓葉下秋渚，二妃愁渡湘。',36,'全唐诗/poet.tang.1000.json','["楓葉下秋渚，二妃愁渡湘。", "疑山空杳藹，何處望君王？", "日落水雲裏，油油心自傷。"]'),
('12b601e6-d430-4602-9468-6f711b10be39','琴曲歌辭 湘夫人','李頎','唐','唐诗','tang','','[]','九嶷日已暮，三湘雲復愁。',36,'全唐诗/poet.tang.1000.json','["九嶷日已暮，三湘雲復愁。", "窅藹羅袂色，潺湲江水流。", "佳期來北渚，捐玦在芳洲。"]'),
('01cc3e31-e2e4-4598-915f-36e8dbbe7c95','琴曲歌辭 湘夫人','郎士元','唐','唐诗','tang','','[]','娥眉對湘水，遙哭蒼梧間。',72,'全唐诗/poet.tang.1000.json','["娥眉對湘水，遙哭蒼梧間。", "萬乘既已歿，孤舟誰忍還。", "至今楚山上，猶有淚痕斑。", "南有涔陽路，渺渺多新愁。", "昔神降回時，風波江上秋。", "彩雲忽無處，碧水空安流。"]'),
('258c6029-d04c-435f-9bb6-b4dadc2d7aea','琴曲歌辭 霹靂引','沈佺期','唐','唐诗','tang','','[]','歲七月，火伏而金生。',146,'全唐诗/poet.tang.1000.json','["歲七月，火伏而金生。", "客有鼓瑟於門者，奏霹靂之商聲。", "始戛羽以騞砉，終扣宮而砰駖。", "電耀耀兮龍躍，雷闐闐兮雨冥。", "氣嗚唅以會雅，態歘翕以橫生。", "有如驅千旗，制五兵，截荒虺，斮長鯨。", "孰與廣陵比，意別鶴儔精而已。", "俾我雄子魄動，毅夫髮立，懷恩不淺，武義雙輯，視胡若芥，翦羯如拾。", "豈徒慨慷中筵，備羣娛之翕習哉。"]'),
('86be8315-dc90-4cd4-a3fa-a5c44bfa3535','琴曲歌辭 拘幽操','韓愈','唐','唐诗','tang','','[]','目揜揜兮其凝其盲，耳肅肅兮聽不聞聲。',53,'全唐诗/poet.tang.1000.json','["目揜揜兮其凝其盲，耳肅肅兮聽不聞聲。", "朝不日出兮夜不見月與星，有知無知兮爲死爲生。", "嗚呼！臣罪當誅兮天王聖明。"]'),
('de20d7c4-b4d0-439a-a765-bd5f796f04e3','琴曲歌辭 越裳操','韓愈','唐','唐诗','tang','','[]','雨之施，物以孳，我何意於彼爲。',75,'全唐诗/poet.tang.1000.json','["雨之施，物以孳，我何意於彼爲。", "自周之先，其艱其勤。", "以有疆宇，私我後人。", "我祖在上，四方在下。", "厥臨孔威，敢戲以侮。", "孰荒於門，孰治於田。", "四海既均，越裳是臣。"]'),
('6066fefa-2f60-42ef-a7cd-247f3ca068c7','琴曲歌辭','韓愈','唐','唐诗','tang','','[]','我家于豳，自我先公。',60,'全唐诗/poet.tang.1000.json','["我家于豳，自我先公。", "伊我承緒，敢有不同。", "今狄之人，將土我疆。", "民爲我戰，誰使死傷。", "彼岐有岨，我往獨處。", "人莫余追，無思我悲。"]'),
('9ce57b19-4e05-403d-9be2-f3670edbf7fa','琴曲歌辭 履霜操','韓愈','唐','唐诗','tang','','[]','父兮兒寒，母兮兒飢。',80,'全唐诗/poet.tang.1000.json','["父兮兒寒，母兮兒飢。", "兒罪當笞，逐兒何爲？", "兒在中野，以宿以處。", "四無人聲，誰與兒語。", "兒寒何衣，兒飢何食。", "兒行于野，履霜以足。", "母生衆兒，有母憐之。", "獨無母憐，兒寧不悲。"]'),
('9079e16c-a6d4-4106-aef4-c003da92c773','琴曲歌辭 雉朝飛操','李白','唐','唐诗','tang','','["\u7434\u66f2\u6b4c\u8f9e", "\u5b64\u72ec", "\u7231\u60c5", "\u4e50\u5e9c"]','麥隴青青三月時，白雉朝飛挾兩雌。',102,'全唐诗/poet.tang.1000.json','["麥隴青青三月時，白雉朝飛挾兩雌。", "錦衣綺翼何離褷，犢牧采薪感之悲。", "春天和，白日暖，啄食飲泉勇氣滿。", "爭雄鬬死繡頸斷，雉子班奏急管弦，心傾美酒盡玉椀。", "枯楊枯楊爾生荑，我獨七十而孤棲。", "彈弦寫恨意不盡，瞑目歸黃泥。"]'),
('138a3527-5f85-4380-8619-c44082b33c0e','琴曲歌辭 雉朝飛操','韓愈','唐','唐诗','tang','','[]','雉之飛，于朝日。',62,'全唐诗/poet.tang.1000.json','["雉之飛，于朝日。", "羣雌孤雄，意氣橫出。", "當東而西，當啄而飛。", "隨飛隨啄，羣雌粥粥。", "嗟我雖人，曾不如彼雉雞。", "生身七十年，無一妾與妃。"]'),
('7b1f320f-14f3-4520-9bd8-314be626f5f3','琴曲歌辭 雉朝飛操','張祜','唐','唐诗','tang','','[]','朝陽隴東泛暖景，雙啄雙飛雙顧影。',78,'全唐诗/poet.tang.1000.json','["朝陽隴東泛暖景，雙啄雙飛雙顧影。", "朱冠錦襦聊日整，漠漠霧中如衣褧。", "傷心盧女弦，七十老翁長獨眠。", "雄飛在草雌在田，衷腸結憤氣呵天。", "聖人在上心不偏，翁得女妻甚可憐。"]'),
('050952a1-e091-45e6-a189-28cae91ecc11','琴曲歌辭 思歸引','張祜','唐','唐诗','tang','','[]','重重作閨清旦鐍，兩耳深聲長不徹。',64,'全唐诗/poet.tang.1000.json','["重重作閨清旦鐍，兩耳深聲長不徹。", "深宮坐愁百年身，一片玉中生憤血。", "焦桐罷彈絲自絕，漠漠暗魂愁夜月。", "故鄉不歸誰共穴，石上作蒲蒲九節。"]'),
('94f344ae-9834-4133-a350-e2cb30265fdf','琴曲歌辭 猗蘭操','韓愈','唐','唐诗','tang','','[]','蘭之猗猗，揚揚其香。',80,'全唐诗/poet.tang.1000.json','["蘭之猗猗，揚揚其香。", "不采而佩，於蘭何傷。", "今天之旋，其曷爲然。", "我行四方，以日以年。", "雪霜貿貿，薺麥之茂。", "子如不傷，我不爾覯。", "薺麥之茂，薺麥之有。", "君子之傷，君子之守。"]'),
('f0d03f1b-abb4-4c3c-84b8-ee1925878a97','琴曲歌辭 幽蘭','崔塗','唐','唐诗','tang','','[]','幽植衆能知，貞芳只暗持。',36,'全唐诗/poet.tang.1000.json','["幽植衆能知，貞芳只暗持。", "自無君子佩，未是國香衰。", "白露霑長早，青春每到遲。"]'),
('16f612a1-559a-4fe0-a9aa-67728642ad85','琴曲歌辭 將歸操','韓愈','唐','唐诗','tang','','[]','秋之水兮其色幽幽，我將濟兮不得其由。',61,'全唐诗/poet.tang.1000.json','["秋之水兮其色幽幽，我將濟兮不得其由。", "涉其淺兮石齧我足，乘其深兮龍入我舟，我濟而悔兮將安歸尤？", "歸乎歸乎，無與石鬬兮無應龍求。"]'),
('2bd9bf11-d7d5-4127-bd5a-7df036c66d02','琴曲歌辭 龜山操','韓愈','唐','唐诗','tang','','[]','龜之氣兮不能雲雨，龜之枿兮不中梁柱，龜之大兮祗以奄魯。',46,'全唐诗/poet.tang.1000.json','["龜之氣兮不能雲雨，龜之枿兮不中梁柱，龜之大兮祗以奄魯。", "知將隳兮哀莫余伍，周公有鬼兮嗟余歸輔。"]'),
('b2363908-b4bc-416c-9b63-dcca77eacb7e','琴曲歌辭 殘形操','韓愈','唐','唐诗','tang','','[]','有獸維狸兮我夢得之，其身孔明兮而頭不知。',40,'全唐诗/poet.tang.1000.json','["有獸維狸兮我夢得之，其身孔明兮而頭不知。", "吉凶何爲兮覺坐而思，巫咸上天兮識者其誰。"]'),
('9ce3f413-a677-4e46-a301-43f8be3a40c2','琴曲歌辭 雙燕離','李白','唐','唐诗','tang','','["\u5199\u71d5", "\u7231\u60c5", "\u5bd3\u8a00\u8bd7"]','雙燕復雙燕，雙飛令人羨。',76,'全唐诗/poet.tang.1000.json','["雙燕復雙燕，雙飛令人羨。", "玉樓珠閣不獨棲，金窗繡戶長相見。", "柏梁失火去，因入吳王宮。", "吳宮又焚蕩，雛盡巢亦空。", "憔悴一身在，孀雌憶故雄。", "雙飛難再得，傷我寸心中。"]'),
('7ccd9915-51a1-4748-9989-af243036455b','琴曲歌辭 列女操','孟郊','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u8d5e\u9882", "\u5987\u5973", "\u4e50\u5e9c"]','梧桐相待老，鴛鴦會雙死。',36,'全唐诗/poet.tang.1000.json','["梧桐相待老，鴛鴦會雙死。", "貞婦貴徇夫，舍生亦如此。", "波瀾誓不起，妾心井中水。"]'),
('781a5cf4-dc33-45f0-be78-ae0dcdb04aa1','琴曲歌辭 別鵠操','韓愈','唐','唐诗','tang','','[]','雄鵠銜枝來，雌鵠啄泥歸。',48,'全唐诗/poet.tang.1000.json','["雄鵠銜枝來，雌鵠啄泥歸。", "巢成不生子，大義當乖離。", "江漢水之大，鵠身鳥之微。", "更無相逢日，安可相隨飛。"]'),
('0a6798a1-eae0-48d8-9a2a-7dde2eae81fc','琴曲歌辭 別鶴','楊巨源','唐','唐诗','tang','','[]','海鶴一爲別，高程方杳然。',84,'全唐诗/poet.tang.1000.json','["海鶴一爲別，高程方杳然。", "影搖江海路，思結瀟湘天。", "皎然仰白日，真姿棲紫煙。", "含情九霄際，顧侶五雲前。", "遐心屬清都，淒響激朱弦。", "超搖間雲雨，迢遰各山川。", "東南信多水，會合當有年。"]'),
('e3c39438-5647-430e-b814-1318cde0ffb1','琴曲歌辭 別鶴','王建','唐','唐诗','tang','','[]','主人一去池水絕，池鶴散飛不相別。',64,'全唐诗/poet.tang.1000.json','["主人一去池水絕，池鶴散飛不相別。", "青天漫漫碧海重，知向何山風雪中？", "萬里雖然音影在，向心終是死生同。", "池邊巢破松樹死，樹頭年年烏生子。"]'),
('1bba0f29-6b38-446b-98d5-20268903330c','琴曲歌辭 別鶴','張籍','唐','唐诗','tang','','[]','雙鶴出雲谿，分飛各自迷。',48,'全唐诗/poet.tang.1000.json','["雙鶴出雲谿，分飛各自迷。", "空巢在松杪，折羽落江泥。", "尋水終不飲，逢林亦未棲。", "別離應易老，萬里兩淒淒。"]'),
('4c91b589-bd48-42db-8034-5b8c236dd885','琴曲歌辭 別鶴','杜牧','唐','唐诗','tang','','[]','分飛共所從，六翮勢摧風。',48,'全唐诗/poet.tang.1000.json','["分飛共所從，六翮勢摧風。", "聲斷碧雲外，影孤明月中。", "青田歸路遠，月桂舊巢空。", "矯翼知何處，天涯不可窮。"]'),
('dd4808c5-cefb-4840-8782-a1636acc9856','琴曲歌辭 走馬引','李賀','唐','唐诗','tang','','[]','我有辭鄉劒，玉鋒堪截雲。',48,'全唐诗/poet.tang.1000.json','["我有辭鄉劒，玉鋒堪截雲。", "襄陽走馬客，意氣自生春。", "朝嫌劒光靜，暮嫌劒花冷。", "能持劒向人，不解持照身。"]'),
('00c7dc13-8eed-4e09-8479-b35f76d3e883','琴曲歌辭 昭君怨','白居易','唐','唐诗','tang','','[]','明妃風貌最娉婷，合在椒房應四星。',64,'全唐诗/poet.tang.1000.json','["明妃風貌最娉婷，合在椒房應四星。", "只得當年備宮掖，何曾專夜奉幃屏。", "見疎從道迷圖畫，知屈那教配虜廷。", "自是君恩薄如紙，不須一向恨丹青。"]'),
('25723633-8e6d-4adb-857e-7f371a2572fd','琴曲歌辭 昭君怨 一','張祜','唐','唐诗','tang','','[]','萬里邊城遠，千山行路難。',24,'全唐诗/poet.tang.1000.json','["萬里邊城遠，千山行路難。", "舉頭唯見日，何處是長安。"]'),
('a26eb089-1854-4fda-b922-6f7be2e3e54c','琴曲歌辭 昭君怨 二','張祜','唐','唐诗','tang','','[]','漢庭無大議，戎虜幾先和。',24,'全唐诗/poet.tang.1000.json','["漢庭無大議，戎虜幾先和。", "莫羨傾城色，昭君恨最多。"]'),
('89ba3c9f-ac0b-474a-85b6-e273072daaca','琴曲歌辭 昭君怨','梁氏瓊','唐','唐诗','tang','','[]','自古無和親，貽災到妾身。',48,'全唐诗/poet.tang.1000.json','["自古無和親，貽災到妾身。", "胡風嘶去馬，漢月弔行輪。", "衣薄狼山雪，妝成虜塞春。", "回看父母國，生死畢胡塵。"]'),
('034a8779-06a1-4be8-8a41-7d1cd91b9e50','琴曲歌辭 明妃怨','楊淩','唐','唐诗','tang','','[]','漢國明妃去不還，馬駞弦管向陰山。',32,'全唐诗/poet.tang.1000.json','["漢國明妃去不還，馬駞弦管向陰山。", "匣中縱有菱花鏡，羞對單于照舊顏。"]'),
('2019c628-e417-42eb-8e73-9991b9003a32','琴曲歌辭 蔡氏五弄 遊春曲二首 一','王涯','唐','唐诗','tang','','[]','萬樹江邊杏，新開一夜風。',24,'全唐诗/poet.tang.1000.json','["萬樹江邊杏，新開一夜風。", "滿園深淺色，照在綠波中。"]'),
('4ba05592-e341-4956-b1fe-386bd7db5272','琴曲歌辭 蔡氏五弄 遊春曲二首 二','王涯','唐','唐诗','tang','','[]','上苑何窮樹，花開次第新。',24,'全唐诗/poet.tang.1000.json','["上苑何窮樹，花開次第新。", "香車與絲騎，風靜亦生塵。"]'),
('74bb4a3f-696f-4218-9ffd-ae4cd1554d02','琴曲歌辭  遊春辭二首 一','王涯','唐','唐诗','tang','','[]','曲江絲柳變煙條，寒骨冰隨暖氣銷。',32,'全唐诗/poet.tang.1000.json','["曲江絲柳變煙條，寒骨冰隨暖氣銷。", "纔見春光生綺陌，已聞清樂動雲韶。"]'),
('637ae116-527c-45fd-9563-79c91c654969','琴曲歌辭  遊春辭二首 二','王涯','唐','唐诗','tang','','[]','經過柳陌與桃蹊，尋逐風光著處迷。',32,'全唐诗/poet.tang.1000.json','["經過柳陌與桃蹊，尋逐風光著處迷。", "鳥度時時衝絮起，花繁衮衮壓枝低。"]'),
('314ba785-3431-4b8d-9ea3-ae18063492d4','琴曲歌辭  遊春辭三首 一','令狐楚','唐','唐诗','tang','','[]','晚遊臨碧殿，日上望春亭。',24,'全唐诗/poet.tang.1000.json','["晚遊臨碧殿，日上望春亭。", "芳樹羅仙仗，晴山展翠屏。"]'),
('95a1424f-b97b-481e-bf7a-50c140e1354b','琴曲歌辭  遊春辭三首 二','令狐楚','唐','唐诗','tang','','[]','一夜好風吹，新花一萬枝。',24,'全唐诗/poet.tang.1000.json','["一夜好風吹，新花一萬枝。", "風前調玉管，花下簇金羈。"]'),
('cebc8c62-57f4-4b5c-bee3-9ef0de0e1df7','琴曲歌辭  遊春辭三首 三','令狐楚','唐','唐诗','tang','','[]','閶闔春風起，蓬萊雪水消。',24,'全唐诗/poet.tang.1000.json','["閶闔春風起，蓬萊雪水消。", "相將折楊柳，爭取最長條。"]'),
('d473eaba-72be-4de0-a7da-db3d833e6564','琴曲歌辭  淥水曲','李白','唐','唐诗','tang','','["\u7434\u66f2\u6b4c\u8f9e", "\u5973\u5b50", "\u4e50\u5e9c", "\u8377\u82b1"]','淥水明秋月，南湖采白蘋。',24,'全唐诗/poet.tang.1000.json','["淥水明秋月，南湖采白蘋。", "荷花嬌欲語，愁殺蕩舟人。"]'),
('2ec9007f-0dc2-4cfb-8f69-d3b0714a6db5','琴曲歌辭  淥水辭','李賀','唐','唐诗','tang','','["\u7231\u60c5", "\u56de\u5fc6", "\u5973\u5b50", "\u76f8\u601d"]','今宵好風月，阿侯在何處？',48,'全唐诗/poet.tang.1000.json','["今宵好風月，阿侯在何處？", "爲有傾城色，翻成足愁苦。", "東湖采蓮葉，南湖拔蒲根。", "未持寄小姑，且持感愁魂。"]'),
('3b52ca46-63f4-441a-97cc-dd5d1b722a47','琴曲歌辭  幽居弄','顧況','唐','唐诗','tang','','[]','苔衣生，花露滴，月入西林蕩東壁。',64,'全唐诗/poet.tang.1000.json','["苔衣生，花露滴，月入西林蕩東壁。", "扣商占角兩三聲，洞戶谿窗一冥寂。", "獨去滄洲無四鄰，身嬰世網此何身？", "關情命曲寄惆悵，久別江南山裏人。"]'),
('ed919b66-0fbe-4b4d-a985-9da7e82edc3d','琴曲歌辭  秋思二首 一','李白','唐','唐诗','tang','','["\u5199\u666f", "\u7434\u66f2\u6b4c\u8f9e", "\u79cb\u5929", "\u4e50\u5e9c", "\u611f\u4f24"]','春陽如昨日，碧樹鳴黃鸝。',48,'全唐诗/poet.tang.1000.json','["春陽如昨日，碧樹鳴黃鸝。", "蕪然蕙草暮，颯爾涼風吹。", "天秋木葉下，月冷莎雞悲。", "坐愁羣芳歇，白露凋華滋。"]'),
('2e8f31ad-6b8c-422f-8c5d-71f6d5a0cf11','琴曲歌辭  秋思二首 二','李白','唐','唐诗','tang','','["\u60b2\u4f24", "\u79cb\u5929", "\u6292\u6000"]','閼氏黃葉落，妾望白登臺。',48,'全唐诗/poet.tang.1000.json','["閼氏黃葉落，妾望白登臺。", "月出碧雲斷，蟬聲秋色來。", "胡兵沙塞合，漢使玉關回。", "征客無歸日，空悲蕙草摧。"]'),
('b281e5ae-9731-4a72-b474-7ac786246f35','琴曲歌辭  秋思二首 一','鮑溶','唐','唐诗','tang','','[]','胡風吹雁翼，遠別無人鄉。',168,'全唐诗/poet.tang.1000.json','["胡風吹雁翼，遠別無人鄉。", "君近鴈來處，幾回斷君腸。", "昔奉千日書，撫心怨星霜。", "無書又千日，世路重茫茫。", "燕國有佳麗，蛾眉富春光。", "自然君歸晚，花落君空堂。", "君其若不然，歲晚雙鴛鴦。", "顧兔蝕殘月，幽光不如星。", "女兒晚事夫，顏色同秋螢。", "秋日邊馬思，武夫不遑寧。", "燕歌易水怨，劒舞蛟龍腥。", "風折連枝樹，水翻無蒂萍。", "立身多戶門，何必燕山銘。", "生世不如鳥，雙雙比翼翎。"]'),
('6b2d7014-6a5e-4e92-a1bc-e31e13bb609b','琴曲歌辭  秋思二首 二','鮑溶','唐','唐诗','tang','','[]','季秋天地閑，萬物生意足。',84,'全唐诗/poet.tang.1000.json','["季秋天地閑，萬物生意足。", "我憂長於生，安得及草木。", "試從古人願，致酒歌秉燭。", "燕趙皆世人，詎能長似玉。", "俯憐老期近，仰視日車速。", "蕭颯御風君，魂夢願相逐。", "百年夜銷半，端爲垂纓束。"]'),
('78657ec0-5fb7-4c24-8b85-a0c10a418bab','琴曲歌辭  秋思','司空曙','唐','唐诗','tang','','[]','靜與嬾相偶，年將衰共催。',48,'全唐诗/poet.tang.1000.json','["靜與嬾相偶，年將衰共催。", "前途歡不集，往事恨空來。", "晝景委紅葉，月華鋪綠苔。", "沈思更何有？結坐玉琴哀。"]'),
('84049d3f-864e-4ffd-bfc7-8ed97e4a5c2d','琴曲歌辭  秋思','司空圖','唐','唐诗','tang','','[]','身病時亦危，逢秋多慟哭。',36,'全唐诗/poet.tang.1000.json','["身病時亦危，逢秋多慟哭。", "風波一搖蕩，天地幾翻覆。", "孤螢出荒池，落葉穿破屋。"]'),
('a3863ffe-6786-4785-9e56-6234fe5922f8','琴曲歌辭  秋思二首 一','王涯','唐','唐诗','tang','','[]','網軒涼吹動輕衣，夜聽更長玉漏稀。',32,'全唐诗/poet.tang.1000.json','["網軒涼吹動輕衣，夜聽更長玉漏稀。", "月渡天河光轉溼，鵲驚秋樹葉頻飛。"]'),
('bbcf126a-4653-4297-8d15-52e894fcaaf4','琴曲歌辭  秋思二首 二','王涯','唐','唐诗','tang','','[]','宮連太液見蒼波，暑氣微清秋意多。',32,'全唐诗/poet.tang.1000.json','["宮連太液見蒼波，暑氣微清秋意多。", "一夜輕風蘋末起，露珠翻盡滿池荷。"]'),
('e1f24e9c-4e19-44f1-b2e3-faff9539d036','琴曲歌辭 胡笳十八拍 第一拍','劉商','唐','唐诗','tang','','[]','漢室將衰兮四夷不賓，動干戈兮征戰頻。',82,'全唐诗/poet.tang.1000.json','["漢室將衰兮四夷不賓，動干戈兮征戰頻。", "哀哀父母生育我，見離亂兮當此辰。", "紗窗對鏡未經事，將謂珠簾能蔽身。", "一朝虜騎入中國，蒼黃處處逢胡人。", "忽將薄命委鋒鏑，可惜紅顏隨虜塵。"]'),
('dff6c8a4-beba-41cf-852d-4ebff7178019','琴曲歌辭 胡笳十八拍 第二拍','劉商','唐','唐诗','tang','','[]','馬上將余向絕域，厭生求死死不得。',64,'全唐诗/poet.tang.1000.json','["馬上將余向絕域，厭生求死死不得。", "戎羯腥膻豈是人，豺狼喜怒難姑息。", "行盡天山足霜霰，風土蕭條近胡國。", "萬里重陰鳥不飛，寒沙莽莽無南北。"]'),
('c421b42a-d13e-4531-b92b-6f7890911e80','琴曲歌辭 胡笳十八拍 第三拍','劉商','唐','唐诗','tang','','[]','如羇囚兮在縲紲，憂慮萬端無處說。',64,'全唐诗/poet.tang.1000.json','["如羇囚兮在縲紲，憂慮萬端無處說。", "使余力兮翦余髮，食余肉兮飲余血。", "誠知殺身願如此，以余爲妻不如死。", "早被蛾眉累此身，空悲弱質柔如水。"]'),
('afb354cd-575a-4bd9-837a-c5a4c199524a','琴曲歌辭 胡笳十八拍 第四拍','劉商','唐','唐诗','tang','','[]','山川路長誰記得，何處天涯是鄉國？',64,'全唐诗/poet.tang.1000.json','["山川路長誰記得，何處天涯是鄉國？", "自從驚怖少精神，不覺風霜損顏色。", "夜中歸夢來又去，朦朧豈解傳消息。", "漫漫胡天叫不聞，明明漢月應相識。"]'),
('788b5b30-f9e9-47f0-b51c-aa396a2bdac7','琴曲歌辭 胡笳十八拍 第五拍','劉商','唐','唐诗','tang','','[]','水頭宿兮草頭坐，風吹漢地衣裳破。',64,'全唐诗/poet.tang.1000.json','["水頭宿兮草頭坐，風吹漢地衣裳破。", "羊脂沐髮長不梳，羔子皮裘領仍左。", "狐襟貉袖腥復膻，晝披行兮夜披臥。", "氈帳時移無定居，日月長兮不可過。"]'),
('63703064-7741-4e1f-802a-f37572bbe641','琴曲歌辭 胡笳十八拍 第六拍','劉商','唐','唐诗','tang','','[]','怪得春光不來久，胡中風土無花柳。',64,'全唐诗/poet.tang.1000.json','["怪得春光不來久，胡中風土無花柳。", "天翻地覆誰得知，如今正南看北斗。", "姓名音信兩不通，終日經年常閉口。", "是非取與在指撝，言語傳情不如手。"]'),
('f1732f3c-f3c8-4f2f-80de-f293835118b0','琴曲歌辭 胡笳十八拍 第七拍','劉商','唐','唐诗','tang','','[]','男兒婦人帶弓箭，塞馬蕃羊臥霜霰。',64,'全唐诗/poet.tang.1000.json','["男兒婦人帶弓箭，塞馬蕃羊臥霜霰。", "寸步東西豈自由，偷生乞死非情願。", "龜茲篳篥愁中聽，碎葉琵琶夜深怨。", "竟夕無雲月上天，故鄉應得重相見。"]'),
('afa11a8c-8bce-408c-a688-2af0cc6632b5','琴曲歌辭 胡笳十八拍 第八拍','劉商','唐','唐诗','tang','','[]','憶昔私家恣嬌小，遠取珍禽學馴擾。',64,'全唐诗/poet.tang.1000.json','["憶昔私家恣嬌小，遠取珍禽學馴擾。", "如今淪棄念故鄉，悔不當初放林表。", "朔風蕭蕭寒日暮，星河寥落胡天曉。", "旦夕思歸不得歸，愁心想似籠中鳥。"]'),
('174db93b-a107-453b-b886-008cebf67118','琴曲歌辭 胡笳十八拍 第九拍','劉商','唐','唐诗','tang','','[]','當日蘇武單于問，道是賓鴻解傳信。',64,'全唐诗/poet.tang.1000.json','["當日蘇武單于問，道是賓鴻解傳信。", "學他刺血寫得書，書上千重萬重恨。", "髯胡少年能走馬，彎弓射飛無遠近。", "遂令邊雁轉怕人，絕域何由達方寸。"]'),
('171eb58b-bb4c-4495-afec-5e09ef658a83','琴曲歌辭 胡笳十八拍 第十拍','劉商','唐','唐诗','tang','','[]','恨凌辱兮惡腥膻，憎胡地兮怨胡天。',64,'全唐诗/poet.tang.1000.json','["恨凌辱兮惡腥膻，憎胡地兮怨胡天。", "生得胡兒欲棄捐，及生母子情宛然。", "貌殊語異憎還愛，心中不覺常相牽。", "朝朝暮暮在眼前，腹生手養寧不憐。"]'),
('ca98fed4-d62e-480c-bcb7-b2b95749441a','琴曲歌辭 胡笳十八拍 第十一拍','劉商','唐','唐诗','tang','','[]','日來月往相推遷，迢迢星歲欲周天。',64,'全唐诗/poet.tang.1000.json','["日來月往相推遷，迢迢星歲欲周天。", "無冬無夏臥霜霰，水凍草枯爲一年。", "漢家甲子有正朔，絕域三光空自懸。", "幾回鴻雁來又去，腸斷蟾蜍虧復圓。"]'),
('d6e20a39-bf74-4373-9181-f7dc61b22c33','琴曲歌辭 胡笳十八拍 第十二拍','劉商','唐','唐诗','tang','','[]','破瓶落井空永沈，故鄉望斷無歸心。',64,'全唐诗/poet.tang.1000.json','["破瓶落井空永沈，故鄉望斷無歸心。", "寧知遠使問姓名，漢語泠泠傳好音。", "夢魂幾度到鄉國，覺後翻成哀怨深。", "如今果是夢中事，喜過悲來情不任。"]'),
('16c5ed5e-3738-4454-9580-c3929d9aea70','琴曲歌辭 胡笳十八拍 第十三拍','劉商','唐','唐诗','tang','','[]','童稚牽衣雙在側，將來不可留又憶。',64,'全唐诗/poet.tang.1000.json','["童稚牽衣雙在側，將來不可留又憶。", "還鄉惜別兩難分，寧棄胡兒歸舊國。", "山川萬里復邊戍，背面無由得消息。", "淚痕滿面對殘陽，終日依依向南北。"]'),
('bab04bd0-d69a-4a0b-ad70-f312ae4e2850','琴曲歌辭 胡笳十八拍 第十四拍','劉商','唐','唐诗','tang','','[]','莫以胡兒可羞恥，恩情亦各言其子。',64,'全唐诗/poet.tang.1000.json','["莫以胡兒可羞恥，恩情亦各言其子。", "手中十指有長短，截之痛惜皆相似。", "還鄉豈不見親族，念此飄零隔生死。", "南風萬里吹我心，心亦隨風渡遼水。"]'),
('4ecbe1b7-261f-4a6c-867b-8bdf85041193','琴曲歌辭 胡笳十八拍 第十五拍','劉商','唐','唐诗','tang','','[]','歎息襟懷無定分，當時怨來歸又恨。',64,'全唐诗/poet.tang.1000.json','["歎息襟懷無定分，當時怨來歸又恨。", "不知愁怨意若何？似有鋒鋩擾方寸。", "悲歡竝行情未快，心意相尤自相問。", "不緣生得天屬親，豈向仇讐結恩信。"]'),
('48ced39d-5dd8-4338-8d84-872036b9cb90','琴曲歌辭 胡笳十八拍 第十六拍','劉商','唐','唐诗','tang','','[]','去時只覺天蒼蒼，歸日始知胡地長。',64,'全唐诗/poet.tang.1000.json','["去時只覺天蒼蒼，歸日始知胡地長。", "重陰白日落何處？秋鴈所向應南方。", "平沙四顧自迷惑，遠近悠悠隨鴈行。", "征途未盡馬蹄盡，不見行人邊草黃。"]'),
('c02906d2-c9d0-4319-8996-95902b618962','琴曲歌辭 胡笳十八拍 第十七拍','劉商','唐','唐诗','tang','','[]','行盡胡天千萬里，惟見黃沙白雲起。',64,'全唐诗/poet.tang.1000.json','["行盡胡天千萬里，惟見黃沙白雲起。", "馬飢跑雪銜草根，人渴敲冰飲流水。", "燕山髣髴辨烽戍，鼙鼓如聞漢家壘。", "努力前程是帝鄉，生前免向胡中死。"]'),
('1809b35f-90e9-48f1-9844-c467caabddd7','琴曲歌辭 胡笳十八拍 第十八拍','劉商','唐','唐诗','tang','','[]','歸來故鄉見親族，田園半蕪春草綠。',64,'全唐诗/poet.tang.1000.json','["歸來故鄉見親族，田園半蕪春草綠。", "明燭重然煨燼灰，寒泉更洗沈泥玉。", "載持巾櫛禮儀好，一弄絲桐生死足。", "出入關山十二年，哀情盡在胡笳曲。"]'),
('d56a5527-058e-49dc-918a-1cc378feed24','琴曲歌辭 飛龍引二首 一','李白','唐','唐诗','tang','','["\u7434\u66f2\u6b4c\u8f9e", "\u8054\u60f3", "\u4e50\u5e9c", "\u6292\u60c5"]','黃帝鑄鼎於荆山，鍊丹砂。',78,'全唐诗/poet.tang.1000.json','["黃帝鑄鼎於荆山，鍊丹砂。", "丹砂成黃金，騎龍飛上太清家。", "雲愁海思令人嗟，宮中綵女顏如花。", "飄然揮手凌紫霞，從風縱體登鑾車。", "登鑾車，侍軒轅。", "遨遊青天中，其樂不可言。"]'),
('82319857-3f0e-4f8f-8e9b-d636d68cae97','琴曲歌辭 飛龍引二首 二','李白','唐','唐诗','tang','','["\u795e\u8bdd", "\u7434\u66f2\u6b4c\u8f9e", "\u4e50\u5e9c", "\u6292\u60c5"]','鼎湖流水清且閑，軒轅去時有弓劒。',107,'全唐诗/poet.tang.1000.json','["鼎湖流水清且閑，軒轅去時有弓劒。", "古人傳道留其間，後宮嬋娟多花顏。", "乘鸞飛煙亦不還，騎龍攀天造天關。", "造天關，聞天語，長雲河車載玉女。", "載玉女，過紫皇，紫皇乃賜白兔所擣之藥，後天而老凋三光。", "下視瑤池見王母，蛾眉蕭颯如秋霜。"]'),
('a6392275-4bf7-46df-ba00-314acb2923e1','琴曲歌辭 烏夜啼引','張籍','唐','唐诗','tang','','[]','秦烏啼啞啞，夜啼長安吏人家。',90,'全唐诗/poet.tang.1000.json','["秦烏啼啞啞，夜啼長安吏人家。", "吏人得罪囚在獄，傾家賣產將自贖。", "少婦起聽夜啼烏，知是官家有赦書。", "下牀心喜不重寐，未明上堂賀舅姑。", "少婦語啼烏，汝啼慎勿虛。", "借汝庭樹作高巢，年年不令傷爾雛。"]'),
('16c63af4-622a-45e2-9a1c-ebb406711054','琴曲歌辭 宛轉歌 一','郎大家宋氏','唐','唐诗','tang','','[]','風已清，月朗琴復鳴。',44,'全唐诗/poet.tang.1000.json','["風已清，月朗琴復鳴。", "掩抑非千態，殷勤是一聲。", "歌宛轉，宛轉和且長。", "願爲雙鴻鵠，比翼共翱翔。"]'),
('261f0670-83cc-482d-bdcf-a5c090d0f5bd','琴曲歌辭 宛轉歌 二','郎大家宋氏','唐','唐诗','tang','','[]','日已暮，長簷鳥應度。',50,'全唐诗/poet.tang.1000.json','["日已暮，長簷鳥應度。", "此時望君君不來，此時思君君不顧。", "歌宛轉，宛轉那能異棲宿。", "願爲形與影，出入恆相逐。"]'),
('d1f3e67e-7367-4ec5-883c-1034927aff24','琴曲歌辭 宛轉歌二首 一','劉方平','唐','唐诗','tang','','[]','星參差，月二八，燈五枝。',50,'全唐诗/poet.tang.1000.json','["星參差，月二八，燈五枝。", "黃鶴瑤琴將別去，芙蓉羽帳惜空垂。", "歌宛轉，宛轉恨無窮。", "願爲波與浪，俱起碧流中。"]'),
('f5e1247c-6c4a-45a3-9f2e-60adee788526','琴曲歌辭 宛轉歌二首 二','劉方平','唐','唐诗','tang','','[]','曉將近，黃姑織女銀河盡。',50,'全唐诗/poet.tang.1000.json','["曉將近，黃姑織女銀河盡。", "九華錦衾無復情，千金寶鏡誰能引。", "歌宛轉，宛轉傷別離。", "願作楊與柳，同向玉窗垂。"]'),
('debccda9-ee99-40d6-9b3e-f4b38cdfa8bb','琴曲歌辭 宛轉行','張籍','唐','唐诗','tang','','[]','華屋重翠幄，綺席雕象牀。',60,'全唐诗/poet.tang.1000.json','["華屋重翠幄，綺席雕象牀。", "遠漏微更疎，薄衾中夜涼。", "爐氳暗裴回，寒燈背斜光。", "妍姿結宵態，寢臂幽夢長。", "宛轉復宛轉，憶憶更未央。"]'),
('be5f29a5-663b-4905-80e7-b034a6b2a745','琴曲歌辭 王敬伯歌','李端','唐','唐诗','tang','','[]','妾本舟中客，聞君江上琴。',108,'全唐诗/poet.tang.1000.json','["妾本舟中客，聞君江上琴。", "君初感妾歎，妾亦感君心。", "遂出合歡被，同爲交頸禽。", "傳杯惟畏淺，接膝猶嫌遠。", "侍婢奏箜篌，女郎歌宛轉。", "宛轉怨如何，中庭霜漸多。", "霜多葉可惜，昨日非今夕。", "徒結萬里歡，終成一宵客。", "王敬伯，淥水青山從此隔。"]'),
('b145a90c-e179-4cc0-8a66-1d63af2bfe6b','琴曲歌辭 三峽流泉歌','李季蘭','唐','唐诗','tang','','[]','妾家本住巫山雲，巫山流水常自聞。',128,'全唐诗/poet.tang.1000.json','["妾家本住巫山雲，巫山流水常自聞。", "玉琴彈出轉寥敻，直似當時夢中聽。", "三峽流泉幾千里，一時流入深閨裏。", "巨石奔崖指下生，飛波走浪弦中起。", "初疑噴湧含雷風，又似嗚咽流不通。", "回湍曲瀨勢將盡，時復滴瀝平沙中。", "憶昔阮公爲此曲，能使仲容聽不足。", "一彈既罷復一彈，願似流泉鎮相續。"]'),
('333b66bc-2738-4424-aaf9-c8834be7fabe','琴曲歌辭 風入松歌','僧皎然','唐','唐诗','tang','','[]','西嶺松聲落日秋，千枝萬葉風颼飀。',111,'全唐诗/poet.tang.1000.json','["西嶺松聲落日秋，千枝萬葉風颼飀。", "美人援琴弄成曲，寫得松間聲斷續。", "聲斷續，清我魂，流波壞陵安足論。", "美人夜坐月明裏，含少商兮照清徵。", "風何淒兮飄飉，攪寒松兮又夜起。", "夜未央，曲何長，金徽更促聲泱泱。", "何人此時不得意，意苦弦悲聞客堂。"]'),
('7ecd869d-dd96-421b-905b-a70a0cb44bad','琴曲歌辭 秋風引','劉禹錫','唐','唐诗','tang','','["\u5199\u98ce", "\u79cb\u5929", "\u98ce", "\u601d\u4e61"]','何處秋風至？蕭蕭送鴈羣。',24,'全唐诗/poet.tang.1000.json','["何處秋風至？蕭蕭送鴈羣。", "朝來入庭樹，孤客最先聞。"]'),
('7b4cf3ff-a6ad-440d-bdd1-85fea0b62ae4','琴曲歌辭 明月引','盧照鄰','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','洞庭波起兮鴻鴈翔，風瑟瑟兮野蒼蒼。',115,'全唐诗/poet.tang.1000.json','["洞庭波起兮鴻鴈翔，風瑟瑟兮野蒼蒼。", "浮雲卷靄，明月流光。", "荆南兮趙北，碣石兮瀟湘。", "澄清規於萬里，照離思於千行。", "橫桂枝於西第，繞菱花於北堂。", "高樓思婦，飛蓋君王。", "文姬絕域，侍子他鄉。", "見胡鞍之似練，知漢劒之如霜。", "試登高而極目，莫不變而迴腸。"]'),
('9cc847cf-e7a7-4e9b-a32b-d621e1f0b3e1','琴曲歌辭 明月歌','閻朝隱','唐','唐诗','tang','','[]','梅花雪白柳葉黃，雲霧四起月蒼蒼，箭水泠冷刻漏長。',40,'全唐诗/poet.tang.1000.json','["梅花雪白柳葉黃，雲霧四起月蒼蒼，箭水泠冷刻漏長。", "揮玉指，拂羅裳，爲君一奏楚明光。"]'),
('d058b37e-109f-4f52-be37-f42936cdd75b','琴曲歌辭 綠竹引','宋之問','唐','唐诗','tang','','[]','青溪綠潭潭水側，修竹嬋娟同一色。',48,'全唐诗/poet.tang.1000.json','["青溪綠潭潭水側，修竹嬋娟同一色。", "徒生仙實鳳不遊，老死空山人詎識。", "妙年秉願逃俗紛，歸臥嵩丘弄白雲。"]');
